window.ROTATION_LLM_ABOUT = {"deadmau5~professional-griefers":{"src":"haiku","haiku":"Self-destructive nihilism and technological alienation in a broken world.","sonnet":"A violent, anarchic vision of technological society destroying itself through machines, bombs, and human brutality.","opus":"A dystopian, apocalyptic vision of youth, technology, warfare and self-destruction, presented as a chaotic video-game world of broken, awful things the narrator made."},"nine-inch-nails~wish":{"src":"haiku","haiku":"Despair and isolation amid broken trust and disillusionment with existence.","sonnet":"Alienation and self-loathing in a world that feels hollow and fake, with no authentic connection left to find.","opus":"Self-loathing and bitter despair at rock bottom, having lost faith in God and a partner, wishing for anything real in an empty life."},"linkin-park~somewhere-i-belong":{"src":"haiku","haiku":"Personal emotional void and struggle to find belonging and self-worth.","sonnet":"A person trapped in emptiness and self-blame searching for healing, identity, and a place where they feel they belong.","opus":"Struggling to break free of inner numbness and pain to heal, find identity, and reach a sense of belonging on one's own terms."},"linkin-park~hit-the-floor":{"src":"haiku","haiku":"Confronting betrayal and waiting for redemption through revenge on a manipulator.","sonnet":"Confronting a manipulative person who lies and belittles, and waiting for the moment their power collapses.","opus":"Confronting a manipulative liar who kept you down, and anticipating their inevitable fall once their deceit collapses."},"bring-me-the-horizon~dear-diary":{"src":"haiku","haiku":"Apocalyptic horror scenario with infection and societal collapse.","sonnet":"A zombie apocalypse experienced through diary entries as the narrator gradually succumbs to infection and eats their dog.","opus":"A darkly comic diary of someone descending into a zombie-outbreak apocalypse, going mad and cannibalistic as the human race ends."},"linkin-park~in-the-end":{"src":"haiku","haiku":"Wasted effort in a relationship despite trying hard; ultimate futility and betrayal.","sonnet":"The futility of straining toward a relationship or goal that ultimately falls apart despite every effort made.","opus":"The futility of effort and trust in a failed relationship, realizing that all one's striving ultimately amounts to nothing."},"crystal-castles~concrete":{"src":"sonnet","sonnet":"The dismantling of fixed belief and certainty, leaving nothing permanent or solid in its place.","opus":"Cryptic imagery of siege, submission and deceit, insisting that nothing is solid or certain and grief has been abandoned."},"linkin-park~with-you":{"src":"haiku","haiku":"Longing for an absent lover and memories haunting waking life.","sonnet":"Holding onto the memory of someone emotionally distant, haunted by a troubled past together that can't be undone.","opus":"Clinging to the memory of a lost, emotionally distant partner after a destructive relationship, unable to bring them back yet still hoping."},"nine-inch-nails~the-hand-that-feeds":{"src":"haiku","haiku":"Questioning blind obedience to authority and willingness to challenge control.","sonnet":"A challenge to passive obedience under political or religious authority, urging people to question and resist blind compliance.","opus":"Challenging blind obedience and religious or political authority, daring the listener to question the system and rebel against it."},"nine-inch-nails~somewhat-damaged":{"src":"haiku","haiku":"Cumulative disappointment and psychological collapse from unmet promises.","sonnet":"Collapse into self-destruction and emotional ruin after being abandoned by someone who promised to be there.","opus":"Bitter emotional collapse and abandonment, feeling broken and poisoned after idolizing someone who was absent when needed most."},"machine-head~aesthetics-of-hate":{"src":"haiku","haiku":"Honoring a fallen brother against disrespect and defending his memory fiercely.","sonnet":"A furious defense of a fallen comrade against a critic who disrespected his memory after his death.","opus":"Furious defense of a murdered friend's honor against a hateful critic, vowing vengeance and damnation for the attacker."},"nine-inch-nails~march-of-the-pigs":{"src":"haiku","haiku":"Consumption, greed, and violent destruction of systems and institutions.","sonnet":"Contempt for a conformist, greedy crowd of followers who are manipulated and fed what those in power want them to consume.","opus":"Sadistic craving to watch the powerful ('pigs') be torn down and destroyed, reveling in appetite, cruelty and domination."},"dragged-under~instability":{"src":"haiku","haiku":"Self-inflicted mental torment and accepting responsibility for one's own misery.","sonnet":"Self-awareness of depression, stagnation, and self-sabotage, recognizing oneself as the source of one's own misery.","opus":"Self-inflicted mental instability and depression, accepting that one's own bitterness and inertia, not others, is the source of misery."},"machine-head~clenching-the-fists-of-dissent":{"src":"haiku","haiku":"Anti-war protest against militarism, propaganda, and senseless violence.","sonnet":"Anti-war rage against government propaganda, corporate war profiteering, and the sacrifice of young lives for oil and power.","opus":"An anti-war protest against government propaganda, patriotic manipulation, and blood spilled for oil, urging nonviolent revolution."},"bring-me-the-horizon~kingslayer-feat-babymetal":{"src":"haiku","haiku":"Breaking free from control systems and awakening to liberation.","sonnet":"A call to break free from a corrupt, controlling system and join a rebellious savior figure to fight back.","opus":"Rallying a corrupted, controlled person to break free from their strings and rebel, framed in cyber-dystopian battle imagery."},"ocean-grove~sex-dope-gold":{"src":"haiku","haiku":"Cynicism about materialism and excess in modern shallow pursuit of pleasure.","sonnet":"The hollow, compulsive pursuit of pleasure — sex, drugs, and money — that leaves the narrator laughing bitterly at its own emptiness.","opus":"The empty, self-destructive chase after sex, drugs and wealth, laughing through loneliness and suffering while craving ever more."},"pro8l3m~molly":{"src":"haiku","haiku":"Hedonistic party lifestyle, wealth display, and sexual conquest.","sonnet":"A boastful night of VIP excess — luxury cars, alcohol, drugs, and women — with a sharp-tongued Polish rap bravado.","opus":"Hedonistic bragging about a lavish, chaotic party of drugs, luxury, women and money, living recklessly like Mick Jagger."},"linkin-park~by-my-self-remix":{"src":"haiku","haiku":"Existential paralysis and inability to trust anyone or make decisions.","sonnet":"The paralysis of self-doubt and social anxiety, unable to trust others or oneself while feeling permanently stuck on the outside.","opus":"Paralyzing self-doubt, distrust and fear of failure, feeling unable to rely on oneself or anyone while isolated and stretched thin."},"slayer~jihad":{"src":"haiku","haiku":"Religious violence and holy war justified by faith in God.","sonnet":"The September 11 attacks narrated from the perspective of a hijacker framing the act as holy war and martyrdom.","opus":"A chilling depiction of holy war and religious terrorism, voiced as a jihadist's fanatical instructions to kill nonbelievers in God's name."},"ocean-grove~junkie":{"src":"sonnet","sonnet":"A self-celebratory band manifesto about their distinctive, hard-hitting sound and loyal fanbase who bang their heads to it.","opus":"A self-referential party anthem hyping the band's bass-driven sound and their crowd of head-banging 'familiar junkies.'"},"ocean-grove~cali-sun":{"src":"haiku","haiku":"Addiction, depression, and melancholy romance in California culture.","sonnet":"Disillusionment and emotional sickness beneath the glamorous surface of Los Angeles, numbed by drugs and chasing a distant love.","opus":"Feeling sick, sad and drugged amid the glamorous emptiness of California, chasing love and escape while numbing on pills."},"system-of-a-down~war":{"src":"haiku","haiku":"Historical religious crusades and justified violence against non-believers.","sonnet":"The religious and political manipulation behind holy wars, questioning why men kill each other in the name of God.","opus":"A critique of holy war and the Crusades, questioning whether faith or greed for riches drives men to kill in God's name."},"crystal-castles~celestica":{"src":"sonnet","sonnet":"A desire to be left alone to fade away and disappear, rejecting comfort or rescue from an indifferent world.","opus":"Surrendering to oblivion and death, asking not to be found or saved, amid cryptic imagery of cleansing and letting go."},"ocean-grove~thousand-golden-people":{"src":"haiku","haiku":"Apocalyptic vision of humanity's decline and societal decay.","sonnet":"Passive drift through a technologically numbing world where humanity watches itself decay without connection or urgency.","opus":"An uneasy meditation on facing the future, mortality and numb detachment as one watches a fading world go by."},"northlane~bloodline":{"src":"haiku","haiku":"Generational trauma and inescapable toxic family bloodline.","sonnet":"Growing up in a chaotic, neglectful household under drug-addicted parents and escaping that toxic inherited trauma alone.","opus":"Escaping a hellish childhood shaped by drug-addicted parents, carrying their bad blood and trauma while surviving on one's own."},"queens-of-the-stone-age~you-think-i-ain-t-worth-a-dollar-but-i-feel-like-a-millionaire":{"src":"sonnet","sonnet":"A high-energy, fragmented ode to heavy rock excess — toro (bullishness), booze, B-movies, and raw appetite for more.","opus":"A hedonistic radio-framed anthem of craving and excess, demanding ever more indulgence, thrills, gore and gratification."},"ocean-grove~superstar":{"src":"haiku","haiku":"Sexual attraction and infatuation with a mysterious woman.","sonnet":"Infatuation with a captivating woman whose presence and movement take over the narrator's mind entirely.","opus":"Infatuation and desire for a captivating woman who dazzles the narrator, mixing romance, ego and ecstatic escapism."},"machine-head~halo":{"src":"haiku","haiku":"Rejecting religious hypocrisy and fighting oppressive faith-based systems.","sonnet":"Anti-religious defiance against the Christian right's political power, rejecting their God and refusing to submit.","opus":"A militant attack on organized Christianity and the religious right, refusing to pray and vowing to fight their hypocrisy over abortion rights."},"nine-inch-nails~the-big-come-down":{"src":"sonnet","haiku":"Internal struggle and descent into despair and emotional breakdown.","sonnet":"An inescapable inner hatred and self-destructive spiral that the narrator cannot outrun no matter where they go.","opus":"Self-destructive craving to hit rock bottom, smashing everything apart as inner hatred and misery keep rising from within."},"type-o-negative~everything-dies":{"src":"haiku","haiku":"Mortality, grief over lost loved ones, and universal human death.","sonnet":"Grief over the deaths of family members and the universal fact that everything and everyone dies.","opus":"Grief and existential despair over mortality, mourning dead relatives and dreading the death of everyone loved, including oneself."},"bring-me-the-horizon~teardrops":{"src":"sonnet","haiku":"Emotional numbness and suicidal ideation masked by substance use.","sonnet":"Emotional numbness and suicidal ideation — feeling emptied out until even sadness runs dry, trapped in one's own dark mind.","opus":"Emotional numbness, depression and self-destruction, feeling drained and empty while high, isolated and turning against oneself."},"machine-head~blood-for-blood":{"src":"haiku","haiku":"Betrayal by close ally and violent retribution for violation of trust.","sonnet":"Demanding respect through physical retaliation against a false friend who exploited and betrayed the narrator.","opus":"A vow of retaliatory violence and demand for respect, repaying betrayal and disrespect with beatings under a 'blood for blood' code."},"nine-inch-nails~heresy":{"src":"haiku","haiku":"Attacking Christianity as destructive manipulation and hypocrisy.","sonnet":"A wholesale rejection of Christianity and organized religion as a hypocritical, manipulative institution built on invented divinity.","opus":"An atheist attack on Christianity, declaring God dead and condemning religion as a man-made instrument of suffering and control."},"the-dillinger-escape-plan~milk-lizard":{"src":"haiku","haiku":"Toxic sexual obsession and predatory desire masked as love.","sonnet":"A toxic sexual attraction to a manipulative woman who takes from the narrator while offering only pain in return.","opus":"A predatory, sadomasochistic sexual encounter with a wounded woman, tangled in mutual manipulation and inevitable estrangement."},"nine-inch-nails~survivalism":{"src":"haiku","haiku":"Survival instinct and indifference amid propaganda and violence.","sonnet":"Societal indifference to destruction — consuming violent media, abandoning the suffering, and choosing self-interest over solidarity.","opus":"Ruthless survivalism amid societal collapse, embracing propaganda and violence and abandoning others to save oneself."},"combichrist~never-surrender":{"src":"haiku","haiku":"Mental anguish and refusal to surrender despite suffering and despair.","sonnet":"Enduring shame, self-punishment, and mental anguish while refusing to surrender or be broken by the pain.","opus":"Self-medicating through guilt and despair, refusing to surrender despite suffering, and rising from one's own ashes."},"aimer~insane-dream":{"src":"haiku","haiku":"Psychological breakdown and fragmented trauma memories.","sonnet":"A desperate, haunted plea for forgiveness and release from traumatic memories that suffocate and will not fade.","opus":"A tormented, nightmarish struggle with painful memories and desperate prayers for forgiveness, trying to shake free of an insane dream."},"limp-bizkit~my-generation":{"src":"haiku","haiku":"Generational apathy and defiant nihilism of Gen X youth.","sonnet":"Generational defiance — a disillusioned youth culture demanding to be taken seriously and refusing to care what others think.","opus":"A defiant, party-hard generational anthem of not caring what critics say until they respect the narrator's disaffected generation."},"magdalena-bay~chaeri":{"src":"haiku","haiku":"Regret for hurting a close friend and inability to escape cycles of harm.","sonnet":"Regret over failing a friend named Chaeri who was struggling with depression, wishing past comfort had been offered sooner.","opus":"Regret and guilt over failing a depressed friend named Chaeri, wishing one had said the right words to help them."},"machine-head~elegy":{"src":"haiku","haiku":"Environmental destruction and Earth's suffering from human exploitation.","sonnet":"A lament for environmental destruction — pollution, deforestation, and acid rain — treated as humanity's crime against the earth.","opus":"An ecological lament for a poisoned, dying Earth, mourning pollution and humanity's destruction of nature as a requiem."},"nine-inch-nails~echoplex":{"src":"sonnet","haiku":"Emotional isolation and psychological withdrawal from the world.","sonnet":"Retreating into an interior fortress of self-isolation, becoming unreachable and letting one's voice echo back to oneself alone.","opus":"Retreating into an isolated inner fortress rebuilt from a broken self, feeling safe, detached and untouchable from others' torment."},"pro8l3m~2-17":{"src":"haiku","haiku":"Digital exploitation and cybercrime threatening personal security and privacy.","sonnet":"Total digital surveillance and data exploitation — everything you do online is tracked, hacked, and owned by unseen others.","opus":"A menacing warning about digital surveillance and hacking, threatening to seize someone's phone, accounts and money in minutes."},"pro8l3m~hazard":{"src":"haiku","haiku":"Urban alienation, drug use, paranoia, and self-destruction.","sonnet":"A night of gambling, drinking, and drugs in a seedy atmosphere, drifting on money, vice, and street-level paranoia.","opus":"A bleak, drug-fueled gambling scene of betting, cocaine, women and paranoia, chasing luck amid grim addiction and risk."},"nine-inch-nails~closer":{"src":"haiku","haiku":"Raw sexual desire and using another person to approach transcendence.","sonnet":"Using raw, animalistic sex to escape self-loathing and a flawed existence, seeking transcendence through physical union.","opus":"Obsessive, self-loathing sexual desire, using degrading sex with another to escape oneself and feel closer to God."},"pro8l3m~na-audiencji":{"src":"haiku","haiku":"Seduction leading to rough sexual encounter.","sonnet":"An explicit, graphic sexual encounter narrated in boastful detail from start to finish.","opus":"Graphic, boastful account of a rough sexual encounter in a lavish apartment, ending on a disturbing note of violence."},"dragged-under~here-for-war":{"src":"haiku","haiku":"Choosing confrontation and standing firm against someone who has failed you.","sonnet":"Cutting off a chronically failing, unreliable person and finding the strength to stand alone without them.","opus":"Cutting off an ungrateful, self-sabotaging person who squandered every chance, declaring independence and readiness to fight on without them."},"machine-head~wipe-the-tears":{"src":"haiku","haiku":"Overcoming hardship and maintaining inner strength through persistent struggle.","sonnet":"Persisting through years of failure, rejection, and hardship and refusing to give up on life or one's own resilience.","opus":"Enduring years of pain, failure and rejection but refusing to give up, wiping away tears and fighting for what one loves."},"eisbrecher~verr-ckt":{"src":"sonnet","haiku":"Social alienation and threat of explosive breakdown from repression.","sonnet":"Embracing one's own madness and difference as freedom, celebrating being unhinged rather than conforming to normality.","opus":"Embracing one's own madness and menace, taunting a hypocritical, fearful other while blurring who is truly normal or sick."},"kyuss~one-inch-man":{"src":"haiku","haiku":"Emotional isolation and loneliness of a small, overlooked man.","sonnet":"A small, lonely man craving intimacy and connection, wondering if anyone could truly want or hold him.","opus":"A lonely soul aching for connection and physical intimacy, doubting whether the desired person truly wants to hold him."},"wargasm-uk~pyro-pyro":{"src":"haiku","haiku":"Mental breakdown and burning down systems while drowning in despair.","sonnet":"Pandemic-era lockdown rage — claustrophobia, collective mental breakdown, and the urge to burn down the system confining everyone.","opus":"Feeling trapped, suffocated and driven to the brink of insanity, threatening to burn everything down if kept caged."},"machine-head~imperium":{"src":"haiku","haiku":"A person refuses to be controlled or defined by others' expectations and prejudice, standing defiantly against external pressure to conform or submit.","sonnet":"A declaration of self-reclamation against societal conditioning and prejudice, where the speaker vows to break free from imposed chains, convert fear and rage into strength, and take back control of their own life.","opus":"A defiant declaration of self-liberation, in which the speaker refuses to be a slave to society, prejudice, and self-doubt, vowing to turn every weakness, rage, and fear into strength and take back control of his own life."},"nine-inch-nails~gave-up":{"src":"haiku","haiku":"After someone changed the speaker's sense of self, they descend into self-destruction and despair, caught in a cycle of trying and failing to escape the damage.","sonnet":"A portrait of total self-destruction: the speaker has systematically dismantled their own sanity, integrity, and sense of self, arriving at a point of resigned surrender after repeatedly trying and failing to hold together.","opus":"A song about self-destruction and despair, in which the speaker describes smashing everything he believed in and valued, hating what he has become, and ultimately giving up after trying and failing."},"linkin-park~numb":{"src":"haiku","haiku":"Emotional numbness and loss of identity develop from being pressured to live under someone else's expectations and rules rather than as oneself.","sonnet":"The speaker is exhausted by the pressure of living up to someone else's expectations, feeling emotionally deadened by the constant sense of falling short, and asserting a need to reclaim their own identity rather than conform.","opus":"A song about being worn down by someone else's expectations, where the speaker feels smothered and constantly judged, and grows numb and detached while longing to be himself instead of who the other person wants him to be."},"linkin-park~papercut":{"src":"haiku","haiku":"Internal paranoia and anxiety manifest as an inner critical voice that judges every action and witnesses every lie, creating persistent self-doubt.","sonnet":"The speaker is consumed by a paranoid inner voice — an imagined face beneath the skin — that catalogues every mistake and lie, and the lyric suggests this same self-critical consciousness exists inside everyone.","opus":"A song about paranoia and self-scrutiny, describing an inner \"face\" that watches, judges, and points out every mistake and lie, a relentless internal voice the speaker cannot silence."},"linkin-park~faint":{"src":"haiku","haiku":"The speaker experiences emotional distance and one-sided effort in a relationship, feeling unheard and ignored while desperately trying to be acknowledged.","sonnet":"The speaker feels chronically invisible and dismissed by someone who refuses to acknowledge them, and the song escalates from quiet hurt at being ignored to a furious demand to finally be heard.","opus":"A song about insecurity and desperation in a one-sided relationship, where the speaker pleads not to be ignored or turned away by someone he clings to, insisting his feelings are real and demanding to be heard."},"linkin-park~from-the-inside":{"src":"haiku","haiku":"Exhaustion from broken trust and inability to rely on someone leads to withdrawal and refusal to invest in the relationship any longer.","sonnet":"Worn down by deceit and broken trust in a relationship, the speaker resolves to cut off emotionally — stripping out everything they gave — and swears they will no longer risk themselves on someone who has proven untrustworthy.","opus":"A song about broken trust and exhaustion from deceit, where the speaker feels isolated from everyone and resolves to throw away his feelings and stop trusting himself with a person who drains him."},"babymetal~starlight":{"src":"haiku","haiku":"A journey of searching and flying toward light and hope, with commitment to never forgetting the brightness and connection that binds people together.","sonnet":"A song about persisting through separation and distance, urging flight toward a guiding starlight and promising that wherever either person ends up, the bond and the memory of that light will never be forgotten.","opus":"A song about soaring beyond time and distance toward a distant light, promising to always stay with and never forget a loved one, keeping their memory alive like a shining, shooting star."},"nine-inch-nails~discipline":{"src":"haiku","haiku":"The speaker needs external discipline and control from a partner because internal self-control has worn away and they cannot stop their own destructive impulses.","sonnet":"The speaker craves external restraint from another person because, once a compulsive pattern starts, they are unable to stop themselves — the song maps a loss of self-control and a dependent need for someone else to impose limits.","opus":"A song about craving control and structure from another person, where the speaker admits he cannot stop himself once he starts and needs discipline, help, and clearly defined limits, blurring where he ends and the other begins."},"ozzy-osbourne~let-me-hear-you-scream":{"src":"haiku","haiku":"An anthem celebrating survival, resilience, and vocal defiance in the face of struggle; the imperative to fight hard and make noise in adversity.","sonnet":"A call-to-arms demanding full-throated, uncompromising effort: the speaker, battered but unbroken, goads an audience to commit entirely rather than hold back, framing the moment as a final stand where going quietly is not an option.","opus":"A combative, taunting song urging a rival or listener to fight loudly and go all out in a do-or-die confrontation, with the speaker vowing to break them down and demanding to hear them scream."},"babymetal~kagerou":{"src":"haiku","haiku":"Wavering and flickering emotions—jealousy, hope, and burning passion—oscillate like a heat haze, never settling into stable ground.","sonnet":"The lyrics circle around something that cannot be hidden or denied — swaying and falling like a pendulum, rising and burning with jealousy — portraying an emotional state of barely-contained, wavering feeling that the speaker knows is obvious to the other person.","opus":"A song about suspicion and jealousy in which the speaker senses that concealment and evasion will not hide the truth, using a swaying pendulum and rising heat haze as images of flickering hope, falling petals, and a burning flame of envy."},"queens-of-the-stone-age~first-it-giveth":{"src":"haiku","haiku":"A cyclical, manipulative relationship dynamic where one person alternates between offering affection and taking it away, leaving the other dependent and confused.","sonnet":"The song describes being hooked on something — or someone — that grants pleasure only to take it away, leaving the speaker dangling, desperate, and aware that the cycle of getting and losing will keep repeating.","opus":"A song about a cruel, deceptive entanglement that first gives and then takes away, leaving the speaker begging, hooked, and toyed with as fortunes turn over time."},"linkin-park~a-place-for-my-head":{"src":"haiku","haiku":"Resentment toward someone who makes emotional demands and extracts energy under the guise of past kindness; the speaker seeks escape and rest.","sonnet":"The speaker resents a person who does favors only to demand repayment, using the image of the sun and moon to explain the one-sided dynamic, and ultimately tells them to leave so they can find peace away from the manipulation.","opus":"A song about resentment toward a greedy, controlling person who gives favors only to demand things back, as the speaker, sick of the tension, wants to break free and find peace of his own away from them."},"type-o-negative~i-don-t-wanna-be-me":{"src":"haiku","haiku":"Existential self-rejection and refusal of one's own identity; the speaker's life is marked by failure and the desire to cease being.","sonnet":"Through the story of a man who lives in mounting failure and dies alone in the snow, the song expresses a deep wish to shed one's own identity, while the closing request — celebrate at the wake, don't mourn — frames that self-rejection with dark resignation.","opus":"A song about self-loathing and a wish to no longer be oneself, framed around a man who lives poorly, dies alone in the snow, and a request that his wake be a celebration rather than a mournful gathering in black."},"nine-inch-nails~head-like-a-hole":{"src":"haiku","haiku":"Rejection of control and manipulation by a dominating force that exploits others; refusal to submit or bow down despite coercion.","sonnet":"A fierce refusal to submit to the power of money and greed, personified as a god that demands worship and tramples the sick and powerless, with the speaker insisting they would rather die than surrender their autonomy to it.","opus":"A song attacking the worship of money as a false god, refusing to surrender control to it and declaring one would rather die than obey, while condemning its indifference and greed."},"linkin-park~points-of-authority-cristal-remix":{"src":"sonnet","sonnet":"The speaker confronts someone who projects their own damage onto others — demanding authority they haven't earned, hurting people to share their pain — while also acknowledging being drawn into self-harm as a way to strike back at that person.","opus":"A song aimed at a controlling, self-righteous person who takes pleasure in others' pain and repeats the harm they learned, while the speaker describes his pride broken and even hurting himself to strike back at them."},"queens-of-the-stone-age~go-with-the-flow":{"src":"haiku","haiku":"Acceptance of impermanence and the realization that connections and memories ultimately don't matter; letting go without resistance or regret.","sonnet":"The song captures a mood of detachment and mild nihilism — people fall in and out of love, discard things, and go along without conviction — while the speaker admits wanting something worth dying and living for rather than just drifting.","opus":"A song about detachment and passivity in a fleeting relationship, where the speaker shrugs that nothing matters anymore even as he wants something worth dying for and living beautifully, willing to just go with the flow."},"linkin-park~don-t-stay":{"src":"haiku","haiku":"Ending a relationship and reclaiming individual identity after being damaged and changed by another person's influence and faithlessness.","sonnet":"The speaker demands the end of a relationship that has eroded their sense of self, asking the other person to take their faithlessness and go, and insisting on reclaiming their own identity rather than being slowly worn away.","opus":"A song about needing to end a toxic relationship, where the speaker asks the other person to leave, forget their shared memories, and give him himself back, insisting he no longer needs them wasting him away."},"nine-inch-nails~only":{"src":"haiku","haiku":"Isolation and realization that a relationship was imaginary—created by the speaker themselves as a vehicle for self-inflicted emotional harm.","sonnet":"The speaker recognizes that a significant other may have been a self-constructed fiction used as a tool for self-inflicted pain, and concludes by acknowledging that forcing their way through a sealed internal doorway has revealed something ugly on the inside.","opus":"A song about dissolving identity and self-isolation, in which the speaker feels himself fading and abstract, concludes that the other person was never real but something he invented to hurt himself, and realizes there is only himself."},"puddle-of-mudd~famous":{"src":"haiku","haiku":"Aspires to fame and hedonistic celebrity excess, willing to trade substance for the allure of wealth, status, and easy conquest.","sonnet":"The narrator fantasizes about achieving celebrity — the Oscars, the Grammys, partying with famous people — while acknowledging the warning that comes with it: be careful what you wish for, because fame brings jadedness and things falling apart.","opus":"A craving for celebrity and its excesses, cataloguing Hollywood parties, awards shows, money and easy sex, while warning to be careful what you wish for as fame can leave everything falling apart."},"the-dillinger-escape-plan~black-bubblegum":{"src":"haiku","haiku":"Confronts someone seeking shallow attention and temporary fame, warning them that their obsession with fleeting recognition will ultimately lead to regret.","sonnet":"A narrator turns on someone they once were captivated by, accusing her of self-delusion, attention-seeking, and a compulsion for notoriety — insisting he saw through the facade all along and that she is destined for regret.","opus":"A bitter address to a vain, attention-hungry person who thinks they're a special queen, with the narrator claiming he sees through the act, knows everything, and pairs their fleeting fame with regret."},"slipknot~left-behind":{"src":"haiku","haiku":"Grieves the loss and deterioration of friendships or relationships, watching people slip away while memories of connection and betrayal linger.","sonnet":"The narrator feels cut off from people and memories that have slipped away, caught between wanting to ignore a toxic presence and being pulled toward it, unable to fully let go.","opus":"Alienation, decay and betrayal, as the narrator feels everything slipping away and describes being left behind after being deceived by someone he now wants to keep at a distance."},"linkin-park~lying-from-you":{"src":"haiku","haiku":"A person breaks free from pretending to be someone they are not, realizing that conforming to others' expectations has corrupted their true self.","sonnet":"Someone who has spent years pretending to be the person others wanted them to be reaches a breaking point, recognising that the false self they performed has become part of them, and decides to break free even if it means hurting those who knew only that mask.","opus":"The exhaustion of maintaining a false self to please someone, as the narrator admits he pretended to be who others wanted and now lies his way out, realizing the worst part of the other person is himself."},"korn~spike-in-my-veins":{"src":"haiku","haiku":"Expresses internal torment and the drive to harness pain as power, refusing to be stopped by suffering or the judgment of others.","sonnet":"The narrator describes being driven by pain and a sense of betrayal while refusing to give in or be stopped, channelling rage and suffering into a relentless forward push against obstacles and external control.","opus":"Pain, rage and self-destruction under the pressure of doing what others demand, with the narrator lashing out, feeling insane and dangerous while pounding spikes into his veins."},"slayer~eyes-of-the-insane":{"src":"haiku","haiku":"Combat trauma haunts a soldier with vivid, intrusive memories of death and violence that break the mind into fragmented, tormented pieces.","sonnet":"A soldier is consumed by the psychological aftermath of combat — relentless flashbacks, mutilated faces haunting his dreams, shell shock and panic attacks that will not let him rest.","opus":"A soldier tormented by war, haunted by mutilated faces, flashbacks, panic attacks and shell shock, unable to rest as death keeps coming back for him."},"marilyn-manson~deep-six":{"src":"haiku","haiku":"Warns against self-deception and the danger of allowing someone into one's mind, using mythic imagery to suggest spiritual invasion and control.","sonnet":"The narrator describes a destructive relationship in which someone has invaded and rearranged his inner world, using imagery of wax feathers and artillery to convey a power imbalance, while invoking the myth of Narcissus as a warning against self-absorption.","opus":"A confrontation with a narcissistic, controlling figure, invoking Zeus's warning to Narcissus, as the narrator resists having his mind invaded and equates love with evil and sin."},"limp-bizkit~my-way":{"src":"haiku","haiku":"Someone asserts independence and refuses further submission to another's authority, choosing freedom and solitude over continued conflict.","sonnet":"Tired of being looked down on and controlled in a relationship or situation, the narrator declares he is done compromising and will leave on his own terms, doing things his way from now on.","opus":"A defiant break from someone's controlling leadership, with the narrator declaring he'll do things his own way, walk out, and let the other person be left missing him."},"a-perfect-circle~the-outsider":{"src":"haiku","haiku":"A speaker condemns another for self-destructive behavior and delusion, refusing to witness further self-sabotage and urging them to take their tragedy elsewhere.","sonnet":"The narrator confronts someone who is self-destructing — lying, threatening suicide, courting drama — with a mixture of exhausted frustration and cold ultimatum, telling them to go through with it somewhere far away if they truly mean it.","opus":"An exasperated plea to a self-destructive, attention-seeking person, urging them to stop their reckless, suicidal behavior, and coldly telling them to do it far away if they go through with it."},"linkin-park~figure-09":{"src":"haiku","haiku":"Someone realizes they have internalized and embodied the pain inflicted by another, becoming like their tormentor and unable to separate themselves from that hurt.","sonnet":"The narrator cannot stop thinking about someone who has left a lasting psychological mark on him; by expressing his pain he realises he has made it a permanent part of his identity, and now he desperately wants to expel that person from his mind.","opus":"How dwelling on the pain someone caused turns into an obsession, as the narrator realizes he took what he hated and made it part of himself, trying to let go and reclaim his own space."},"northlane~carbonized":{"src":"haiku","haiku":"Exposes deception and predatory behavior, predicting that when exposed to scrutiny the false persona will burn away and reveal the corruption beneath.","sonnet":"The narrator exposes a predatory figure who hid behind a false ally facade — using mirrors and smoke, exploiting those beneath him — and declares that once the light comes out, his true nature will be burned away and he will face the consequences.","opus":"An indictment of a manipulative, predatory person who uses smoke and mirrors and looks down on others, with the narrator vowing they'll be exposed and warning he has no heroes left."},"a-day-to-remember~paranoia":{"src":"haiku","haiku":"Paranoia and anxiety manifest as an invasive, all-consuming force that lodges in the mind and cannot be escaped no matter what is tried.","sonnet":"The song gives voice to an invasive, obsessive presence — described as a time bomb ticking inside someone's head — that fuels paranoia: the inability to sleep, fear of unknown callers, the sense of being watched and followed.","opus":"The grip of paranoia and dread, with sleeplessness, fear of unknown callers and footsteps, imagined as a ticking time bomb clouding judgement and lodged inside one's own head."},"bring-me-the-horizon~antivist":{"src":"haiku","haiku":"Critiques apathy and performative activism, arguing that real change requires leaving screens and taking real risks rather than empty posturing.","sonnet":"The narrator rails against hollow online activism and self-righteous posturing, arguing that the world is broken, those in power are predatory, and performative outrage only makes things worse — demanding real action or honest silence instead.","opus":"An angry, cynical rant against apathy and hollow activism, telling people fed up with the world to get off their screens and act, while insisting no revolution comes without blood."},"slayer~new-faith":{"src":"haiku","haiku":"Rejects religious belief and biblical authority, embracing heresy and personal power as liberation from faith-based systems of control.","sonnet":"The narrator rejects organised religion as a system of lies and control for weak minds, and invites listeners to abandon it in favour of a new, self-defined creed built on chaos, indulgence, and personal heresy.","opus":"A blasphemous rejection of religion, mocking a holy man's faith and rejecting biblical prophecy, as the speaker sets himself up as a false savior offering a new faith of indulgence and evil."},"strapping-young-lad~underneath-the-waves":{"src":"haiku","sonnet":"The narrator is exhausted by an endless cycle — fighting, lying, trying, waiting — and suggests that those who follow such patterns end up submerged and lost beneath the waves.","opus":"Weariness and futility, with the narrator sick of waiting, fighting and trying for nothing, longing for a new age while others are lost underneath the waves.","haiku":"The song expresses profound exhaustion with waiting, fighting, and false hope. A speaker buried in fatigue, lies, and waking dread names what lies beneath: something or someone submerged, lost, or gone for good."},"nine-inch-nails~every-day-is-exactly-the-same":{"src":"haiku","haiku":"Expresses the monotony and despair of a heavily controlled, repetitive existence where love is absent and the self is constantly suppressed.","sonnet":"A person trapped in a numb, repetitive existence — stripped of purpose, voice, and feeling — hides a secret message hoping someone will one day find it, clinging to a small remaining piece of selfhood buried beneath a hollow routine.","opus":"Numb, hopeless monotony, as the narrator repeats the same routine, feels neither love nor pain, has lost his voice and purpose, and can predict exactly how it all ends."},"raubtier~det-finns-bara-krig":{"src":"haiku","haiku":"A warrior's existence defined by ceaseless conflict and suffering, with only pain and struggle constituting life's fundamental nature.","sonnet":"The song describes the warrior's existence as an unending state of war: every dawn brings the sound of battle, every heartbeat is a skirmish, and the only fate waiting at the end of the path of hardship is a dark grave beneath a blood-red sky.","opus":"Sung in Swedish, it portrays a warrior's grim existence in which there is only war and life is struggle, with each breath and heartbeat marked by rage, pain and an eternal, deadly vigil."},"machine-head~old":{"src":"haiku","haiku":"Rejects religious hypocrisy and divine authority, embodying defiance against faith systems that have failed humanity.","sonnet":"The narrator attacks organised religion as a corrupt, centuries-old lie that feeds on greed and cruelty, presenting himself as an ancient, defiant force that no crown of thorns or holy authority can subdue.","opus":"Voiced by a blasphemous, anti-Christian figure who reigns over a corrupt, hateful world, defies religion, mocks Jesus, and boasts that attempts to blind, bury or drain him will fail."},"type-o-negative~christian-woman":{"src":"haiku","haiku":"Portrays sexual repression and shame intertwined with religious devotion, depicting a woman trapped between religious doctrine and bodily desire.","sonnet":"The song portrays a devout woman whose religious devotion is entangled with repressed sexual desire — her cross, her prayers, and her guilt converging in an interior conflict between faith and bodily longing.","opus":"A religious woman whose devotion becomes erotic, conflating worship of a suffering Christ with sexual desire and guilt over lust she believes will damn her."},"nine-inch-nails~last":{"src":"haiku","haiku":"A transient, temporary connection devoid of lasting meaning, with desire and addiction masking the inevitability of separation and decay.","sonnet":"The narrator, hollowed out by loss of purpose and self-respect, craves someone to enter him, fix him, and ultimately discard him — fully aware that whatever he seeks is temporary and that nothing can truly rescue him from his own decay.","opus":"Total self-loathing and surrender, as the narrator describes giving up, going all the way down, seeing through lies, and wanting someone to make, take, break and throw him away."},"rob-zombie~reload":{"src":"haiku","sonnet":"The lyrics circle around a commanding, godlike presence called Pin Eyed God and repeated commands to reload and prepare to die, but the imagery is too fragmented and abstract to yield a clear narrative subject.","opus":"A violent, chaotic scene built around loading a gun and 'time to die,' invoking a 'Pin Eyed God' amid disorienting imagery of destruction.","haiku":"A violent, cyclical vision of destruction and transformation: snapping magazines, blowing away, and reloading for another round. The repeated 'time to die' and the image of the 'Pin Eyed God' render an apocalyptic inevitability without escape."},"bloodhound-gang~foxtrot-uniform-charlie-kilo":{"src":"haiku","haiku":"Uses crude euphemisms to describe sexual acts while maintaining a playful, deliberate tone about physical intimacy without pretense.","sonnet":"The entire song is an extended exercise in euphemism, piling up comic slang phrases that all describe the same sex act, while the refrain spells out an obscenity in NATO phonetic alphabet.","opus":"A comedic sex song built entirely on absurd euphemisms and the spelled-out phrase 'fuck,' bluntly declaring the singer doesn't want to beat around the bush."},"bring-me-the-horizon~shadow-moses":{"src":"haiku","haiku":"Confronts the past and secrets that cannot be buried, trapped in an endless cycle of repetition where nothing ever truly ends.","sonnet":"The narrator thought he had buried and escaped something — a feeling, a memory, or a part of himself — only to find it has broken back through; the song frames this return as sempiternal, something that can never truly be killed off.","opus":"A sense of being trapped and going nowhere while living as if ready to die, confronting a buried past or enemy that refuses to stay dead in an endless, cyclical struggle."},"northlane~eclipse":{"src":"haiku","haiku":"Endures abuse and becomes a willing target for another's pain, yet refuses to become like their abuser.","sonnet":"The narrator addresses someone — likely a parent or guardian — who used fear and abuse to control them, resolving that despite carrying the marks of that treatment they refuse to become the same kind of person.","opus":"Standing up to an abuser who takes out their own fear, blame and shame on the narrator, who refuses to be afraid and vows he will never let himself become like his tormentor."},"northlane~talking-heads":{"src":"haiku","haiku":"Internal voices and self-doubt silence the mind while the person resists pharmaceutical escape, refusing to numb the internal chaos.","sonnet":"The narrator feels locked out of his own mind, unable to fit comfortably in his own skin, and overwhelmed by internal voices that drown out rational thought — resisting medication as a way out while searching for a sense of self.","opus":"A struggle with mental turmoil and intrusive voices, as the narrator feels locked out of his own mind, doesn't fit his skin, refuses medication, and is silenced by the 'talking heads' in his head."},"nine-inch-nails~the-idea-of-you":{"src":"haiku","haiku":"Separation and transformation leave only fragments; the narrator asks to be remembered as an idea rather than the deteriorated present self.","sonnet":"A dissociating speaker — uncertain whether his past self or a relationship even existed — urges someone to retreat back to a comfortable idealised image of him rather than witness whatever he is becoming, while an inner voice insists none of this is happening.","opus":"A fractured, dissociative confession in which the narrator insists something is wrong with him, disowns his own words and identity, and begs someone to go back to the idea of him rather than the reality."},"machine-head~bite-the-bullet":{"src":"haiku","haiku":"Encourages endurance and fierce determination, transforming hatred into fuel for overcoming weakness and breaking free from constraints.","sonnet":"The song is a direct address urging someone to convert pain and hatred into strength, to push through inner battles with ferocity and determination rather than yield.","opus":"A defiant call to endure pain and hardship, turning heart to steel and channeling hate into the will to win, urging a lion-hearted refusal to give in to weakness."},"massive-attack~girl-i-love-you":{"src":"haiku","sonnet":"The narrator acknowledges that his love for a woman is gone even as he misses her, recalling a promise she made to stay and expressing the difficulty of accepting that the bond has permanently ended.","opus":"A love that has faded, as the narrator tells a girl he still loves her but his love has gone forever, missing her while acknowledging the connection has ended.","haiku":"A love that has irreversibly faded. The speaker professes devotion yet acknowledges their own love is gone forever; back in Spanish town, a promise to never let down rings hollow against the reality of absence."},"nine-inch-nails~mr-self-destruct":{"src":"haiku","haiku":"An inner force of self-destruction speaks from within, claiming control over all aspects of life and identity, pulling toward ruin and addiction.","sonnet":"An omnipresent inner voice catalogues all the forces — religion, denial, addiction, violence — that it embodies and uses to control and destroy the person it inhabits.","opus":"A personification of self-destruction and control, an inner voice that claims to be one's hate, addiction, lies, religion and ruin, dragging the listener down while they let it happen."},"nine-inch-nails~terrible-lie":{"src":"haiku","haiku":"Confronts God over suffering and broken promises, expressing rage at faith betrayed and the world's darkness despite spiritual devotion.","sonnet":"The narrator accuses God of betrayal — of promising salvation and delivering only hatred, loneliness, and moral collapse — oscillating between rage and a desperate need for something to hold onto.","opus":"An anguished, accusatory address to God, demanding an apology and railing against a betrayal of faith, as the narrator, stripped of security and pride, still desperately wants someone to hold onto."},"redhook~fake":{"src":"haiku","haiku":"Denounces someone as a fraud whose false persona conceals predatory behavior and whose true colors emerge through betrayal and cruelty.","sonnet":"The narrator calls out someone they once admired who turned out to be a fraud — performing values they don't hold, wearing social awareness as a costume — and declares there is no bridge left between them.","opus":"A takedown of a hypocritical public figure whose kind image is a cover, accusing them of performative virtue, stealing others' work, and being exposed as a phony once their true colors show."},"celldweller~switchback":{"src":"haiku","haiku":"Regrets a choice made with lasting consequences from which there is no turning back or escape.","sonnet":"The narrator is trapped by an irreversible choice he regrets — chained to something he cannot reclaim — and the song turns on the impossibility of going back to who he was before.","opus":"Regret over an irreversible choice, as the narrator realizes it's too late to look back or undo what he can't reclaim, chained to a decision that means he'll never be the same."},"machine-head~beautiful-mourning":{"src":"haiku","haiku":"Sorrow and despair consume someone who faces their own violent reflection and confronts the end of hope.","sonnet":"The narrator describes a person in extreme psychological and emotional collapse — dissociating in front of a mirror, contemplating self-harm, consumed by depression — framing it as a final goodbye.","opus":"A descent into depression, self-hatred and suicidal despair, with the narrator not recognizing himself in the mirror, contemplating a razor at his wrist, and bidding a final goodbye."},"a-pale-horse-named-death~dmslt":{"src":"haiku","haiku":"Life feels meaningless and cruel, with a mind collapsing under the weight of existence and the desire to end it.","sonnet":"The narrator describes a life of unrelenting pain and failure in a world he experiences as cruel from birth, expressing an exhausted wish to simply lie down and die.","opus":"Exhaustion with a cruel, painful life, as the narrator feels his mind crumbling, sees no point in living or praying, and expresses a wish to lie down, take a pill, and let himself die."},"linkin-park~by-myslf-josh-abraham-and-mike-shinoda-reanimation":{"src":"haiku","haiku":"Questions whether to trust instinct or caution, unable to rely on the self when stretched between fear and the impossibility of genuine connection.","sonnet":"The narrator is paralysed by contradictory impulses — trust no one versus risk betrayal, fight back versus be overtaken — unable to rely on himself, stretched too thin, and feeling permanently stuck on the outside.","opus":"Being torn by self-doubt and distrust, as the narrator questions whether to trust others or no one, feels stretched too thin, and concludes he can't rely on himself."},"grimes~kill-v-maim":{"src":"haiku","haiku":"Refuses conventional behavior and restraint, accepting consequences for misbehavior while asserting personal autonomy despite systems trying to control them.","sonnet":"A defiant, rule-breaking narrator — invoking mob imagery and declaring a state of war against expected behaviour — insists on acting as he pleases despite external pressure to behave, describing a charismatic, dangerous energy he cannot fully control.","opus":"A brash, defiant persona who refuses to behave, boasting of getting into fights, getting away with it through connections, and having declared a state of war against being good."},"type-o-negative~life-is-killing-me":{"src":"haiku","haiku":"Medical institutions and authority figures exploit the vulnerable, turning life itself into a profitable instrument of suffering.","sonnet":"The narrator rages against the medical establishment as corrupt and incompetent, arguing that doctors are overpaid and useless, and demanding the right to die with dignity rather than be kept alive against his will on life support.","opus":"A scathing attack on doctors and the medical system, comparing physicians to executioners and quacks, and demanding the right to die with dignity rather than be kept alive to run up a bill."},"sodom~in-war-and-pieces":{"src":"haiku","haiku":"War and violence reduce people to fragments and decay, leaving only horror and the knowledge that death is inevitable.","sonnet":"The song dwells in an extreme landscape of mental collapse and physical carnage — fractured minds, rotting bodies, death and sewage — presenting war and psychic destruction as states that leave the self shattered and irretrievable.","opus":"Graphic depictions of war's carnage and madness, with corpses, mental decay and death, as the narrator leaves an enemy 'in war and pieces,' driving them insane with visions of slaughter."},"tankard~die-with-a-beer-in-your-hand":{"src":"haiku","haiku":"Celebrates metal devotion and defiant excess, framing alcohol-fueled rebellion and heroic defiance as the ultimate life choice.","sonnet":"Cast in the language of fantasy battle, the song celebrates a warrior ethos where fighting hard and drinking beer are fused into a single defiant last stand — die with honour, beer in hand.","opus":"A rowdy anthem of metal, battle and beer, mocking rivals who don't drink and vowing to make a final stand and die with a beer in hand."},"nine-inch-nails~we-re-in-this-together":{"src":"haiku","haiku":"Two people remain bound through destruction and pain, determined to survive together despite external forces trying to separate and damage them.","sonnet":"The narrator pledges absolute commitment to another person against a hostile world that wants to destroy what they have found together, declaring their bond unbreakable even as everything else falls apart.","opus":"A defiant devotion to a partner against a hostile world, as the narrator pledges that the two of them will make it through together no matter what tries to tear them apart."},"nutronic~icon":{"src":"haiku","haiku":"Seeks an icon or symbol to fill inner emptiness and provide meaning, grasping for faith in something transcendent.","sonnet":"The narrator, isolated and lacking belief in anything, reaches toward an idealised figure — an icon — to fill an inner emptiness, heal his doubts, and anchor him beyond his own disbelief.","opus":"A plea to an idealized 'icon' to fill an inner emptiness and give a reason to believe, as the narrator, full of disbelief and having fallen from grace, asks to be healed, anchored and freed from tormenting thoughts."},"machine-head~block":{"src":"haiku","haiku":"Hatred and corruption feed systems of control while media and ignorance keep people blind to the destruction of the poor.","sonnet":"The song catalogues systemic failures — racial division, media manipulation, poverty, corruption, pollution — and expresses total disgust with a society that perpetuates suffering while keeping people ignorant and blind.","opus":"An angry protest against societal corruption, racism, poverty, pollution and media manipulation, raging that hate breeds hate and the system feeds on the poor while people are kept blind."},"deadmau5~sofi-needs-a-ladder-ft-sofi":{"src":"haiku","haiku":"Roles reverse when attention shifts, with the pursuer becoming the pursued in a game of attraction and manipulation.","opus":"A power reversal in a toxic relationship, framed as musical chairs, in which the narrator flips the script on someone who tried to figure them out, promising they're about to get burned."},"nine-inch-nails~ruiner":{"src":"haiku","haiku":"Someone with infectious power deceives and corrupts others, gathering followers while destroying everything pure they touch.","sonnet":"The narrator addresses a manipulative, predatory figure who deceived and corrupted everyone around him — including the narrator — and ends by asserting, with increasing desperation, that none of the damage actually hurt him.","opus":"An accusation against a manipulative 'ruiner' who deceives followers and destroys everything he touches, coveting and corrupting what was the narrator's, who insists he wasn't hurt and can't be stopped."},"northlane~4d":{"src":"haiku","haiku":"Guilt and the burden of survival follow those who lost loved ones to overdose and tragedy.","sonnet":"The narrator reflects on losing someone to addiction or an overdose in a broken home and is left carrying guilt rather than grief — the weight of having survived and perhaps failed to prevent what happened.","opus":"Grief and survivor's guilt over losing someone to overdose in a broken home, as the narrator wrestles with the sense that someone like himself took the world away from them."},"rammstein~wiener-blut":{"src":"haiku","haiku":"A figure invites others into darkness and isolation beneath the surface, promising intimacy and eternity in solitude and sadness.","sonnet":"A captor lures victims — framed as children — into a cellar beneath his house, promising play and paradise while sealing them in darkness forever; the song depicts imprisonment and abuse through the voice of a predator who presents himself as protector.","opus":"Sung in German, it depicts a predatory captor luring a victim into a hidden underground room, welcoming them into darkness and imprisonment under the guise of pleasure and companionship."},"gorillaz~clint-eastwood":{"src":"haiku","haiku":"A mystical presence offers guidance and perception, helping others see beyond the material surface to inner spiritual understanding.","sonnet":"A rapping ghost or spirit describes itself as an invisible force running through nature and music itself, offering clarity and psychic guidance to those perceptive enough to see past surface reality — projecting confidence in a coming transformation.","opus":"A mix of weary optimism and mystical bravado, with a hook about feeling glad despite unhappiness and hope that the future is coming on, and a rapped verse casting the speaker as a spiritual guide who perceives destruction and offers survival through the mind."},"hollywood-undead~we-are":{"src":"haiku","haiku":"Broken, rejected, and overlooked people rise from the darkness of the city, demanding recognition for the dreams society ignores.","sonnet":"The song describes people forged from damage and broken beginnings — outsiders, addicts, the overlooked — who persist despite a brutal industry and world that discard them, finding solidarity in shared brokenness.","opus":"An anthem for the broken and overlooked, declaring that we are made from broken parts, chasing dreams in a hellish city of angels, and defiantly refusing to let anyone take away what's theirs."},"rammstein~rosenrot":{"src":"haiku","haiku":"A young man climbs to fetch a rose for his lover but both fall to their deaths, their desire leading to destruction.","sonnet":"Reworking the fairy-tale image of the rosebud on the cliff, the song tells of a young man who climbs a dangerous mountain to fetch a red rose for the girl who demands it; a stone gives way and both fall to their deaths — desire exacting its fatal cost.","opus":"Sung in German and echoing a folk tale, it tells of a girl who demands her beloved climb a mountain to fetch a rose for her, ending when a stone breaks loose and both fall to their deaths."},"limp-bizkit~eat-you-alive":{"src":"haiku","haiku":"Raw attraction and desire overpower a person, becoming an inescapable compulsion that consumes their thoughts.","sonnet":"The narrator is overwhelmed by physical attraction to a woman who ignores him, obsessively describing the pull she has on him while insisting there is nothing wrong with wanting someone who wants nothing to do with you.","opus":"Aggressive, obsessive lust for a woman who wants nothing to do with him, as the narrator fixates on her beauty and repeatedly declares he'd 'eat you alive.'"},"machine-head~davidian":{"src":"haiku","haiku":"A person hardens themselves against pain and disrespect, feeding on suffering and hatred until they become consumed by rage and violence.","sonnet":"A speaker fuelled by rage and hardship turns suffering into strength, feeding on pain and hatred to declare a violent, defiant freedom — the repeated shotgun-blast refrain signals a break from victimhood toward an unforgiving sense of power.","opus":"A defiant refusal to submit, channeling pain and street-bred rage into strength and calling for freedom won by violence. Suffering becomes purity and fuel, ending on the image of a wound with salt poured in it."},"machine-head~now-i-lay-thee-down":{"src":"haiku","haiku":"A haunting meditation on death and the ambiguous killing of a loved one, exploring whether the act was murder or mercy and questioning divine punishment.","sonnet":"A narrator grapples with having killed the person he loved, cycling through near-death imagery and tunnel-of-light hallucinations before arriving at guilt-ridden anguish — the song blurs whether the act was love or murder, and ends with a scream directed at God.","opus":"A narrator wrestling with death and a killing, haunted by whether it was love or murder, and screaming at God after having killed the one he loved. Imagery of dying, tunnels of light, and being laid down runs throughout."},"nine-inch-nails~the-day-the-world-went-away":{"src":"haiku","haiku":"A decay of communication and presence, where voices sound hollow and plastic, and a place exists that consumes fear and pain.","sonnet":"A figure perceived as hollow and decayed — his face a forced mask, his insides cold and grey — faces a reckoning whose cost is described as sweet but total, marking the day everything fell away.","opus":"A portrait of decay behind a false, plastic face, and a place that consumes fear and pain. It centers on the price paid on the day the whole world went away."},"nine-inch-nails~god-given":{"src":"haiku","haiku":"Religious manipulation and cult ideology that uses faith to divide people by race and class, claiming divine selection for some while condemning others.","sonnet":"A satirical portrait of religious self-righteousness: a preacher-figure claims divine authority, demands submission, and uses faith to exclude and dehumanise others, exposing how a sense of being \"chosen\" can become a cover for intolerance.","opus":"A bitter satire of religious certainty, voiced by self-declared chosen ones who claim divine sight while turning people away for their skin color and telling them to know their place. It exposes zealotry that separates the righteous from the 'swine.'"},"nine-inch-nails~suck":{"src":"haiku","haiku":"Sexual addiction and obsession portrayed as a compulsive force, where the speaker experiences shame and degradation while unable to resist.","sonnet":"A song about compulsive desire and self-disgust: the speaker is drawn irresistibly toward a figure who fuses pleasure with a corrosive sense of inner filth, comparing the craving to addiction and blasphemously to religious ecstasy.","opus":"A song of addiction and self-destruction cast in religious and sexual terms, where god is absent and the sickness is self-inflicted. The narrator feels dirty inside and wants to do terrible things."},"strapping-young-lad~s-y-l":{"src":"haiku","haiku":"A worker rejects corporate systems and institutional lies he encountered in low-wage labor, refusing to comply and reclaiming his defiance.","sonnet":"A first-person eruption of anger at a soul-crushing corporate existence — the speaker (referred to as Devy) describes being exploited, lied to, and diminished by a workplace system, before pivoting to a declaration of defiant self-determination and refusal to be controlled.","opus":"A furious rejection of a soul-crushing corporate job, spitting contempt at bosses, lies, and wasted opportunities while declaring the arrival of a defiant 'new age.' It builds into repeated shouts of 'fuck you' as a refusal to obey."},"nine-inch-nails~the-line-begins-to-blur":{"src":"haiku","haiku":"Loss of moral clarity and certainty about one's own identity and beliefs while trapped in an inescapable situation.","sonnet":"A speaker describes losing his sense of moral identity and self as isolation deepens — the boundary between who he was and who he is becoming dissolves, leaving uncertainty about whether anything or anyone has control over his descent.","opus":"A descent into confusion and self-erasure, where the longer the narrator stays inside himself the less clear anything becomes. Once sure which side he was on, he now watches the line blur as he disappears."},"pro8l3m~michael-de-santa":{"src":"haiku","haiku":"A Polish rap portrait of a man living a hedonistic, violent lifestyle in a palm-lined paradise, dealing with wealth, crime, and family chaos.","sonnet":"A first-person narrator moves through a sun-soaked, palm-tree city living out a GTA-style fantasy — armed confrontations, fast cars, casino nights, shady associates — pausing only for fleeting, irritated interactions with a wife and daughter before putting on goggles and heading back out.","opus":"A first-person crime fantasy narrated in the voice of a Grand Theft Auto-style gangster, moving through palm trees, drinks, drugs, shootings, and carjackings between casinos and family arguments. He treats mayhem as a game he can pause by taking off his goggles, blurring the line between player and character."},"machine-head~slanderous":{"src":"haiku","haiku":"Reclaiming slurs and insults as a response to systemic oppression, questioning internal hatred and division while resisting dehumanization.","sonnet":"The song reclaims every slur and marginalising label hurled at the outcast — addict, reject, deviant — and turns them into a statement of solidarity, asking why hatred of others might really be self-hatred, and calling out forces that divide and silence the vulnerable.","opus":"The narrator adopts every slur hurled at him as an outcast, turning bigoted names back on those who use them to divide and conquer. It hinges on the tension between loving and hating a brother, and whether that hatred is really self-hatred."},"a-pale-horse-named-death~when-crows-descend-upon-you":{"src":"haiku","haiku":"Death arrives in the form of black crows that feed on broken bodies and lies, inevitably claiming all souls regardless of their decay.","sonnet":"Death, figured as a pale horse and a murder of black crows, closes in on a person who is already breaking apart — the birds come from lies and wait for the body to rot, as time stops for no one and the soul is inevitably taken.","opus":"Crows gather over a dying, broken soul, tied to the lies that person told, while Death himself rides a pale horse to claim them. The imagery marks the approach and inevitability of dying."},"lia-lia~i-m-a-moth":{"src":"haiku","haiku":"Longing to transform into something beautiful while struggling with emotional pain and parental disconnection, eternally drawn to the moon.","sonnet":"A speaker compares herself to a moth — drawn helplessly toward light, unable to become the butterfly she might have been — weaving in childhood longing for parental love and the bittersweet, persistent pull of things that never quite disappear.","opus":"A speaker mourns being a plain moth rather than the pretty butterfly she could have been, tangling that self-image with a child's ache over whether her father loves her. Love is described as electric and painful, chased like shadows and apologized for."},"my-ticket-home~hyperreal":{"src":"haiku","haiku":"A sense of displacement and emptiness where the mind fragmented and detached, faking emotions while slipping into an unknown state.","sonnet":"A song about a disoriented, emotionally numb state — the speaker feels trapped somewhere between memory and the present, simultaneously locked in and left out, searching for a way to process or escape an unnamed inner strain.","opus":"A song about numb emptiness and dissociation, slipping into a flood of memory and staring into the void while faking away sorrow. The narrator feels locked in yet left out, counting down and asking to be cut loose."},"nine-inch-nails~branches-bones":{"src":"haiku","haiku":"Repetitive cycle of being trapped and erased, unable to escape sensations of decay and the familiar dread of a place once visited before.","sonnet":"A fragmented meditation on dissociation and loss of self: the speaker recognises that what he thought mattered has been shown to be false, that patterns he used to find comfort in no longer hold, and he just wants everyone to go away and leave him to his unravelling.","opus":"A disoriented, decaying state of mind where the narrator has been here before, no longer knows or cares, and his sense of self and memory fall apart. The lyrics dissolve into fractured, looping fragments about whether his thoughts and past ever really mattered, ending with a plea for everyone to go away."},"nine-inch-nails~beside-you-in-time":{"src":"haiku","haiku":"Separation and reunion across parallel spaces, as one person fades away from existence but promises reunion with another.","sonnet":"A speaker who has decided not to stay — likely facing death or departure — finds peace in the idea of fading away and being reunited with someone in a state that transcends time, framed as permanence rather than loss.","opus":"A meditation on parting and reunion, with the narrator sensing a loved one in parallel places as he decides to fade away. He promises they will never die and will be beside each other in time, over an endlessly repeating refrain."},"porcupine-tree~sleep-together":{"src":"haiku","haiku":"An escape from pressure and duty through mutual abandonment and erasure, leaving behind all traces of former identity.","sonnet":"Two people choose a complete exit from their lives — erasing files, burning possessions, abandoning the future — in a pact that frames escape as relief and a shared surrender as the only way to release pressure.","opus":"A pair plotting to erase all trace of themselves and escape their lives together, framed as fate and a final way out. Sleeping together becomes a way to relieve pressure and switch off the future for good."},"bring-me-the-horizon~the-house-of-wolves":{"src":"haiku","haiku":"Religious structures and faith built on lies crumble like a house of wolves, where death is the only salvation from corrupt belief systems.","sonnet":"A rejection of organised religion framed as confrontation: the speaker refuses to accept faith built on manipulation and fear, insisting the promised kingdom is nothing but a grave, and that the edifice of belief will ultimately burn.","opus":"A scornful rejection of religious faith, demanding a reason to believe while dismissing it as a sorry excuse and predicting the believer's 'house of wolves' will collapse and burn. It insists that after death the only kingdom awaiting is a two-foot-wide, six-foot-deep grave."},"nine-inch-nails~right-where-it-belongs":{"src":"haiku","haiku":"Reality and perception questioned as potentially illusory, exploring whether individual consciousness and identity are merely dreams.","sonnet":"A quiet but unsettling examination of constructed reality: the speaker asks whether the world, the self, and perceived safety are all illusions or mental projections, and whether most people are too afraid to look through the cracks and see what — or who — is really there.","opus":"A series of unsettling questions about whether reality is just an elaborate dream and the world exists only inside one's own head. It probes the fear of looking through the cracks and finding oneself utterly alone."},"blue-stahli~give-me-everything-you-ve-got":{"src":"haiku","haiku":"Defiance against someone's attempts to control and intimidate, standing stronger than expected and refusing to submit.","sonnet":"A defiant response to someone who uses fear and negativity as weapons: the speaker strips away the opponent's power by naming it clearly and declaring they can absorb and outlast anything thrown at them.","opus":"A defiant taunt aimed at an adversary whose only weapon is projected fear, with the narrator standing stronger than expected and refusing to be overtaken. He dares them to throw everything they have at him."},"karnivool~nachash":{"src":"haiku","haiku":"Being drawn into an overwhelming force that swells and consumes awareness, a pivotal moment where one becomes part of something larger.","sonnet":"A song about a moment of overwhelming transformation — something vast and beautiful and feared is taking over, and the speaker, who normally keeps his thoughts distant and out of reach, finds himself finally present in a pivotal, irreversible instant.","opus":"An account of a mind-altering, awe-filled experience that feels bigger than the self, both terrifying and beautiful as it takes over. It shifts into private struggle with fading colors, self-doubt, and the fear of having wasted a last chance."},"nine-inch-nails~sin":{"src":"haiku","haiku":"Betrayal and violation in an intimate relationship where purity was stolen and the speaker is used as a vessel for someone else's control.","sonnet":"A relationship defined by violation and control: the speaker gave up something pure and had it stolen, and now oscillates between anger at the other person and a self-flagellating acceptance of punishment and degradation.","opus":"A relationship framed as violation, where the narrator's purity was stolen and he sees himself as an effigy to be disgraced and replaced. He recognizes the compromise, the kiss and fist getting under his skin, and takes in the extent of his own sin."},"nine-inch-nails~capital-g":{"src":"haiku","haiku":"Greed and corruption overtake moral conviction when power is attained, leading to rationalization and indifference to suffering.","sonnet":"A first-person confession from a figure who has abandoned principle for self-interest and power — indifferent to war, inequality, and environmental destruction — revealing that greed (the capital G) is the new god he now serves.","opus":"A satirical monologue in the voice of a selfish, power-worshipping figure who dismisses climate concern, personal accountability, and the suffering of others. The 'capital G' he now worships is revealed to be greed itself."},"filter~the-best-things":{"src":"haiku","haiku":"Life's best things are inaccessible and never free, while everyone pursues the same empty game going nowhere.","sonnet":"A cynical song about stasis and futility: despite apparent freedom or fresh starts, everything keeps going nowhere, and the refrain insists that the best things in life are neither free nor available — the green light promises progress that never arrives.","opus":"A portrait of stalled, going-nowhere lives where green lights lead nowhere and rules no longer matter. The refrain insists the best things in life are neither free nor meant for the narrator."},"woods-of-ypres~december-in-windsor":{"src":"haiku","haiku":"A memory of loneliness and numbness from 2002, when at 22 the speaker felt too old and developed an appetite for self-destructive behavior.","sonnet":"A speaker recalls a specific winter — December 2002 in Windsor — when he was young, alone, and beginning to numb himself with alcohol, and finds that even now the memory of that emotional coldness still has power over him.","opus":"A lonely winter night of drinking to numb pain and forcing oneself out to feel alive, still haunted by someone whose touch would shatter him. It looks back on a cold December, feeling far older than his years and developing a taste for poison."},"nine-inch-nails~the-beginning-of-the-end":{"src":"haiku","haiku":"Complicity in one's own downfall through desperation and selfishness, where facing consequences marks the beginning of collapse.","sonnet":"A warning addressed to the complacent and self-serving: those who have climbed over others, depended on lies, and looked out only for themselves are now facing the consequences — a reckoning that is, paradoxically, both an ending and a beginning.","opus":"A warning that those who climbed over others and lived on lies will face their consequences. The refrain declares this reckoning the beginning of the end."},"rammstein~zwitter":{"src":"haiku","haiku":"A being that is self-sufficient and complete within itself, containing both genders and finding love and fulfillment within its own dual nature.","sonnet":"A celebration of being intersex or dual-gendered — the speaker describes being both sexes merged into one, self-sufficient and self-contained, capable of self-love and self-fertilisation, and delighted not to need anyone else.","opus":"Sung from the perspective of a hermaphrodite who is both sexes in one body and joyfully in love with himself, able to please and even impregnate himself without needing anyone else. The German lyrics revel in this self-sufficiency, kissing his own reflection and shrugging off insults."},"machine-head~wolves":{"src":"haiku","haiku":"A brotherhood of outcasts and the damaged who operate through violence and competition, seeking dominance without satisfaction.","sonnet":"A song about a brotherhood of the damaged and rejected — beaten, dysfunctional, unwanted — who find unity and ferocity in their shared suffering, turning against rivals and tyrants with pack-like aggression, even as they admit the victories bring no lasting satisfaction.","opus":"A brutal anthem of a violent brotherhood of outcasts who bury their rivals and bow to no tyrant, likened to a wolf pack driven by rage and loyalty. Even in victory there is no satisfaction, only the endless hunt."},"make-them-suffer~hollowed-heart":{"src":"haiku","haiku":"Trauma and assault leave someone appearing composed to others while internally broken, with demons haunting them in solitude.","sonnet":"Written on behalf of someone who has endured abuse or assault in private — outwardly composed but inwardly haunted — the song condemns the perpetrators as cowards and acknowledges the survivor's pain while affirming their worth.","opus":"An address to someone secretly suffering, crying themselves to sleep behind closed doors while hiding their pain and blaming themselves. The narrator calls the tormentors cowards and sees the hurting person as a hero rather than a victim."},"nevermore~the-termination-proclamation":{"src":"haiku","haiku":"A violent station where the powerless march to death, where systems murk the line between freedom and execution.","sonnet":"A bleak portrait of lives that are determined before they begin and extinguished by systems beyond their control — whether read as abortion, war, or institutional death, the song indicts the machinery that marches the powerless to their graves and strips them of will.","opus":"A grim vision of a violent system that marches people to their deaths, where all who enter are killed and free will is forgotten. It condemns a mechanical order in which the voiceless take their positions and die."},"slayer~cult":{"src":"haiku","haiku":"Organized religion portrayed as oppressive propaganda that breeds abuse and corruption, using faith to exploit and control vulnerable people.","sonnet":"An all-out assault on organised religion, accusing it of spreading violence, exploitation, and abuse — the speaker rejects Christianity entirely, naming it a contagion and aligning himself against the church's moral authority.","opus":"A blistering attack on organized religion, equating it with hate, fear, war, and exploitation, and casting Jesus and the Bible as instruments of oppression and corruption. The narrator declares open war on God and rejects the 'cult of purity.'"},"megadeth~holy-wars-the-punishment-due":{"src":"haiku","haiku":"Religious conflict drives bloodshed across borders while those preaching superiority hide their complicity, leading to violent retaliation.","sonnet":"A two-part song: the first part condemns killing in God's name and the self-righteous certainty of religious and political leaders; the second shifts to a personal revenge narrative — a man whose family was killed hunts down those responsible — with both halves linked by the theme of violence justified by ideology.","opus":"The first part condemns killing in the name of religion and the divisions that tear countries apart; the second shifts into a mercenary's tale of revenge and paid violence. Together they trace war, righteous posturing, and the fear of having one's very thoughts taken away."},"devin-townsend~life":{"src":"haiku","haiku":"Life's inevitable end approaches and transforms perspective on existence, where death levels all distinctions and individuality.","sonnet":"A meditation on the awareness that life is finite: the speaker urges living on one's own terms, resisting the pull to simply let time slip away, and frames the eventual reckoning with death as something to be faced rather than fled.","opus":"A reflection on facing mortality and owning one's limited time, urging living fully on your own terms rather than fading away. It repeats the reassurance of meeting again on the other side, while noting death levels everyone to the same ground."},"bloodhound-gang~ralph-wiggum":{"src":"sonnet","sonnet":"A collage of non-sequiturs and absurdist one-liners drawn from the character Ralph Wiggum — the song has no narrative or emotional throughline, existing entirely as comedic randomness strung together in the voice of an oblivious child.","opus":"The lyrics are a collage of nonsensical one-liners in the voice of a dim, childlike character, strung together with a mock pop-star chorus telling him to get off the stage. The backward-spelled 'join the navy' hidden in the refrain is its one recurring wink."},"limp-bizkit~why-try":{"src":"haiku","haiku":"Aggressive dominance and destruction of competitors through confidence and violence, with contempt for those who try to challenge or oppose.","sonnet":"A bravado-heavy battle rap framing the speaker as an unstoppable force who will destroy any rival — with boxing and street-fight imagery throughout — arguing that opponents are already beaten before they start.","opus":"A braggadocious battle rap taunting rivals and rap contenders with threats of destruction and violent knockouts. The narrator crowns himself the top predator, promising anyone who challenges him will fry."},"serj-tankian~cornucopia":{"src":"haiku","haiku":"Environmental destruction driven by ignorance and lust, where humanity exploits nature without understanding the consequences.","sonnet":"A song about humanity's destructive relationship with the natural world: we rape and exploit the Earth without understanding why it suffers, surrounded by escalating ecological disasters — hurricanes, tornadoes, tsunamis — while the speaker mourns a broken pact and wonders why we disfigure what is beautiful.","opus":"An eco-conscious lament weaving a strange love plea with images of humanity raping the Earth and reaping violent storms, hurricanes, and tsunamis as consequence. It muses on why people disfigure beautiful things while still hoping for extraordinary connection."},"aimer~closer":{"src":"haiku","haiku":"An inevitable tragic ending that the speaker knows approaches, standing trapped between pretense and a predetermined conclusion.","sonnet":"A song about the slow, inevitable end of a relationship or moment: the speaker watches colours fade, memories slip, and the distance grow, knowing how the story ends but moving toward it anyway — closer to loss, farther from escape.","opus":"A song of hiding behind lies while falling apart inside, clinging to fading memories and pain as the only stable reality. The narrator moves closer to and farther from a moment, certain that however the story unfolds, it always ends with a particular person."},"paradise-lost~channel-for-the-pain":{"src":"haiku","haiku":"Persistent loneliness and a refusal to engage with life, where suffering itself becomes the only constant in existence.","sonnet":"A speaker who lives alone and seems to have always lost — never choosing, never seeking, never demanding — finds that his very existence has become a conduit for pain, and accepts this not with resistance but with passive, broken endurance.","opus":"A study of isolation and passivity, where the narrator lives alone, never chooses, and expects only to lose. His very existence becomes a channel for pain as his mind breaks and he avoids seeking the truth."},"dragged-under~hypochondria":{"src":"haiku","haiku":"Genuine illness dismissed by others as psychological delusion, leading to desperation for medical validation that never comes.","sonnet":"A person convinced something is genuinely wrong with them is dismissed as paranoid by everyone around them: the song captures the terror of feeling ill and unheard, of losing the battle with one's own mind while the world insists there is nothing to fix.","opus":"A first-person account of health anxiety and being disbelieved, terrified of an illness others insist is only in his head. Torn between fear of dying and wanting to live, he wages a losing war with his own mind."},"bring-me-the-horizon~parasite-eve":{"src":"haiku","haiku":"An epidemic or plague spreads through a population that ignored warnings, where suspension and fear replace normal life and death becomes inevitable.","sonnet":"Using pandemic and infection imagery, the song frames a coming catastrophe as inevitable and uncontainable — society is unprepared, leaders are incompetent, and the question is not whether disaster will arrive but whether anyone will remember the lesson once it has passed.","opus":"A song about a spreading plague and mass panic, framed as a war rather than a mere warning, with fever, quarantine, and paranoia about hidden agendas. It questions whether people will remember the lesson once the infection is forgotten, and warns that no amount of hand-washing can escape it."},"deftones~prayers-triangles":{"src":"haiku","haiku":"Internal conflict between divine and demonic forces that render someone eternally imprisoned and spiritually enslaved.","sonnet":"A speaker trapped between an inner demonic force and the angels he tries to keep finds that prayers and mental constructs offer no release — the repeated refrain \"you will never be free\" describes a state of spiritual and psychological captivity with no visible exit.","opus":"A struggle with a godless demon awakening inside, feeling enslaved to forces slowly rotting the speaker from within. The refrain warns someone they will never be free, amid images of tearing one's own heart out."},"nine-inch-nails~sunspots":{"src":"haiku","haiku":"Transformation through obsession with another person who awakens and consumes the self, burning away what was previously real.","sonnet":"A speaker is overwhelmed by an irresistible force — figured partly as a woman, partly as a consuming inner drive — that pulls him out of his old life completely; by the end he has stared into the sun long enough to lose the sense of ever having been a coherent self.","opus":"A compulsive, self-destructive attraction the narrator can't disobey, tied to a woman who makes him feel real even as he burns everything down. He stares into the sun reviewing all he's done, sensing he could have been someone but can't stop what he's begun."},"system-of-a-down~p-l-u-c-k":{"src":"haiku","haiku":"Genocide and systemic extermination of a people requires armed response and restitution for stolen lives and dignity.","sonnet":"A furious response to genocide — specifically the Armenian Genocide, given the band's heritage — calling for recognition, restoration, and reparation, and arguing that revolution is the only answer to a crime of that scale.","opus":"A protest against genocide and the erasure of an entire people, calling for revolution, recognition, restitution, and reparation. It condemns a system that took the children and left the few survivors unfound."},"nine-inch-nails~you-know-what-you-are":{"src":"haiku","haiku":"Self-deception fails eventually when others recognize one's true nature, leaving no choice but to return to origins and accept reality.","sonnet":"A speaker who tried to pass as something he is not — patching over his flaws long enough to be accepted — has been found out, and now confronts himself (or someone like him) with the demand to stop pretending and acknowledge what he really is.","opus":"A song of self-loathing and exposure, where the narrator's attempt to patch over his flaws and sneak by ultimately rots away and is found out. The furious refrain, aimed at himself, demands he remember what he really is and where he came from."},"queens-of-the-stone-age~no-one-knows":{"src":"haiku","haiku":"Following rules and taking pills designed to control, while realizing internal fulfillment and connection exist but remain unknowable to others.","sonnet":"A speaker adrift — rules to follow, pills to swallow, drifting across deserts and oceans — describes surrendering to something or someone that possesses him entirely, recognising himself as a fool for it but unable to resist what feels like a hidden gift.","opus":"A disoriented drift through rules, pills, and desire toward someone the narrator both surrenders to and feels a fool for, journeying through a desert of the mind. It closes with a Spanish-language radio-DJ skit introducing the band."},"queens-of-the-stone-age~avon":{"src":"haiku","haiku":"A system for controlling and dispensing with people portrayed as simple and efficient, with no distinction between victims.","sonnet":"A brief, impressionistic sketch of observation and control — the speaker watches people moving in a haze, strings them up and cuts them down, and notes that free-range humans end up cooped regardless, leaving a sense of detached, cyclical manipulation.","opus":"A cryptic sketch of watching someone move through a park in a haze, laced with unsettling images of stringing things up and cutting them down and of 'free range humans' cooped up. The meaning stays elusive, built on repetition and detachment."},"megadeth~hangar-18":{"src":"haiku","haiku":"Secret military facility housing alien remains and cryogenic subjects under enforced amnesia, held behind impenetrable security.","sonnet":"A song about a secret government facility — Hangar 18 — where the speaker claims alien bodies and technology are stored, and where selective amnesia is used to silence anyone who gets too close to the truth.","opus":"A conspiracy narrative about a secret military installation storing foreign life forms in cryogenic suspension, hidden behind impenetrable walls. The narrator fears he has seen and knows too much, mocking the notion of 'military intelligence.'"},"nine-inch-nails~getting-smaller":{"src":"haiku","haiku":"Increasing erasure and powerlessness as individuality and voice are stripped away, leaving only obedience and fading away.","sonnet":"A portrait of slow erasure: the speaker has lost his grip, his voice, his sense of purpose, and now shrinks into invisibility — obeying, behaving, fading away — with a sardonic acceptance that the shrinking world is somehow okay, even as it clearly isn't.","opus":"A portrait of paranoia and diminishing self, where the narrator loses his grip, obeys, and fades into a faceless nobody in the crowd. He recalls once believing in achieving something great but can no longer tell what's real, resigning himself to his shrinking world."},"a-day-to-remember~bad-vibrations":{"src":"haiku","haiku":"Toxic emotional influence that permeates and corrupts, leaving the speaker emptied and heartless.","sonnet":"A song about absorbing someone else's toxicity: the speaker feels an external darkness pressing in — distorting perception, inducing numbness, and shaping identity — framed as a sickness he cannot escape and did not choose.","opus":"A song about inner darkness and consuming pain treated as a sickness and a choice one must live with. Bad vibrations surround and corrupt the narrator, casting shadows that reshape who he is each day."},"cage-the-elephant~aberdeen":{"src":"haiku","haiku":"Obsessive cyclical abuse from someone dangerously seductive, repeatedly burning the speaker emotionally.","sonnet":"A speaker repeatedly drawn back to someone who burns him — a relationship defined by compulsive return despite knowing it's destructive — the name Aberdeen anchoring a specific feeling of being unable to cut the cord.","opus":"A song about being repeatedly burned by a manipulative, creeping lover the narrator keeps returning to, cutting the cord only to look way back. Recognizing his own dark side and the toll of the cycle runs beneath the restless refrain."},"carcass~death-certificate":{"src":"haiku","haiku":"Death reduced to data and administrative record, stripped of meaning and memory in institutional systems.","sonnet":"A person reduced to data after death: cross-indexed, machine-coded, digitised into a statistical obituary — the song strips away any notion of legacy or meaning, leaving only a certificate and a database entry as the final trace of a life.","opus":"A bleak meditation on death reduced to bureaucracy, where a life is cross-indexed, dissected, and filed away as data. A person's only legacy becomes a statistical obituary and a certificate of death."},"architects~these-colours-don-t-run-feat-jon-green-of-deez-nuts":{"src":"haiku","haiku":"Deception and corruption pervade systems of power and freedom, where materialistic pursuit leads to spiritual death.","sonnet":"A critique of the American Dream and capitalist society: the streets are not paved with gold, freedom comes at a price, and beneath the surface lies deception, chemical numbness, and a grinding suburban futility that benefits those at the top.","opus":"A furious critique of the false promise of the 'land of the free,' where streets aren't paved with gold and corruption and deception pervade everything. It mocks forced reassurances that 'everything is fine' and blames the greedy for the rot."},"nine-inch-nails~1-000-000":{"src":"haiku","haiku":"Describes a state of severe numbness and disconnection, with the narrator unable to feel anything despite suicidal ideation and existential despair. The repeating refrain of emotional emptiness frames a consciousness that has shutdown completely.","sonnet":"A person consumed by numbness and spiritual emptiness describes going through the motions of life — waking up, starting again — while feeling nothing and wondering whether any of it matters. The recurring image of jumping from rooftops and feeling a million miles away captures a complete disconnection from reality and self.","opus":"A portrait of numbness and self-erasure, where the narrator feels a million miles away, unable to feel anything, and fantasizes about falling from rooftops or putting a gun in his mouth. It captures the sense of going through the motions of life while doubting whether anything ever mattered."},"trivium~in-waves":{"src":"haiku","haiku":"Confronts the question of whether to end one's life and take others down in the process, with death approaching fast and life lacking purpose. The song explores waves of destructive impulses and the desire to drag everyone into oblivion.","sonnet":"The speaker wrestles with the impulse toward self-destruction and the awareness that death is approaching, questioning the purpose of a finite life and expressing a dark desire to pull others down into ruin alongside them.","opus":"The narrator wrestles with the urge to end it all publicly and whether he would drag everyone else down with him. Facing the fast approach of death, he questions the point of a life that won't last, imagining himself and others igniting and sinking in flames."},"nine-inch-nails~hurt":{"src":"haiku","haiku":"Charts the breakdown of a self through self-harm and regret, measuring pain to feel alive while watching everyone leave. The narrator reflects on becoming a disappointment and his decayed empire of broken promises.","sonnet":"A person reflects on self-inflicted pain as the only way to feel something real, surveying a life of broken promises, addiction, and emotional emptiness, and acknowledging that they will inevitably disappoint and wound those closest to them.","opus":"A confession of self-harm and despair from someone who hurts himself just to feel something real, mourning what he has become and how everyone he knows eventually leaves. He addresses a loved one, admitting he will let them down, and wishes he could start over and keep himself intact."},"the-prodigy~wall-of-death":{"src":"haiku","haiku":"A defiant call to abandon false institutions and conventions, rejecting sterilization and conformity. The song embraces chaos and destruction as a response to systematic control.","sonnet":"A blunt, confrontational provocation that rejects conformity and commercialism in favor of reckless, defiant energy, repeatedly inviting the listener to follow to a dangerous extreme with contempt for caution or consequence.","opus":"A confrontational, taunting invitation to follow the narrator to the 'wall of death,' rejecting money and defying anyone who tries to sterilize or contain him. The mood is aggressive and dismissive, built on repeated dares and curses."},"nine-inch-nails~burn":{"src":"haiku","haiku":"Expresses rage at being rejected by the world and a desire to burn it down from within, positioning the narrator as a destructive force both angelic and demonic. The song frames destruction and subversion as revenge against a system that never accepted him.","sonnet":"A figure who feels cast out and destroyed by society awakens to a consuming rage, declaring themselves both destroyer and savior, and vowing to burn the entire world down in retribution for a lifetime of rejection.","opus":"A furious outsider who feels rejected and thrown away by the world vows to make it pay, casting himself as a cancer in the system and a force of destruction. He describes an awakening rage inside him and a desire to burn the whole world down."},"cradle-of-filth~temptation":{"src":"haiku","haiku":"Describes an irresistible pull toward forbidden desire that cannot be resisted or denied, with temptation as both alluring and destructive. The song frames giving in as inevitable and impossible to escape.","sonnet":"A cover of the Heaven 17 song depicting someone utterly unable to resist a powerful attraction — each day, every second draws them closer despite the high cost, and the repeated refrain of \"temptation\" underlines how completely the desire overrides any will to resist.","opus":"A song about surrendering to desire and the pull of temptation, framed as a risky bargain you can take or leave but had better believe in. The narrator can't break away from an intense, consuming attraction, invoking the plea to be led not into temptation even as he keeps climbing higher."},"type-o-negative~halloween-in-heaven":{"src":"haiku","haiku":"Imagines a festival in the afterlife where dead musicians celebrate together, blending Halloween and Christmas imagery. The song playfully explores death as freedom and release, with celebrity musicians continuing their legacies eternally.","sonnet":"A darkly comic afterlife fantasy in which deceased rock legends — Bonham, Entwistle, Bon Scott, Randy Rhoads, Hendrix, Lennon, Harrison — party together in heaven while hell hosts Christmas, blending genuine grief for lost musicians with absurdist humor about death being cooler than life.","opus":"A darkly comic fantasy of the afterlife as an endless party where dead rock musicians play together and holidays blur into one another. Beneath the humor runs real grief over lost idols and a morbid suggestion that death is so appealing the narrator wishes he'd died sooner."},"rammstein~mehr":{"src":"haiku","haiku":"Expresses insatiable greed and the inability to ever feel satisfied, with the narrator always wanting more regardless of what he possesses. The song portrays endless consumption and material hunger as an inescapable condition.","sonnet":"Sung from the perspective of someone driven by insatiable greed, the song describes a figure who is never satisfied no matter how much they have, covets what others possess, and sees no reason for restraint or sharing — \"more\" is always the only goal.","opus":"A study of insatiable greed voiced by a narrator who wants everything and always ten times more, never satisfied, with no goal and no such thing as too much. He dismisses modesty and would even take what little others have, since they supposedly don't need it."},"serj-tankian~the-unthinking-majority":{"src":"haiku","haiku":"Critiques a passive populace controlled by systems of oppression and chemical pacification, arguing that antidepressants and democracy are tools of manipulation. The song rails against manufactured consent and political hypocrisy.","sonnet":"A political attack on state hypocrisy, manufactured consent, and corporate-driven war, arguing that antidepressants serve as tools of social control to keep a passive majority compliant while governments clear the way for oil interests under false pretexts.","opus":"A political protest against a hypocritical system that manipulates a passive, unthinking public, using antidepressants as controlling tools to make life tolerable. It attacks manufactured wars waged to clear the way for oil interests and calls for real democracy."},"bloodhound-gang~along-comes-mary":{"src":"haiku","haiku":"Describes how a mysterious figure named Mary arrives to disrupt the narrator's life with psychological games and sexual complexity. The song portrays her as an agent of transformation, leaving trauma and confusion in her wake.","sonnet":"A cover of the Association's 1966 song about a mysterious, transformative woman named Mary whose arrival offers the possibility of relief, connection, and altered perception to someone stuck in loneliness and routine — though whether she brings salvation or further disillusionment remains ambiguous.","opus":"A cryptic, wordplay-heavy song about a figure named Mary who arrives to rescue the lonely narrator and transform how he sees reality, leaving him feeling his empty cup now tastes sweet. It hints at illusions, games, scars, and altered perception surrounding her influence."},"wheel~ascend":{"src":"haiku","haiku":"Addresses feelings of stagnation and the human tendency to follow rather than lead, calling for breaking free from mediocrity. The song urges rising above resignation and reigniting lost spark.","sonnet":"A call to break free from collective stagnation and creative resignation — the lyrics describe a group trapped in repetition and boredom, and ultimately urge abandoning the standardized form in favor of reigniting something genuine and ascending beyond mediocrity.","opus":"A critique of passivity and conformity, describing people conditioned to follow rather than lead and to waste energy while bored and uninspired. The narrator calls for breaking the standardized mold, reigniting a spark, and rising above monotony and emptiness."},"magdalena-bay~live-4ever":{"src":"haiku","haiku":"Celebrates the reckless thrill-seeking of youth, driving fast and pushing limits to feel immortal. The song captures the adrenaline rush of living dangerously with someone you want to stay with forever.","sonnet":"Two people go on a reckless late-night drive at extreme speed, chasing the sensation of invincibility — the rush of adrenaline and momentum creates a feeling of living forever, even as the imagery hints at the possibility of burning out.","opus":"A reckless late-night drive fueled by adrenaline and the euphoric fantasy of living forever. The narrator urges a companion to go faster and trust the moment, chasing the thrill of speed and the feeling of being intensely alive even while going nowhere."},"nine-inch-nails~love-is-not-enough":{"src":"haiku","haiku":"Argues that love cannot sustain a relationship or heal deeper wounds, with both partners fading and becoming strangers. The song questions whether love can overcome emptiness when both people lie to themselves.","sonnet":"A relationship has deteriorated beyond repair, and the speaker acknowledges that despite the effort invested, love alone cannot sustain what has been built on deception and mutual damage — both people are left hollowed out, and the feeling that \"love is not enough\" becomes the bitter conclusion.","opus":"A disillusioned look at a failing relationship, admitting that the closeness two people imagined never got them far and that they cover themselves with lies. The blunt conclusion is that beneath the toughness they're fragile, and love alone is not enough to save them."},"bring-me-the-horizon~obey-with-yungblud":{"src":"haiku","haiku":"Warns of systematic brainwashing and societal control masquerading as safety and free choice. The song depicts a population willingly complicit in their own oppression, numbed and manipulated.","sonnet":"A critique of systems of social control — the song depicts authority figures using psychological manipulation, manufactured compliance, and corruption to keep people passive and unquestioning, with the command to \"obey\" repeated as a sardonic corporate reassurance.","opus":"A song about mass control and self-destruction, mocking a sinister authority that tells people to obey, behave, and not notice the corruption or the chains binding them. It ties this manipulation to inner torment and the urge to hurt oneself, insisting that even monsters are people."},"type-o-negative~in-praise-of-bacchus":{"src":"haiku","haiku":"Recounts a bittersweet relationship marked by desire and disappointment, set against Brooklyn's industrial landscape. The narrator recalls a lover who wanted to burn together but ultimately left him behind.","sonnet":"A figure drinks to dull the pain of a relationship in which the woman hates him — set against a wet Brooklyn night, the song moves through fractured street-level images and ends with a mutual call to burn together, blending bitterness with a strange intimacy.","opus":"A drink-soaked, bittersweet reminiscence set on the streets of Brooklyn, addressing the god of wine while recalling a woman who hates him yet vowed they would burn together. It weaves memory, longing, and intoxication into a haunted love scene."},"pro8l3m~flary":{"src":"haiku","haiku":"Portrays a volatile, passionate relationship oscillating between tenderness and violence, with the narrator unable to recall or separate the intimate moments from the chaos. Polish lyrics depict intoxicated passion and emotional turbulence.","sonnet":"A Polish rap about the deterioration of a relationship — the speaker describes explosive fights, mutual cruelty, and a drunken night out that ends in violence and collapse, all while the chorus mourns the inability to remember the tender details of the woman he has lost.","opus":"A volatile, toxic relationship told through a drunken, drug-blurred night of fighting, where a woman's fury feels like tornadoes and love bleeds into violence. The narrator can no longer remember her tenderness, only the wreckage, as the night dissolves into blood, vomit, and blackout before she reappears to pull him back."},"megadeth~take-no-prisoners":{"src":"haiku","haiku":"Depicts war's brutal machinery and conquest, warning of the cost paid by soldiers who become disposable. The song questions patriotic sacrifice and shows how warfare destroys individuals even when they survive.","sonnet":"The song moves from the brutal logic of wartime orders — infiltrate, eliminate, take no prisoners — to a bitter critique of how soldiers are discarded after service, left wounded and forgotten while the country that sent them to war offers nothing in return.","opus":"An anti-war piece that opens with brutal orders to exterminate the enemy and take no prisoners, then turns to the human cost, depicting a maimed veteran left in a wheelchair, forgotten and uncared for. It bitterly twists the call to serve one's country into a portrait of sacrifice and abandonment."},"trash-boat~alpha-omega-feat-kamiyada":{"src":"haiku","haiku":"Describes a cycle of substance abuse, self-harm, and failed attempts at change, with addiction as the alpha and omega of existence. The narrator questions whether resurrection is possible from this repetitive downward spiral.","sonnet":"A cycle of addiction, self-destruction, and futile attempts at recovery is depicted through the lens of a person trapped in a loop — prescribed opioids, wasted years, and suicidal ideation alternate with moments of defiant survival, while the title phrase marks the endless repetition of beginning and end.","opus":"A raw account of addiction and mental collapse, cycling through painkillers, self-loathing, and the sense of a wasted decade with no way out. The narrator battles suicidal thoughts and his own demons, oscillating between giving up and defiantly claiming he'll resurrect."},"tokio-hotel~monsoon":{"src":"haiku","haiku":"Dreams of escaping through a violent storm to reach a lost lover, determined to overcome all obstacles. The song frames their reunion as redemption amidst chaos and darkness.","sonnet":"Someone pushes through isolation and stormy conditions driven by the thought of a person they need to reach — the monsoon serves as both literal and emotional obstacle, and the determination to reunite with that person is the only force strong enough to keep them moving.","opus":"A song about running through a storm toward a distant loved one, using the monsoon as an image of hardship braved for the sake of reunion. From a cold, empty room the narrator vows to fight the elements and never be held back until they're together."},"pearl-jam~do-the-evolution":{"src":"haiku","haiku":"Sarcastically charts humanity's destructive evolution from primal instinct to reckless domination, where progress equals exploitation. The song ironically praises our irresponsible rise to power.","sonnet":"A savage satirical monologue delivered in the voice of a self-congratulating human who mistakes conquest, greed, and destruction for progress, using the language of evolution to justify colonialism, environmental ruin, and moral bankruptcy.","opus":"A savage satire of human arrogance and greed, voiced by a self-glorifying narrator who boasts of dominance, exploitation, and destruction while calling it all evolution. It skewers hypocrisy, conquest, and reckless self-interest driving the species toward ruin."},"dream-theater~the-enemy-inside":{"src":"haiku","haiku":"Confronts inescapable trauma and regret that haunts the narrator's mind, creating a prison of suffocating memories. The song portrays the self as both the source and victim of psychological torment.","sonnet":"A person is haunted by intrusive memories and violent flashbacks that they cannot escape — the \"enemy inside\" is a psychological torment, described as suffocating and inescapable, that has severed them from the world and from the life they once had.","opus":"A depiction of trauma and inner torment, where the narrator relives a painful moment over and over, haunted by flashbacks and violent dreams he cannot escape. He describes cutting himself off from the world, drowning in regret and irrational fear as the enemy within pursues him."},"nevermore~narcosynthesis":{"src":"haiku","haiku":"Describes manipulation and spiritual degradation through hypnosis and indoctrination, where truth is twisted and the soul is salvaged only through the passage of time. The song warns of toxic influence disguised as care.","sonnet":"A plea for transformation and redemption addressed to an unnamed force — the speaker feels alienated, victimized, and spiritually depleted, and asks time to act as healer and concealer while lamenting that life keeps slipping away like sand through an hourglass.","opus":"A disoriented plea shaped by manipulation and lost faith, as the narrator is hypnotized, alienated, and drained while questioning how things came to this. Amid images of blood turning to sand and lives falling through an hourglass, he begs for his soul to be salvaged."},"the-prodigy~wild-frontier":{"src":"haiku","haiku":"Warns of a dangerous frontier where dreams become real or blood spills, requiring facing inner fears. The song frames life as an untamed wilderness demanding courage.","sonnet":"The lyrics evoke a dangerous, lawless territory off the beaten track where dreams and bloodshed are equally possible — the recurring warning to watch your back and face your fears frames this frontier as both a physical and psychological space of reckless risk.","opus":"A song built on the image of a dangerous, uncharted 'wild frontier' where dreams can come true or blood can be spilled. Its message is to stay alert, watch your back, and face your fears in a lawless, high-stakes place."},"coroner~the-favorite-game":{"src":"haiku","haiku":"Fragmented imagery suggests being lost in a game of suffering and servitude, with love offered without reciprocation. The song questions belonging amidst sorrow and fear.","sonnet":"Fragmented, abstract imagery of fire, shadows, and lost love circles around a central question of belonging — the repeated \"where do I belong?\" is the emotional core of a song that gestures at grief, dislocation, and a search for meaning through imagery that is deliberately obscure.","opus":"An abstract, dark meditation on tragedy, fear, and love given without reply, using imagery of fire, smoke, and scars left on angels' faces. Amid the shattered voice of reason, the narrator is left asking where he belongs."},"i-scintilla~taken":{"src":"haiku","haiku":"Critiques censorship and mass deception, where illusions are used to control and blind populations to the truth. The song warns that those who enforce silence are the real enemies.","sonnet":"A song about censorship and deliberate manipulation of information — those in power are described as editing, hiding, and blurring the truth to maintain control, while the listener is warned not to close their eyes to what is being concealed.","opus":"A song about censorship and manipulation of information, with 'bullets of a softer kind' standing for edited, hidden truths meant to keep people blind. It warns against the illusions and delusions fed to the public and urges vigilance rather than closing one's eyes."},"perturbator~venger-feat-greta-link":{"src":"haiku","haiku":"Grieves the loss of a loved one taken away, leaving the narrator hollowed out and seeking revenge. The song describes being displayed and pained, unable to move forward.","sonnet":"Grief and the desire for revenge after losing someone are the twin drives — the speaker is hollowed out by absence, haunted by the same dream every night, and consumed by the need to make those responsible pay for taking someone irreplaceable away.","opus":"A haunted account of loss and grief trapped in a recurring nightmare of dark decay and drowning. The narrator's love was taken away, leaving a hollow heart stitched up and displayed but never healed, wishing only to have that person back."},"the-mad-capsule-markets~fly-high":{"src":"haiku","haiku":"Celebrates the freedom of flying and transcending earthly concerns, encouraging others to pursue their dreams without distraction. The song embraces limitless possibility and liberation.","sonnet":"A song about the sensation of freedom and forward motion — the lyrics describe soaring through a limitless sky, urging the listener not to be tripped up by what surrounds them and to keep moving until they find whatever they are searching for.","opus":"An exhilarated song about flying free across the sky as a metaphor for liberation and clearing the mind. It encourages ignoring distractions, keeping your eyes ahead, and gliding onward until you find what you're searching for."},"m-i-a~bad-girls":{"src":"haiku","haiku":"Glorifies reckless living at high speed, with young women breaking rules and pushing boundaries without regard for consequences. The song celebrates the thrill and danger of living fast.","sonnet":"A celebration of reckless, high-speed femininity and defiance — the speaker drives fast, lives by her own rules, and refuses to slow down, framing the \"bad girl\" lifestyle as both exhilarating and a conscious rejection of expectations placed on her.","opus":"A defiant celebration of fearless, fast-living 'bad girls' set around high-speed driving, swagger, and control. The narrator flaunts recklessness and confidence, daring anyone to keep up while she accelerates and leaves others behind."},"crystal-castles~kerosene":{"src":"haiku","haiku":"Explores false protection and toxic comfort, where harmful substances and deceptive care are used to manage suffering. The song warns that salvation offered may destroy rather than heal.","sonnet":"A dark meditation on institutional religion and the way comfort, language, and identity are stripped away — the imagery of washing with kerosene to cleanse impurity, and protecting someone from what has already been witnessed, suggests a corrosive kind of care that does more damage than good.","opus":"An unsettling song about corrupted care and control, where charity, purity, and protection are twisted into instruments of harm. Kerosene and cleansing imagery run through promises to protect and heal wounds, blurring the line between comfort and destruction."},"lantl-s~vertigo":{"src":"haiku","haiku":"Captures the disorienting sensation of summer infatuation and sensual overload, using fruit and sensory imagery to describe overwhelming attraction. The song conveys dizzying passion and ethereal desire.","sonnet":"A dreamy, sensory portrait of an overwhelming summer infatuation — every image is saturated with ripe fruit, warmth, and brightness, and the dizziness of the title describes the intoxicating effect the object of desire has on the speaker.","opus":"A lush, sensory ode to a summer crush, saturated with images of fruit, sunlight, and water as a dizzying intoxication of desire. It renders infatuation as a blissful, unworldly experience of ecstasy and vertigo."},"deftones~rubicon":{"src":"haiku","haiku":"Encourages surrendering to collective power and losing oneself in shared experience, breaking records together. The song frames unity as transcendence and escape from isolation.","sonnet":"A song about surrendering to collective intensity — the speaker urges someone to stop trying to face the crowd alone, to embrace the shared power of the moment, let go of inhibition, and give themselves over entirely to the experience.","opus":"A seductive, hypnotic invitation to surrender the self to a collective power and to the spectacle of a crowd. The narrator coaxes another to give in, face the lights, and writhe in shared delight, bodies aching to be draped in pleasure."},"machine-head~bulldozer":{"src":"haiku","haiku":"Celebrates unstoppable force and refusing to be broken by opposition, embodying a crushing power that destroys weaker forces. The song glorifies relentless forward momentum against all odds.","sonnet":"A declaration of relentless forward drive against obstacles and conformity — the bulldozer is a metaphor for refusing to yield, following instinct over instruction, and pushing through resistance at full force regardless of what stands in the way.","opus":"An aggressive anthem of defiance and relentless drive, refusing to submit to anyone who tries to give orders. It casts the self as a bulldozer that crushes the weak and pushes against the odds and the grain, trusting instinct and living to win."},"coaltar-of-the-deepers~joy-ride":{"src":"haiku","haiku":"Depicts the simple pleasure of driving fast with a companion until the thrill wears off and they seek a new car. The song celebrates youthful restlessness and constant movement.","sonnet":"A lighthearted snapshot of aimless driving with a companion — the sky is wide, the destination irrelevant, and once boredom sets in the answer is simply to find a new car and keep going without any particular purpose.","opus":"A carefree song about the simple pleasure of driving fast with a companion under a wide blue sky. When boredom sets in, the answer is just to go get another car and keep the joyride going."},"system-of-a-down~sugar":{"src":"haiku","haiku":"Portrays paranoia, violence, and social alienation, with the narrator isolated and despairing, describing casual abuse and feeling hunted. The song ends in fatalistic nihilism where nothing matters.","sonnet":"A chaotic, fragmentary portrait of a person on the edge — Russian roulette as a daily habit, domestic violence, isolation in a dark room, and a final fantasy of having \"killed everyone\" cascade into a resigned refrain that in the end it all goes away, suggesting numbness rather than resolution.","opus":"A frantic, fragmented rant on insanity, violence, and alienation, with the narrator playing daily 'Russian roulette' with life and feeling hunted by people trying to drain his mind. It spirals into isolation and rage before collapsing into the numb refrain that in the end it all goes away."},"celldweller~new-elysium":{"src":"haiku","haiku":"Calls for a new utopian kingdom built by young generations rising against despair and forgetting their worth. The song urges unified voices to create paradise and transcend mortal limitations.","sonnet":"A generational anthem calling for a new order to replace a world that has forgotten its own worth — the young are framed as chosen voices who must tear down an oppressive empire and build a new Elysium in its place before time runs out entirely.","opus":"A call for the young to unite their voices and build a new world, framed as entering a new Elysium after the old order ends. It laments how humanity has forgotten its worth and urges people to rise up and tear down an oppressive empire."},"type-o-negative~dead-again":{"src":"haiku","haiku":"Confronts chronic addiction and the cycle of death and resurrection it brings, acknowledging self-destruction while claiming some things are worse than death. The song portrays addiction as literal dying and rebirth.","sonnet":"A first-person account of severe drug addiction delivered as a warning — the speaker describes overdosing repeatedly, losing self-respect, accumulating physical damage, and arriving at the conclusion that some things are worse than death, while explicitly telling the listener not to follow the same path.","opus":"A stark reckoning with drug addiction, in which the narrator admits he's a doomed addict warning others not to follow his path. He describes overdosing to the point of feeling dead, valuing self-respect over his life, and concluding some things are worse than death."},"nine-inch-nails~something-i-can-never-have":{"src":"haiku","haiku":"Grieves an impossible love that lingers as memory and obsession, filling every moment with longing for someone unreachable. The song frames desire as all-consuming and inescapable.","sonnet":"An obsessive longing for someone who once gave life meaning but is now permanently out of reach — everywhere the speaker looks the person is present as a reminder of who they used to be, and the knowledge that this connection can never be recovered becomes an unbearable weight.","opus":"An aching song of longing for a lost person who once made everything better, now reduced to memories that haunt the narrator's dreams and waking hours. He's down to one obsessive wish, frightening himself with his craving for something he can never have."},"annihilator~w-t-y-d":{"src":"haiku","haiku":"Welcomes the listener to death and the afterlife, where they encounter an endless cycle and spectral presence. The song treats death as initiation into a new strange realm.","sonnet":"A tour through grotesque death imagery — burning stars, fields of sin, the beckoning of those already slain — that cumulatively constructs a ritualistic welcome to oblivion, inviting the listener to slip into death as though it were natural and even hospitable.","opus":"A menacing welcome to death, addressing the listener as someone born into death and lured toward their own end. Through images of sin, slain hands beckoning, and tempting wine, it presents death as inescapable and grimly inviting."},"arch-enemy~we-will-rise":{"src":"haiku","haiku":"Declares rebellion against mediocrity and conformity, positioning the narrator as an antidote to standardized thinking. The song celebrates standing apart and rising above the masses.","sonnet":"A rejection of mediocrity and conformity, with the speaker positioning themselves as both enemy of the status quo and antidote to it, calling on a collective to rise above a sea of sameness and assert individual identity and worth.","opus":"A rallying anthem of defiance and self-empowerment, urging people to tear down walls, reject mediocrity and conformity, and stand up. The narrator casts themselves as both enemy and antidote, insisting they can be anything and that together they will rise above."},"architects~delete-rewind":{"src":"haiku","haiku":"Questions how youth lost their voice after being backed into corners by oppressive systems since childhood. The song calls for erasing corrupted beliefs and reclaiming agency.","sonnet":"A song about a generation that has been misled and silenced by those in power, expressing frustration at having been pushed into a world they cannot trust and calling for a collective decision to reclaim agency before it is too late.","opus":"A protest voiced by a 'misguided youth' who feel cornered, manipulated, and pushed to distrust the world they've inherited. Wanting something to believe in, they wish they could delete and rewind to change their state of mind, and ask when they will finally stand up."},"linkin-park~given-up":{"src":"haiku","haiku":"Expresses complete exhaustion and hopelessness, claiming surrender after repeated disappointment and internal torment. The song portrays the narrator as his own worst enemy suffocating under pressure.","sonnet":"A person has reached total psychological collapse — trapped in self-loathing, unable to breathe, unable to locate the source of their pain — and reaches out desperately for something or someone to relieve the suffocation, asking to be put out of their misery.","opus":"A raw expression of despair and self-loathing from someone who feels stuck, suffocating, and their own worst enemy. Having given up and sick of feeling, the narrator cries out for relief and to be put out of their misery."},"system-of-a-down~know":{"src":"haiku","haiku":"Questions the nature of knowledge and reality through surreal imagery, contrasting earthly skepticism with flying and transcendence. The song suggests that conventional understanding fails to reveal truth.","sonnet":"A fragmented, surrealist meditation on spiritual seeking, the unreliability of knowledge, and the contradictory impulses toward flight, death, and transcendence — the repeated refrain that \"you never think you know why\" frames existence as essentially unknowable.","opus":"A surreal, riddling song questioning certainty and knowledge, insisting that people never really know why. Through strange imagery of walls, flying, and death, it repeatedly probes whether one has ever wanted to fly, or to die, framing transcendence as leaving the body behind."},"alice-in-chains~we-die-young":{"src":"haiku","haiku":"Warns of street violence and quick death for those in dangerous situations, with victims losing their way. The song treats premature death as an inevitable consequence of certain environments.","sonnet":"A bleak portrait of street violence and drug culture — young people caught in a cycle of alley trips, bullets, and hits are dying fast, with the image of blood floating in a muddy sewer and the refrain \"we die young, faster we run\" distilling a life with no escape.","opus":"A grim portrait of street life and lost youth, marked by violence, bloodshed in the gutter, and drug hits, where danger lurks and lives are cut short. Its refrain that 'we die young, faster we run' captures a doomed, accelerating trajectory."},"limp-bizkit~livin-it-up":{"src":"haiku","haiku":"Celebrates hedonistic living and rejecting responsibility, boasting about rock star excess and not caring about consequences. The song glorifies fast living and shameless indulgence.","sonnet":"A boastful, irreverent self-portrait of living recklessly and without apology — the speaker catalogues his brash persona, pop culture references, and disregard for convention, framing the fast lane as a conscious lifestyle choice even while acknowledging the cage the world can be.","opus":"A brash, name-dropping boast about living recklessly in the fast lane without giving a damn. The narrator flaunts a party lifestyle of pop-culture references, bravado, and indulgence while noting how easy it is to lie and hide but how hard it is to truly be alive."},"triptykon~boleskine-house":{"src":"haiku","haiku":"Evokes a haunted location where mystical rituals and dark forces once resided, with the ground charged by past suffering. The song treats the space itself as embodying ancient spiritual corruption.","sonnet":"A meditation on a place saturated with occult history and departed presence — the ground walked upon is invoked as sacred soil, and the evocation of invisible gods and a \"bornless one\" frames the site as a threshold between the mortal world and something beyond it.","opus":"A dark, occult-tinged evocation addressed to a departed figure whose world is long gone, set upon the ground they once walked. It calls forth invisible gods and a 'Western Star' through ritual language of evocation and tortured flesh."},"nevermore~beyond-within":{"src":"haiku","haiku":"Warns of apocalypse and societal collapse, describing apathetic observation of suicide and despair. The song critiques reality as stage performance where the world falls apart.","sonnet":"A darkly prophetic survey of a world collapsing under ignorance and violence — civilizations fall, sanity fractures, and the speaker watches in apathy as suicides shock a world moving toward inevitable ruin, with the millennium framed not as renewal but as the final fall.","opus":"An apocalyptic vision welcoming the end of a hate-filled world and a black, hopeless future born of ignorance. Amid rising suicide, apathy, and delirium, it charts the fall of one man's sanity as reality and fable blur together."},"nine-inch-nails~while-i-m-still-here":{"src":"haiku","haiku":"Reflects on mortality and things slipping away, trying to hold onto fading memories before time expires. The song expresses resignation to inevitable loss while still here.","sonnet":"A person facing the end of something — life, a relationship, a world — spends their remaining time noting what is slipping away, asking to be held close while they still can be, and accepting the passage with quiet resignation rather than rage.","opus":"A meditation on mortality and running out of time, as the narrator watches life fall apart and slip away a little more each day. Learning the world is ending, he makes peace with it while asking a loved one to stay close and hold him near while he's still here."},"type-o-negative~angry-inch":{"src":"haiku","haiku":"Details a botched transgender medical procedure and the lasting physical and psychological trauma that resulted. The song expresses bitterness about transformation becoming mutilation.","sonnet":"A cover of the song from the musical Hedwig and the Angry Inch, narrating a botched gender-reassignment surgery and its aftermath — told with dark humor, the speaker describes leaving their homeland, reinventing themselves, and being permanently defined by the surgical failure, one inch of flesh that encapsulates their entire history.","opus":"A darkly comic, defiant story of a botched sex-change operation that left the narrator with a scarred one-inch mound of flesh. Recounting the ordeal and its humiliation, they turn the wound into a stubborn identity and a readiness to fight back."},"grimes~butterfly":{"src":"haiku","haiku":"Contrasts being trapped in systems and constraints with the freedom of butterflies flying without limits. The song warns against seeking perfection in others while celebrating transcendent flight.","sonnet":"A loosely structured song that circles around themes of freedom, self-definition, and refusal to be a fantasy for someone else — the butterfly image carries a sense of expansive possibility, and the closing lines make clear that the speaker has no interest in fitting the mold of a \"dream girl.\"","opus":"A dreamlike song about freedom, imperfection, and refusing to be someone else's fantasy, insisting the enemy isn't the self and finding harmony in everything. Recurring butterfly imagery signals transformation and flight, while the narrator declares she'll never be a 'dream girl,' choosing the real world instead."},"celldweller~end-of-an-empire":{"src":"haiku","haiku":"Meditates on the inevitable fall of all empires and systems built by mortals, which cannot escape fate and must eventually crumble. The song philosophizes about impermanence and the cycles of civilization.","sonnet":"A reflection on the universal cycle of rise and fall — every empire, system, and individual life is subject to the same paradigm of creation and destruction, and no amount of power or ambition can exempt anyone from the inevitable end.","opus":"A grand meditation on the inevitable rise and fall of empires, civilizations, and life itself, insisting nothing is eternal and no one immortal. It frames every ending as the start of another cycle, with even death itself destined to end in time."},"limp-bizkit~full-nelson":{"src":"haiku","haiku":"A complaint about being constantly mocked and talked about behind one's back. The narrator warns that insults backed only by big talk will get met with violence.","sonnet":"A response to people who talk behind someone's back, directed at those who spread false rumors without knowing the target personally. The speaker demands that any insults be said face to face, threatening violent consequences for those whose words exceed their ability to back them up.","opus":"A defiant confrontation with people who talk behind the narrator's back, daring them to say it to his face and promising a beating for anyone whose mouth outruns what they can back up. It builds into a vow to overthrow those who mock and 'verbally rape' him and his crew."},"deadmau5~ghosts-n-stuff-feat-rob-swire":{"src":"haiku","haiku":"A relationship marked by intense connection and emotional upheaval. The narrator seeks to navigate this turbulent bond and reach a promised destination together.","sonnet":"A song about a consuming, disorienting connection to another person — one that pulls the speaker out of his body and away from reality. Despite the distance and uncertainty, there is a persistent desire to push through and reach something real together.","opus":"A restless, out-of-body craving to break free with someone, feeling alone even when close and urging release and abandon. The narrator wants to get it right and reach some destination together tonight, aware that time is running out."},"rammstein~feuer-und-wasser":{"src":"haiku","haiku":"Desire for a woman who is unreachable and indifferent, using water and fire as metaphors for incompatibility. The narrator burns with passion while she remains cold and distant.","sonnet":"A man watches a woman swimming and is overwhelmed by desire, but the central image is the impossibility of union: fire and water cannot come together, and he burns while submerged, consumed by longing for someone who does not notice him at all.","opus":"An obsessive, sexual fixation on a woman the narrator watches swimming, likening desire to fire and her to water that can never mix with it. He knows his longing is hopeless: she doesn't notice him, and he burns even while drowning."},"magdalena-bay~you-lose":{"src":"haiku","haiku":"A relationship where trust is broken and attempts at manipulation fail. The narrator rejects false affection and warns the other person that their tactics will ultimately fail.","sonnet":"A song about the end of a relationship in which the speaker no longer trusts or wants the other person. Despite exhaustion and the feeling of time running out, she holds onto enough self-respect to reject the other's advances, naming them the loser in the power struggle.","opus":"A crumbling relationship framed as a losing game, where the narrator distrusts a partner's professed devotion and refuses to fall for what she calls a lie. She feels time and pride slipping away, insisting that in this contest of attacks there are no winners."},"marilyn-manson~this-is-the-new-shit":{"src":"haiku","haiku":"A satirical critique of pop culture's recycled provocations packaged as rebellion. Everything has been said before, yet people mindlessly consume and repeat empty slogans.","sonnet":"A cynical take on mass media, pop culture, and entertainment, which the song presents as an endless recycling of the same provocations — sex, violence, rebellion, sentiment — fed to an audience that neither truly understands nor questions what it consumes.","opus":"A cynical send-up of pop culture and shock entertainment, reducing music to interchangeable slogans of sex, violence and manufactured rebellion. It mocks audiences who demand the same recycled provocation packaged as something new."},"babymetal~gimme-chocolate":{"src":"haiku","haiku":"A playful demand for chocolate that expresses desire with urgency and some anxiety. The narrator wants the treat and asks repeatedly and impatiently.","sonnet":"A playful internal conflict between craving chocolate and worrying about the consequences for one's figure, with the speaker ultimately deciding to give in to the temptation after working hard enough to deserve a reward.","opus":"A playful inner tug-of-war over craving chocolate while worrying about weight, the singer begging for a treat as a reward after working hard. The push and pull between temptation and restraint is voiced with cartoonish delight."},"sodom~among-the-weirdcong":{"src":"haiku","haiku":"Combat and carnage in a jungle war setting. Soldiers face brutal slaughter where death is methodical and minds are shattered by violence.","sonnet":"A violent depiction of close-quarters jungle warfare, told from the perspective of a soldier surrounded by death and atrocity. The speaker describes losing his bearings amid machine gun fire, slaughter, and the sight of friends killed.","opus":"A brutal first-person account of jungle warfare, full of machine-gun fire, shattered skulls and methodical slaughter. The narrator loses himself amid the carnage, emotions deadened, especially at the sight of friends impaled and killed."},"puddle-of-mudd~already-gone":{"src":"haiku","haiku":"Escape and detachment from an addiction-bound life. The narrator has already left mentally and refuses to engage with demands or old patterns.","sonnet":"A song about escaping addiction and the destructive patterns surrounding it, with the speaker declaring he has already mentally departed from that life. The lyrics alternate between images of flight and freedom and an acknowledgment that the pull of addiction still needs to be killed.","opus":"A restless drive to break free from addiction and the systems that trap people, wanting to live for a reason rather than stay imprisoned. The narrator declares himself 'already gone' while repeatedly vowing to kill his addiction."},"alice-in-chains~hollow":{"src":"haiku","haiku":"Emotional and spiritual emptiness descending into silence and loss of direction. The imagery of mountains hollowed from within reflects internal desolation and erosion.","sonnet":"A portrait of someone who has been emotionally hollowed out — drained and drilled through like a mountain — leaving only confusion, silence, and an inability to tell up from down. The song observes how a person loses their mind and their color, becoming unrecognizable.","opus":"A portrait of emotional emptiness, using a hollowed-out, drilled mountain as an image for someone drained and disoriented. Colors fade to grey, meaning drains away, and a deafening silence leaves the narrator unable to tell up from down."},"the-prodigy~take-me-to-the-hospital":{"src":"haiku","haiku":"Chaotic scene of a crash or disaster invoked through fragmentary repetition. The song evokes urgency and emergency amid fashion-obsessed crowds.","sonnet":"Built around the image of arriving at the scene of a crash, the song describes an encounter with a deceptively friendly but dangerous figure — likened to a spider — that ends in an adrenaline-fueled collision. The call-and-response chorus anchors it to a live, crowd-facing energy.","opus":"A frantic chant built around being taken to the hospital and the scene of a crash, laced with a spider-and-Dracula image of a deceptive predator that lures and bites. It channels a chaotic, adrenaline-charged party energy."},"pro8l3m~macki-meduzy":{"src":"haiku","haiku":"Reckless escapism and seduction by a dangerous woman who embodies chaos and disregard for consequences. The narrator is drawn to her cruelty despite the destructive spiral.","sonnet":"A Polish rap about a toxic, demonic relationship with a woman who brings out the darkest impulses in the speaker — recklessness, violence, and moral dissolution. She is portrayed as a force whispering the devil's words, a nightmare over the city that he can neither resist nor escape.","opus":"A dark, intoxicated night of destruction shared with a dangerous woman, mixing drugs, alcohol, violence and menace as the pair terrorize a crowd. She whispers in the narrator's ear while a devil whispers in hers, and his craving for her deepens his own evil."},"soundgarden~pretty-noose":{"src":"haiku","haiku":"Entrapment in a toxic relationship or situation that feels like slow strangulation. The narrator resents whatever force or person has them bound and diminished.","sonnet":"A song about being trapped in a relationship or situation that is superficially attractive but fundamentally harmful — the \"pretty noose\" is the beautiful thing that still strangles. The speaker resists, ultimately declaring total indifference to what the other person has or needs.","opus":"A seductive but destructive attachment imagined as a beautiful noose that is really hate and pain. The narrator recoils from what it has him hanging from, insisting he wants nothing more from it."},"rammstein~amerika":{"src":"haiku","haiku":"Critique of American cultural dominance spreading globally, controlling minds, and replacing authentic local culture. The song sarcastically frames this colonization as inevitable and inescapable.","sonnet":"A satirical critique of American cultural dominance spread across the globe, using images of Mickey Mouse outside Paris and Coca-Cola replacing local identity. The song frames this as a forced dance in which everyone must follow America's lead whether they choose to or not.","opus":"A sardonic take on American cultural dominance, with everyone worldwide 'living in Amerika' amid Coca-Cola, Mickey Mouse and Santa Claus. The narrator leads the dance and controls the steps, while flatly stating this is not a love song."},"a-perfect-circle~magdalena":{"src":"haiku","haiku":"Obsessive desire for a woman treated as a sacred or divine object. The narrator would sacrifice everything and debase himself for one moment with her.","sonnet":"A song about overwhelming, self-debasing desire for a woman cast as a goddess or sacred figure. The speaker frames his obsession in religious terms — altar, Madonna, soul — willing to surrender his self-esteem entirely for a single moment with her.","opus":"An overwhelming, worshipful lust for a woman treated as an earthly goddess or black Madonna at an altar. The narrator would trade his soul and self-esteem a dollar at a time for a single kiss or taste of her."},"northlane~details-matter":{"src":"haiku","haiku":"A response to criticism and betrayal from someone who exploited and tried to destroy the narrator. Despite attempts to erase and break, the narrator endures and refuses to disappear.","sonnet":"A defiant response to someone who has spread lies, undermined the speaker's reputation, and tried to erase him. Despite the attacks, the speaker insists he has not disappeared and directly confronts the other person's insincerity and fraudulence.","opus":"A furious rebuttal to someone who lied, belittled and tried to silence the narrator to build up their own reputation. Against their attempts to break him and make him disappear, he defiantly insists he is still here."},"type-o-negative~gravity":{"src":"haiku","haiku":"Suicidal ideation and existential despair weighing heavily on the narrator. Something external or internal pulls them down, making continued existence unjustifiable.","sonnet":"A stark depiction of suicidal despair, in which the speaker feels the weight of a hopeless future crushing him — gravity as a metaphor for the force pressing him toward death. The song ends abruptly with an out-of-place voice announcing a bomb threat and urging the crowd to leave.","opus":"A bleak spiral of suicidal despair, the narrator feeling the weight of the world crushing him and seeing no reason to live. The pull dragging him down is finally identified as another person, 'gravity is you.'"},"tool~right-in-two":{"src":"haiku","haiku":"Critique of humanity's tendency toward division and conflict over resources. Humans are blessed with reason but waste it fighting each other instead of cooperating.","sonnet":"A meditation on humanity's self-destructive tendency to divide and fight over shared resources, framed as angels watching in bewilderment as \"monkeys\" given free will and reason choose instead to make weapons and kill each other over patches of ground.","opus":"A view of humanity from angels watching in bafflement, questioning why beings given free will and reason use them only to divide and destroy. It repeatedly casts people as 'monkeys' who fight and kill each other over pieces of ground despite having enough to share."},"carcass~keep-on-rotting-in-the-free-world":{"src":"haiku","haiku":"Commentary on western decline, consumer culture, and the false hope offered to the masses. People decay in comfort, trapped in economic systems they cannot escape.","sonnet":"A sardonic commentary on the hollowness of Western freedom, where citizens are encouraged to consume and dream while the real conditions of their lives — economic exploitation, sweatshop labor, and systemic despair — remain unchanged beneath the surface.","opus":"A bitter critique of the declining Western consumer world, where freedom amounts to the right to consume and be consumed. It mocks empty dreams of salvation while real lives are cheapened by sweatshop economics and everyone is left to 'rot.'"},"kyuss~green-machine":{"src":"haiku","haiku":"Rebellion against systems of control and consumption powered by greed. The narrator shuts down complicity and burns away corrupting forces.","sonnet":"The speaker describes an internal war and a drive to dismantle greed — specifically \"shutting down\" the greed for money (\"green\") — while the machine metaphor suggests both a weapon being loaded and a system being subverted. There is also a wish for simple, peaceful isolation.","opus":"A defiant stand against greed and the systems that feed it, the narrator waging an internal war and 'loading his war machine' to shut down others' hunger for money. He wants freedom and to be left alone with the simple beauty around him."},"deftones~swerve-city":{"src":"haiku","haiku":"A woman dominates and controls through mysterious, otherworldly forces and voices. She breaks the narrator's resistance and makes him hers.","sonnet":"A brief, atmospheric song centered on the hypnotic power of a woman's voice — described as strange and distant — that tames and controls the speaker, carrying through the air like a force that keeps him floating and unable to break free.","opus":"An enthralling, dreamlike image of a woman who tames and controls the narrator with strange, distant voices and forces that drift through the air. The mood is hypnotic and surrendering, held aloft by her power."},"celldweller~own-little-world":{"src":"haiku","haiku":"Escape into fantasy and isolation from a cruel, deceptive world. In this private realm, the narrator is free from pain and external judgment.","sonnet":"A fantasy of retreat from a world dominated by people who exploit and deceive, into a private inner space where time does not exist, no one makes demands, and the speaker is free to be and do anything. The tone shifts from resentment toward others to joy in the imagined refuge.","opus":"A retreat into a private inner world as escape from people who exploit and break others down, promising the world only to take it away. Inside this self-made refuge the narrator breathes freely, does as he wants, and imagines never dying."},"blue-stahli~scrape":{"src":"haiku","haiku":"Desire to burn away and destroy those who deceive and manipulate. Violence and infliction are presented as passionate, destructive acts of rebellion.","sonnet":"A song driven by a volatile mix of destructive desire and contempt for false leaders — \"parasite messiahs\" — who feed people lies. The speaker turns this aggression into something almost erotic, fixating on the violence inside another person's mind as a source of fascination.","opus":"A violent, seething anthem of destruction and toxic obsession, calling to set 'parasite messiahs' on fire and burn everything down. It fuses cruelty, desire and menace, wanting and needing someone while vowing to break them."},"dream-theater~new-millennium":{"src":"haiku","haiku":"Hope for renewal and change in the face of endless frustration and broken systems. The narrator waits for a fresh beginning despite constant setbacks.","sonnet":"A song poised on the threshold of a new era, surveying exhaustion with the present — cold, ruthless people, broken promises, faith that does not pay the rent — while holding onto a feeling that the tide is turning and things will finally improve.","opus":"An uneasy hope at the turn of a new era, sensing a wind of change while facing bleak realities where faith doesn't pay overdue rent and glitter turns blue. The narrator urges others to keep their heads up and endure the deja-vu nightmare toward a fresh start."},"porcupine-tree~fear-of-a-blank-planet":{"src":"haiku","haiku":"Youth trapped in apathy, medicated numbness, and digital distraction. Nothing holds meaning; curiosity and desire are dead; emptiness is the default state.","sonnet":"A portrait of a disengaged, medicated adolescent — living in front of screens, shoplifting out of boredom, numb to sex and friendship — who has been so flattened by prescription drugs and overstimulation that he genuinely wonders whether he still exists.","opus":"A numb, disaffected teenager narrates a life of boredom, prescription drugs, screens, porn and disconnection from parents. Emotionally hollowed out, he questions whether he even exists and drifts toward violent, empty impulses."},"skywalker~no-leader":{"src":"haiku","haiku":"Spiritual awakening and rejection of faith-based hierarchy and saviors. The narrator claims independence and daily rebirth without external guidance.","sonnet":"A song about rejecting organized religion and external authority in favor of a personal, self-discovered spiritual awakening. The speaker finds beauty and meaning on his own terms, renouncing faith in any single name or savior and declaring himself reborn daily from nothing.","opus":"A declaration of freedom found by abandoning religion, the narrator waking reborn and finding heaven right where he stands after leaving the 'Book' behind. He claims no faith, bows to no king, calls himself no leader and no saviour, and says he comes from nothing."},"black-light-burns~lie":{"src":"haiku","haiku":"Complicity in a false, deceptive existence maintained by violence and distrust. The narrator struggles between accepting this lie and trying to reclaim truth.","sonnet":"A song about living a double life built on deception, in which the speaker is simultaneously aware of his own dishonesty and disgusted by the corrupt system he operates within. He struggles to suppress his conscience while crawling toward some kind of escape or authenticity.","opus":"A confession of living a lie built on manipulation and betrayed trust, the narrator trying and failing to kill the vulnerable 'little boy' inside himself. Once ignorant and blissful, he now feels irrelevant and mired in filth, clawing his way back toward the surface."},"babymetal~shanti-shanti-shanti":{"src":"haiku","haiku":"Cycles of existence, desire, and spiritual transformation expressed through Sanskrit concepts. The world turns in recurring patterns of longing and resolution.","sonnet":"A meditation on the cyclical nature of existence — seasons, karma, fate, and time turning endlessly — expressed through Sanskrit and Japanese spiritual vocabulary. The lyrics invoke prana, chakra, samsara, and moksha to describe a world of endless, shimmering transformation leading toward freedom.","opus":"An incantatory meditation drawing on Hindu and Buddhist ideas of peace, prana, karma, samsara and liberation. It celebrates cycles of the seasons, the world and fate spinning onward as souls yearn for love and dance toward freedom."},"limp-bizkit~gold-cobra":{"src":"haiku","haiku":"Arrogant assertion of superiority and dominance over rivals. The narrator dismisses all competition and claims sole kingship through braggadocio.","sonnet":"A boastful rap-rock declaration of dominance and indifference to critics, positioning the speaker as the sole king on the hill who holds the \"gold\" and owes nothing to anyone. The lyrics cycle through aggression, bravado, and contempt for anyone who challenges his position.","opus":"A boastful, aggressive flex about hard living, wealth and dominance, waking up irritated and threatening rivals who cross him. The narrator crowns himself the one king on the hill, indifferent to what anyone thinks."},"celldweller~one-good-reason":{"src":"haiku","haiku":"Suicidal despair and anger at those who claimed to care but failed to provide meaning or support. The narrator challenges them to give a reason to live.","sonnet":"A confrontation with someone who warned the speaker against suicidal thoughts but offered no real reason to stay alive, and who turned out to be a liar. The speaker is consumed by betrayal and demands the one good reason that was promised but never delivered.","opus":"An angry reckoning with someone who told the narrator not to die yet couldn't offer a single good reason to live, having lied to and manipulated him. He berates himself for trusting a liar and pushes the person out of his way."},"a-pale-horse-named-death~as-black-as-my-heart":{"src":"haiku","haiku":"Profound emotional decay and spiritual death. Everything inside the narrator has withered and burned away, leaving only blackness.","sonnet":"A song about total internal collapse — a hollow soul, a dead sky, a world burned to the ground — and the desire to be buried and done. The speaker describes numbing himself to the point of feeling nothing, lying down in his own ruin.","opus":"A descent into despair as the narrator's world burns to the ground and his soul goes hollow, longing to be put back in his grave. He buries himself under others' lies, repeating that nothing is as black as his heart."},"carcass~no-love-lost":{"src":"haiku","haiku":"Romance stripped of authentic emotion, where hearts are played as instruments and severed. Love is a tragic, emotionless performance.","sonnet":"A cold dissection of romantic feeling as cheap and easily manipulated — heartstrings strummed and severed, love romanticized into a synthetic tragedy. The central refrain declares that when it is over, nothing of value was really there to lose.","opus":"A clinical, disillusioned view of love as an emotionless, doomed transaction, the heart played like an instrument and severed to a tragic tune. Human weakness is easy prey, and when all is said and done, there is no love lost."},"bloodhound-gang~altogether-ooky":{"src":"haiku","haiku":"Creepy, invasive behavior that repels the narrator. The relationship is perverse and disturbing, driving the narrator away with disgust.","sonnet":"A crude, comedic rejection of someone the speaker finds repulsive, cataloguing a series of grotesque or absurd encounters and announcing his complete desire to be rid of her. The repeated refrain borrows a line from Silence of the Lambs for comic shock effect.","opus":"A crude, comedic kiss-off to a repulsive ex, cataloguing disgust at their behavior and threatening a mob with torches. It laces the insults with horror-movie references to convey total revulsion at ever having been close to them."},"a-pale-horse-named-death~die-alone":{"src":"haiku","haiku":"Isolation and loss amid repeated life collapse. No matter who surrounds you, death and ultimate solitude are inevitable.","sonnet":"A song about repeated loss, isolation, and the certainty of dying alone — the one constant the speaker can count on across a life that has fallen apart many times. Suicidal thoughts appear as a recurring feature of this bleakness rather than a singular crisis.","opus":"A meditation on sudden loss, betrayal and grief, noting how worlds can collapse overnight and loved ones vanish. Its refrain insists on one grim certainty: no matter what, you always die alone."},"vader~devilizer":{"src":"haiku","haiku":"A demonic entity rising from suffering and pain to fulfill desires and desires. It spreads its influence through chaos and awakens the buried undead.","sonnet":"A first-person account from a demonic entity that rises from darkness in answer to human cruelty and pain, offering a dark kind of relief while spreading its wings and preparing to raise the undead. The song frames evil as something summoned by and responsive to human suffering.","opus":"A demonic entity narrates its own rise from crypts and a lake of tears, summoned by cruelty and pain to bring dark 'relief' to empty souls. It spreads its wings, howls in madness, and comes to claim its listener and raise the undead."},"massive-attack~group-four":{"src":"haiku","haiku":"Surveillance, meditation, and consciousness observing itself through surveillance and introspection. The narrator navigates awareness while monitored, daydreaming internally.","sonnet":"A fragmented, meditative song narrated from what feels like a surveillance or security shift — cameras, monitors, a flask of tea, strip lights — while the inner voice ranges through daydreams, martial arts training, and a quiet sense of floating in a private world.","opus":"An interior, meditative account of someone under surveillance who withdraws into inner stillness, sensing and roaming with eyes closed while cameras monitor them. Amid dummy screens and strip lights, they find a private world within themselves."},"paledusk~wind-back":{"src":"haiku","haiku":"Regret and desire to undo the past while moving forward together. The narrator and another must release old pain and start fresh to find new light.","sonnet":"A song addressed to a past or future version of oneself, urging that person to \"wind back\" to a better time and start over. The speaker works through reluctance and exhaustion toward an acceptance that it is not too late to change course, and that running forward with no time to die is possible.","opus":"An urgent plea to a friend to rewind time and revive a bond, insisting it is never too late to mend and that there is no time to die. Looking into each other's eyes, they see a shared future and resolve to start over and make it."},"ocean-grove~neo":{"src":"haiku","haiku":"Mutual destruction and blame where breaking one breaks the other. The cycle of pain and enmity between two people who drag each other down.","sonnet":"A mirrored back-and-forth between two voices — one breaking, one falling, one screaming — locked in shared pain that has made them both outcasts. The song captures a state of mutual suffering with no way out, the two perspectives echoing each other until indistinguishable.","opus":"A cycle of mirrored pain between two people, where one's breaking, falling and screaming echoes in the other, who becomes 'everybody's enemy.' The narrator is trapped, unable to find a way out despite claiming to trust the other."},"nine-inch-nails~the-becoming":{"src":"haiku","haiku":"Transformation into an artificial consciousness, losing humanity to machinery and noise. The former self decays while wires replace emotions and autonomy.","sonnet":"A song about losing one's humanity through a process of mechanical transformation — wires replacing feelings, circuitry replacing consciousness — until the person others knew is gone. The speaker is caught between relief at the numbness and horror at the noise driving the change.","opus":"A disturbing transformation of a person into a numb, wired machine, the feeling self decaying while a mechanical new consciousness takes over. Pleading for someone to hold him tighter, he fights a relentless inner noise that wants him dead."},"resolve~seasick-sailor":{"src":"haiku","haiku":"Struggle against internal darkness and suicidal urges through determined perseverance. The narrator fights against the tide of despair to reach solid ground.","sonnet":"A song about persisting through a prolonged personal crisis using the sustained metaphor of a storm-tossed sailor — battered, lost, lungs full of salt water — who keeps building his own raft and refuses to sink, trusting that the shore is reachable.","opus":"A struggle against despair cast as a lone, seasick sailor steering through a storm past underwater monsters toward shore. Having lost his certainties, he builds his own raft, refuses to sink, and learns to keep pushing without an end in sight."},"korn~rotting-in-vain":{"src":"haiku","haiku":"Parasitic need for another's pain to sustain oneself. The narrator feeds on suffering but grows weaker as the victim's pain fades.","sonnet":"A song about being trapped in a cycle of pain and repulsion that feels both self-generated and fed by the suffering around the speaker. Each day passes without escape, the agony digging deeper while the speaker screams into an indifferent sky.","opus":"A portrait of festering pain and a toxic bond, the narrator feeding on another's suffering and craving their tears. Digging through his own agony day after day, he feels stuck and 'rotting in vain.'"},"sodom~surfin-bird":{"src":"haiku","haiku":"Pure nonsense and repetition celebrating a bird as a cultural meme. The lyrics are absurdist, emphasizing the repetition of a single phrase.","sonnet":"A cover of the classic novelty song built entirely around the nonsense proclamation that \"the bird is the word,\" with no interpretable narrative beyond the gleeful, relentless repetition of that phrase and accompanying scat syllables.","opus":"A rowdy, nonsensical chant built entirely around the refrain that 'the bird is the word,' repeating that everybody has heard about the bird. There is no story beyond the gleeful, hammering repetition itself."},"slayer~flesh-storm":{"src":"haiku","haiku":"War's brutal horrors and indiscriminate violence driving people to madness. Media profits from bloodshed while soldiers endure endless suffering.","sonnet":"A brutal indictment of war as a permanent, media-fed condition of human existence — shrapnel, screaming, and daily bloodshed treated as spectacle and entertainment. The song argues that violence is humanity's way of life and that war has no cure, leaving only death as the escape.","opus":"A savage condemnation of endless war and the media that feeds on it, depicting shrapnel, screams and slaughter as an everyday spectacle. It rails against 'psychotic devotion' and men killing men for someone else's cause, concluding there is no cure for war."},"nine-inch-nails~non-entity":{"src":"haiku","haiku":"Dissolution of identity and existence, becoming a ghost or memory. The narrator fades from reality, losing coherence and presence.","sonnet":"A song about the erosion of identity and belief — everything once trusted turns out to be false, the self is fading from view, and what remains is barely a presence at all. The speaker is lost in a grey, burned-out landscape where nothing of the former self survives.","opus":"A disorienting loss of self and belief, the narrator lost in a monochrome maze where everything he thought true has collapsed. As his old identity burns away, he fades from sight, reduced to a 'non-entity.'"},"type-o-negative~some-stupid-tomorrow":{"src":"haiku","haiku":"Inability to forgive and cycles of violent, self-destructive behavior. Therapy and punishment blur together in a loop of regret and shame.","sonnet":"A song about the inability to forgive, move on, or find productive outlets for rage — punching walls only produces bruised knuckles, therapy is slow, anger remains. The refrain dismisses any promise of resolution as \"some stupid tomorrow\" that never arrives.","opus":"A struggle with guilt, anger and the difficulty of forgiveness, the narrator lashing out at walls and rejecting therapy or jail as fixes. He wants to leave behind stupid tomorrows and yesterdays alike, unable to fully forget."},"nutronic~code-war":{"src":"haiku","haiku":"Digital warfare and loss of control in an information age. Humanity surrenders its data and soul to machines and upgrades.","sonnet":"A song framed around digital-age conflict — the internet spreading lies, an information war being waged inside the machine — asking which side you are on and whether you will surrender your data and identity to the network or trace your way back to truth.","opus":"A vision of conflict in the information age, where a network spreads lies at the speed of light and war is waged inside the machine. It asks which side you're on as people surrender their 'code' and let others reap what's left of their souls."},"muse~hysteria":{"src":"haiku","haiku":"Desperate desire and emotional breakdown under pressure. The narrator's sanity erodes as they crave release and fear losing control.","sonnet":"A song about desperate, consuming desire — internal pressure building to the point of implosion — in which the speaker demands total surrender from the other person, driven by a need so urgent it feels like the last chance before losing all control.","opus":"A consuming, desperate craving that twists the narrator inside out, demanding a lover's heart and soul right now. Feeling his self-control slip, he strains to break out even as his faith erodes."},"queens-of-the-stone-age~the-lost-art-of-keeping-a-secret":{"src":"haiku","haiku":"A shared secret and the commitment to never reveal a hidden bond. The narrator takes this secret to the grave, preserving intimacy through silence.","sonnet":"A song about the intimacy of a shared secret — something between two people that must never be disclosed to anyone else. The speaker swears absolute loyalty to this pact, insisting he would take their secret to the grave rather than let it reach the outside world.","opus":"A pact of secrecy between two people who share something no one else can know, insisting the other tell no one. The narrator vows how far he'd go to keep it, taking their private song to the grave."},"sepultura~ratamahatta":{"src":"haiku","sonnet":"A chant-driven song built from Brazilian slang for favela life and references to iconic Brazilian folk figures — Zé do Caixão, Zumbi, Lampião — alongside percussive vocal patterns. It functions as a rhythmic celebration of Brazilian street culture and underground identity rather than a narrative song.","opus":"A rhythmic tribute to Brazilian life and folklore, name-dropping figures like Ze do Caixao, Zumbi and Lampiao and chanting images of favelas, garages and shacks. It greets uptown and downtown alike in a percussive celebration of place and heritage.","haiku":"An invocation of Brazilian and Caribbean resistance figures—Zumbi, Lampião, and folk horror icon Zé do Caixão—set against imagery of slums and urban streets across uptown, downtown, and trench town. A confrontational, rhythmic anthem rooted in marginal communities and outlaw culture."},"serj-tankian~honking-antelope":{"src":"haiku","haiku":"Apocalyptic reflection on humanity's destruction of nature and indigenous cultures. Only nature will survive humanity's arrogance and cruelty.","sonnet":"A song lamenting humanity's destruction of the natural world — vanishing indigenous peoples, poets corrupting the Tao, humans as the cause of a broken world — while suggesting that nature and nature-based beings will ultimately outlast human civilization.","opus":"A lament for vanishing indigenous cultures and a warning that nature will outlast humanity's destructiveness. It urges documenting what is passing before it's gone, casting humans as the cause of a broken world that only nature-based beings may survive."},"the-prodigy~rebel-radio":{"src":"haiku","haiku":"A rebel radio broadcasts a message of resistance and awakening to all who hear. The medium carries a call to freedom and dissent.","sonnet":"A minimalist call-to-action built around the repeated image of rebel radio broadcasting a message that is clear and universal — a sound playing in everyone's ear that calls them to something, though the precise cause is left open. The energy is collective and insurgent.","opus":"A hypnotic chant celebrating 'rebel radio' as a defiant sound broadcast to everyone. The message is simply that the radio plays its calling in your ear, clear to all who hear it."},"ocean-grove~intimate-alien":{"src":"haiku","haiku":"Two beings attempt connection across difference and incomprehension, seeking to understand each other through a digital realm while grappling with their fundamental otherness.","sonnet":"A disoriented narrator tries to connect with an entity whose cold, alien gaze makes him question his own identity and purpose, wondering whether he is just a glitch in a program or something transcendent, while stripping away the barriers around himself in search of understanding.","opus":"A dazed, exhausted narrator reaches out to a strange other being, offering to journey together through a digital land while questioning his own reality and nature. He wonders whether he is just a glitch, a blueprint, or a fragile structure, and resolves to break down the walls around him."},"limp-bizkit~shark-attack":{"src":"haiku","haiku":"A narrative of confrontation and competitive aggression where the singer positions himself as unstoppable and dominant against challengers and detractors.","sonnet":"A confrontational attack on a rival who has talked trash, framing the retaliation as self-defense against disrespect and a declaration that the narrator will outmaneuver anyone who comes for him.","opus":"A defiant boast aimed at a rival who has been talking trash, with the narrator promising to strike back hard and survive the fight. He casts himself as a lone predator who swims among sharks and comes out without a scratch."},"acid-drinkers~25-cents-for-a-riff":{"src":"haiku","haiku":"A satire on capitalism's debasement of human values, where life itself and artistic expression are reduced to commodities auctioned off at the same negligible price.","sonnet":"A sardonic commentary on the devaluation of both music and human life, equating a riff with a soul at auction and asking who is to blame when culture and existence are sold for next to nothing.","opus":"Framed as a bleak auction, the song laments a world where a human life and a piece of music are valued the same and sold off cheap. It treats the trading of souls as a done deal, with the hammer coming down at 25 cents apiece."},"celldweller~blackstar":{"src":"haiku","haiku":"A wish granted by ominous forces brings irreversible consequences that cannot be undone or reversed no matter how much one tries to escape them.","sonnet":"Unstoppable enforcers arrive on a Blackstar to fulfil a wish that should never have been made, and no amount of resistance or reversal can undo it — the only response is helpless acceptance.","opus":"Menacing, unstoppable figures arrive on a black star to grant a wish the listener should never have made, and there is no way to reverse it. The refrain insists you can only sing hallelujah because nothing can be changed."},"system-of-a-down~prison-song":{"src":"haiku","haiku":"A critique of mass incarceration and drug policy, exposing how the prison system grows as a tool of social control and oppression against marginalized populations.","sonnet":"A polemic arguing that the U.S. prison system was deliberately expanded after the civil rights era by making drugs available to minorities, filling jails with minor offenders while drug money funds covert wars and corrupts elections abroad.","opus":"A protest against mass incarceration in the United States, arguing that drugs were deliberately made available and that minor offenders fill the prisons. It claims taxes and drug money fund wars and rigged elections, and calls for treatment over law enforcement."},"death-angel~5-steps-of-freedom":{"src":"haiku","haiku":"A person trapped in confinement—literal or psychological—struggles to break free and reclaim their humanity against a system designed to contain and destroy them.","sonnet":"A prisoner, trapped in a cycle of pain and confinement with no hope of release, contemplates the few steps between his cell and a final escape — whether through rebellion or death.","opus":"A prisoner serving a long sentence rages against confinement, feeling his mind caged and his life reduced to survival. He resolves to break out and reclaim his humanity, even as death seems the likely end."},"alice-in-chains~would":{"src":"haiku","haiku":"Regret for mistakes and abandonment of someone important, questioning whether the damage done can ever be repaired.","sonnet":"A narrator caught in a self-destructive pattern reflects on a serious mistake and wonders whether he has strayed too far to return to someone he left behind, ending with an unanswered plea for mutual forgiveness.","opus":"A brooding reflection on a mistake and a lost connection, with the narrator pleading to be seen his way. He asks whether he has run too far from home and left someone behind, ending on an uncertain offer of mutual trust."},"tool~jambi":{"src":"haiku","haiku":"A meditation on love as the ultimate value, willing to sacrifice wealth and worldly success for the presence and peace of mind found in another person.","sonnet":"A narrator who once revelled in wealth and dark pleasures says he would surrender it all rather than lose the person who pulled him back from self-destruction, pleading with a benevolent, sun-like force to keep them unified.","opus":"A man who has indulged in every pleasure and dabbled in darkness says he would wish it all away to keep the one who saved and changed him. Torn between wants and needs, he clings to that person as his center and prays for two to become one."},"a-pale-horse-named-death~devil-came-with-a-smile":{"src":"haiku","haiku":"A Faustian bargain in which someone trades their soul for fame and fortune, only to discover the devil's promises lead to ruin and death.","sonnet":"A rock musician sells his soul to the devil for fame, rides a brief high of money and chart success, then watches it all collapse into overdoses, jail time, and abandonment — the devil simply moves on to new replacements.","opus":"A cautionary tale of a musician who signs away his soul to a smiling devil in exchange for fame, riches, and rock stardom. Once used up, he is dropped and replaced, ending poor, ruined, and headed for a nameless grave."},"sodom~sodomized":{"src":"haiku","haiku":"A perpetrator exults in sexual violence and domination, driven by cruelty and absence of compassion; the lyrics describe the act of rape from the aggressor's perspective, framed as satisfying violent pride.","sonnet":"A narrator consumed by violent, predatory desire describes a life of cruelty and sexual aggression, presenting domination and degradation as the sole drives of existence.","opus":"A brutal first-person account of a predator driven by pride, lust, and cruelty, taking what he wants without pity or compassion. The lyrics dwell on violation, wickedness, and violence with no tenderness in the heart."},"dragged-under~riot":{"src":"haiku","haiku":"A call to resistance against systems of control and oppression, urging collective uprising against silencing and manipulation by those in power.","sonnet":"A call to revolt against a media-controlled, politically rigged system that keeps people passive and spending, urging a new generation to break free and reclaim what has been taken from them.","opus":"A call to revolt against a system that keeps people distracted, indebted, and obedient while pretending to offer real choices. The narrators declare themselves a new generation ready to start a riot and take the world back."},"filter~nothing-in-my-hands":{"src":"haiku","haiku":"Powerlessness and loss of autonomy, as freedom is stolen and the individual is left with nothing to offer or claim.","sonnet":"A stripped-down statement of powerlessness: freedoms have been confiscated and justice is dead, leaving the speaker with nothing to offer and nowhere to turn but down.","opus":"A defiant stand against authorities who have seized people's freedom and let justice die. The narrator, forced face down on the ground, insists he holds nothing and has told them all he has."},"type-o-negative~i-like-goils":{"src":"haiku","haiku":"A woman declares her sexual preference for women and rejects traditional courtship and male advances with sharp defiance and humor.","sonnet":"A blunt, humorous rejection of advances from a man, in which the narrator — straight and unapologetic about it — declares his exclusive attraction to women and tells the unwanted suitor to leave.","opus":"A crude, tongue-in-cheek insistence that the narrator is straight and attracted only to women, rebuffing a man's advances with mockery. He declares his preference for women over and over while rejecting the come-ons directed at him."},"slipknot~spit-it-out":{"src":"haiku","haiku":"Confrontation with backstabbing and duplicitous people, framed as justified retaliation against those spreading falsehoods and seeking to undermine.","sonnet":"An all-out verbal assault on a backstabbing rival who spreads rumours and talks trash, with the narrator demanding the antagonist either face him directly or shut up.","opus":"A furious confrontation with an enemy the narrator accuses of spreading rumors, backstabbing, and trying to drag him down. He answers every insult with threats, vowing to stamp the other person out."},"nine-inch-nails~happiness-in-slavery":{"src":"haiku","haiku":"The paradox of people embracing conformity and servitude, finding contentment in submission rather than pursuing authentic freedom.","sonnet":"A portrait of a man who believes he is free but is thoroughly conditioned by the system he inhabits, finding comfort in conformity; the narrator recognises himself as human debris trapped inside a broken machine.","opus":"Over the sound of screaming, the song depicts a person beaten into submission who convinces himself he can find happiness in slavery. It portrays conformity and willing captivity as a numbing security, reducing a human to junk in a broken machine."},"muse~stockholm-syndrome":{"src":"haiku","haiku":"A cycle of emotional attachment mixed with pain and abandonment, repeating patterns of hurt and hopelessness without escape.","sonnet":"A relationship in which cycles of hatred, abandonment, and desperate reconnection repeat without resolution, with the narrator vowing — each time — that this will be the last time he forgets or leaves, yet doubting he can keep that promise.","opus":"A tangled, destructive bond in which the narrator refuses to stand in the way of another's hatred and anger as they burn out together. He repeatedly vows this is the last time he will abandon and forget the other, wishing he could."},"nine-inch-nails~starfuckers-inc":{"src":"haiku","haiku":"A critique of shallow celebrity worship and the sell-out mentality of those who sacrifice integrity for fame and power.","sonnet":"A savage portrait of celebrity worship and shameless self-promotion, skewering people who cultivate fame through insincerity, flattery, and calculated image-making.","opus":"A scathing takedown of shallow celebrity and social climbing, mocking a vain, soul-selling idol worshipped like a god. The narrator admits his own insincerity, playing along only as long as it serves him."},"alice-in-chains~check-my-brain":{"src":"haiku","haiku":"Mental exhaustion and disorientation in California, where time and emotional toll have hollowed out the narrator's mind.","sonnet":"A narrator who has wound up in California reflects on years spent, tears accumulated, and a past self left behind — suggesting a kind of bewildered, hard-won arrival that calls his own sanity into question.","opus":"The narrator finds himself in the California sun after a long, hard run, half-marveling and half-disbelieving at where he has ended up. He repeatedly asks someone to check his brain, worn down by years and tears."},"slayer~darkness-of-christ":{"src":"haiku","haiku":"A rejection of religious doctrine and divine authority, arguing that knowledge and reason reveal the hypocrisy and failure of organized religion.","sonnet":"A spoken-word prelude declaring that humanity's rejection of religious knowledge and the collapse of all religious structures have revealed that God is indifferent or hostile to mankind, framing this as the root of all chaos.","opus":"A spoken apocalyptic vision in which mankind rejects religion, all faiths collapse, and life prays for death. It traces the coming end of creation to a single event and concludes that God hates us all."},"the-pineapple-thief~nothing-at-best":{"src":"haiku","haiku":"Emotional emptiness and the burden of a relationship where one person offers nothing of value and brings only pain and death.","sonnet":"A confession of emotional unavailability: the narrator admits he has given a partner nothing to hold onto, tells her to run even as he asks her to stay, and accepts that the damage he has caused is his to carry.","opus":"A confession of guilt from someone who admits he gives a partner nothing to hold on to yet urges them to run for their life even while asking them to stay. He accepts blame and vows to carry the weight of the relationship as long as he is allowed."},"babymetal~elevator-girl":{"src":"haiku","haiku":"A descent through levels alternating between heaven and hell, with Japanese station announcements framing the journey as perilous and requiring constant risk.","sonnet":"An elevator-announcement conceit in which the ride always ends going down — to a floor described as a fiery hell two thousand levels below ground — with life itself framed as a constant, mortal gamble between up and down.","opus":"Framed as an elevator announcement, the song turns the ride into a descent toward hell, with floors of fire and needle torture thousands of levels underground. The refrain teasingly asks whether you are going up or, inevitably, down."},"type-o-negative~my-girlfriend-s-girlfriend":{"src":"haiku","haiku":"A polyamorous relationship in which three people find intimacy and acceptance together, indifferent to society's judgment.","sonnet":"A cheerful, matter-of-fact account of a consensual three-way relationship between a man and two women who resemble each other, presented as an uncrowded and perfectly natural arrangement.","opus":"A cheerful ode to a polyamorous threesome, with the narrator delighting in the closeness he shares with two women who are also involved with each other. He shrugs off what others might say as the trio walks openly together."},"a-pale-horse-named-death~shallow-grave":{"src":"haiku","haiku":"Betrayal by a deceptive lover leads to emotional death and the desire to bury that person in the mind, letting them decay and be forgotten.","sonnet":"Fury and relief at the end of a toxic relationship with a deceptive woman: the narrator buries her metaphorically in his mind, letting the memory rot while moving on without mourning.","opus":"A bitter fantasy of revenge against a deceitful lover the narrator regrets ever trusting and falling for. He imagines killing and burying her in a shallow, nameless grave, both literally and by erasing her from his mind."},"strapping-young-lad~aftermath":{"src":"haiku","haiku":"War and religious hypocrisy, depicting violence and violation justified by competing faiths and powers fighting over resources.","sonnet":"A stark condemnation of religiously and economically motivated warfare, depicting violence committed in the name of competing faiths as demonic and without moral justification.","opus":"An indictment of war waged in the name of religion and oil, portraying soldiers as demons who burn, beat, and rape while claiming to fight for God. It condemns all faiths alike as the pretext for endless riding into war."},"gorillaz~on-melancholy-hill":{"src":"haiku","haiku":"Emotional refuge with a beloved person as medicine against melancholy, seeking escape and companionship to avoid loneliness.","sonnet":"From a lonely hilltop where dreams fall short of reality, a narrator offers himself as comfort to someone who cannot get what they want, inviting them to set sail together and find closeness instead.","opus":"A wistful invitation to escape together to sea with a beloved who feels like medicine when close. Set on a melancholy hill with a plastic tree, it longs for the day the two are near even if you can't get what you want."},"uneven-structure~your-scent":{"src":"haiku","haiku":"Betrayal and victimization at someone's hands, as they exploit and consume others for their own twisted satisfaction.","sonnet":"An accusation directed at a seductive, consuming figure who lured others with false promises, fed on their suffering as seasoning, and left the narrator and fellow victims with nothing but lament and a hollow sense of validation.","opus":"An accusatory address to a seductive, devouring figure, likened to a mermaid, who lures people to their ruin and consumes them. The speakers refuse to be thankful or forgiving, framing their suffering as a lament for the unchosen victims."},"orgy~wide-awake-and-dead":{"src":"haiku","haiku":"Emotional numbness and zombie-like existence despite being awake, as numbing substances and disconnection replace genuine feeling.","sonnet":"Two people numb themselves with substances and distractions in a loveless, parasitic relationship, going through the motions of living while functioning like zombies — present but emotionally absent.","opus":"A portrait of two numbed, indifferent people medicating themselves through a loveless, cyclical relationship. The refrain likens the emotionally deadened partner to a zombie, wide awake yet spiritually dead."},"rammstein~los":{"src":"haiku","haiku":"Overcoming namelessness and enforced silence through music and collective voice, resisting censorship and asserting presence through sound.","sonnet":"A band's origin story told through a cascade of German privative adjectives: once nameless and wordless, they were hit by a storm that launched them, and despite critics calling them tasteless and hopeless, they will never be silenced or gotten rid of.","opus":"A defiant German-language declaration of a band or group that was once nameless, wordless, and songless but has found its name and voice. It answers critics who call the music tasteless, godless, and worthy of banning, insisting they will never be rid of them."},"ashen~hidden":{"src":"haiku","haiku":"Identity concealment behind protective masks worn to survive and fit in, leading to a loss of self trapped within lies and pretense.","sonnet":"A call to shed the masks and false identities people are conditioned to wear, recognising that self-deception and fear of rejection keep individuals imprisoned in chameleon-like performances instead of authentic selves.","opus":"An examination of hiding one's true self behind masks and lies, losing identity to fit in like a chameleon out of fear of rejection. The narrator pleads to tear down the mask, escape the self-made prison, and finally reveal who he really is."},"rammstein~mann-gegen-mann":{"src":"haiku","haiku":"A homosexual man navigates desire and social condemnation, claiming ownership of his body and sexuality against family and society's judgment.","sonnet":"A celebration and defence of gay male desire: the narrator embraces his attraction to men as destiny and as his own gift, while acknowledging the cold condemnation — homophobic slurs, hostile tongues — that society directs at him.","opus":"A first-person German-language declaration of homosexual desire, sung by a man who calls himself a king without a queen and whose skin belongs to other men. He acknowledges being branded a traitor and the nightmare of fathers, and faces slurs hurled at him while asserting his nature."},"sepultura~phantom-self":{"src":"haiku","haiku":"Loss of identity following a traumatic event, as the person becomes someone else entirely and must confront this transformed self.","sonnet":"A survivor of a traumatic crash — described in fragmented flashbacks of carnage and blood — struggles with the loss of his former identity, haunted daily by the person he was before the accident destroyed his sense of self.","opus":"A survivor of a sudden, violent crash struggles with lost memory, injury, and a changed identity, haunted by flashbacks of the carnage. He feels transformed into someone else and must confront the phantom self he has become while searching for a truth no longer there."},"serj-tankian~lie-lie-lie":{"src":"haiku","haiku":"A narrative of deception and betrayal culminating in the narrator watching someone fall to their death, masked by falsehood throughout.","sonnet":"A narrator takes a person to a cliff edge under the guise of love or brotherhood and lets them fall to their death on the rocks below, smiling throughout — a story of intimate betrayal disguised as affection.","opus":"Beneath a sing-song refrain, the song tells of a toxic love in which the narrator coldly lets a lover fall to her death on the rocks below. He describes smiling and delighting as she dies, framing the whole affair around lies."},"airbourne~runnin-wild":{"src":"haiku","haiku":"Breaking free from an unhappy and suffocating relationship, driving toward liberation and rejecting any hope of reconciliation.","sonnet":"A definitive breakup: the narrator burns with rage at a draining partner, hits the open road without looking back, and finds a bitter freedom in putting as many miles as possible between them.","opus":"A driver leaves a bad relationship for good, refusing to turn back no matter how much the other cries. He revels in the freedom of the open road, his anger fueling the escape from a partner he wants out of his life."},"uneven-structure~alkaline-throat":{"src":"haiku","haiku":"Longing to escape mundane existence through another person, seeking transcendence and meaning through intense connection and passion.","sonnet":"Two people chase an adrenaline-fuelled, intoxicating connection — a shared drive toward intensity and excess — until the heat between them curdles into loathing and the narrator's contempt echoes back at the other's laughter.","opus":"An intoxicating, self-destructive pull toward a tempting presence the narrator both craves and distrusts, chasing whatever lights him up. The imagery moves from seductive sweetness to burning flesh, ending in loathing that echoes back as laughter."},"limp-bizkit~take-a-look-around":{"src":"haiku","haiku":"Apathy and hatred as responses to societal contempt, with the narrator claiming indifference while reflecting on life's meaninglessness.","sonnet":"The narrator deflects criticism and hatred by owning his flaws, arguing that the world's pervasive hostility explains why people turn on him, while insisting life is a fast, unforgiving lesson you either keep up with or lose.","opus":"Framed with a mock spy briefing, the narrator vows to live his own way despite critics and a world full of tension and hate. He reflects that hate is all the world seems to see lately and that life is a fast, unforgiving lesson learned only at the end."},"mot-rhead~in-the-black":{"src":"haiku","haiku":"Pursuit and romantic overture toward someone desired, with the narrator positioning himself as capable of love and commitment despite his reputation.","sonnet":"A persistent, openly infatuated narrator pursues a woman who keeps giving him the runaround, declaring he has changed for good and that she is the one he has been waiting for — even if he cannot be who he once was.","opus":"A blunt courtship in which the narrator approaches someone he's smitten with, promising to treat them well and asking them to say yes. He insists he's changed from who he was and offers to protect them, admitting he'll fall apart if they refuse."},"slayer~disciple":{"src":"haiku","haiku":"Anti-religious defiance and rejection of divine authority, claiming individual hatred and superiority over blind faith and conformity.","sonnet":"A rejection of religion and of any faith in a god who, in the face of global violence, drug abuse, and human self-destruction, is either absent or actively hateful — the narrator insists on hating everyone equally rather than following any doctrine.","opus":"A militant rejection of religion and blind faith, with the narrator refusing to be God's disciple or bear the cross. He preaches that God hates everyone, declares he hates everyone equally, and stands alone in a world of enemies."},"ocean-grove~glass-gloss":{"src":"haiku","haiku":"Assertion of individuality against mass consumption and commodification, resisting being reduced to another weapon of commercial appeal.","sonnet":"Frustration with slow progress and the pressure to conform to mass appeal leads the narrator to assert his own reality and map his own exit, finding life and purpose in cycles of experience rather than in what others demand of him.","opus":"A restless narrator, disillusioned with the grind and pressure to conform and consume, questions the cost of progress and nearly selling his soul. He insists on being seen as real, not a marketing product, and dreams of blasting away from it all while asserting who he truly is."},"jamal~defto":{"src":"haiku","haiku":"Isolation and emotional distance between two people, where connection is blocked and loneliness persists despite proximity and time together.","sonnet":"A Polish-language meditation on a failing relationship in which words come easily to one person but cut like a knife to the other; as the connection collapses, the narrator walks on alone through a city where solitude is both the beginning and the end of every bond.","opus":"A Polish-language meditation on a failing relationship and deep loneliness, where words wound like a knife and the two can no longer reach the heights they once shared. Amid images of the city at night and slow dying, the narrator concludes that loneliness stands at both the beginning and the end."},"bring-me-the-horizon~chelsea-smile":{"src":"haiku","haiku":"Guilt and shame about hidden secrets leading to self-harm, with the burden of concealed pain growing unbearable and consuming.","sonnet":"A narrator buries a secret guilt that consumes him from within, admitting he can only fake happiness while questioning whether God would bother with someone who cannot even believe, as the weight of hidden shame threatens to destroy him.","opus":"A confession of a devouring secret, guilt, and regret that eats at the narrator like cancer and keeps him from sleep. He masks his pain behind a smile, wrestles with shame and belief in God, and reflects that everyone carries hidden burdens that drag them down."},"deftones~diamond-eyes":{"src":"haiku","haiku":"Escape and transcendence with a beloved person, imagining cosmic union and realignment beyond earthly constraints.","sonnet":"An urgent invitation to escape together to some transformed, shared realm — framed as a once-and-for-all departure where cosmic alignment and diamonds falling from the sky mark the moment of transcendence.","opus":"An urgent invitation to run away together into outer space and be realigned, once and for all. Amid imagery of diamonds raining across the sky, the narrator vows to lead them both into the same realm."},"machine-head~battery-bonus":{"src":"haiku","haiku":"Aggression and violent rage as an unstoppable natural force that cannot be controlled or killed, only expressed and perpetuated.","sonnet":"An ode to relentless, self-perpetuating force: the song personifies a crushing, unstoppable energy that feeds on aggression and cannot be killed, framing this power as both family bond and primal drive.","opus":"A cover celebrating a relentless, aggressive force called the battery that crushes the weak and cannot be stopped or killed. It frames this violent energy as something bred within, an unstoppable powerhouse of destruction."},"tesseract~dystopia":{"src":"haiku","haiku":"Nightmarish visions and psychological torment where the narrator resists manipulation while struggling to maintain autonomy against control.","sonnet":"Trapped in a nightmare of dark, multiplying figures and manipulative relationships, the narrator finally refuses to comply — asserting the freedom to live on his own terms rather than give in to someone who wanted him to surrender.","opus":"A fearful, dreamlike state of dark figures, liars, and chasing visions gives way to a struggle to live free and resist giving in to another. The narrator refuses to be swayed or comforted, holding to the idea that the greatest thing is to love and be loved in return while there's nowhere left to hide."},"gorillaz~feel-good-inc":{"src":"haiku","haiku":"Urban decay and societal breakdown masked by consumerism and synthetic happiness, with the wealthy exploiting the poor for profit.","sonnet":"A critique of a hollow, city-based cycle of manufactured pleasure and distraction that keeps people trapped while a separate, windmill-and-open-sky vision of free love and turning together offers an alternative outside the system.","opus":"A contrast between a bleak, crumbling, melancholy town where no one smiles and a longing for an idealized windmill land of love and freedom. A boastful rap voice cuts through, hyping itself while the wider mood is one of numb, escapist detachment."},"placebo~pure-morning":{"src":"haiku","haiku":"Complexity of friendship intertwined with sexual desire and physical intimacy, celebrating unconventional bonds that blur boundaries.","sonnet":"A catalogue of what the ideal companion looks like — someone who teases, bleeds, confesses, and endures — building to a sense of hard-won, unbreakable bond that arrives with the rawness of early morning.","opus":"A playful, repetitive ode to the value of a true friend, cataloguing the many kinds of friends who make life better. It circles a bond with a woman who passed some test, set against a strung-out morning of dawning day and crawling skin."},"nine-inch-nails~meet-your-master":{"src":"haiku","haiku":"Servitude and the reversal of power, as the formerly dominant are forced into submission and made to obey.","sonnet":"A dominant power strips a formerly in-charge figure of authority, forces compliance through blindfolds and orders, and promises that a reckoning is coming fast — the former leader will learn his true place.","opus":"A menacing address from captors to a former leader now forced to submit, blindfolded and made to obey. Counting down to a coming disaster, they tell him it's time to meet his master and learn his place."},"nine-inch-nails~reptile":{"src":"haiku","haiku":"Toxic and contaminating sexuality, where desire spreads infection and corruption, mixing beauty with disease and degradation.","sonnet":"An obsessive, self-aware attraction to a dangerous, parasitic woman: the narrator recognises her corrupting, reptilian nature but is drawn in by the need to contaminate and be contaminated, knowing it makes him impure.","opus":"A dark, obsessive portrait of a woman cast as a deceiving lover and whore, and the narrator's tainted attraction to her. He describes needing to contaminate to ease his loneliness, calling her his disease and confessing his own impurity."},"kendrick-lamar~humble":{"src":"haiku","haiku":"Pride, self-affirmation, and superiority claimed through wealth and success, with the narrator asserting dominance over competitors and critics.","sonnet":"From a Compton upbringing of syrup sandwiches to current wealth and dominance, the narrator demands that rivals and posers acknowledge their place, while also calling out the fakery of Photoshop beauty and insisting on natural, unfiltered reality.","opus":"A braggadocious track flaunting the narrator's rise from poverty to wealth and status while demanding that a rival be humble and sit down. He rails against fakeness and Photoshop, calling for something natural and real, and crowns himself the realest of all."},"nine-inch-nails~with-teeth":{"src":"haiku","haiku":"A transformative and controlling force that draws someone in, fundamentally changes them, and refuses to release them from its grip.","sonnet":"A seductive, addictive force — figured as a woman — takes hold of the narrator completely, blurring all former boundaries until he surrenders to it and knows he will not come back from where it has taken him.","opus":"A woman gets inside the narrator and transforms him, making him feel he's finally found where he belongs, an experience as deep and dark as the blackest sea. Yet she will not let him go, and he insists he cannot go through this again and this time won't come back."},"slayer~south-of-heaven":{"src":"haiku","haiku":"Apocalyptic judgment and inevitable damnation, depicting moral decay and familial corruption that deserve eternal punishment and suffering.","sonnet":"A vision of an apocalyptic moral collapse, where judgement arrives without warning, generations corrupt one another through hate and lust, and existence is permanently settled in a realm south of heaven — beneath divine reach, ruled by chaos and a black-souled evil.","opus":"An apocalyptic vision of judgment day, damnation, and a world of chaos, distrust, and moral corruption. It depicts souls condemned for eternity beneath a domineering deity, with hope and dignity lost south of heaven."},"limp-bizkit~counterfeit":{"src":"haiku","haiku":"A confrontation with someone who's adopted a false identity and mimics the speaker's style. The song denounces counterfeit behavior and exposes the faker's betrayal of trust.","sonnet":"A confrontation with someone accused of wholesale fakery — stealing another's style, riding trends, and stabbing former friends in the back while hiding behind a false identity.","opus":"A scornful takedown of an imitator who copies the speaker's style, culture, and even appearance while hiding behind a fake persona, dismissed repeatedly as a phony and a counterfeit."},"the-pineapple-thief~wake-up-the-dead":{"src":"haiku","haiku":"A speaker confronting someone unresponsive to their attempts at connection, haunted by trauma—specifically a suicide that has metaphorically washed ashore—while trying to penetrate the other's emotional silence.","sonnet":"A speaker grapples with the aftermath of a loved one's suicide, vowing to understand what was in that person's head and somehow reach them even across death.","opus":"Addressed to someone who once protected the speaker but has since changed, the song fixates on that person's suicide washing up at the speaker's door and a desperate, obsessive urge to get inside their head."},"limp-bizkit~get-a-life":{"src":"haiku","haiku":"An aggressive boast from a rapper establishing dominance over detractors and rivals. The speaker celebrates his rise from humble origins and demands respect, dismissing those who envy his success.","sonnet":"A boastful declaration of self-made toughness and disdain for haters, delivered by a rapper who frames his rise from a Carolina redneck background as proof that the jealousy of others is irrelevant.","opus":"A boastful, confrontational rap in which the narrator brags about his toughness, drinking, women, and North Carolina roots while taunting rivals and jealous haters to back off."},"anthrax~only":{"src":"haiku","haiku":"A relationship fractured by differing temperaments and broken promises. The speaker expresses frustration that the other person won't try to understand and has taken control away, leaving incompatibility on both ends of the spectrum.","sonnet":"A relationship marked by erratic mood swings and mutual incomprehension, where the speaker feels that control was taken from them and the other person never truly tried to understand.","opus":"A portrait of a volatile, self-absorbed relationship where the other person's unpredictable mood swings and refusal to understand leave the speaker feeling controlled and driven to the edge."},"queens-of-the-stone-age~quick-and-to-the-pointless":{"src":"haiku","haiku":"A loose, fragmented track describing a sexually charged encounter with an age difference, rendered in Dutch and English slang without coherent narrative structure or clear meaning.","sonnet":"A fragmentary, lustful pursuit of a young woman, mixing Dutch interjections ('life is hard, people get scared,' 'I think yes, but no') with a refrain about age, desire, and a general 'let's go' energy.","opus":"A loose, repetitive come-on mixing English and Dutch lines, where an older speaker fixates on a young girl amid vague remarks that life is hard and people grow afraid."},"ministry~worthless":{"src":"haiku","haiku":"A scathing internal monologue condemning self-hatred and degradation. The song frames the subject as worthless and directs them toward self-destruction through various forms of abuse and numbness.","sonnet":"A relentless barrage of contempt and commands for self-destruction aimed at a target the speaker declares entirely worthless — the song works as a brutal litany of dehumanisation.","opus":"A relentless barrage of contempt urging the listener toward self-hatred, self-destruction, and self-degradation, insisting they are worthless and mean nothing to the speaker."},"idiot-pilot~red-museum":{"src":"haiku","haiku":"An unsettling surreal narrative of trespass and transformation in a strange red museum where residents are merged into singular entities and red sky dominates, trapping visitors who cannot escape the intrusion.","sonnet":"A disquieting scene of intrusion — an unseen figure enters through an open window near a sleeping baby — set in a cold, silent place where individuals are absorbed into an undifferentiated collective and an unstoppable force cannot be held back.","opus":"An eerie, unsettling scene of intruders slipping through a window past a sleeping baby into a silent museum-like place, with a refrain about people becoming one and being unable to stop them from coming in."},"deftones~dai-the-flu":{"src":"haiku","haiku":"A muddled reflection on physical pain, proof of love through suffering, and a moment of realization that the other person does love despite hardship and the metaphorical illness of the relationship.","sonnet":"A volatile, ambiguous intimacy where pain and damage ('fifteen stitches,' dislocated joint, sinking teeth) are reinterpreted as evidence of love, and the speaker arrives at a relieved, if uneasy, certainty that he is cared for.","opus":"A tangled, wounded meditation on a manipulative intimacy, where injury, deceit, and fleeting affection blur together and the speaker clings to the reassurance that he is loved at all."},"dream-theater~a-change-of-seasons":{"src":"haiku","haiku":"A narrative of lost innocence and the encroaching darkness of adult life, set against advice to seize the day. Culminates in the death of the speaker's mother, crushing the wisdom imparted.","sonnet":"A meditation on losing childhood wonder and innocence to grief and disillusionment, anchored by a teacher's 'carpe diem' lesson that gains devastating weight when the speaker's mother is killed — the song traces the arc from youthful wonder through trauma to a plea to seize what life remains.","opus":"A sweeping reflection on the passage of life from innocent youth to disillusioned adulthood, framed by the death of the narrator's mother and the urgent lesson to seize the day before time runs out."},"sodom~get-what-you-deserve":{"src":"haiku","haiku":"A violent revenge fantasy where the speaker, wronged and exploited, promises to return suffering to the betrayer who tapped their vein and laughed at their pain.","sonnet":"A revenge narrative in which an abandoned, war-scarred narrator tracks down the person who betrayed and laughed at him, promising lethal retribution with a shotgun.","opus":"Told by a man broken by war trauma and betrayal, the song is a vow of vengeance against the person who wronged him, promising to hunt them down with a shotgun so they get what they deserve."},"trivium~chaos-reigns":{"src":"haiku","haiku":"An introspective exploration of inner conflict and self-loathing. The song describes internal hate built from fragments of pain and wretchedness, giving form to the chaos dwelling inside.","sonnet":"An inward struggle with destructive self-hatred, where the speaker acknowledges that chaos and loathing originate from within and cannot be escaped.","opus":"A self-lacerating declaration of inner turmoil, picturing the speaker building wings from his own broken pieces while hate and wretchedness fester inside and chaos rules within him."},"strapping-young-lad~detox":{"src":"haiku","haiku":"A claustrophobic account of social isolation and emotional numbness in a high-school setting. The speaker feels watched, disconnected, and lost, unable to escape their sense of inadequacy.","sonnet":"A wretched social alienation — the speaker finds himself somewhere he doesn't belong, surrounded by people who all seem to be watching, numbed and unable to function, wanting only to feel something.","opus":"A raw account of alienation and breakdown, where the speaker feels numb, watched, and lost among people, drowning in high-school loneliness and despair, with clinical narration about the brain amplifying the sense of dread."},"n-e-r-d~rock-star":{"src":"haiku","haiku":"A track mocking poseurs and self-serving imitation while claiming authentic rebel status. The speaker warns pretenders that accountability is coming and their time is up.","sonnet":"A challenge hurled at posers and imitators who tried to mimic the group's style, warning them that their time is up and authenticity will win out.","opus":"A defiant address to posers and imitators, warning that their fakery is almost over as the swaggering narrator asserts his authenticity as a rebel rock star and tells them to be themselves."},"deftones~around-the-fur":{"src":"haiku","haiku":"A critique of shallow vanity and fashion obsession paired with desire for attention. The speaker rejects both superficiality and false claims of authenticity from a self-serving subject.","sonnet":"A taunted, obsessive fixation on someone the speaker describes as vain and hollow, demanding her attention while condemning the superficiality and dishonesty around her.","opus":"A jealous, disillusioned reproach aimed at a partner caught up in vanity and appearances, as the speaker begs only for her attention while calling her a liar and pleading with her not to destroy herself."},"rammstein~keine-lust":{"src":"haiku","haiku":"A German-language song cataloging lack of desire and motivation for bodily functions and engagement. The speaker is cold, unmotivated, and reduced to counting flies while lying down.","sonnet":"An extreme, comic apathy — the speaker catalogues all the things he would like to do but has no drive to attempt (eat, masturbate, undress, go out in the snow), culminating in the observation that he has simply been lying still so long he has gone cold.","opus":"Sung from total apathy and depression, the narrator lists all the things he has no desire to do, from touching himself to eating or moving, preferring to lie still, count flies, and note how long he has already been cold."},"nine-inch-nails~copy-of-a":{"src":"haiku","haiku":"An examination of identity as derivative and assembled from fragments. The speaker feels like a shadow and echo, controlled and hollow, a copy without original agency.","sonnet":"A crisis of identity and authenticity, where the speaker sees himself as nothing but a degraded copy of copies — assembled from borrowed pieces, obediently following instructions, with no original self remaining.","opus":"An identity crisis rendered as endless repetition, with the speaker describing himself as merely a copy of a copy, an echo and a shadow, assembled from borrowed pieces and doing only what he is told."},"system-of-a-down~suite-pee":{"src":"haiku","haiku":"A transgressive spiritual narrative invoking Jesus as a figure around which people construct philosophy and devotion. The imagery is violent and sacrilegious, exploring religious fervor and bodily transgression.","sonnet":"A chaotic, blasphemous assault on religious devotion, casting Christ as a female figure whose philosophy demands dying for her, and mixing ecstatic surrender with provocative sexual imagery to destabilise sacred narratives.","opus":"A provocative, blasphemous piece imagining Jesus as a woman and mixing religious imagery of dying for her philosophy with violent, sexual, and mocking depictions of following and abandoning Christ."},"type-o-negative~cinnamon-girl":{"src":"haiku","haiku":"A romantic fantasy about living with a dreamed-about woman while making music with her. The speaker seeks her support to achieve success and live together harmoniously.","sonnet":"A cover of Neil Young's song rendered faithfully: a romantic daydream of living with an idealized woman and chasing moonlight together, with a plaintive aside to a parent for money to sustain the dream.","opus":"A love song about longing to spend a lifetime with a 'cinnamon girl,' full of dreamlike night-time images, band imagery, and a young man pleading with his mother for money as he tries to make it."},"a-day-to-remember~exposed":{"src":"haiku","haiku":"A political critique of manipulation and control by governments and institutions who trade freedom for illusion. The speaker exposes systemic deception and calls for resistance.","sonnet":"A politically charged rejection of manufactured consent, arguing that workers and citizens are kept compliant through the illusion of choice while the powerful exploit them — the song calls for confronting that system rather than accepting it.","opus":"A politically charged protest against manipulation and false choice, distrusting politicians and pacifists alike, warning workers to fall in line while insisting the powerful are never through with you until you're left exposed."},"a-perfect-circle~passive":{"src":"haiku","haiku":"A confrontation with someone emotionally unresponsive or catatonic, interpreted as death or refusal to engage. The speaker threatens to walk away if they won't face reality and participate.","sonnet":"An angry confrontation with someone who is emotionally shut down and unresponsive, the speaker demanding they wake up and engage rather than retreat into passive, catatonic withdrawal.","opus":"Addressed to someone emotionally 'dead' and unresponsive, the song alternates between coaxing them to wake up and face the speaker and bitter frustration, ultimately dismissing their coldness as passive-aggressive."},"poets-of-the-fall~the-lie-eternal":{"src":"haiku","haiku":"A speaker seducing someone into a deceptive romantic bond, promising to heal and complete them while acknowledging the relationship is built on illusion and manipulation.","sonnet":"A lover recognises that the intense relationship he has fallen into is built on illusion, yet cannot pull away because only this person's presence makes the world feel real and bearable.","opus":"A surrender to an intoxicating love that the speaker knows is also a lie, falling into another's embrace where all mistakes feel forgiven and only that person can wound or heal him."},"nine-inch-nails~everything":{"src":"haiku","haiku":"A transformation and transcendence narrative where the speaker sheds their previous identity and home, replaced by an internal entity that awakens and takes over.","sonnet":"A speaker emerges from a prolonged ordeal transformed — old identity dissolving, an inherited darkness still threatening to rise — yet arrives at a feeling of being finally home and free.","opus":"A declaration of survival and transformation, as the speaker sheds his former self, watches his old identity break apart, and finds a sense of freedom and homecoming even as something new rises within him."},"ocean-grove~lights-on-kind-of-lover":{"src":"haiku","haiku":"A fragmented urban scene depicting casual sexual desire, longing, and relationship dysfunction. The speaker navigates unwelcoming spaces and negotiates intimacy with emotional hesitation.","sonnet":"Fragmented snapshots of low-level urban drift — a laundromat, cheap vices, thin walls, a lover's warning not to bite too hard — held together by a narrator who feels unwelcome yet refuses to be rattled.","opus":"A fragmented, edgy account of a tense, unwelcome encounter and a fraught relationship, laced with imagery of laundromats, drug use, and self-destruction, with the speaker insisting he won't be unnerved."},"islander~the-outsider":{"src":"haiku","haiku":"A declaration of lifelong outsider status and identity. The speaker accepts their role as marginalized and refuses to change, resigned to their position on the periphery.","sonnet":"A resigned self-portrait of someone who has always existed on the margins, too broken and exhausted to pretend otherwise, accepting that being an outsider is simply who they are.","opus":"An anthem of defiant self-acceptance, in which the speaker embraces always having been an outsider, refuses to change who he is, and voices exhaustion at waiting and chasing fading dreams."},"skywalker~away":{"src":"haiku","haiku":"A song addressing someone whose sense of self and belief have been stolen or lost. The speaker urges them to fight or flee while wrestling with the weight of isolation and self-doubt.","sonnet":"An appeal to someone whose sense of self and belief have been stripped away by outside forces, urging them to stop bottling everything up and choose to fight rather than surrender.","opus":"A song about loss and desperation, urging someone crippled by fear and self-loathing to choose 'fight or flight' after everything they believed in has been taken away, reassuring them they're fine as they are."},"rammstein~zick-zack":{"src":"haiku","haiku":"A German-language song satirizing cosmetic surgery and body modification obsession. The narrative catalogs surgical procedures and the pain endured for beauty standards and rejuvenation.","sonnet":"A satirical inventory of cosmetic surgery procedures — breast implants, liposuction, Botox, facelifts, foreskin removal, gender reassignment — delivered as a gleeful chant that beauty demands pain and time is running out.","opus":"A biting satire of cosmetic surgery and vanity, cataloguing implants, liposuction, Botox, and cutting in graphic detail, with the refrain that beauty demands suffering as time relentlessly ticks toward old age."},"limp-bizkit~faith":{"src":"haiku","haiku":"A song about needing emotional space after being hurt in a previous relationship. The speaker demands faith in his ability to overcome heartbreak but must guard his heart carefully.","sonnet":"A cover of George Michael's song: a guarded speaker who has been hurt before refuses to give his heart away again without caution, insisting he must have faith before committing to a new relationship.","opus":"A cover about needing to guard one's heart after being hurt, resisting a lover's plea to stay because love without devotion isn't enough, and insisting on faith while showing the other person the door."},"make-them-suffer~that-s-just-life":{"src":"haiku","haiku":"A meditation on hardship and transformation within a corrupt power structure. The song accepts that adaptation or collapse is inevitable when systems change and bind people.","sonnet":"An announcement of a new order rising from a troubled past, framed in the language of crowns and royal blood, with the pragmatic message that change is inevitable and one must either adapt or fall apart.","opus":"Built on royal imagery of a heavy crown and changing reigns, the song frames upheaval and inevitable change as simply part of life, where all bonds break to embrace the winds of change."},"korn~let-the-guilt-go":{"src":"haiku","haiku":"An examination of how dishonesty and backtracking lead to psychological anguish and self-torment. The speaker's overthinking and guilt prevent forward movement and authentic connection.","sonnet":"A candid account of how obsessive second-guessing and guilt spiral into paralysis, with the speaker unable to break free from a mental loop that poisons communication and wastes days.","opus":"A song about the corrosive weight of guilt, dishonesty, and obsessive overthinking, with the speaker berating himself for listening to his head instead of his gut and urging himself to let the guilt go."},"nevermore~c-b-f":{"src":"haiku","haiku":"A critique of apathetic numbness and self-destructive addiction. The speaker witnesses someone choosing death through indifference and chemical escape rather than confronting their will to live.","sonnet":"A direct address to someone destroying themselves through substance abuse — watching ambition die, will erode, and life waste away — with the speaker finally admitting cold resignation: if the person keeps choosing this path, he will count the days until they are gone.","opus":"A grim portrait of addiction and self-destruction, watching a friend numb their pain, waste away, and court a death wish hit by hit, with the speaker vowing to count the days until they're gone if they keep living this way."},"strapping-young-lad~critic":{"src":"haiku","haiku":"An obscure and fragmentary song touching on internal conflict, cheating, and ambivalent self-awareness. Meaning is difficult to extract from the lyrical abstraction.","sonnet":"A late-night reckoning with infidelity and guilt, the speaker calling out to someone named Mora for help while knowing what he has done is wrong, suspended between confession and self-justification.","opus":"A restless, wounded address to a 'critic' and a demanding presence, mixing exhaustion, sleeplessness, and guilt with a desperate need for connection and help to make it through the nights."},"celldweller~louder-than-words":{"src":"haiku","haiku":"A demand for authentic action over hollow promises and verbal deception. The speaker is tired of insincere apologies and wants to see genuine change demonstrated, not spoken.","sonnet":"A confrontation with a habitual liar whose apologies and stories keep shifting, the speaker insisting that only actions matter — words have become meaningless noise.","opus":"A furious dismissal of a habitual liar whose empty apologies and shifting stories mean nothing, insisting that actions speak louder than words and demanding they shut up and prove themselves by what they do."},"filter~take-a-picture-radio-edit":{"src":"haiku","haiku":"A commentary on memory loss and loss of privacy in a medicalized or invasive state. The speaker feels dislocated from their body and begs for documentation since they won't remember anything.","sonnet":"A fragile, dissociated moment on an airplane — the speaker feels newborn and exposed, asking someone to photograph him because he knows he won't remember, and reaching out toward a distant father.","opus":"A hazy, dissociated song about feeling exposed and reborn while awake on an airplane, asking someone to take a picture because the speaker won't remember, and rejecting notions of sanctity and privacy, with a pointed aside to his father."},"the-prodigy~omen":{"src":"haiku","haiku":"A minimal and repetitive warning about an inevitable sign of doom written on a wall. The track emphasizes automaticity and inescapable premonition with little narrative elaboration.","sonnet":"A sparse, ominous warning: writing is already on the wall, the outcome is inevitable, and people are running on automation — something is coming that cannot be avoided.","opus":"A minimal, ominous warning built on the repeated declaration that the writing is on the wall and won't go away, an unavoidable omen while people run on autopilot."},"melt-banana~lost-parts-stinging-me-so-cold":{"src":"haiku","haiku":"A surreal account of forgotten past injuries and lost parts of the self haunting the present. The speaker attempts to exorcise these spectral remnants but fails, leaving them embedded.","sonnet":"Sensory fragments from the past — broken pieces, ghost signals, forgotten seeds — that keep haunting the present, stinging and cold; the speaker tries to shoot them down but eventually lays down the gun, unable to rid themselves of what has been lived and lost.","opus":"A surreal, unsettling meditation on painful fragments of the past that cling like ghosts, stinging cold, which the speaker tries to shoot down and reject but ultimately recognizes as parts of himself he can't escape."},"limp-bizkit~pollution":{"src":"haiku","haiku":"A hip-hop track defending provocative lyrical content and aggressive style against narrow-minded censorship. The speaker insists on artistic freedom and refuses to tone down the volume.","sonnet":"A defense of the group's music against narrow-minded critics, framing their sound as an unstoppable force and daring detractors to accept it or get out of the way.","opus":"A combative rap boasting about the narrator's rhyming skill while confronting narrow-minded critics, framing their noise and complaints as pollution and defiantly refusing to turn down or shut up."},"pro8l3m~v8":{"src":"haiku","haiku":"A Polish-language rap chronicling substance abuse, fast cars, and reckless hedonism. The speaker boasts about speed, drug use, and a lifestyle of excess without consequence.","sonnet":"A rapid-fire ride through Warsaw nightlife — drugs, women, police patrols, fast cars, and money — delivered with the detached bravado of someone accelerating through the city while everything blurs past.","opus":"A Polish rap set in a world of fast driving, drugs, money, and nightlife, boasting about racing in the outside lane, a good-looking woman, debts and karma catching up with others, and reckless indulgence."},"nine-inch-nails~less-than":{"src":"haiku","haiku":"A song questioning whether acquiring material comforts actually fixes internal brokenness or simply deepens emptiness. The speaker challenges whether oblivion and consumption fulfill the promised healing.","sonnet":"A challenge aimed at those who justified aggression and violence — missile trails, silencing, demanding compliance — asking whether getting what they wanted actually fixed anything or just led to oblivion.","opus":"A confrontation with someone who justifies violence and self-deception, repeatedly asking whether getting what they wanted actually fixed what was wrong with them or left them feeling 'less than,' welcoming oblivion."},"korn~gravity-of-discomfort":{"src":"haiku","haiku":"An account of persistent psychological weight and self-directed hate that crushes the speaker daily. The pain is unavoidable and will never fade, marking them irreversibly.","sonnet":"An account of being crushed under hate and shame so persistent it feels designed to destroy — the speaker moves through denial and isolation but cannot escape the weight that chips away at everything he loves.","opus":"A description of being trapped in inescapable inner pain and self-hatred, where crushing hate 'dominates,' promising a premature death, and the only relief comes from releasing one's soul."},"ocean-grove~sunny":{"src":"haiku","haiku":"A depiction of depression masked by external optimism and addiction as coping. The speaker feels dead inside despite the sunny weather, stuck in cycles of intoxication and self-care failure.","sonnet":"A portrait of stagnation and low-grade self-destruction — waking late, sinking into the carpet, craving a thrill — where the sunny world outside contrasts with an interior state too numb to climb out of.","opus":"A song about numbness and addiction under a deceptively bright surface, where the speaker feels stalled and doubtful, tries to get sober, and admits that nothing is enough to pull him up even as it looks sunny outside."},"puddle-of-mudd~out-of-my-head":{"src":"haiku","haiku":"A song about elevated consciousness and rejection of peer influence. The speaker refuses to be held down by those around him and feels superior to their moral compromises.","sonnet":"A sense of alienation from a social circle the speaker sees as hypocritical, paired with an elevated, almost manic self-assurance — he feels higher than the people around him and refuses to let them hold him back.","opus":"An account of alienation from hypocritical friends and a spinning, out-of-control mind, with the speaker feeling superior and detached, insisting these people aren't really his friends and refusing to let go."},"make-them-suffer~fireworks":{"src":"haiku","haiku":"A narrative of leaving behind a life to start anew with someone, burning the past and watching it illuminate. The speaker seeks freedom through destruction and shared transformation with a partner.","sonnet":"A reconciliation and shared act of burning the past down together, two people choosing to start over — sailing east, watching the flames, and finally heading home.","opus":"A song of departure and defiant devotion, in which the speaker leaves to make things right and imagines burning everything down alongside a loved one, watching the flames like fireworks in the hope of being sent home."},"pro8l3m~styl-sportowy":{"src":"haiku","haiku":"A Polish-language rap celebrating hedonistic street culture, money, drugs, and casual sexual encounters. The speaker flaunts material excess and dismisses judgment or accountability.","sonnet":"A nocturnal brag track set in Warsaw club culture — denial of witnessing anything, nights spent with women, no-sleep mornings, expensive cars and clothes — projecting cool indifference to consequences while cataloguing lifestyle excess.","opus":"A Polish rap flaunting an angry, aggressive lifestyle of money, brand names, violence, drugs, women, and denial, with the narrator repeatedly claiming he saw nothing and knows nothing while boasting of his sporty style and two houses."},"serj-tankian~money":{"src":"haiku","haiku":"A critique of money's tyrannical grip over human desires and autonomy. The song frames financial obsession as the root of servitude and dysfunction in modern society.","sonnet":"A critique of money as a system of servitude and dysfunction, trapping people in obsessive accumulation and stripping them of autonomy — the speaker traces his own ineptitude and submission back to its tyranny.","opus":"A caustic critique of greed, chanting the obsessive hoarding and worship of money and tracing human ineptitude and servitude back to the tyranny of money itself."},"dream-theater~caught-in-a-web":{"src":"haiku","haiku":"A narrative of emotional entanglement and deception within a relationship. The speaker is trapped, spinning lies to hide desire while fearing that authenticity isolates them.","sonnet":"A person isolated from the world and trapped in self-deception, spinning lies in their own head, unable to share the dance of life with anyone or have their inner wounds healed by others.","opus":"A portrait of someone trapped and isolated by their own lies and inner deceptions, spinning webs in their head, torn between watching another's hidden pain and confronting wounds of the soul that can't be healed."},"bloodhound-gang~fire-water-burn":{"src":"haiku","haiku":"A satirical hip-hop track built on absurdist humor and juvenile boasts. The speaker uses exaggeration and pop-culture references to undermine any coherent message or meaning.","sonnet":"A comic, self-deprecating party rap built around the 'roof is on fire' chant, in which the narrator mocks himself as a 'dumb white guy' posing as a hardcore rapper and jokes about his own inadequacy in a string of crude, absurdist boasts.","opus":"A raucous party song built around the 'roof is on fire' chant, packed with crude, self-deprecating jokes and pop-culture name-drops as the narrator brags about himself and eggs the crowd on."},"linkin-park~part-of-me":{"src":"haiku","haiku":"A song about psychological integration and the struggle to accept and transform one's painful past. The speaker learns that freedom comes from integrating shadow parts rather than cutting them away.","sonnet":"A struggle to excise a destructive inner force — something that causes ongoing self-harm and self-disgust — balanced against the terrifying possibility of freedom if that part of the self is finally cut away.","opus":"A struggle with a self-destructive part of the self that won't go away, marked by cutting imagery and self-loathing, and the hard, frightening work of cutting free and finding peace by removing the broken parts."},"tool~parabola":{"src":"haiku","haiku":"A meditation on mortality and embodiment as a path to understanding eternity. The speaker frames bodily pain and suffering as illusion, emphasizing presence and the gift of being alive.","sonnet":"A meditation on the sacred nature of physical existence: pain is an illusion, the body is a reminder that we are not alone, and being alive in this moment is itself a holy gift worth celebrating.","opus":"A meditation on presence and mortality, celebrating the body and the fleeting chance to be alive and breathing in this moment, reframing pain as an illusion and existence as a holy, eternal gift."},"tesseract~king":{"src":"haiku","haiku":"A critique of authoritarianism and tyranny masked as strength. The song condemns the 'king' figure who uses revenge and words to control and destroy, demanding coexistence without submission.","sonnet":"A reckoning with a domineering, totalitarian figure — a 'king' who demands submission, weaponises words, massacres others' dreams, and suppresses individuality — with the subjects beginning to push back.","opus":"A confrontation with a tyrannical, all-consuming figure crowned 'king,' condemning their vengeance and control, calling to strip away their power and demanding freedom to simply be oneself and coexist again."},"northlane~clockwork":{"src":"haiku","haiku":"A portrait of burnout and creative emptiness where the speaker runs on fumes and fear of failure. Time is running out, energy is depleted, and the dream risks derailment by internal sabotage.","sonnet":"A confession of creative paralysis and self-sabotage — an inner voice insisting the speaker is inferior and destined to fail — with a desperate plea for someone to help him see through the clouds before time runs out entirely.","opus":"A song about running out of time, creative paralysis, and self-doubt, where the speaker feels inferior and empty, fears he's destined to fail, yet keeps searching for a reason to go on and 'see the rainbow.'"},"ocean-grove~sense-again":{"src":"haiku","haiku":"Reclaiming mental clarity and rejecting passive acceptance of labels and lies; finding authentic self beyond what society imposes.","sonnet":"A speaker reclaims clarity and self-awareness after losing themselves to conformity and outside pressure, rejecting labels and passive groupthink while admitting an internal struggle between wanting to destroy and wanting to simply be oneself.","opus":"A defiant break from a generation of conformity and empty labels, where the speaker regains clarity and 'finds his senses again' while wrestling with a self-destructive urge to hurt himself and just be no one else."},"a-perfect-circle~weak-and-powerless":{"src":"haiku","haiku":"Complete helplessness and desperation in the face of another's control; willing to make any compromise just to avoid the crushing feeling of surrender.","sonnet":"The song depicts obsessive, addictive desire for someone — the speaker digs ever deeper toward numbness, dismissing both angelic and devilish counsel, all in search of relief from the desperate craving that one person over whom they feel completely powerless.","opus":"Addiction and helpless obsession, told through images of digging one's own grave and chasing a fix; the speaker feels desperate, ravenous, and powerless over another person, letting the devil promise him solace so he won't feel."},"acid-drinkers~what-s-happenin-in-the-heart-of-a-pacifist":{"src":"haiku","haiku":"The internal turmoil of someone committed to nonviolence but conscious of injustice and enemies around them; the toll of pacifist principle on the heart.","sonnet":"The speaker insists that truly knowing peace means remaining fully human — able to see, hear, and feel — and asks what it costs a pacifist to stay aware of enemies and violence rather than blinding themselves to the world.","opus":"The impossibility of true pacifism: the speaker argues he'd have to be blind, deaf, and senseless to stay 'safe' and ignore an enemy, but then he wouldn't be human, and he questions what really goes on in a pacifist's heart."},"tv-on-the-radio~staring-at-the-sun":{"src":"haiku","haiku":"Transcendence and physical dissolution; bodies merging as consciousness confronts annihilation through an overwhelming force.","sonnet":"A figure is overwhelmed by an intense, possibly doomed connection — water rising to the neck, lightning in the teeth, the body consumed — while a voice observes that all human weariness is shared, urging surrender to the moment even at the cost of going under.","opus":"A person overwhelmed and drowning, staring at the sun and standing in the sea while their own voice can't save them; it dwells on mortality, the temporary nature of the body, and surrendering to something vast and consuming."},"novelists-fr~do-you-really-wanna-know":{"src":"haiku","haiku":"The void inside hidden by a normal appearance; enslaved by internal emptiness and asking if anyone truly wants to see the darkness beneath.","sonnet":"The speaker hides an inner void from everyone around them, feeling enslaved by their own inability to heal or change, and wonders whether anyone really wants to see the emptiness inside that lies beneath the surface they present to the world.","opus":"The hidden emptiness behind a person who hides in plain sight, feeling dead inside and enslaved to a void; he doubts anyone really wants to see his inner self and pleads to know who will set him free."},"serj-tankian~feed-us":{"src":"haiku","haiku":"Leaders deceiving and disposing of their people with lies; the dying world as humanity grows spiritually numb to the destruction.","sonnet":"The song accuses an unnamed authority of feeding people lies, exploiting them when useful and discarding them when not, while warning that the world is dying and the chance to save it has already been squandered through deception.","opus":"An accusation against those in power who exploit, kill, and deceive people while feeding them lies, tied to imagery of a dying world and a squandered chance to save 'the garden' before it's too late."},"crystal-castles~year-of-silence":{"src":"haiku","haiku":"Intimate moments of connection and grief; a beloved person and shared breathing and kissing through tears and sadness.","sonnet":"Icelandic lyrics repeat images of bad behavior and weeping in an embrace — \"badly behaved, crying in arms, when we met, when we kissed\" — alongside lines about swallowing tears and breathing hair for a best friend, conveying a cycle of troubled intimacy and grief shared between two people.","opus":"An Icelandic refrain of embracing and weeping in each other's arms when the lovers meet and kiss, addressed to a dearest friend, with the singer swallowing tears and breathing in the other's hair; a mood of tender, sorrowful closeness."},"slipknot~all-out-life":{"src":"haiku","haiku":"Rejecting mediocrity and false worth; demanding authentic living and refusing to accept predictable, commercialized existence.","sonnet":"A rejection of mediocrity and cultural fakery — the speaker demands that listeners refuse empty entertainment, empty idols, and the idea that age equals irrelevance, calling for full engagement with life rather than passive consumption.","opus":"A rallying rejection of mediocrity and conformity, insisting old doesn't mean dead and new doesn't mean best; the speaker refuses to worship empty shells or sell his attention, declaring 'we are not your kind' and challenging the listener to all-out life."},"type-o-negative~creepy-green-light":{"src":"haiku","haiku":"Death, obsession, and resurrection; waiting in a grave for a lover to rise and return from the underworld.","sonnet":"On Halloween, a grieving lover lies drunk on his dead beloved's grave, waiting for her to rise from beneath the soil, drawn toward the eerie green light that marks her supernatural return to him.","opus":"A grieving lover lies drunk on his dead beloved's grave, waiting for her to rise; guided by an eerie green light and her final words not to be afraid, he feels drawn into her shadowy realm to join her in death."},"gojira~stranded":{"src":"haiku","haiku":"Isolation and internal sickness; feeling locked out and abandoned while another person's indifference slowly kills.","sonnet":"A person trapped in emotional and psychological darkness pleads not to be shut out by someone close to them, feeling that being locked away would be fatal — each passing day in isolation leaves another part of them wasted.","opus":"A sickness in the heart and a mind crushed by inner noise, with the speaker feeling abandoned, stranded in the cold and dark, and pleading not to be shut out by someone whose rejection feels like death."},"taconafide~tamagotchi":{"src":"haiku","haiku":"Life reduced to cycles of eating, drinking, sleeping like a digital pet; searching for love and meaning amid shallow consumption and loneliness.","sonnet":"A Polish rapper compares his generation's hollow routine — eat, sleep, drink, scroll through phones — to caring for a Tamagotchi, while also describing his own isolation, creative burnout, and longing for a woman who has grown tired of him.","opus":"A restless, disillusioned life of fame, drink, and isolation where the narrator reduces existence to eat, drink, sleep like a Tamagotchi; he longs for a woman who's tired of him, feels emptiness amid smog, hotels, and dating apps, and wonders whether love can be ordered like takeout."},"nine-inch-nails~home-bonus-track":{"src":"haiku","haiku":"Trapped inside another person; trying to escape but always returning, unable to break the tie that binds.","sonnet":"A speaker is trapped in a relationship or psychological bond they cannot escape — repeatedly returning despite efforts to break free, uncertain of what is real, and feeling that another person has fundamentally altered or consumed their sense of self.","opus":"Disorientation and loss of self, where everything catches up with the speaker and he can't tell what's real; despite trying to break free, he keeps returning to a person who is the only place he's ever felt he belongs."},"megadeth~tornado-of-souls":{"src":"haiku","haiku":"Breaking free from a toxic relationship and finding refuge in solitude; the lies that sustained it now exposed.","sonnet":"The song moves through a painful breakup — the speaker makes the decisive call to end things, finding strange calm in being free from a destructive relationship, then shifts to the perspective of a poison voice that promises to haunt and fill the mind of the one left behind.","opus":"Ending a destructive relationship, framed as making the call that ends it all and finding calm in the eye of a tornado; it turns from relief at escaping the lies to a bitter, vengeful farewell delivered as a 'kiss of death.'"},"gorillaz~kids-with-guns":{"src":"haiku","haiku":"Youth as weapons; desire and impulse turning young people into instruments of force and consumption.","sonnet":"Children armed with weapons are taking over, shaped by forces that strip them of innocence and turn them into instruments of desire and violence, while a frightened voice pleads not to be killed in the chaos they have been made to embody.","opus":"Children armed and 'taking over,' mesmerized and turned into monsters by desire; it warns of youthful violence and lost innocence as the kids are pushed toward destruction."},"how-to-destroy-angels~the-space-in-between":{"src":"haiku","haiku":"Intimate exposure under harsh light; things hidden revealed and the boundaries between people collapsing into visible decay.","sonnet":"Two people have laid their hidden selves bare — blood on the floor, secrets exposed — and even as their story draws to a close, what could not be destroyed remains visible in each other's eyes, with hate beginning to bleed into the frame.","opus":"A relationship exposed like a staged scene, with blood on the floor and a crowd watching what the couple tried to hide; as the narrative draws to a close, lingering hate and unkillable things spill out while they try to fill the emptiness between them."},"marilyn-manson~mobscene":{"src":"haiku","haiku":"Society as spectacle and transgression; freedom through obscenity and descent into shared debasement.","sonnet":"A provocateur invites the audience into a spectacle of deliberate obscenity, framing transgression and excess as more honest than respectable society's freedoms, and urging everyone to embrace visibility and degradation rather than politely staying silent.","opus":"A provocative spectacle presented as a show more obscene and thrilling than sex, staged in a decayed 'Deformation Age'; it revels in shock, sin, war, drugs, and the demand to 'be obscene' before a hungry crowd."},"mortal-sin~lebanon":{"src":"haiku","haiku":"War in Lebanon; brutal combat with graphic depictions of violence, bloodshed, and soldiers' struggle to survive.","sonnet":"The song depicts the Lebanese civil war as a scene of relentless urban combat — machine-gun fire, trenches, religious factions, suicide attacks, and civilian casualties — cataloguing the destruction without taking sides.","opus":"The horror of war in Lebanon, depicting bombs, machine-gun fire, and bloodshed as Muslims and Christians fight, with massacres and defenseless children caught in the destruction."},"slayer~bloodline":{"src":"haiku","haiku":"Vampiric immortality through feeding on others' life and bloodline; eternal predation and defiance of god.","sonnet":"Narrated by a vampire, the song describes feeding on human blood to sustain immortality — the speaker was condemned by a single kiss, defies God, stalks prey, and demands the victim's bloodline to fuel another thousand years of reign.","opus":"A vampiric predator who feeds on blood to live forever, killing to renew his youth and condemning his victims; he boasts of defying God, contaminating the world, and reigning immortal for a thousand years."},"queens-of-the-stone-age~feel-good-hit-of-the-summer":{"src":"haiku","haiku":"A rapid-fire recitation of drugs and controlled substances—nicotine, Valium, Vicodin, marijuana, ecstasy, alcohol, and cocaine—presented as a ritualistic litany without narrative or judgment.","sonnet":"The lyrics consist almost entirely of a repeated list of substances — nicotine, Valium, Vicodin, marijuana, ecstasy, alcohol, cocaine — with no additional narrative, functioning as a blunt inventory of intoxicants.","opus":"A blunt litany of drugs, listing nicotine, Valium, Vicodin, marijuana, ecstasy, alcohol, and cocaine over and over; the substances themselves are the entire subject."},"nine-inch-nails~all-the-love-in-the-world":{"src":"haiku","haiku":"Invisible and alone despite being surrounded; one person receives all love while the narrator remains unseen and forgotten.","sonnet":"A lonely outsider watches others move with purpose and belonging, feeling invisible and unheard, and asks with mounting anguish why connection and warmth seem to flow to everyone else while leaving them stranded.","opus":"Alienation and jealousy: the speaker feels invisible in a crowd, unheard, and stuck in the past, yet brightened when a certain person is near, repeatedly demanding to know why that person gets all the love in the world."},"tesseract~juno":{"src":"haiku","haiku":"Falling from grace and burning; judgment and self-destruction with imagery of wreckage and fire.","sonnet":"A speaker in freefall — burning wings, nosediving through the wreckage of their life — pleads for someone to reveal themselves and offer salvation as all illusions of dignity and purpose collapse around them.","opus":"A fiery self-destruction and reckoning, with the speaker nosediving in flames through the wreckage of his life while facing judgment; amid delusion and damage, he pleads for someone to reveal and save themselves for him."},"muse~map-of-the-problematique":{"src":"haiku","haiku":"Despair, isolation, and human failure to see shared suffering; loneliness as an endless condition.","sonnet":"Loneliness and despair tighten their grip since meeting someone who offered relief but has left the speaker unable to get things right, with flashes of life's brevity underscoring a desperate wish for the isolation to end.","opus":"Fear, panic, and crushing loneliness, with the speaker desperate to escape despair and refusing to let someone go; he insists that beneath our differences 'when we bleed we bleed the same.'"},"filter~so-i-quit":{"src":"haiku","haiku":"Rejecting a hypocritical situation and quitting; fed up with fakeness and choosing to walk away.","sonnet":"The speaker severs a relationship they view as cheap and degrading, moving from bitter contempt to an explosive threat, and declares the break final.","opus":"A furious kiss-off to a partner treated as a 'legal' possession and likened to a common whore, whom the speaker walks away from with rage and threats when they try to take something from him."},"the-brave~desolation":{"src":"haiku","haiku":"Physical and psychological breakdown in a barren wasteland; thirst, hallucinations, and numbness as death approaches.","sonnet":"A traveler lost in a scorching desert, circled by vultures, hallucinates and drinks venom out of desperation, teetering on the edge of death — the landscape serves as both literal setting and an image of total desolation and physical collapse.","opus":"A hallucinatory ordeal of being lost in a desert, dying of thirst as vultures circle; pushed to the brink, the speaker drinks venom, hallucinates, and feels a hellish desolation running through his veins."},"filter~hey-man-nice-shot":{"src":"haiku","haiku":"Respect for someone's final act of defiance through suicide; witnessing their strength in ending their struggle.","sonnet":"The speaker addresses someone who chose a public self-destruction that those in power could not stop, expressing regret at never having met them and a kind of grim admiration for someone who resisted a system that was too strong.","opus":"An address to someone who took their own life with a gun, mixing regret at never meeting them with a grim, sardonic 'nice shot'; it observes how others who judged the act only grew stronger and more fearful afterward."},"alice-in-chains~breath-on-a-window":{"src":"haiku","haiku":"Loneliness and invisibility; haunting someone from a distance, a ghost present in their world but unacknowledged.","sonnet":"A driver moves through empty, blighted roads carrying the weight of a past relationship that lingers like a scar — the narrator cannot shed the other person, who remains the damage already done, even as the journey pushes forward into strange terrain.","opus":"A lonely, ghostly journey down an empty highway, feeling invisible and hollow ('there ain't nobody home'); it turns to a damaging bond with someone always in the way, whom the speaker calls the scar and damage he can't leave behind."},"type-o-negative~everyone-i-love-is-dead":{"src":"haiku","haiku":"Repeated loss and grief over everyone close dying; using alcohol and disdain to mask the pain of serial mourning.","sonnet":"The speaker confronts accumulated grief as the people they have loved die one by one, finding that alcohol and drugs mask rather than heal the loss, and arriving at a bitter, darkly self-aware accounting of survival and what it costs.","opus":"Grief and despair over losing loved ones one after another, where every love brings the 'kiss of death'; the speaker admits drink and dope only mask the hurt and bitterly concludes everyone he loves is dead."},"annihilator~syn-kill-1":{"src":"haiku","haiku":"Terrorism and violent revolutionary action; assassination, kidnapping, and bombing as tools of ideological warfare.","sonnet":"Voiced as a terrorist or political assassin, the song lays out a campaign of kidnapping, murder, bombing, and intimidation carried out in the name of a cause — the speaker justifies the killing of innocents through ideology and the pursuit of power.","opus":"A terrorist's chilling first-person boast of killing for god and power and for propaganda's sake, justifying kidnap, murder, arson, and bombing while threatening a targeted victim with death."},"megadeth~tout-le-monde-set-me-free":{"src":"haiku","haiku":"Final goodbye before death; the last words are a farewell to everyone, and dying is freedom.","sonnet":"A farewell note from someone at the end of their life — they look back on plans left unfulfilled, ask friends to smile rather than mourn, and bid goodbye in French and English, finding release in the act of letting go.","opus":"A dying person's farewell to friends, realizing too late how little they accomplished; they ask loved ones to smile when remembering them, saying these final words, including a French address to everyone they love, will set them free."},"nine-inch-nails~in-two":{"src":"haiku","haiku":"Identity fracturing into two selves; unable to tell which version is real as one consumes the other.","sonnet":"A person is splitting into two irreconcilable versions of themselves — one urges violent self-renewal through shedding the old skin, the other denies responsibility — until neither can remember which one they originally were.","opus":"A violent splitting of the self, urging one to shed their skin and become their disease; the speaker can no longer tell his two halves apart and admits he just doesn't know who he is anymore."},"ocean-grove~stratosphere-love":{"src":"haiku","haiku":"Sacrifice and prayer within intimate connection; a piece slowly dying and both partners praying through cold exchanges.","sonnet":"The speaker is slowly coming apart trying to hold a relationship together, feeling the other person's indifference like cold grace thrown at their feet, and asking whether the connection — physical and emotional — is still mutual.","opus":"A piece of the speaker is slowly dying as he prays to make it through a strained, cold intimacy; he clings to the grace and desire thrown at his feet, urging the other to feel the pleasure and admit they're 'with it.'"},"acid-drinkers~fuel-of-my-soul":{"src":"haiku","haiku":"Alcohol and transgression as life force; indulgence and excess fueling existence through the night.","sonnet":"The speaker assembles an eclectic, rowdy gathering — poets, drunks, jailbirds, a dancing queen — and declares alcohol and raucous company the fuel that fills the emptiness and keeps him going through long sleepless nights.","opus":"A raucous celebration of drinking and revelry, summoning drunkards and poets, calling for booze and hamburgers, kicking out the abstainers, and fueling the soul through a hundred sleepless nights of indulgence."},"limp-bizkit~sour":{"src":"haiku","haiku":"A relationship soured from sweetness to betrayal; manipulated and used, finally breaking free from toxic connection.","sonnet":"The speaker unloads resentment at an ex who used and verbally abused them, swings between anger at her and self-blame for staying too long, and ultimately decides the relationship is over even if the bitterness lingers.","opus":"A bitter breakup, where the speaker regrets pouring his love and pride into a partner who used and abused him; he cuts her loose, calling her fake and worthless, while admitting his own anger and taking some blame."},"filter~under":{"src":"haiku","haiku":"A descent into private possession and escape, where the speaker claims absolute ownership of their world and invites surrender into a state of bliss beneath or beyond everyday reality.","sonnet":"The speaker claims ownership of their own world and recommends surrendering to numbness — going under, swallowing something, sinking into bliss — as a coping strategy, while rejecting anyone else's problems as irrelevant to them.","opus":"A defiant, sneering assertion of ownership over one's own world, taunting someone who thinks they have it bad while inviting them to 'go under' and escape into a numbing bliss the speaker controls."},"raubtier~achtung-panzer":{"src":"haiku","haiku":"Tank warfare and military destruction; metal beasts bringing death and violent devastation across burning ground.","sonnet":"A Swedish industrial metal song glorifying the tank as an instrument of war — steel storms, diesel veins, blood-sweating pores, and armored battalions dominate the battlefield in tight formations, with destruction framed as an overwhelming force of nature.","opus":"A Swedish martial ode to armored tanks as beasts of war, with veins pumping diesel and pores sweating blood; the tanks roll out in tight formations, burning the ground and bringing thunderous, fiery death across the battle zone."},"rammstein~benzin":{"src":"haiku","haiku":"Gasoline as metaphor for life energy and violent desire; fuel and explosive potential running through veins.","sonnet":"The speaker declares that gasoline is the only thing they need — not drugs, love, friends, or medicine — treating fuel as an all-consuming obsession that flows through veins and dreams, and insisting that anything to be left behind must be burned.","opus":"A German declaration of craving gasoline above all drugs, friends, or medicine, wanting explosive fuel that runs through the veins; it ends with the idea that to be rid of something forever, you burn it and drown it in petrol."},"the-prodigy~the-day-is-my-enemy":{"src":"haiku","haiku":"Antagonism toward daylight; the night is friend and refuge while day brings hostility.","sonnet":"The lyrics establish a single opposition — the day is hostile, the night is a refuge — with no further development beyond that repeated contrast.","opus":"A stark repeated declaration that daytime is the speaker's enemy and night is his friend, painting a nocturnal mind at odds with the daylight world."},"nevermore~born":{"src":"haiku","haiku":"Religious and social conformity breeding ignorance and spiritual sickness; the legacy of inherited suffering and apathy.","sonnet":"The song condemns organized religion and political authority for breeding ignorance, enforcing conformity, and fostering spiritual sickness and apathy, warning that if nothing changes the next generation will inherit a meaningless world of silence and indifference.","opus":"An indictment of religion and blind obedience, portraying people as pigs ordering conformity and 'thou shalt not think'; it laments spiritual sickness, apathy, and indifference, warning that if nothing changes our children will inherit nothing."},"thornhill~where-we-go-when-we-die":{"src":"haiku","haiku":"Death and loss; questioning what lies beyond and the pain of separation, doubting paradise without the other.","sonnet":"The speaker questions a promised paradise they no longer believe in, watching the world die while others are kept compliant by illusions of freedom, and desperately needing another person to be with them rather than leaving them alone in a world that feels dead.","opus":"A disillusioned meditation on death and a false 'paradise' sold as a lie, questioning what happens when we die; the speaker rejects the promised afterlife and insists life is pointless without being together with the one he needs beside him."},"polaris~vagabond":{"src":"haiku","haiku":"Wandering and homelessness; carrying pain while traveling nowhere feels like home, moving alone through monochrome world.","sonnet":"A restless traveler who has never found anywhere that feels like home encourages someone else facing the same rootlessness to keep moving, promising that even when life has its hands around your throat, you can learn to breathe again.","opus":"A wanderer's reckoning with rootlessness and loss, learning that everything we love we leave behind and that nowhere feels like home; it speaks of surviving fear and hardship, of finding peace in unknown places, and of leaning on another to keep breathing."},"skywalker~charon-s-song":{"src":"haiku","haiku":"Death and crossing into the underworld; Charon's journey across the Styx with only silence and the sound of death.","sonnet":"The speaker grapples with an impending loss — someone crossing the river Styx into death — and finds that grief does not end with moving on; instead, hurt is swallowed and time spirals, while the wish to absorb the dying person's pain remains.","opus":"Facing the death of a loved one through the myth of crossing the Styx into the silent underworld; the speaker dreads the parting, questions who to trust, and reflects that there's no real moving on, only swallowing the hurt and wishing he could eat the other's pain."},"pendulum~self-vs-self-feat-in-flames":{"src":"haiku","haiku":"Internal conflict and struggle to find home within oneself; darkness and fragmentation when identity cannot be located.","sonnet":"A person at war with themselves — unable to find direction, doubting their own reality, and losing their sense of identity — asks how to get home when everything feels fake and even those closest cannot help them find their way.","opus":"An internal war with the self, questioning identity, meaning, and worth; feeling like an empty shell fed on by a demon, the speaker keeps asking how to get home when he can't find himself and everything feels fake."},"anthrax~the-giant":{"src":"haiku","haiku":"Battling an inner giant; self-destruction, contradiction, and endless internal warfare that feeds on itself.","sonnet":"The speaker battles an internal giant — an overwhelming, out-of-control force within — that traps them in a vicious cycle of self-conflict and moral uncertainty, with the struggle framed as both literal combat and a search for the soul.","opus":"A relentless internal struggle personified as a giant the speaker must break down; caught between right and wrong and drowning to find his soul, he vows to keep fighting even when nothing is left."},"onslaught~suicideology":{"src":"haiku","haiku":"Suicide as liberation and escape; the relief of silence and peace through self-destruction and the end of suffering.","sonnet":"Voiced as a predatory, almost supernatural force that feeds on self-destruction, the song catalogues methods of suicide — overdose, blood-letting, immolation, gunshot — and frames the speaker as the embodiment of the suicidal impulse itself, whose own misery ends only through the victim's death.","opus":"A grim, graphic catalogue of suicide and self-destruction, voiced partly by a tormenting force that feeds on the victim's pain and death; it dwells on overdose, bloodletting, asphyxiation, and gunshot as release from misery."},"testament~agony":{"src":"haiku","haiku":"Prisoners of war suffering in endless captivity; fighting and dying slowly with no rescue or end to their agony.","sonnet":"The song depicts prisoners of war or soldiers trapped in prolonged suffering, dying slowly without rescue, and calls on America to free those missing in action who endure endless agony without hope of salvation.","opus":"The suffering of prisoners of war and those missing in action, trapped in endless torment and dying slowly each day, praying to be freed from their agony and asking whether America will ever set them free."},"bring-me-the-horizon~alligator-blood":{"src":"haiku","haiku":"Hidden predatory nature revealed in high-stakes games; deception and the primitive self breaking through the mask.","sonnet":"A confrontation framed as a high-stakes card game — Russian roulette, poker faces, dead man's hands — in which the speaker's cold-blooded nature finally surfaces and the other party is warned that the game has already been lost and they should leave while they can.","opus":"A dangerous relationship played like Russian roulette and a rigged card game of bluffs and secrets; the speaker's cold 'alligator blood' shows as he begs to be torn apart and remade, urging both to quit before it's too late."},"combichrist~throat-full-of-glass":{"src":"haiku","haiku":"Suffocation, numbness, and inward screaming; unable to breathe or speak, burning with internal pain.","sonnet":"Surrounded by judgment and choked by an environment of lies, the speaker feels broken into pieces and unable to express their pain — like screaming with a throat full of glass — drifting between numbness, the wish never to have existed, and the struggle to stay conscious.","opus":"Suffocating pain, numbness, and self-loathing under others' judgment, where the speaker feels perpetually in the wrong and burning alive; his life shattered into pieces, he finds it impossible to scream 'with a throat full of glass' or breathe the poisoned, lie-filled air."},"bring-me-the-horizon~sleepwalking":{"src":"haiku","haiku":"A person struggling with suffocation and emotional paralysis, feeling trapped in a recurring cycle of despair as though moving through life without consciousness, begging for rescue.","sonnet":"A person describes feeling trapped in a dissociated, drifting state — cut off from their own body, overwhelmed by secrets and inner pain — and pleads to be pulled back to a reason to keep going.","opus":"A person feels numbed and suffocated, unable to breathe and cut off from the world as if trapped in a waking dream, begging someone to pull them out and give them a reason to start over."},"pendulum~hold-your-colour":{"src":"haiku","haiku":"A call to preserve one's identity and values against overwhelming forces that seek to strip everything away; maintaining personal integrity when threatened with erasure.","sonnet":"Someone urges another to hold their identity firm when everything is being stripped away, while a separate voice describes a woman who saw through a person's surface and declared the cycle complete, leaving no escape.","opus":"Over hypnotic repetition, the song urges someone to hold their ground against everything being stripped away, framed by a menacing figure who twists a knife to force another's eyes open and completes a fatal circle."},"a-perfect-circle~the-hollow":{"src":"haiku","haiku":"Sexual desire and excess as a futile attempt to fill an internal void, driven by appetite that can only be temporarily pacified rather than permanently satisfied.","sonnet":"The song describes a person driven entirely by unchecked sexual desire — an insatiable hunger that consumes and cycles through indiscretion — until a call to bridle that drive and fill the emptiness with something lasting.","opus":"An examination of insatiable desire and appetite, where a hollow emptiness screams to be fed and temporarily pacified, driving cycles of consuming and indiscretion that never truly fill it."},"the-prodigy~colours":{"src":"haiku","haiku":"A rallying cry to display defiance and readiness for conflict, framing visible personal identity as an act of war preparation.","sonnet":"A rallying cry for conflict and allegiance: listeners are called to raise their banner, show their true colours, and declare whose side they are on as a confrontation builds.","opus":"A charged call to arms that rouses a crowd for confrontation, urging people to show their colours and bring them to the floor amid sirens, fighting dogs, and the readiness for war."},"black-light-burns~mesopotamia":{"src":"haiku","haiku":"Mesopotamia (ancient Babylon) is personified as a menacing force that disturbs and threatens the speaker, who faces death and feels weaponized violence directed at him.","sonnet":"A speaker addresses a city — Mesopotamia — with a mix of dread and compulsion, describing a destructive relationship that mirrors the city's endless cycle of burning and rebuilding, with the narrator trapped between wanting out and wanting to stay.","opus":"Using a city that repeatedly burns and is rebuilt as its image, the song channels revulsion and betrayal toward someone who wounds the speaker even while he says he'd give everything just to be with them."},"linkin-park~runaway":{"src":"haiku","haiku":"A person accused and blamed for circumstances beyond his control seeks escape and truth, desperate to understand why he bears guilt and yearning to break free from false accusations.","sonnet":"Someone living under broken trust, false lessons, and constant blame fantasises about escaping it all — running away, finding truth, shutting out the noise, and clearing their mind.","opus":"Weighed down by broken trust, blame, and lies, the speaker wants to escape it all and find the truth, longing to shut the door and open up his mind rather than keep being accused."},"slipknot~before-i-forget":{"src":"haiku","haiku":"The speaker claims primal identity before human form and warns against forgetting one's essence before it vanishes, reflecting on delay and evasion as life strategies.","sonnet":"The narrator asserts a primal, pre-human identity — existing as a creature before a man — while wrestling with a sense of being smeared across chaos, perpetually delaying a reckoning, and determined to remember who he is before losing himself entirely.","opus":"A claustrophobic, defiant declaration of self, where the speaker feels sealed in and exposed while insisting he is a world and a creature before he is a man, and that his ends justify his means."},"limp-bizkit~the-one":{"src":"haiku","haiku":"A lonely man searching for romantic connection hopes a potential partner could be 'the one,' acknowledging that chemistry and commitment require genuine effort and chance-taking.","sonnet":"A lonely person, worn down by failed searches for connection, wonders whether the person in front of them could finally be the right match — acknowledging uncertainty while clinging to the possibility.","opus":"Out of loneliness and misery, the speaker hopes a particular person could be the one for him, weighing whether they might be soulmates and pleading with them to stay."},"hyper~lies":{"src":"haiku","haiku":"Confronts someone with an accusation of deception, asserting that everything they do reveals the truth they're trying to hide.","sonnet":"A fragmented accusation directed at someone whose deception is self-evident: the speaker insists the person knows the truth of what they have done, reducing the charge to a relentless, chopped repetition of that knowledge.","opus":"Built almost entirely from fragmented repetition, the song accuses someone of bluffing, insisting they know the truth about everything they do."},"artillery~the-end":{"src":"haiku","haiku":"A meditation on mortality, watching the world's destruction while accepting that apocalypse is inevitable and near, driven by internal hatred and external burning.","sonnet":"A figure watches a world consumed by hatred, fear, and apocalyptic signs — blood-red skies, inner war, voices screaming in the dark — and concludes that the end is near and inescapable.","opus":"Facing mortality and a world consumed by fear, hatred, and fire, the speaker watches everything he loves head toward death and warns that the end is near."},"type-o-negative~less-than-zero-0":{"src":"haiku","haiku":"A person views himself as worthless and inhuman, made only of bodily waste and corruption, questioning God's love while condemning mankind as inferior and cursed.","sonnet":"A bitter self-portrait: the speaker catalogues his own worthlessness in grotesque bodily terms, mocks any notion of a heroic self, and declares that those around him are all willing participants in their own suffering.","opus":"A bleak, self-loathing meditation on being made of filth and decay, questioning why God won't grant release and casting suffering as a punishment that its victims volunteered for."},"nevermore~final-product":{"src":"haiku","haiku":"A critique of how media exploits tragedy for profit, examining a world ravaged by religious and political violence, where survival in decay becomes the final human product.","sonnet":"A broadside against a world in moral and civilisational decay — media that profits from suicide, religious and governmental violence that starves the innocent, and the creeping certainty of Armageddon — summed up as the inevitable final product of human hatred.","opus":"A condemnation of a decaying world, attacking media that profits from tragedy and religions and governments that let the innocent die, leaving a lone survivor questioning how anyone endures."},"megadeth~five-magics":{"src":"haiku","haiku":"A wizard seeks mastery over five magical disciplines—alchemy, wizardry, sorcery, thermatology, and electricity—to overthrow tyranny and defeat a supernatural adversary.","sonnet":"A student of the arcane seeks initiation from an all-knowing wizard, asking to master five magical disciplines — alchemy, wizardry, sorcery, thermatology, electricity — in order to overthrow a tyrannical ruler and dominate all rivals.","opus":"A fantasy narrative in which a would-be ruler seeks arcane knowledge from a wizard and vows to master five magics to seize a kingdom, hunting an abyss lord in a deadly contest where only one survives."},"stone-sour~through-glass":{"src":"haiku","haiku":"Separation and observation from behind barriers create emotional distance; the speaker watches someone through glass, isolated and waiting, reflecting on manufactured reality versus authenticity.","sonnet":"The speaker observes a world that has become hollow and performative — people reduced to mannequins, emotion folded away like paper — and reflects on the alienation of watching life from the outside, separated from genuine feeling.","opus":"A sense of isolation and detachment, watching others from behind glass while feeling unseen and reduced, insisting that what they stare at is really him and that even the stars can lie."},"bring-me-the-horizon~home-sweet-hole":{"src":"haiku","haiku":"A person trapped in self-deception and harmful patterns confesses to crossing moral lines repeatedly until the boundaries blur, warning about the dangers of spoken and unspoken lies.","sonnet":"Someone repeatedly crosses lines and digs deeper into self-destructive behaviour, recognising that their own lies are a noose around their neck and that the comfortable, familiar hole they keep falling into is of their own making.","opus":"A person struggles with self-destruction and self-deception, recognizing a devil that looks just like him and repeatedly crossing lines until the truth spills out and lies tighten like a noose."},"machine-head~left-unfinished":{"src":"haiku","haiku":"A man abandoned by his biological parents channels his pain into love, vowing to live opposite to their cruelty while expressing rage at their rejection and disappearance.","sonnet":"A direct address to biological parents who abandoned the narrator: raw fury at their neglect is matched by gratitude toward the parents who actually raised him, and a vow to live the opposite of what his birth parents were.","opus":"A furious address to abandoning birth parents, contrasting the love of the parents who raised him with rage at those who left, and vowing to live the opposite of what they were and to love the unwanted."},"linkin-park~keys-to-the-kingdom":{"src":"haiku","haiku":"A speaker admits to self-sabotage, throwing away control and kingdom keys into an inner abyss, unable to stop destroying everything he encounters.","sonnet":"The narrator describes surrendering control of his own life — throwing away the keys to his kingdom through self-destructive choices — while also asserting defiant lyrical dominance against anyone who challenges him.","opus":"A portrait of self-sabotage and futility, where the speaker throws away his own chances and fights pointless battles, mixed with defiant boasting and a warning to be careful what you aim at."},"nine-inch-nails~piggy":{"src":"haiku","haiku":"Betrayal and abandonment from someone close leave the speaker broken and indifferent to consequences, repeating a refrain of hopeless detachment.","sonnet":"The speaker addresses someone who abandoned him, leaving him broken and alone, and finds that the loss and betrayal have pushed him past caring — arriving at a hollow, damaged indifference rather than recovery.","opus":"Addressed to a person derisively called a pig, the song voices the pain of being left broken and alone by them, hardening into a numb, reckless refrain of no longer caring."},"tool~hooker-with-a-penis":{"src":"haiku","haiku":"A musician addresses a young fan's accusations of selling out, pointing out that selling exists at every level of society—producer and consumer alike participate in commercialism.","sonnet":"The narrator confronts a fan who accuses the band of selling out, turning the accusation back: everyone participates in the same commercial system, and buying the record makes the accuser equally complicit.","opus":"A scornful reply to a fan accusing the band of selling out, arguing that everyone is complicit in commerce and that the accuser bought the very product he condemns."},"carcass~arbeit-macht-fleisch":{"src":"haiku","haiku":"Industrial machinery and forced labor grind workers to raw material in an endless cycle; bodies become interchangeable parts sacrificed to systems of power ('work makes flesh').","sonnet":"Industrial machinery is used as a sustained metaphor for the grinding exploitation of labour: workers are reduced to raw material — flesh pulped, consumed, and discarded — with the Nazi slogan \"Arbeit macht frei\" twisted into \"Arbeit macht Fleisch\" (work makes flesh/meat).","opus":"A visceral depiction of humans ground up by industrial machinery, reducing people to raw material and flesh fed into furnaces, invoking the Nazi camp slogan 'Arbeit macht frei' to frame labor as dehumanizing slaughter."},"the-prodigy~rok-weiler":{"src":"haiku","haiku":"A predatory figure prowls through streets at night hunting victims, presenting a threatening and menacing presence.","sonnet":"A predatory figure prowls alleys at night, biting at heels — presenting itself as feral, dangerous, and unstoppable, like the dog breed the title names.","opus":"Built on a chanted refrain and a warning to watch yourself, the song evokes a menacing, predatory figure stalking an alleyway at night, biting at heels like an attack dog."},"arch-enemy~nemesis":{"src":"haiku","haiku":"A united legion of rebels fights against systemic hypocrisy and oppression, embodying anarchic resistance and collective strength.","sonnet":"A collective of the oppressed declares itself a revolutionary force — united, anarchic, anti-system — and calls for freedom and the destruction of hypocrisy under the banner of Nemesis.","opus":"A collective anthem of rebellion, casting the group as an avenging legion fighting for freedom, crushing hypocrisy and the system while insisting all blood runs the same."},"raubtier~kamphund":{"src":"haiku","haiku":"A battle hound (kamphund) embodies the predatory nature forced by hardship and wilderness; hunger drives wolves to violence and hunting—a dark reminder of mankind's fragility.","sonnet":"The Swedish lyrics use the image of a fighting dog and a wolf pack led by an alpha to explore themes of hunger, hardness, and survival: harsh conditions demand toughness, the weak cannot keep up, and nature's law is the only law that matters.","opus":"In Swedish, the song likens a warrior to a fighting dog and a wolf pack led by its alpha, where hunger and hardship drive predators to savagery, and warns of a dark truth in the wolf's song that reminds man of his own weakness and downfall."},"toronto-is-broken~reminisce":{"src":"haiku","haiku":"A reggae reflection on aging and life's changes; the speaker recalls childhood games and penny spending, now exchanging pounds for marijuana as adulthood brings different values.","sonnet":"A man looks back on growing up and the gap between boyhood — spending pocket money, playing freely — and manhood, where habits and spending have changed, reflecting on how much has shifted since youth.","opus":"Sung in patois, the speaker looks back on growing up, contrasting the small pleasures of boyhood with the concerns of manhood, insisting he knows in his heart it's true, amid warnings about violence and gunplay when hard times come."},"enmy~damn":{"src":"haiku","haiku":"Despair and loss of purpose drive the speaker through cycles of blind living and self-deception until confronting harsh truths and the decay of toxic relationships.","sonnet":"Someone trapped in a destructive relationship driven by lies and self-serving pride has reached a breaking point, losing the will to continue while still searching, uncertainly, for something better.","opus":"Trapped in a life poisoned by someone's lies and selfish pride, the speaker has lost the will to go on and pours it into a song, searching for answers before he loses his mind."},"celldweller~breakout":{"src":"haiku","haiku":"Prisoners break free after seven years of confinement, heading toward a new frontier and liberation beyond their cell.","sonnet":"Prisoners on a distant planet called Helion plan and execute a jailbreak after seven years of captivity, eventually reaching a new frontier and finding freedom in a place they come to call home.","opus":"A science-fiction escape story of prisoners held for years in a cell on a distant world, eyeing the sky and vowing to break out until they finally reach a new frontier and a place called New Elysium."},"monuments~deadnest":{"src":"haiku","haiku":"A person drowning in their former home, poisoning themselves with toxic habits and denial, unable to escape despite knowing the wreckage around them.","sonnet":"A person describes the numbing, corrosive effect of living in a toxic and broken environment — self-medicating to suppress pain, denying the damage, and slowly losing any sense of direction or self.","opus":"A person feels trapped and drowning in a home turned toxic, poisoning himself to cope, torn over whether to break blood ties, and ultimately admitting he is responsible for the wounds inflicted."},"babymetal~catch-me-if-you-can":{"src":"haiku","haiku":"A Japanese children's hide-and-seek game ('kakurenbo') playfully frames pursuit and evasion, with playful warnings about the dangers of red shoes and running.","sonnet":"The Japanese lyrics frame the song as an exuberant game of hide-and-seek: the singer taunts a pursuer with \"not yet!\" calls, daring them to find a perfect hiding spot, and relishing the chase.","opus":"Framed as a children's game of hide-and-seek in Japanese, the song calls to the 'oni' seeker with taunts of 'not yet' and 'catch me,' warning against putting on the dangerous red shoes as the chase spins on."},"northlane~freefall":{"src":"haiku","haiku":"Witnessing violence and trauma numbs the speaker, severing him from empathy and leaving him incapable of feeling connection or pain.","sonnet":"The narrator describes a childhood marked by domestic violence — a father breaking down the door, a family in terror — and the lasting emotional numbness it produced, an inability to feel or empathise that was stolen from them permanently.","opus":"A harrowing scene of a home invasion witnessed by a child, who recalls a father begging not to be killed in front of his children and is left emotionally numb, unable to feel or give empathy after the trauma."},"type-o-negative~are-you-afraid":{"src":"haiku","haiku":"A stark, repeated urging toward suicide, presenting self-harm as release from fear of death.","sonnet":"A blunt, provocative address that urges someone not to fear death and frames suicide as an act of daring — stripping away any emotional mediation and presenting self-destruction in cold, direct terms.","opus":"A darkly provocative taunt that dares the listener not to fear death, goading them toward suicide with grim, mocking directness."},"black-light-burns~cruel-melody":{"src":"haiku","haiku":"A one-sided love where the speaker would sacrifice everything for a reconnection that will never happen, viewing past relationship as poison with no cure.","sonnet":"The speaker mourns a lost relationship: the other person's emotional absence is as persistent as a tune that won't leave, the past is poisoned and irreversible, and a desperate longing to be taken away is the only remaining response.","opus":"A lament over a lost love, imagining merging into the beloved like the sea while recognizing her heart is empty of him, and calling his past a poison with no cure as he begs to be taken away."},"black-light-burns~4-walls":{"src":"haiku","haiku":"Emotional and physical abuse within a confined space drives the speaker to deeper violation and control, finding satisfaction in inflicting pain on a suffering partner.","sonnet":"Within a claustrophobic and stifling space, a relationship plays out as something mutual but corrosive — not love, not clean — where both parties infect and damage each other, with the narrator taking out his inner pain on someone who keeps absorbing it.","opus":"A disturbing portrait of a cruel, controlling relationship, where the speaker admits it is not love but a compulsion to hurt and get under another's skin, taking his own pain out on a partner who lets him in."},"rammstein~wo-bist-du":{"src":"haiku","haiku":"A German meditation on a lost love—beauty and warmth fade, time stops, and laughter dies; the speaker searches everywhere for the absent person ('where are you').","sonnet":"The German lyrics trace a speaker's grief after losing someone's love: the world has gone cold and joyless, all clocks have stopped, and he searches everywhere — behind light, under every stone — asking where the absent person has gone, unable to sleep without a knife.","opus":"In German, the song charts love curdling into its absence, where beauty and warmth turn cold and clocks stop, as the speaker desperately searches everywhere for a vanished lover and falls asleep clutching a knife."},"nine-inch-nails~the-good-soldier":{"src":"haiku","haiku":"A soldier witnesses warfare's devastation and questions the reality of his experience, uncertain of purpose while surrounded by death and divine justification for violence.","sonnet":"A soldier in an active war zone struggles to hold onto meaning: the ideological certainties that justified the fight have dissolved, leaving only gunfire, corpses, and a disorienting sense that no one knows what they are fighting for or who they are.","opus":"A soldier in the midst of war steps over the dead amid gunfire and bombs, struggling to believe he belongs there and doubting what anyone is even fighting for as he grows numb and detached."},"celldweller~eon":{"src":"haiku","haiku":"An isolated and trapped person refuses to wait indefinitely, determined to break through confinement even at great cost and push forward into freedom.","sonnet":"Trapped and isolated in a kind of stasis or imprisonment, the narrator refuses to wait any longer for his life to be erased — he fights through the darkness, driven by the things he has been missing, determined to reclaim his birthright rather than endure another eon of nothing.","opus":"Trapped, isolated, and losing his memories in a tomb-like space where time is dislocated, the speaker refuses to wait any longer and claws his way forward, determined to push through and reclaim his birthright."},"in-flames~deliver-us":{"src":"haiku","haiku":"A person seeks escape and permanence with another, acknowledging confusion but embracing shared momentary aliveness despite incomprehension.","sonnet":"The lyrics reach toward connection and escape — urging someone to fly away together, disappear for a while, and simply be present in the moment — while acknowledging that the world is hard to make sense of.","opus":"An impressionistic plea for connection and escape, urging a companion to fly into the distance and disappear together, clinging to feeling alive in the present even as things fall apart and sense slips away."},"helloween~are-you-metal":{"src":"haiku","haiku":"A celebration of devotion to loud, fast, heavy metal music as the speaker's true identity and the only sound worth hearing.","sonnet":"A declaration of devotion to loud, fast heavy metal as a way of life — the narrator insists it is the only noise worth believing in and challenges listeners to confirm whether they share that commitment.","opus":"A celebration of loud, fast heavy metal and the joy of the music itself, repeatedly challenging the listener with the question of whether they are metal."},"wheel~where-the-pieces-lie":{"src":"haiku","haiku":"A person flees isolation and desperation, attempting a final push toward survival despite overwhelming weight and the realization that recovery may be impossible.","sonnet":"Someone overwhelmed by isolation and a crushing sense of purposelessness considers fleeing the wreckage of their circumstances, unsure whether connection or safety lies anywhere ahead or whether they are simply racing toward death.","opus":"A weary, desperate struggle for survival, pushing toward a distant border with no way to start again, craving connection while feeling too small to matter and tormented by a purpose beyond one's strength."},"rush~caravan":{"src":"haiku","haiku":"A young person on a caravan journey to the city dreams of escape and opportunity, determined to break from the past while harboring ambition in a world that makes him feel small.","sonnet":"A young person leaves behind obligation and travels by night toward a city of possibility, carried forward by an uncontainable ambition and the refusal to think small, no matter how large the world feels around him.","opus":"A traveler journeys by night in a fire-lit, primitive world toward the distant dream of a city where a young man might make good and break from his past, unable to stop thinking big even while feeling small."},"magdalena-bay~domino":{"src":"haiku","haiku":"A contrast between a winner bearing weight gracefully and a loser unable to express vulnerability; causation and design remain mysterious as people fall like dominoes.","sonnet":"Two people circle a relationship that seems fated and mechanically inevitable — like dominoes falling by physics — while questioning whether its end was designed or just happened, and saying goodnight to something neither fully chose.","opus":"A wistful reflection on a relationship's end, addressing a cold, statue-like lover and wondering whether the falling-apart is by design or just physics, like a toppling domino, before saying goodnight."},"linkin-park~blackout":{"src":"haiku","haiku":"A person discovers lies and betrayal in someone they trusted, confronting deception that cuts deeply while the betrayer takes and takes without accountability.","sonnet":"Rage at a partner's sustained deception and self-serving denial erupts into a confrontation, followed by a dreamlike descent where the singer calls someone down from a distance, waiting to reclaim what was lost or let go.","opus":"Furious address to a deceitful, taking partner who keeps secrets and never gives, the speaker refusing to swallow the lies, before shifting into a dreamlike passage about coming down to collect what has been let go."},"gorillaz~dare":{"src":"haiku","haiku":"An invitation to move physically and emotionally, to participate and feel present in experience rather than remaining a passive observer.","sonnet":"An insistent, hypnotic urge to commit fully to the moment — press into it, move with it, feel it from the inside — built around the single word \"dare\" as both command and release.","opus":"An insistent, hypnotic dance-floor invitation urging the listener to let go, move, and lose themselves in the moment, reassuring that it never did any harm."},"the-brave~technicolor":{"src":"haiku","haiku":"A person lost in confinement watches reality distort into color while remaining trapped in grayscale, unable to escape despite mental dissolution.","sonnet":"A person lost inside their own mind — disoriented, time-blind, watching their inner world dissolve into swirling colour while they themselves feel drained of it — searches desperately for a way out of a dissociated mental state.","opus":"A disorienting depiction of losing one's grip, staring at walls and losing track of time in a room that seems to melt into technicolor while the speaker stands in black and white, unable to find a way out of his own mind."},"rob-zombie~dragula":{"src":"haiku","haiku":"A primal, supernatural force moves through death and chaos in a hot rod ('Dragula'), embodying destruction and transgression against the natural world.","sonnet":"The narrator casts himself as an omnipresent, predatory force of death and decay — spreading like disease, inescapable as a hound of hell — prowling through grotesque imagery and burning through everything in his path in his vehicle, the Dragula.","opus":"A macabre, horror-tinged boast in which the speaker declares himself death itself in many forms, tearing through witches and ditches and speeding away in a monstrous hot-rod hearse he cannot die in."},"foo-fighters~the-pretender":{"src":"haiku","haiku":"A person refuses to conform to others' expectations and games, confronting pretense while also acknowledging his own role as both mirror and antagonist in the cycle.","sonnet":"The narrator refuses to be kept in the dark or manipulated by someone who performs sincerity while hiding secrets, positioning himself as the mirror that forces a reckoning with who that person really is.","opus":"A defiant confrontation with a manipulator who keeps others in the dark, refusing to be just another pawn or to surrender, and revealing himself as the buried voice and enemy that will bring the pretender down."},"sodom~marines":{"src":"haiku","haiku":"Marines sacrifice themselves for flag and country, fighting across terrain while serving patriotic duty, though the cost is perpetual death and blood in the name of freedom.","sonnet":"A portrait of soldiers sent into combat under the banner of freedom and honour — used as tools of aggression, self-sacrificing in killing fields, stepping on mines — with a tone that is part tribute and part unflinching record of the cost.","opus":"A depiction of marines sent to war under the banner of peace, fighting and dying for others across jungles and deserts, framing hatred as a tool of control while honoring their sacrifice amid mines and gunfire."},"machine-head~ten-ton-hammer":{"src":"haiku","haiku":"A force of vengeance and wrath strikes like a hammer, breaking down obstacles and enemies through brutal force and accumulated hatred.","sonnet":"The speaker positions himself as the embodiment of someone else's blame, fear, and denial — the very thing they despise and cannot escape — and promises to be the unstoppable force that brings them down.","opus":"The speaker casts himself as the embodiment of an enemy's guilt, fear, and downfall, promising to expose their lies and batter them like a ten-ton hammer with real, deep-seated hatred."},"alice-in-chains~what-the-hell-have-i":{"src":"haiku","haiku":"A person masks truth and hides his inner light, struggling to begin anew while trapped in cycles of fire and deception.","sonnet":"The narrator faces a relationship defined by falsehood and distance — a person whose soul feels hollow and whose presence feeds on lies — and confronts the difficulty of starting over while the fire of that dynamic still burns.","opus":"A strained relationship defined by masks, lies, and growing distance, where the speaker senses tension and dwindling worth and questions what little he has left to give."},"slayer~supremist":{"src":"haiku","haiku":"A tyrant revels in domination and suffering, seeking to eradicate the weak and establish perpetual reign through violence and spiritual obliteration.","sonnet":"A voice of pure domination and contempt describes the pleasure taken in others' pain and desperation, declaring an intent to obliterate the weak and maintain total control through supreme, atrocious force.","opus":"A monologue of absolute tyranny and cruelty, in which the speaker takes ecstasy in others' pain and vows to dominate, obliterate, and depopulate the weak while defiling faith and reigning over the free."},"crystal-castles~kept":{"src":"haiku","haiku":"Pledges unwavering commitment to keeping promises despite the chaos and strangeness that life brings.","sonnet":"A minimal, looping assertion that strange, unexpected things lie ahead while promises are kept regardless — the repetition itself creates a sense of waiting in place, held by obligation, with no further narrative offered.","opus":"Built entirely from a single repeated refrain, the song hovers on the idea of stranger things approaching and a vow to keep certain promises, staying just out of the way."},"nevermore~the-tiananmen-man":{"src":"haiku","haiku":"The iconic Tank Man photograph from Tiananmen Square becomes a symbol of defiant resistance against tyranny, with the singer examining how the image was weaponized through media to either inspire or manipulate the public.","sonnet":"A retelling of the lone protester who stood before a tank in Tiananmen Square on June 5, 1989, the song frames his act as a deliberate and media-conscious challenge to state tyranny, arguing that the real power of his defiance lay in the world watching — that he manipulated the spectacle of the confrontation to expose the government's use of force against its own people.","opus":"It recounts the lone protester who faced down a tank in Tiananmen Square in June 1989, framing his stand for freedom and democracy as a deliberate act performed for a watching world and the media."},"nine-inch-nails~not-so-pretty-now":{"src":"haiku","haiku":"A superstar's fall from grace as their facade crumbles and they fade into irrelevance, leaving behind only the shell of someone who once seemed untouchable.","sonnet":"A cold, mocking address to someone whose self-aggrandising facade has collapsed — a person who hid flaws behind greed and performance, believed themselves a superstar, and is now fading and broken, no longer able to sustain the image that once defined them.","opus":"A mocking address to a self-styled superstar consumed by greed and hiding, whose brightness is fading; the speakers coldly predict the person will soon be gone, forgotten, and no longer admired."},"the-prodigy~thunder":{"src":"haiku","haiku":"A powerful force without visible cause that shatters structures and breaks through barriers, leaving only destruction in its wake.","sonnet":"The song evokes a force — heard as thunder but producing no rain — that operates entirely from within, breaking through walls and barriers without any visible weather source, suggesting an internal or man-made pressure with destructive physical impact.","opus":"The words evoke a powerful, rain-less thunder that breaks walls and windows and comes from inside, using the image as a metaphor for overwhelming force."},"megadeth~train-of-consequences":{"src":"haiku","haiku":"Reckless living and moral bankruptcy set an unstoppable chain of consequences in motion, trapping the speaker in a fate they cannot escape.","sonnet":"A self-portrait of someone locked in a cycle of gambling, deceit, and reckless living, using the metaphor of a runaway train to convey that their choices — corrupted thinking, squandered money, and burned bridges — have set events in motion that cannot be reversed.","opus":"A gambler and thief narrates his own reckless downfall, taking others' money and betting it away while he speeds down an unstoppable \"train of consequences\" toward ruin he cannot turn back from."},"melt-banana~blank-page-of-the-blind":{"src":"haiku","haiku":"A fragmented meditation on blindness, concealment, and the powerlessness of those without agency or sight to understand what surrounds them.","sonnet":"A fragmented, confrontational picture of people stripped of agency — no hands, no map, no exit — trapped in a loop of manipulation and futility, building to a direct challenge asking what the \"traitor\" or the speaker's opponent will answer for amid the chaos.","opus":"Through fragmented, clipped commands and images of blackouts, dead ends, betrayal and blood, it sketches trapped, blind figures with no map or way out, ending on a declaration of being on \"the phase of nothing.\""},"the-mad-capsule-markets~pulse":{"src":"haiku","haiku":"An energetic call to embrace possibility and self-direction, rejecting hesitation and encouraging authentic expression over conformity.","sonnet":"A rallying call to join a crowd and act without hesitation — the song urges self-examination, openness, and confident decision-making rather than waiting on the sidelines, framing collective energy and individual choice as inseparable.","opus":"A shouted call to join the crowd and start moving, urging listeners to open their minds, make their own rules and act without hesitation because the future is theirs to seize."},"caravan-palace~lone-digger":{"src":"haiku","haiku":"An invitation to abandon restraint and dance, move, and immerse oneself in rhythm and physical release in the moment.","sonnet":"An invitation to stop holding back and give in to the pull of dancing and physical pleasure, directed at both a man and a woman who are reluctant to let go — the lyrics push them to forget restraint, move to the rhythm, and embrace the heat of the night.","opus":"A night-out invitation urging brother and mama alike to stop holding back and dance, insisting the body move to the rhythm and the head has no right to say no while the party is alive."},"northlane~ohm-northlane-remix":{"src":"haiku","haiku":"Distance and altitude dissolve earthly troubles, offering escape and perspective as one moves away from suffering and toward transcendence.","sonnet":"The song describes the relief of distancing oneself from the world — rising above its noise and shrinking troubles until they feel small — while acknowledging the cost: becoming a perpetual wanderer who can never return home, drifting free of the static but also untethered from belonging.","opus":"It follows a wanderer ascending away from a darkened, shrinking earth, shedding dead weight to take flight and escape into open space where troubles look smaller the farther one goes."},"crystal-castles~vanished":{"src":"haiku","haiku":"Urban predation and hunger drive a restless narrator through the city's night, pursuing stray lives and fleeting connections until death ultimately claims them.","sonnet":"A nighttime urban scene traced through the perspective of a hungry, predatory figure prowling city streets — drawn to sweat and pulse, indifferent to invitation — ending with both pursuer and pursued dead, mutual destruction framed as an inevitable consequence of the city's relentless appetite.","opus":"A predatory, restless figure hungry for strays and for life prowls the city, drawn to a lover's scent and blood; it turns to death as both take their own lives and, now dead, face the dark they fear."},"crystal-castles~intimate":{"src":"haiku","haiku":"A series of brief intimate encounters that feel transformative in the moment, cycling through connection and dissolution without permanence.","sonnet":"A portrait of serial, emotionally detached intimacy — moving from person to person, keeping the encounters secret, each new connection briefly filling a void before yielding to the feeling of dissolution: like falling asleep, like being born, like returning to soil.","opus":"It describes emotionally detached serial romance, collecting hearts and treating each new love as just another face and place to stay, with the fleeting union likened to sleep and to being born and returning to soil."},"dream-theater~honor-thy-father":{"src":"haiku","haiku":"A bitter denunciation of an absent father who abandoned his child and used selfish manipulation instead of parental love.","sonnet":"A direct confrontation with an absent, self-serving father figure — the narrator catalogues his failures as a parent, his refusal to take responsibility, and his tendency to shift blame onto others, culminating in a declaration that the relationship is permanently closed and that the father will die alone and unmourned.","opus":"A furious reckoning with a stepfather who pretended to love the speaker while feeling threatened by the lack of blood ties, took advantage, and neglected them; the speaker rejects the demand for respect and condemns him as the rotted root of the family."},"lantl-s~amber":{"src":"haiku","haiku":"Sheltered isolation protects from pain but also numbs and stifles, creating a struggle between the safety of passivity and the risk of feeling alive.","sonnet":"The song traces a life lived at remove from feeling — born into natural openness, gradually enclosed in protection that becomes suffocation, reduced to observing the world through a plastic veil in an artificial womb, where sensation is carefully dimmed and desire regulated until numbness itself becomes the condition of existence.","opus":"It imagines a life spent sealed inside an artificial, protective womb, an \"orphan of air\" raised in numb, over-sheltered unconsciousness where protection becomes smothering and desire is dimmed."},"limp-bizkit~the-propaganda":{"src":"haiku","haiku":"Manufactured narratives and psychological manipulation create distorted reality, with the speaker confronting exploitation and demanding autonomy.","sonnet":"The narrator rages against a media and social machine that packages rebellion and anger as product — selling manufactured outrage to the credulous — while simultaneously positioning himself as someone who created and now resents those who profited from or imitated him.","opus":"A defiant, unstable narrator rails against manipulation and \"propaganda\" sold to the innocent, boasting of his own volatility and grievances while claiming to have made the very people who now feel his contempt."},"hadouken~levitate":{"src":"haiku","haiku":"Music and connection generate euphoria and weightlessness, allowing transcendence above earthly constraints.","sonnet":"The song describes the physical and emotional sensation of being lifted out of ordinary consciousness by music — feet leaving the ground, the air becoming electric, senses heightened — framing live sound as a force that can genuinely transport a person beyond their bodily weight.","opus":"It describes the euphoric, weightless sensation of being lifted off the ground by music, feeling the air turn electric and the senses heighten as if transcending the earth."},"in-extremo~erdbeermund":{"src":"haiku","haiku":"Passionate, consuming desire for a lover, with their mouth (strawberry-mouth) as the object of desperate longing and intimate devotion.","sonnet":"A raw expression of obsessive physical longing — the narrator aches for a woman's strawberry-red mouth and white body, has spent years without her in tears and wandering, and returns to the strawberry valley where she kept herself for him, their reunion both earthy and ecstatic.","opus":"A frenzied declaration of lust and longing for a woman's \"strawberry mouth\" and body, the speaker aching through days apart and craving the union she has kept for him; the German verses cast desire in earthy, natural imagery."},"a-perfect-circle~blue":{"src":"haiku","haiku":"Willful ignorance of uncomfortable truth, choosing not to see or understand while helplessly watching someone's deterioration.","sonnet":"The narrator deliberately avoids facing the truth about someone who is in serious distress — choosing ignorance and a forced smile over acknowledgment — while the repeated image of the person \"turning blue\" makes clear that this wilful blindness has allowed real harm to go unaddressed.","opus":"The speaker insists they didn't want to know a painful truth, staying deliberately in the shallows and ignoring the smoke while watching a woman \"turn blue,\" mistaking silence and denial for approval."},"anthrax~caught-in-a-mosh":{"src":"haiku","haiku":"Communication breaks down completely between two people, leaving mutual frustration and incomprehension despite endless attempts to connect.","sonnet":"A depiction of furious, circular confrontation with someone who refuses to listen or show basic respect — each quoted exchange escalates the frustration until it feels like being pinned in an inescapable collision, the mosh pit serving as a metaphor for futile, exhausting conflict.","opus":"It stages a furious argument with someone who won't listen or show respect, the speaker's frustration boiling over into a clenched-fist rage likened to being caught in a mosh, where reasoning feels as futile as clapping with one hand."},"architects~day-in-day-out":{"src":"haiku","haiku":"Years of effort can be destroyed instantly, leaving nostalgia for better days and questioning why one remains trapped in a joyless present.","sonnet":"A lament for a sense of purpose and vitality that has quietly drained away — the narrator feels stranded in a joyless present, mourning days that once held colour and meaning, and wondering how they ended up in a world of hollow sympathy with no one watching over them.","opus":"The speaker mourns lost, better days and feels stranded in a world of indifference with nobody watching over them, longing to bring those days back before all the colour drains away and urging others to live in the present."},"stone-temple-pilots~sin":{"src":"haiku","haiku":"Guilt and sin bind the speaker to patterns of suffering and self-destruction, haunted by shame that cannot be shed.","sonnet":"The song maps a descent driven by sin and self-destruction — holy water clouds the mind, the soul is stolen, cold sweat and burning hatred close in — with the narrator bound to a shadow they cannot escape, sinking deeper with each verse into blindness and suffering of their own making.","opus":"It portrays a downward spiral of drinking and self-destruction in which sin is embraced as a source of strength, leaving the speaker blinded by his own sins and shackled to a following shadow."},"nevermore~next-in-line":{"src":"haiku","haiku":"Self-loathing and rejection by everyone close lead to acceptance of inevitable death and self-orchestrated destruction.","sonnet":"A first-person account of someone who has accepted death as the next step — isolated by abandonment, labelled sick, numbed by heroin, and convinced they are a self-described pilot of their own destruction — refusing to be saved and waiting passively for the end.","opus":"Speaking as someone brainwashed and used by a corporation and abandoned by those he loved, the narrator numbs himself with heroin, refuses to be saved, and declares himself the willing pilot of his own destruction, next in line to die."},"sodom~agent-orange":{"src":"haiku","haiku":"The Vietnam War's chemical weapon created lasting multigenerational suffering through cancer, deformity, and haunting trauma that will never heal.","sonnet":"A catalogue of the ongoing human damage caused by the US military's use of the herbicide Agent Orange in Vietnam — poisoned farmland, cancers in civilian bodies, birth defects passed down generations, and no possibility of reparation — described as a fire that destroys without burning.","opus":"It documents the wartime herbicide campaign 'Operation Ranch Hand,' condemning the chemical Agent Orange as a lawless assault that poisons civilians for generations, leaving cancer, deformity, and stillbirths in its wake."},"massive-attack~future-proof":{"src":"haiku","haiku":"Fragmented states of displacement, numbness, and transience as the speaker moves through temporary states of being without solid ground.","sonnet":"A compressed snapshot of marginalised or displaced existence — passport photos, empty pockets, borrowed clothes, chemicals gripping the body in winter — the fragments add up to a picture of someone numbed, passing through the world without leaving a mark, chemically or socially anaesthetised.","opus":"Through disjointed images of borderline lives, chemicals, \"hungry ghosts\" and borrowed clothes, it evokes numbed, transient people passing through and drawing on a pipe amid winter's grip and thin air."},"black-light-burns~so-alive":{"src":"haiku","haiku":"Attraction to a stranger awakens magic and intensity, making the speaker feel vividly, urgently alive in their presence.","sonnet":"A narrator fixated on a striking, unfamiliar woman — cataloguing her physical presence, her effect on him — who finds that the pull of desire makes him feel intensely alive in a way he cannot fully share or contain.","opus":"The speaker is intoxicated by a striking out-of-town woman whose look and strut make him feel intensely alive, even as he admits his head is full of a private \"magic\" he can't share with her."},"the-hellp~vertigo":{"src":"haiku","haiku":"Spinning disorientation and lack of plan or direction leave the speaker caught in chaos, unable to find steady ground.","sonnet":"The song circles around a state of dizzy disorientation — knotted thoughts, a dropping heart, Sisyphean and Orphic references to futile effort — with fragments suggesting entrapment in circumstances with no clear plan and no way to swim free, only the spinning sense of vertigo.","opus":"Amid fragmented references to Sisyphus, Orpheus and being caught in a kingpin, the speaker describes a dizzying spin and blood-dropping tension, repeatedly telling himself to relax while sinking rather than swimming and dying for his sins."},"nine-inch-nails~in-this-twilight":{"src":"haiku","haiku":"Contemplating the end of all things, finding peace in darkness and seeking a better place beyond doubt and suffering.","sonnet":"A meditation on the end of the world or of a life, addressed to someone whose time is running out — the sky blazes, ash settles in hair, darkness falls — and the narrator offers the comfort that in this final twilight a better place exists, even as he admits the possibility of regret for how he lived.","opus":"Watching the sun cross the sky a final time over a world set on fire, the speaker offers gentle reassurance at what seems the end, urging belief that the darkness is really light and that a better place can be found in this twilight."},"gorillaz~19-2000":{"src":"haiku","haiku":"The world's frenetic pace threatens to sweep away the speaker, who struggles to stay grounded while finding solace in rhythm and movement.","sonnet":"A loosely self-aware song about the speed of modern life and the desire to stay grounded — the narrator imagines weighing himself down to avoid being swept away, while the lyrics gently mock the instinct to just keep moving and dancing rather than slowing down and making something of your own.","opus":"It describes a world spinning too fast and the wish to slow down and stay tethered, set against a carefree groove of people doing \"the bump\" and cries to \"get the cool shoeshine,\" with a monkey caught between its brain and its tail."},"bring-me-the-horizon~it-was-written-in-blood":{"src":"haiku","haiku":"Inevitable death and transience are preordained, with farewell accepted as natural as flowers blooming and falling.","sonnet":"A eulogy framed around a suicide note — the central image is a farewell written in blood the day before a death, and the surrounding lines accept the inevitability of dying with a kind of mournful resignation, comparing life to roses that blossom and fall apart.","opus":"A grieving farewell to a friend and love lost to suicide, dwelling on parting and reunion \"by and by,\" comparing life to roses that blossom then die, and returning to the note written in blood the day before the death."},"system-of-a-down~needles":{"src":"haiku","haiku":"Parasitic relationships drain the speaker while addiction (symbolized by needles and veins) compels self-destruction despite recognition of the harm.","sonnet":"The song uses a tapeworm as a metaphor for a controlling, parasitic relationship or addiction — something living inside the narrator that dictates every move, feeds off him until nothing remains, and will simply find a new host once he is used up; the bridge makes the drug dimension literal with the image of a needle in the hand.","opus":"Using a tapeworm as a metaphor for a controlling parasite that feeds on and directs him, the speaker rages at being consumed and unable to grow, intercut with images of sitting alone with a needle in hand awaiting death."},"nine-inch-nails~dear-world":{"src":"haiku","haiku":"Disconnection and obsolescence isolate the speaker among images of absent people, trapped watching the world change beyond recognition.","sonnet":"A fractured farewell addressed to a world the narrator can no longer recognise — locked inside with photographs of absent people, watching a trajectory in decline and himself becoming obsolete — the embedded letter-fragment making explicit that this is a leave-taking driven by an inability to concentrate or trust himself any further.","opus":"An address from someone slipping away as the world grows unfamiliar and obsolete a frame at a time, locked in among absent people and losing the ability to concentrate or trust himself, sensing an unnoticed ending arriving."},"filter~you-walk-away":{"src":"haiku","haiku":"Internal conflict and self-sabotage through greed and self-imposed suffering leave the speaker unable to break free as another person abandons them.","sonnet":"The song sits at the point of a departure — the narrator is suffocated by greed and hatred in their life, unable to breathe or see clearly, and the repeated refrain of someone walking away registers both as loss and as the only possible release toward a life of one's own.","opus":"Consumed by greed, fear and an inability to breathe or see straight, the speaker just wants a life of his own and refuses to give in to hate as someone he addresses keeps walking away from him."},"exodus~burn-hollywood-burn":{"src":"haiku","haiku":"Celebrity culture and entertainment industry vapidity deserve destruction for celebrating fakeness, manufactured fame, and the exploitation of youth.","sonnet":"A sustained attack on celebrity culture and reality television — the song targets the manufactured fame of talentless or morally bankrupt figures, presenting their public visibility as a symptom of cultural rot and calling for the whole industry to be destroyed.","opus":"A scornful attack on Hollywood celebrity culture and its manufactured fame, calling for the whole spectacle of fleeting stars, tabloid heiresses and vapid reality to burn and be forgotten."},"i-o-lights~drift-away":{"src":"haiku","haiku":"Exhaustion and time pressure make authentic living impossible, causing people to drift away from effort and consciousness into numbness.","sonnet":"The song describes the numbing exhaustion of low-wage, emotionally suppressed daily life — sleeping through weekends, bottling up rage, unable to process feelings — and the only available response is to let go of control and drift, since there is never enough time or energy to actually fix anything.","opus":"It captures exhaustion and emotional numbing, with someone sleeping days away, drinking off bottled-up rage and blaming low wages, admitting there's no time to get fixed so they all just drift away."},"rammstein~mein-teil":{"src":"haiku","haiku":"A darkly ironic retelling of the Armin Meiwes cannibalism case, examining consumption, appetite, and the transgressive erotics of domination and death.","sonnet":"Based on the 2001 Armin Meiwes case, the song narrates consensual cannibalism from the perspective of the willing victim — meeting a man who wants to eat him, enduring the cutting and blood loss while the meal is prepared with care and served with wine and candlelight, the whole scene rendered with a grotesque domestic calm.","opus":"Framed by a personal ad seeking someone to slaughter, the German lyric depicts an act of cannibalism served as a refined meal, with the diner eating his own body part through pain; \"you are what you eat\" becomes literal."},"puddle-of-mudd~livin-on-borrowed-time":{"src":"haiku","haiku":"Living recklessly with the certainty of impending death, rejecting control and embracing nihilism in defiant refusal to be constrained.","sonnet":"A defiant, cornered narrator who sees death as imminent and responds with aggression rather than fear — sick of hypocrisy and interference, rejecting any attempt to stop or lecture him, and insisting that no external force will prevent him from acting on his own terms for whatever time remains.","opus":"A defiant, self-destructive rant from someone convinced he's living on borrowed time and will die tomorrow, fed up with others' \"bullshit,\" daring anyone to stop him and coldly asking who cares if you die."},"dream-theater~the-great-debate":{"src":"haiku","haiku":"The ethical debate over embryonic stem cell research unfolds through opposing voices, balancing medical hope against moral objections about human life.","sonnet":"A direct staging of the public argument over embryonic stem cell research — intercutting actual-sounding broadcast voices from both the pro-science and pro-life sides — and then stepping into the moral terrain of the debate itself, asking whether the potential to cure suffering justifies using developing human embryos.","opus":"Built from news clips and voices arguing both sides, it lays out the ethical debate over embryonic stem cell research, weighing the promise of cures and walking again against right-to-life objections and uncertainty about the cost."},"i-scintilla~melt":{"src":"haiku","haiku":"Physical and emotional intimacy creates temporary transcendence, dissolving boundaries and identity in shared vulnerability and sensual connection.","sonnet":"An intimate description of physical and emotional merging — two people losing their edges in each other, the sensation tracked through palms, rhythm, and thin sheets — framed as something temporary but profoundly meaningful, a space between permanence and transience where the most real feeling happens.","opus":"A sensual account of two lovers merging, using tarot cards, palms, rhythm and rain imagery to describe an intimate, transient union that exists \"in-between\" and holds the truth and pleasure of what remains unseen."},"type-o-negative~love-you-to-death":{"src":"haiku","haiku":"Obsessive devotion and servitude to a lover, with the speaker willing to surrender completely and be consumed by love.","sonnet":"A gothic erotic devotion — the narrator is transfixed by a woman's physical presence, positions himself as her servant, and repeatedly offers a love so total and overwhelming that it borders on annihilation, the phrase \"love you to death\" literalising a surrender of self.","opus":"A candlelit scene of seduction in which the speaker vows total servitude to a woman while warning that the beast inside him is coming for her, blurring devotion, desire and a threat to \"love you to death.\""},"thornhill~nurture":{"src":"haiku","haiku":"Seeking unconditional love and nurturing acceptance despite personal imperfection and the terror of abandonment and isolation.","sonnet":"The narrator is in a deteriorating state — physically and mentally sinking — and addresses someone they have placed complete faith in, whose presence is both medicine and poison; the song oscillates between needing to be held and realising that the person they depend on may not truly be there.","opus":"The speaker pleads to be nurtured and loved even in his imperfection and darkness, torn between hope and disease, reaching for someone who feels both like a healing idol and a poison, and who may never really be there."},"refused~new-noise":{"src":"haiku","haiku":"Artistic authenticity demands breaking free from conformity and consumerism, requiring genuinely new voices rather than old formulas.","sonnet":"A manifesto against cultural passivity — the song argues that mainstream art and music serve the interests of money and power, that those without access are locked out, and that the only genuine response is to make something radically new rather than continuing to dance to songs designed for someone else's benefit.","opus":"A call to break out of stale, complicit culture, arguing that the same old voice and \"wrong songs\" keep people from leading; it demands new noise and new art for real people rather than beauty locked behind money and access."},"eat-your-heart-out~closer-to-the-sun":{"src":"haiku","haiku":"Shedding stagnant old habits and identities to grow and bloom toward light, regardless of pain or the loss of familiar roots.","sonnet":"The narrator breaks free from people who resist their growth — who pull them back toward stale habits and a predictable path — choosing instead to follow their own direction even through the pain of that departure, blooming toward something beyond what others mapped out for them.","opus":"The speaker craves change and growth despite others wanting them to stay the same, choosing to be pulled out and cut down so they can bloom \"closer to the sun,\" walking their own painful path on glass alone."},"nine-inch-nails~the-fragile":{"src":"haiku","haiku":"A commitment to protect someone fragile from breaking, bearing witness to their invisible struggle and beauty.","sonnet":"The narrator watches someone beautiful and self-unaware who is slipping toward collapse, and pledges not to let her fall apart — recognising her pain in his own past self and vowing to build a shelter against whatever is closing in on her, even as he admits it may already be too late for him.","opus":"A tender vow to protect a fragile woman who can't see her own beauty and is slipping away; the speaker promises not to let her fall apart and to shield her from those who keep picking at her, even while doubting he can fix himself."},"battle-tapes~belgrade":{"src":"haiku","haiku":"Youthful surrender and deception play out in darkness, with a willing fool who lives and dies for love despite betrayal.","sonnet":"The song is about a seductive and destructive relationship — someone with a heart like a weapon who takes everything owed and leaves damage behind — and the narrator, knowing all this, still surrenders to the sweet songs of seduction, willing to be the fool who lives and dies for them.","opus":"Addressing a dangerous, plundering lover likened to a \"search and destroyer,\" the speaker offers to be the fool who lives and dies for them, amid images of a sinking hull, seduction in the darkness and cutting enemies down."},"linkin-park~one-step-closer":{"src":"haiku","haiku":"Constant conflict and pressure from another person drive the speaker toward emotional collapse, requiring distance to survive.","sonnet":"The narrator is at the edge of a breakdown brought on by a relentless, one-sided conflict — every word from the other person pushes closer to a snapping point — and the song ends with a wordless eruption of rage, the communication having completely collapsed.","opus":"Overwhelmed by someone's words and empty talk, the speaker feels pushed one step closer to breaking, craving room to breathe and finding refuge in ignorance before erupting in a demand for the other to shut up."},"tool~jimmy":{"src":"haiku","haiku":"Reuniting with a childhood self or lost memory, carrying forward an ancient connection to finally heal and move together.","sonnet":"A return to a frozen inner child — \"Eleven\" — who was abandoned when the narrator was eleven years old and has been waiting ever since; the song is about the slow, painful journey back to that stalled part of the self, guided by its distant light, with the hope that reuniting with it will allow both to finally move forward.","opus":"The speaker returns to a childhood self frozen at age eleven, when stability suddenly vanished, seeking to reunite with and free that abandoned inner child and lead him back home into the light so the two can become one and heal."},"zheani~you-saw":{"src":"haiku","haiku":"Death, decomposition, and betrayal leave the speaker as food for worms, haunting others who failed to prevent their despair.","sonnet":"The song mourns a young woman destroyed by lies, jealousy, and social cruelty who chose death — the narrator describes her as flesh returning to soil, food for worms, and reflects on how no one could stop her once reputation was stabbed apart; guilt haunts the survivor who knows the memory of her is already slipping away.","opus":"It tells of a girl driven to suicide by vicious lies and jealousy that stabbed her reputation apart; now dead and food for worms, she jumps into the bay, insisting things stay the same, and vows to haunt those whose cruelty keeps them up at night."},"type-o-negative~these-three-things":{"src":"haiku","haiku":"Apocalyptic religious imagery mingles condemnation of abortion, fascist politics, and prophecy of judgment and salvation.","sonnet":"A theologically dense monologue that moves through three interlinked condemnations — abortion as infanticide, the disputed legitimacy of the state of Israel, and the speaker's own identity as an adversarial or satanic force — woven together with apocalyptic imagery of Babylon, Armageddon, and redemption, and closing unexpectedly with a call to salvation through forgiveness.","opus":"A hellish sermon condemning three things the speaker regards as sins: abortion framed as infanticide, and, through apocalyptic biblical imagery of Babylon and Armageddon, a self-proclaimed state founded in 1948, promising damnation while offering salvation through forgiveness."},"crystal-castles~baptism":{"src":"haiku","haiku":"Forced religious indoctrination repeats lessons of obedience and love, but leaves the speaker unable to forgive the violation.","sonnet":"The song frames religious instruction and forgiveness as coercive rather than liberating — the head held underwater, the lessons forced and repeated, the scriptures misleading — and the refrain insists that whatever baptism was performed, the resentment it bred cannot simply be forgiven away.","opus":"Using the image of a head held under water in a forced baptism, it turns a religious rite into something coercive and unforgivable, with \"lessons repeating\" and misleading chronicles suggesting indoctrination rather than grace."},"a-perfect-circle~judith":{"src":"haiku","haiku":"A critique of blind faith: the singer accuses a believer's god of abandoning them, yet that person continues to pray and obey without ever questioning why they suffer.","sonnet":"The speaker addresses someone whose devout faith has not protected them from suffering, arguing that their god abandoned them while they still pray and never question why. It is a furious rejection of blind religious devotion in the face of real pain.","opus":"A furious address to a devout believer whose faith held even as her God left her broken and paralyzed; the narrator rages at her refusal to question why her savior abandoned her."},"kreator~endorama":{"src":"haiku","haiku":"An apocalyptic force called Endorama crushes and ends all worldly pain, greed, and illusion, offering liberation through the cessation of life itself.","sonnet":"A force called Endorama arrives as an unstoppable annihilation that ends all suffering, pride, selfishness, and strife, leaving nothing behind. It frames total destruction as a dark release from the suffering of being alive.","opus":"A vision of a final apocalyptic end that erases all suffering, pain, greed and human pride, framing death as release from a labyrinth of life into either eden or inferno."},"acid-drinkers~iq-cyco":{"src":"haiku","haiku":"A violent, chaotic confrontation where the narrator finds a gun and pursues a target called IQ CYCO; fragmented imagery of aggression, sleeping bodies, and aftermath suggest a dark chase through the city.","sonnet":"A fragmented pursuit through a city in search of something called IQ CYCO, mixing images of a gun, a sleeping or passive crowd, and chaotic street energy. The lyrics are disjointed and resist a single clear narrative beyond a sense of manic, aimless aggression.","opus":"A fragmentary, gun-in-hand hunt for a figure called IQ CYCO, stringing together violent images of sleeping bodies and a manic pursuit that ends with 'another one bites the dust.'"},"soft-cell~sex-dwarf":{"src":"haiku","haiku":"A wealthy predator parades and exploits a small person as a possession, treating them as an accessory for film, spectacle, and manipulation.","sonnet":"A wealthy narrator plans to use a small companion as a spectacle and prop for luring vulnerable people — referred to as disco dollies — into a life of exploitation, filming them and parading them publicly. The song portrays predatory grooming and sexual degradation in a sleazy, glamorous setting.","opus":"A leering narrator boasts about controlling and exploiting people, luring 'disco dollies' into a life of vice and parading a companion he calls his 'sex dwarf' on a leash amid images of gold cars and depravity."},"man-with-a-mission~hey-now":{"src":"haiku","haiku":"A warning about harsh reality and mass delusion: people sleepwalk through ignorance, heading toward a 'free fall' of collapse while angels and demons close in.","sonnet":"Set in a sleepless, chaotic city, the song warns that blindly following the crowd leads downward, framing life as a gamble between heaven and hell where ignorance and insanity spread. It urges self-awareness against the pull of conformity and inevitable collapse.","opus":"A bleak view of a decaying, sleepless city where people are trapped in line heading downward; it warns that going wrong is easy and that angels and demons alike are closing in on a doomed free fall."},"trivium~watch-the-world-burn":{"src":"haiku","haiku":"A call to break free from dehumanizing systems that consume and digest human life; the singers are the arson, burning it all down in rebellion.","sonnet":"The song describes people crushed and consumed by a dehumanizing system, and declares that those who resist become its enemies, sacrificing themselves to ignite a revolution. The speaker and their allies claim ownership of the destruction, positioning themselves as the arson that burns the whole world down.","opus":"A call to rebellion against a crushing 'great machine' that consumes those who fall in line, with the speakers declaring themselves the arson that sets the world ablaze in revolt."},"serj-tankian~saving-us":{"src":"haiku","haiku":"A couple tears each other apart through conflict and departure, yet paradoxically that very destruction and heartbreak saves and transforms them both.","sonnet":"A relationship tears two people apart through avoidance, hurt, and unresolved conflict, yet the same destructive dynamic paradoxically sustains and even saves them. The speaker cycles through the contradictions of being broken apart and kept alive by the same person.","opus":"A plea against a couple wasting their time wounding each other, insisting they should laugh, cry and warm each other's hearts instead; the same act of tearing, breaking and killing is also framed as saving."},"onslaught~shock-n-awe":{"src":"haiku","haiku":"Glorification of military shock tactics and warfare: merciless killing, silent strikes, and systemic brutality depicted as power and strategy.","sonnet":"The song depicts modern military assault — precision strikes, overwhelming force, and rapid killing — as a cycle of pure, dehumanizing brutality. War is catalogued as a domain of pain, fatality, hate, and inhumanity with no redemptive purpose.","opus":"A depiction of a ruthless military assault that strikes by night to exterminate at will, dwelling on war as a domain of pain, brutality and inhumanity."},"spiritbox~sun-killer":{"src":"haiku","haiku":"Destructive parasitic forces born of dust assault and displace their hosts; a lullaby sung by death itself.","sonnet":"The speaker feels internally destructive, aware that staying means turning violent and that something monstrous within them threatens those around them. They call out to a figure described as a sun killer, asking to be lulled to sleep as a way to suppress or end that danger.","opus":"A struggle with a destructive inner nature that fears becoming violent, seeking a 'sun killer lullaby' to calm the rising waves and monsters and be sung to sleep."},"tesseract~of-matter-proxy":{"src":"haiku","haiku":"A surrogate self bears blame and scorn for others' failings; despite growing stronger, they remain trapped, unable to break free from imposed degradation.","sonnet":"The speaker serves as a surrogate who absorbs others' projections and judgments while recognizing their own inadequacy and the impossibility of the role. Despite burning bridges and pouring out devotion, they feel trapped, unseen, and unable to escape a pattern of self-erasure for someone else's sake.","opus":"A conflicted narrator who devotes himself to propping someone up while feeling inadequate, exhausted by their judgments and refusing to keep playing into their hands even as he wishes he were enough."},"hole~violet":{"src":"haiku","haiku":"A possessive, consuming relationship where desire drives the cycle: once the beloved gets what they want, they lose interest, only to circle back and take more.","sonnet":"The speaker describes a relationship defined by one-sided taking, where the other person wants something intensely until they have it and then loses interest entirely. Turning the pattern around, the speaker finally positions themselves as the one who takes — claiming possession and declaring the cycle their own.","opus":"A defiant song about being used and discarded by people who lose interest once they get what they want, met with a bitter dare to take everything and a vow that the narrator's own possession is forever."},"nine-inch-nails~i-would-for-you":{"src":"haiku","haiku":"A person lies to themselves and wishes they could be someone else entirely in order to be worthy of their partner, haunted by self-blame and disappointment.","sonnet":"The speaker reflects on a relationship that has deteriorated, admitting they keep deceiving themselves rather than confronting what is wrong. The song circles around a painful self-awareness: they wish they could become a different person just to be enough for the other.","opus":"A weary confession of self-deception and self-blame from someone who feels there was a place that could have been; he admits that if he could be somebody else, he would do it for the person he loves."},"health~the-message":{"src":"haiku","haiku":"Death is meaningless, inevitable, and impersonal; we all burn out, and in life we chase age: young people eager to grow old, old people desperate to be young again.","sonnet":"Death is presented as an indiscriminate, meaningless inevitability that takes everyone — saints and criminals, rich and beautiful alike — regardless of readiness. The song observes how people spend youth eager to grow up and then old age wishing they were young, with death as the only constant and its message carrying no meaning at all.","opus":"A meditation on the inevitability of death, which comes for everyone regardless of virtue, wealth or beauty; it frames death as an empty 'message' and notes how people waste their lives longing to be other ages."},"shining~l-t-oss-ta-allt-fr-n-varandra":{"src":"haiku","haiku":"A bleak meditation on mutual destruction: the divine spark is stripped away, judgment falls without mercy, and the speaker finds grim comfort in shared doom and eternal flames.","sonnet":"The Swedish lyrics call for total mutual destruction — stripping away divinity, joy, and self — while awaiting a holy executioner who will carry out a long-decreed sentence. The speaker finds sadistic comfort in the knowledge that everyone, believer or not, will be consumed by flames forever.","opus":"A Swedish self-lacerating hymn urging mutual destruction, inviting an executioner to strip away all that is divine and consign everyone to the flames, interwoven with English lines of self-hatred and a hollow promise to be okay."},"liam-lynch~united-states-of-whatever":{"src":"haiku","haiku":"An absurdist comedy where the protagonist responds to every circumstance with indifference, unfazed by encounters, questions, or life itself.","sonnet":"The narrator drifts through a series of casual encounters and minor confrontations — at the beach, the pool hall, a corner at 3am — responding to every situation with complete indifference. The song is a comic portrait of studied nonchalance as a personal philosophy.","opus":"A blase teenager wanders through encounters with peers, cops and strangers, brushing off every situation with a dismissive 'whatever' as his personal creed of indifference."},"system-of-a-down~violent-pornography":{"src":"haiku","haiku":"A critique of mass consumption of violence and tragedy through media: society is addicted to witnessing suffering, fed a steady diet of brutality as entertainment.","sonnet":"The song frames television as a machine delivering a non-stop diet of sexual violence and degradation to a passive audience, equating entertainment culture with brainwashing. The litany of universal human experiences — fucking, crying, dying — is set against the accusation that this content normalises brutality.","opus":"A caustic attack on television, likening its content to violent pornography and a 'non-stop disco' of brainwashing, insisting everyone lives, fucks, cries and dies inside this cycle."},"black-light-burns~the-mark":{"src":"haiku","haiku":"A speaker bears an invisible mark of exile and burning desire; they want to burn the world and claim that fire as their own, leaving their mark through destruction.","sonnet":"The speaker carries an invisible internal wound — described as a mark or scar — that drives cycles of wandering, destruction, and return without resolution. Unable to ignore or extinguish it, they embrace the burning as their own even while it prevents them from breathing freely.","opus":"A person carries an invisible mark or scar that torments them, wandering in circles back home and concluding that the destructive fire inside is theirs to own as they resolve to burn everything down and leave a mark."},"machine-head~a-farewell-to-arms":{"src":"haiku","haiku":"An anti-war song mourning the children and soldiers killed in conflicts waged by politicians and profiteers who never send their own sons.","sonnet":"The song is an anti-war protest that mourns the human cost of conflict — dead soldiers, grieving families, children in danger — and accuses political leaders and war profiteers of sending the poor to die while they enrich themselves. The speaker waves a white flag and demands accountability.","opus":"An antiwar lament mourning slaughtered soldiers and grieving fathers and children, condemning the leaders and senators who send others to die while their own sons never fight, and asking what humanity has become."},"system-of-a-down~i-e-a-i-a-i-o":{"src":"haiku","haiku":"A rush of surreal, punning wordplay: tongue-twisters, alliteration, and absurdist image-streams (Plutonium wedding rings, icicle stretchings, Lois Lane, Jimmy Carter) that prioritize sonic play over narrative sense.","sonnet":"The song strings together absurdist, punning images — tongue-twister lines, surreal pop-culture references, and nonsensical juxtapositions — without a coherent narrative. The lyrics appear deliberately meaningless, functioning as rhythmic wordplay rather than a decipherable subject.","opus":"A rush of nonsensical, cartoonish images, tongue-twisters and pop-culture names strung together with a chanted refrain and a repeated 'why?', reveling in absurdity more than any single subject."},"a-pale-horse-named-death~cold-dark-mourning":{"src":"haiku","haiku":"An elegy for lost friends and loved ones now dead and at rest; the speaker stands alone, waiting to be reunited with them in the afterlife.","sonnet":"The speaker stands at a graveside and reflects on the loss of everyone they have known, describing grief as a cold, numbing freeze that leaves them the last survivor at an empty table. Death is framed as a temporary passage from womb to stars, but the comfort is outweighed by the isolation of being left behind.","opus":"A grief-stricken meditation on standing at a friend's grave and outliving everyone the narrator has lost, comforted only by the thought that the departed rise to the stars and that he will meet them again."},"introvert~dreamers":{"src":"haiku","haiku":"A person trapped in recurring nightmares, neurotic and drowning, hiding their pain behind lies; they see no way out except through their own teeth (self-destruction).","sonnet":"The speaker feels trapped inside a waking bad dream, hiding their distress behind reassurances while admitting to neurosis and a sense of fading away. They push others at arm's length, fearing that if they are truly seen they will only be abandoned.","opus":"An isolated, self-described neurotic narrator feels trapped in a bad dream and drowning, hiding behind lies and expecting that once someone sees the truth they will give up on him and he will fade away."},"machine-head~this-is-the-end":{"src":"haiku","haiku":"A final goodbye to a past relationship and people who suffocated and disrespected; the singer rejects all they came from and demands respect or complete separation.","sonnet":"The speaker makes a final, definitive break from people who suffocated, condescended to, and denied them respect, declaring that all shared history is now over. It combines a farewell to dead-end chasing with a call for those who remain to stand together or step aside.","opus":"A defiant severing of ties with someone who feigned care and suffocated the relationship; the speaker erases the past, embraces an uncertain future and hurls curses at the 'bastards' he leaves behind."},"high-on-fire~snakes-for-the-divine":{"src":"haiku","haiku":"A dark, mythic narrative of divine punishment: a sinner is sentenced to venomous snakes, ancient crimes echo through time, and suffering plays out as cosmic retribution.","sonnet":"The song conjures an ancient, mythological cycle of punishment, sacrifice, and uprising, where a condemned figure is handed divine serpents and the forces of darkness rise to scourge and destroy. Cities, civilisations, and ten thousand years of history are swept into an endless rhythm of rising and falling.","opus":"A dark occult narrative of sacrifice, venomous serpents and an ancient crime, where the condemned are handed the 'snakes of divine' amid a battle against wolflike killers and a struggle to break a spell and end a master's life."},"ministry~rio-grande-blood":{"src":"haiku","haiku":"Political satire attacking wealthy leaders and war profiteers who exploit the poor for oil and money, enriching themselves while ordering others to die in wars.","sonnet":"The song is a satirical attack on the George W. Bush administration, voiced in first person as Bush confessing to waging war for oil profits, enriching corporations like Halliburton, oppressing the poor, and lying to the public. It frames the Iraq War as straightforward resource extraction driven by greed.","opus":"A savage satire voiced as a caricature of President George W. Bush, portraying him as a greedy dictator who wages war for crude oil and profit while squeezing the poor to enrich the wealthy."},"alice-in-chains~them-bones":{"src":"haiku","haiku":"An existential meditation on mortality: the speaker feels isolated and resigned to becoming nothing but bones and dust, accepting death as the only certainty.","sonnet":"The speaker meditates on mortality as an inescapable condition, suggesting that humans are born already heading toward death and that life is just the time before returning to dust. Loneliness and the certainty of ending as a pile of bones runs through every verse.","opus":"A grim reckoning with mortality, the narrator sensing that he is born toward the grave and will inevitably end up as nothing but a pile of bones, haunted by isolation and dread."},"nevermore~and-the-maiden-spoke":{"src":"haiku","haiku":"A tormented female spirit from centuries past haunts the living, whispering of cold beauty and madness, moving unseen through the world.","sonnet":"The song follows a tortured spirit — a woman born in 1617 — who haunts a space by moving objects, whispering in ears, and speaking to those who are awake, her words fragmented as if her soul is already gone. She is described as deranged, sorrowful, and condemned, a system slave led to a grave without redemption.","opus":"A ghost story about a tortured woman born in 1617 who lingers as a restless spirit, moving furniture and whispering to the living; her sorrow, madness and denied redemption mark her as another 'system slave' led to the grave."},"tesseract~of-energy-singularity":{"src":"haiku","haiku":"A weary soul seeks escape to peaceful natural places, craving freedom from endless conflict and controversy; they plant seeds of change but fear nothing will truly break free.","sonnet":"The speaker oscillates between a longing for escape — an imagined place of green grass, blue sea, and calm — and the inescapable weight of grief, misfortune, and feeling dead inside. They try to plant something that will erode the walls holding them back, while doubting they will ever truly be enough.","opus":"A narrator reaches out to save someone from a fall while longing for his own escape to a calmer place of relief; he wrestles with grief, self-doubt and a numb feeling of being dead inside as he plants a seed of change."},"toronto-is-broken~paragons":{"src":"haiku","haiku":"A self-aware critique of playing victim and fake talk: true growth into a paragon requires acknowledging darkness within, transcending victimhood, and becoming interconnected with others' souls.","sonnet":"The speaker confesses to playing it safe, playing victim, and losing their way, arguing that genuine growth requires confronting darkness and admitting one's own failures. Becoming a paragon — an ideal — is presented as something only achievable through honesty and the recognition that no one stands above anyone else.","opus":"An introspective call to face one's own darkness and stop playing the victim, insisting that no one is above anyone else and that only by owning your flaws can you become a 'paragon' within an interconnected web of souls."},"wargasm-uk~rage-all-over":{"src":"haiku","haiku":"A young, furious generation destroyed by misinformation and designed to fail fights back; they're done being exploited and ready to tear down what they were taught to despise.","sonnet":"A generation raised on misinformation and systemic failure declares itself beyond anger — describing itself as pure rage — and issues a threat to tear down the structures sold to them as sacred. The song maps a young, damned cohort that feels wasted, isolated despite connectivity, and ready for confrontation.","opus":"A generational battle cry channeling misinformation, alienation and rage against a system that sold false sacred values, casting the young and the damned as the violent reaction to what they were taught to despise."},"limp-bizkit~gimme-the-mic":{"src":"haiku","haiku":"A boastful rapper asserts dominance, attacking posers and mediocre competitors; they're a 'microphone fiend' ready to blow away everyone else on the stage.","sonnet":"The speaker positions himself as a genuine MC who despises posers, corporate radio, and watered-down music, demanding the microphone to demonstrate superiority. It is an aggressive assertion of authenticity and territorial dominance within the rap world.","opus":"A braggadocious rap boast in which the narrator, a self-styled 'microphone fiend,' demands the mic and vows to destroy the posers, wannabe bands and repetitive radio he despises."},"polaris~hypermania":{"src":"haiku","haiku":"A manic, destructive cycle of constant ups and downs: the speaker can't stand still, exhausted by their own frantic energy, questioning if they're human or machine.","sonnet":"The speaker describes an unrelenting mental cycle — crashing highs and lows, nervous energy, substance use, and a shrinking sense of self — that they recognise as a waste of time but cannot stop. Trapped in a rabbit hole of mood swings, they ask to be saved while admitting they may always have been this way.","opus":"A raw account of restless mania, insomnia and self-destruction, with the narrator picking a fight with fate, questioning whether he's man or machine, and begging to save a soul he no longer recognizes."},"tool~vicarious":{"src":"haiku","haiku":"Humans feed on tragedy and violence through media like addicts; we watch disasters with fascination, part voyeur and part vampire, drawn to other people's suffering.","sonnet":"The speaker admits to being compelled to watch tragedies and deaths on television from a safe distance, then challenges the audience to admit they share the same voyeuristic appetite for suffering. It diagnoses human nature as carnivorous and vicarious, feeding on others' catastrophes as a substitute for living.","opus":"An unflinching examination of the human appetite for televised tragedy, arguing that people live vicariously by watching others die from a safe distance and refuse to admit they all feed on this morbid fascination."},"system-of-a-down~b-y-o-b":{"src":"haiku","haiku":"A fierce indictment of war: wealthy politicians never send their own children to fight, yet always send the poor and powerless to die for their interests.","sonnet":"The song is a furious anti-war protest that asks why it is always the poor and working class who are sent to fight while presidents and the powerful stay home. Amid surreal imagery of dancing in the desert and blowing up sunshine, the central accusation is that wars are launched for hypocritical, self-serving reasons.","opus":"A protest against war and political hypocrisy, repeatedly demanding to know why presidents never fight the wars they start and always send the poor to die, set against a mocking party refrain."},"crystal-castles~untrust-us":{"src":"haiku","haiku":"A repetitive public-service warning that cocaine is harmful, delivered in Spanish and English as if from an official health announcement.","sonnet":"The lyrics repeat a single statement — cocaine is not good for your health — alternating between Spanish and English with no additional content. The song's entire lyrical substance is this repeated public-health warning, making it uninterpretable beyond its literal message.","opus":"The lyrics consist almost entirely of one repeated bilingual line stating that cocaine is not good for your health, offering little beyond that single warning."},"limp-bizkit~loser":{"src":"haiku","haiku":"After a relationship ends, the speaker feels like a loser, haunted by past abuse and broken promises; they want to escape and reclaim the life they've lost.","sonnet":"The speaker looks back on a relationship that brought out the worst in both people — marked by abuse, manipulation, and mutual damage — and resolves to walk away in order to reclaim himself. He wants simply to be okay and to stop losing his sense of self to a dynamic that has cost him everything.","opus":"A bitter breakup song in which the narrator feels he has been losing ever since he met his partner, dwelling on a hard past and mutual damage while admitting they bring out the worst in each other and must say goodbye."},"limp-bizkit~walking-away":{"src":"haiku","haiku":"Letting go of everything one loves because staying leads only to pain; walking away from cherished things is the only way to survive.","sonnet":"The speaker feels trapped in a cycle of tragedy and emotional baggage they cannot escape, and chooses to deliberately walk away from everything they care about as the only honest path forward. The act of leaving is framed not as abandonment but as an admission of reality.","opus":"A resolution to walk away from everything and everyone the narrator loves and needs, telling the truth for once and treating his own pain as a sign that it's time to leave."},"coroner~son-of-lilith":{"src":"haiku","haiku":"A mystical being—child of Lilith—possesses supernatural power through youth and purity; they need no physical form to affect others, carrying the moon in their veins.","sonnet":"The speaker identifies as the son of the mythological figure Lilith, emerging from a void with youth and purity as his only defenses, carrying the moon in his veins and escorted by souls. The song frames this lineage as something beyond language or explanation, an identity felt rather than reasoned.","opus":"A mystical first-person declaration by a figure who calls himself the son of Lilith, emerging from the void escorted by souls and claiming youth as his defense, purity as his weapon, and the moon in his veins."},"bloodhound-gang~the-bad-touch":{"src":"haiku","haiku":"Explicit celebration of human sexuality as animal instinct: stripped of pretense, humans are just mammals driven by primal urges and desire.","sonnet":"Using the framing of a nature documentary, the song is an extended series of sexual double entendres arguing that human mating is no different from animal behaviour. The tone is entirely comedic, stringing together pop-culture puns to reduce romantic pursuit to pure biology.","opus":"A comic, innuendo-laden come-on that frames sex as animal instinct, with the narrator piling up pop-culture puns to proposition a partner and insisting humans are 'nothing but mammals.'"},"man-with-a-mission~2045":{"src":"haiku","haiku":"In the year 2045, artificial intelligence rises to dominance and humanity faces obsolescence; humans must accept the singularity and their new place in that world.","sonnet":"Set in the year 2045, the song imagines AI reaching singularity and humanity becoming obsolete, yet the speaker faces this not with fear but with a defiant sense of purpose and readiness. It frames the technological transition as another challenge humans have faced before and can meet head-on.","opus":"A playful sci-fi vision of the year 2045 when AI takes the lead and humanity fades, urging listeners not to fear the coming 'singularity' and to embrace another dimension and new galaxy."},"hilltop-hoods~the-hard-road":{"src":"haiku","haiku":"A memoir of rising from poverty and youth crime to success through hip-hop, marked by regret over family pain, struggle, and the hard-won journey to redemption.","sonnet":"Two rappers recount youthful years of delinquency, school dropout, near-imprisonment, and dead-end work, crediting family and music with keeping them alive long enough to find a path out. The song is a retrospective on surviving a chaotic early life without excusing or glamorising it.","opus":"An autobiographical rap about growing up on a hard road of arrests, drink and dead-end jobs, expressing remorse toward family and crediting music and loved ones with pulling the narrators out of trouble."},"annihilator~all-for-you":{"src":"haiku","haiku":"A relationship of control and abuse: the speaker sacrificed family and self for their partner, only to be isolated, blackmailed, and now abandoned by someone still unjustified.","sonnet":"The speaker describes a relationship in which they surrendered everything — family, children, soul — to give a controlling partner complete power, only to be beaten down, manipulated through blackmail, and eventually left with nothing. The song ends as the speaker recognises the exploitation and refuses to be brought down any further.","opus":"An accusation aimed at a controlling, manipulative partner for whom the narrator sacrificed family and soul, calling out their blackmail, lies and hate as he finally sees through and confronts them."},"type-o-negative~she-burned-me-down":{"src":"haiku","haiku":"Betrayal by someone close—family or intimate—cuts deeper than death; the speaker seeks forgiveness yet feels drawn toward the betrayer in a cycle of pain.","sonnet":"The speaker was betrayed by someone close — family or friend rather than a stranger — a wound made worse precisely because of the trust involved. Despite rage and disappointment, they are trying to find forgiveness, while admitting the person has done something worse than death to them.","opus":"A song about betrayal by someone close, insisting that being wounded by family or a loved one through love is worse than death, while confessing a perverse thrill at watching her destructiveness."},"deftones~feiticeira":{"src":"haiku","haiku":"A dark, violent scene: a drunk speaker is restrained, hurt, and forced into photographs by a woman; promises of release hang uncertain while pain continues.","sonnet":"Narrated from the perspective of a captive, the song describes being bound, gagged, transported in a car trunk, and subjected to the whims of a captor who photographs them and keeps promising release. The atmosphere is one of helpless confinement, with the captor's reassurances — soon I'll let you go — becoming increasingly ominous.","opus":"A disorienting, dreamlike scene of a narrator drunk, bound and abducted by a woman who photographs and toys with him, pleading to be untied as she repeatedly sings that soon she'll let him go."},"tesseract~hexes":{"src":"haiku","haiku":"A mind haunted and cursed by traumatic history; terror lives in memory, and the speaker is afraid to breathe or move, locked in the past's grip.","sonnet":"The speaker is haunted by memory in a way they cannot escape or suppress, describing a mind shattered by history and a phantom that lives in their conscious thought. History itself is cast as a hex — something that traps, terrifies, and repeats — yet the speaker asserts they will breathe and live again despite it.","opus":"A haunted meditation on being tormented by memory, with an old phantom lodged in the narrator's mind; he insists his history 'hexes' him yet vows to live and breathe again through it."},"biting-elbows~my-woman":{"src":"haiku","haiku":"An urgent, desperate love: the speaker can't live without their woman and is willing to sacrifice everything; they cling to each other despite instability and fear.","sonnet":"Against a backdrop of restless energy and the sense that staying still is a kind of death, the speaker declares an all-consuming need for his partner — unable to live without her, willing to endure lies and chaos, committed to her till the end of time. The song swings between a desire for freedom and absolute dependence.","opus":"A restless, desperate declaration that the narrator can't live his current life and can't live without his woman, mixing youthful defiance and self-destruction with a vow to stay by her side till the end of time."},"hilltop-hoods~the-nosebleed-section":{"src":"haiku","haiku":"A celebration of hip-hop culture and front-row fans; rooted in street life struggle, the music becomes a life-saving escape and community for the dispossessed.","sonnet":"The rappers address their most devoted fans — those in the front row at shows — with affection and bravado, weaving together boasts about their craft with memories of struggling and finding salvation in hip-hop. Music and the crowd are presented as the things that give their lives meaning.","opus":"A celebration of the group's dedicated fans in the crowd, with the MCs rapping about their love for the front-row 'nosebleed section' crowd and the passion that keeps them making music despite having little money."},"pink-floyd~another-brick-in-the-wall-pt-2":{"src":"haiku","haiku":"Students rebel against a rigid, authoritarian education system that prioritizes obedience and punishment over learning; they reject thought control and demand freedom.","sonnet":"Students collectively reject the authoritarian control of teachers and the educational system, demanding to be left alone rather than subjected to thought control and humiliation. The refrain positions each act of oppression as just one more brick added to a wall of psychological damage.","opus":"A rejection of rigid, controlling schooling, with students rebuking teachers for thought control and dark sarcasm and insisting the education system reduces them to just another brick in the wall."},"linkin-park~breaking-the-habit":{"src":"haiku","haiku":"A person caught in cycles of self-harm and emotional wounds realizes they are their own worst enemy; they commit to breaking this self-destructive pattern.","sonnet":"The speaker examines a self-destructive cycle of inner conflict, self-harm, and confusion, acknowledging they are the source of their own pain rather than any outside force. The song ends with a resolve to break the habit — to stop the pattern tonight rather than continue it.","opus":"A struggle with self-destructive inner turmoil, the narrator confused and lashing out without knowing why, but resolving to break the destructive habit that has consumed him."},"linkin-park~easier-to-run":{"src":"haiku","haiku":"Haunted by traumatic secrets and shame, the speaker chooses numbness and escape over confronting their painful past; it's easier to run than to stand and face the pain.","sonnet":"The speaker carries a hidden wound from the past — a secret locked away that plays in their mind like a film — and admits that numbing the pain or running from it is simpler than facing it and accepting blame. Despite wishing they could undo every wrong move, they remain paralysed between wanting to change and pretending nothing is wrong.","opus":"A confession that it feels easier to run and numb the pain than to face buried wounds and shame, with the narrator wishing he could change, retrace his wrong moves and take back the pain he carries."},"deftones~hexagram":{"src":"haiku","haiku":"Abstract imagery of worship, violence, and cyclical tragedy; a car bomb and crowds merge into a single, repeated moment, suggesting acceptance or resignation to recurring horror.","sonnet":"The song juxtaposes images of streets crowded with people and animals moving through a charged atmosphere with the sudden, casual detonation of a car bomb, all delivered with an unsettling sweetness. The repeated chant of worship and play frames the violence as spectacle, with the bomb tick and crowd noise becoming the same indistinguishable sound.","opus":"A disturbing, fragmented scene of crowds, cameras and a car bomb amid a chanted 'worship, play' refrain, juxtaposing spectacle and praise with sudden violence that all blurs into the same sound."},"sleep-waker~distance":{"src":"haiku","haiku":"A person watches a dying loved one's mind deteriorate and fade away, unable to prevent their death. Though the person is gone, their memory persists in the narrator, who cannot let go of them.","sonnet":"A narrator watches someone they love deteriorate from a terminal illness, eventually giving that person permission to stop fighting and let go, then grapples with grief after the person dies — holding onto their memory even while knowing they are gone.","opus":"Watching a loved one fade and die from a consuming disease, the speaker gives them permission to let go while insisting that a part of them lives on in memory."},"alice-in-chains~stone":{"src":"haiku","haiku":"A persona compares itself to weathered stone—distant, rough, eroded by time. The song refuses intimacy, warning that the speaker is immovable and will not be shaped by another person's desires.","sonnet":"The narrator presents himself as emotionally impenetrable — a cold, weathered stone that resists being claimed or carved into by another person, warning that time alone will deliver hard truths rather than any closeness they might try to force.","opus":"The speaker likens himself to a cold, weathered stone, refusing to be understood, used, or possessed by someone who wants to leave their mark on him."},"bring-me-the-horizon~join-the-club":{"src":"haiku","haiku":"The song exposes shared mental anguish and alienation, inviting listeners into a collective misery. It portrays a world where disconnection, self-harm urges, and existential despair are universal human conditions.","sonnet":"The song addresses people who feel alienated, self-destructive, and convinced their misery is unique, arguing that feelings of not fitting in and wanting to disappear are near-universal — a dark invitation to shared suffering rather than isolation.","opus":"Addressed to someone terrified and self-loathing, the song reframes their private suffering as universal, insisting everyone is broken in some way and they are not alone."},"m-i-a~paper-planes":{"src":"haiku","haiku":"A hustler brags about fast hustles, border crossings, and casual theft, framing street life and crime as aspirational rebellion. The refrain reduces all desire to taking money by any means.","sonnet":"The narrator performs the persona of a hustling outsider — navigating borders, forging documents, and running street schemes — while satirising the immigrant-as-threat stereotype by playing it up with swagger and gunshot sound effects.","opus":"A hustler's boast about crossing borders, forging visas, dealing, and robbery, delivered with mock-menacing lines about taking your money and murdering."},"queens-of-the-stone-age~make-it-wit-chu":{"src":"haiku","haiku":"The song expresses desire and commitment, repeating a plea to build something together. It dwells on uncertainty and mystery, with the narrator insisting only on knowing what they want: to create something with the listener.","sonnet":"Acknowledging that he understands nothing about love's mysteries or origins, the narrator sets all that aside and focuses purely on his uncomplicated desire to be with someone, anytime and anywhere.","opus":"The speaker admits he understands little about life or love but knows for certain he wants to be intimate with someone, again and again, anytime and anywhere."},"orgy~stitches":{"src":"haiku","haiku":"A twisted love affair cycles between devotion and hatred, with the lover described as beautiful yet deadly and deranged. The narrator binds themselves to the lover to fill emptiness, finding both thrill and destruction in the bond.","sonnet":"The narrator is locked in a toxic, compulsive relationship — simultaneously drawn to and repelled by the other person, describing the bond as something that fills an emptiness even as it is destructive and deranged.","opus":"A toxic, obsessive attachment where the speaker both adores and hates a lover who clings to him, describing the relationship as a thrilling, self-destructive sickness."},"muzz~star-glide":{"src":"haiku","haiku":"A triumphant journey of overcoming struggle and rising above hardship, with a companion guiding the narrator to transcendence. The song celebrates breaking free and achieving flight through perseverance.","sonnet":"A figure burdened by regret and dark days draws strength from someone by their side, building toward a sense of empowerment and liberation — the imagery of spreading wings and burning through the sky standing for rising above what held them down.","opus":"Facing storms and regrets, the speaker draws strength from a supportive presence and imagines coming alive, spreading wings, and rising toward paradise."},"queens-of-the-stone-age~i-sat-by-the-ocean":{"src":"haiku","haiku":"A lover retreats to the ocean seeking escape from a broken relationship built on lies. They come to recognize the relationship was never real, drifting apart like passing ships in darkness.","sonnet":"Someone tries to drink away grief after a relationship ends, acknowledging that the bond was built on lies and that the two are now like ships passing in the night — unable to truly face each other or escape the wreckage.","opus":"After a breakup, the speaker tries to drink away the memory of a lover, reflecting bitterly on lies and the loneliness of drifting apart like passing ships."},"nevermore~enemies-of-reality":{"src":"haiku","haiku":"The song critiques conformity and mass manipulation through media and culture. It frames thinking people as threats to societal norms, positioning resistance to authority as the only authentic stance.","sonnet":"A group of nonconformists defines itself against a society that packages and force-feeds its members mainstream values, positioning themselves as those who refuse to be sanitised or consumed by the ignorance that dominates the world around them.","opus":"A defiant stance from outsiders who refuse to conform, railing against a society that sanitizes, processes, and force-feeds the masses while calling reality the strongest drug."},"crystal-castles~doe-deer":{"src":"haiku","haiku":"The repetition of 'deathray' and 'behind you' creates an atmosphere of relentless menace and pursuit—an unseen threat closing in from behind.","sonnet":"The lyrics consist entirely of the repeated words \"deathray\" and \"behind you\" with no further content, conveying a vague sense of threat or menace but offering no developed subject or narrative beyond that atmosphere.","opus":"The lyrics consist only of the repeated words \"deathray\" and \"behind you,\" evoking menace and pursuit but offering no developed subject."},"linkin-park~crawling":{"src":"haiku","haiku":"Internal psychological torment manifests as self-doubt and loss of control, with the narrator struggling to locate themselves amid pressure and fear. Wounds of self-awareness refuse to heal, trapping them in confusion about reality.","sonnet":"The narrator describes being trapped inside overwhelming anxiety and loss of self-control — wounds that refuse to heal, walls closing in, and a fear that the pressure and inner turmoil will never end.","opus":"An account of inner turmoil and lost self-control, where fear, insecurity, and unhealing wounds blur what feels real and leave the speaker trapped by mounting pressure."},"stone-sour~the-house-of-gold-bones":{"src":"haiku","haiku":"A person refuses to conform and declares independence, willing to burn it all down and stand alone. They turn against those who criticize them, choosing solitary survival over acceptance.","sonnet":"A figure rejects the authority and judgment of those around him, insisting on self-determination even at great personal cost — the House of Gold and Bones serving as a symbol of the place he must face alone, burning with both hope and destruction.","opus":"A defiant declaration of independence and self-determination, the speaker rejecting a contemptible other and choosing to go it alone even if it means burning alive."},"limp-bizkit~autotunage":{"src":"haiku","haiku":"An energetic party invitation and call to rock, celebrating music and collective release. The song centers on giving people what they want—music and excitement—without deeper narrative.","sonnet":"A straightforward party and hype track in which the narrator calls the crowd to get loud, celebrates the energy of a live show, and directs his attention toward women in the audience — no subject beyond the performance itself.","opus":"A party-hyping performance about lighting up the venue, commanding the crowd, and rocking until dawn, promising to give the audience whatever they want."},"limp-bizkit~boiler":{"src":"haiku","haiku":"A hurt lover delivers an ultimatum after being betrayed and mistreated, declaring they must walk away and will never return. They catalog their dependency and suffering, then cut ties completely.","sonnet":"The narrator severs ties with someone who hurt him, declaring that depending on them and giving to them is finished, and that he intends to handle everything himself from now on rather than continue in a damaging relationship.","opus":"After being hurt by someone, the speaker resolves to rely only on himself, declares he is done giving to and depending on that person, and vows never to come back."},"nine-inch-nails~i-do-not-want-this":{"src":"haiku","haiku":"A person caught in depression rejects sympathy and refuses to be defined by their suffering. They spiral through contradictory desires—wanting everything and nothing at once—and reject others' attempts to help.","sonnet":"The narrator is paralysed by alienation and a sense of worthlessness — retreating to bed, rejecting false sympathy, and raging between not wanting his current existence and a desperate, contradictory hunger to experience and matter in the world.","opus":"A portrait of depression and helplessness, the speaker rejecting others' pity while voicing a desperate refusal of his state and a raw craving to matter and experience everything."},"limp-bizkit~shotgun":{"src":"haiku","haiku":"A chaotic street narrative mixing survival, violence, and partying in a neighborhood where guns are commonplace. The song captures recklessness, fleeing from law, and indifference to consequences.","sonnet":"The narrator describes a chaotic night of substance use, running from police, and neighbourhood violence, framing it all as the familiar reality of where he lives — the shotgun of the title a ubiquitous sound in that environment.","opus":"A street-life boast about running from police, dealing weed, jail, and gunplay, framing a rough neighborhood where the sound of a shotgun sends everyone jumping."},"the-dillinger-escape-plan~fix-your-face":{"src":"haiku","haiku":"A vengeful persona judges a delusional person who harms others for amusement and will never learn compassion. The narrator promises to pursue them forever and watch them face the consequences of their cruelty.","sonnet":"The narrator confronts someone he considers deluded and self-destructive — a \"queen of delusion\" who starts fires she cannot control — telling her there is no escape, no comeback, and that she will always be a presence he cannot fully shake.","opus":"A venomous address to a deluded, destructive woman, promising relentless pursuit, no reconciliation, and that she will pay the price for what she has done."},"destruction~the-demon-is-god":{"src":"haiku","haiku":"The song warns that written and spoken propaganda are weapons that corrupt minds and manipulate opinion. It critiques how information is weaponized to control populations and spread hatred.","sonnet":"The song argues that language — especially written and broadcast words — is a weapon used to manipulate and mislead, positioning media and rhetoric as a corrupting force that spreads misinformation, stifles independent thought, and serves as the real demonic power in society.","opus":"A polemic casting the written word and media as weapons that manipulate minds, spread misinformation, and enthrone a demonic force over a corrupt, declining world."},"sonoio~not-worth-remembering":{"src":"haiku","haiku":"A failing relationship haunts the narrator as they recall how things used to be. They desperately wish to escape the memory but cannot, dwelling on the death of what once existed between them.","sonnet":"The narrator reflects on a relationship that has drifted into mutual disconnection, deciding that the way things used to be between the two of them is something he no longer wants to dwell on or return to.","opus":"After a relationship has faded, the speaker dwells on how things used to be, wanting to stop feeling this way and deciding the past is not worth remembering."},"type-o-negative~tripping-a-blind-man":{"src":"haiku","haiku":"A dark tale of cruelty toward a defenseless person; the narrator imagines and eventually causes the death of a blind man and his guide dog. The song condemns playing judge and finding pleasure in others' suffering.","sonnet":"The song condemns those who take pleasure in another's suffering or abuse their power as moral arbiters, framing the narrator as someone sent to judge the judges — the extended closing narrative depicting a man whose cruelty leads to the death of a blind man's guide dog, and then the old man himself.","opus":"A condemnation of people who take cruel pleasure in others' suffering, framed around the image of tripping a blind man; the speaker vows to judge the judges, and a graphic scene depicts a blind man's guide dog killed and the old man dying of grief."},"sparklehorse~piano-fire-life-is-strange":{"src":"haiku","haiku":"Surreal imagery of burnt instruments and decaying objects washing ashore evokes decay and loss. The song conveys alienation—solid surfaces close off sight, rust degrades the heart, and the atmosphere is heavy with endings.","sonnet":"The song assembles surreal, fragmented images — sunburnt waiting, circus people, burning pianos washing ashore, organs giving up — to evoke a state of emotional numbness and detachment, with the repeated question \"how do you feel?\" going unanswered behind marble eyes and a rusted heart.","opus":"A stream of surreal, dreamlike images, burning pianos washing ashore and marble eyes and a rusted metal heart, circling around a numbed inability to feel, see, or breathe."},"linkin-park~bleed-it-out":{"src":"haiku","haiku":"A person expels emotional pain through self-destruction, digging deeper only to discard what they unearth. They perform a cathartic but futile ritual, bleeding themselves out while the world ignores their agony.","sonnet":"The narrator channels self-destructive creative frustration — digging deeper into himself only to discard the results — describing the process of making music as a compulsive bleeding out that leaves him unsatisfied and still driven.","opus":"Using violent imagery of nooses, trenches, and blood, the speaker describes purging pain through relentless expression, digging deeper only to throw it away, and forcing others to confront it."},"deftones~korea":{"src":"haiku","haiku":"Sensory and fragmentary, the song dwells on taste, texture, and carnal closeness between lovers. It evokes a transient encounter marked by animal attraction and physical sensation without narrative or emotion.","sonnet":"The lyrics deal in fragmented, sensory images of physical and erotic encounter — taste, skin, claws, heat — sketching a charged and somewhat predatory intimacy without a clear narrative arc.","opus":"An abstract, sensory piece built from images of teeth, skin, claws, and coming inside, evoking a charged, animalistic physical encounter."},"pro8l3m~2040":{"src":"haiku","haiku":"A Polish futuristic vision depicts a dystopian 2040 where technology dominates life, nature is destroyed, and society is stratified. Dreams are digital, nature is dead, and humans are enslaved to an artificial existence.","sonnet":"Set in a speculative near-future Warsaw of 2040, the narrator moves through a city of bionic implants, flying traffic jams, holographic billboards, VR relationships, and in-vitro steaks, reflecting on how technology and geopolitics have reshaped daily life — framed by a phone conversation about a terrorist attack and a comedic subplot about a stash of cocaine forgotten after a bender.","opus":"A dystopian vision of the year 2040 in Warsaw: bionic implants, autopilot flying cars, water rationing, poisoned air, dead jungles, Mars colonies, and online crimes punished by death, seen through a jaded narrator navigating this ruined future."},"magdalena-bay~something-for-2":{"src":"haiku","haiku":"Two people stand at a relationship crossroads—either build something lasting together or let it collapse. The narrator has lost themselves in the relationship's colors and bleakness, offering everything but facing rejection.","sonnet":"After exhausting herself trying to accommodate a volatile partner, the narrator reaches the end of her patience and asks to either build something real together or stop — a plea for genuine investment rather than being shut out or left to drown.","opus":"Weary of a volatile relationship, the speaker reflects on changing herself and offers a choice: build something together or let it collapse and burn down."},"uneven-structure~hero":{"src":"haiku","haiku":"A supposed hero reflects on their exhausting conquest, questioning whether victory was worth the moral cost. They reject false glory and the illusions that feed it, choosing a new path of authentic struggle.","sonnet":"A narrator who has fought and won many battles surveys his trophies with disillusionment, questioning whether the cost was worth it and rejecting the hollow glories of the past — declaring that the real battles still ahead will be fought on his own terms.","opus":"A conqueror recounts his brutal climb over enemies and obstacles to victory, then questions its cost, dismisses hollow illusions of glory, and resolves to fight on for himself."},"crystal-castles~enth":{"src":"haiku","haiku":"Abstract language describes attempts to evade and avoid, with surfaces degrading and numbness fading. The song resists clear meaning, dwelling instead on disintegration and suppression of authentic expression.","sonnet":"The terse, clinical imagery — fraying uniform, appearances maintained, an anesthetic evaporating and skin dilating — sketches a persona under pressure to conform or suppress itself, eluding scrutiny while the outer structure begins to break down.","opus":"Cryptic, clinical fragments about eluding, evading, and maintaining a fraying appearance, with images of anesthetic and dilating skin suggesting concealment breaking down."},"a-perfect-circle~rose":{"src":"haiku","haiku":"A person breaks free from self-destructive passivity and refuses victimhood, standing up and roaring. They declare agency over their own will and refuse to be a silent sacrifice.","sonnet":"The narrator describes moving from a posture of passive compliance and fearful paralysis — frozen, bending to the wind, playing dead — to one of assertive self-determination, rising and roaring rather than continuing to kneel.","opus":"A portrait of self-suppression and passivity, treading softly and playing dead like a deer in headlights, that turns into a defiant refusal to lay down any longer and a rising assertion of will."},"limp-bizkit~bring-it-back":{"src":"haiku","haiku":"A nostalgic celebration of 1990s rock music and party culture, with the band asserting their lasting power. The song is a callback to earlier hits and an invitation to relive that era.","sonnet":"A boast-heavy performance track in which the narrator claims creative dominance, demands a hard riff and a crowd gone wild, and nostalgically invokes the 90s nu-metal era while asserting that no one else has matched its energy.","opus":"A brash hype anthem demanding the music, riffs, and beats to drive people insane, boasting of dominance and threatening rivals with violent metaphors."},"puddle-of-mudd~psycho":{"src":"haiku","haiku":"A narrator contemplates mental illness and paranoia, reflecting on a chaotic past with a volatile lover. They question whether they or the other person embodies madness, drifting through hazy memories of youth.","sonnet":"The narrator oscillates between admiring a woman he sees as magical and unpredictable, and turning the \"psycho\" label on himself, suggesting it might be his own instability — not hers — that defines the relationship.","opus":"The speaker wonders whether he is the unstable, paranoid one in a relationship with a beautiful but self-destructive woman, nostalgic for their reckless younger days."},"alice-glass~white-lies":{"src":"haiku","haiku":"A person demands comforting lies instead of truth, fearing what reality reveals. They accept manipulation to avoid thinking about hard truths, sacrificing authenticity for comfort.","sonnet":"The narrator describes a dynamic of being managed by comforting falsehoods — told stories to avoid uncomfortable truths, shaped into something smaller and more obedient — and pushes back against a figure (addressed as \"Father\") whose depravity she cannot ignore no matter how much she tries not to think about it.","opus":"A survivor pleads for comforting lies to avoid facing painful truths, describing a curse of seeing what others want, self-erasure, and telling a father figure only what he wants to hear."},"machine-head~be-still-and-know":{"src":"haiku","haiku":"Amid struggle and despair, the song urges resilience and human connection. It insists that hardship is temporary, urging listeners to hold onto each other and endure until dawn breaks.","sonnet":"A call to persevere through collective grief and fear, insisting that hardship is temporary, that human connection and shared strength are what allow people to endure, and that dawn will eventually break through the darkest night.","opus":"An anthem of endurance through hardship, urging connection, unity, and belief that pain will pass, the sun will rise, and defeat can be withstood."},"nine-inch-nails~the-downward-spiral":{"src":"haiku","haiku":"A brief, bleak meditation on suicide as a permanent solution to life's pain, followed by depression and numbness. The song treats death matter-of-factly, capturing a state of blue emptiness.","sonnet":"A brief, unflinching description of a suicide — someone puts a gun to his face and pulls the trigger, the lyric observing with cold detachment that problems have solutions, and what follows is a dissociative wash of blue and fuzzy unreality.","opus":"A stark depiction of a suicide by gunshot, framing it as an easy, final solution to a lifetime of failure, followed by a numb, blue haze spilling from the mind."},"slayer~chemical-warfare":{"src":"haiku","haiku":"Chemical and biological weapons devastate soldiers and populations in a hellish apocalypse. The song portrays mass death through poison gas and the collapse of civilization amid weaponized horror.","sonnet":"The song depicts chemical weapons deployment on a battlefield — soldiers dying silently from a smell, bodies lying motionless, generals retreating — framed as a satanic spectacle in which hell's powers watch over the mass genocide with satisfaction.","opus":"A graphic vision of chemical warfare and mass genocide, with deadly gas annihilating soldiers and civilians and their souls consigned to hell."},"death-angel~dethroned":{"src":"haiku","haiku":"A rebel refuses to be contained or shaped by society, rejecting all authority and institutions. They declare independence and promise violent reckonings with those who would control them.","sonnet":"A figure who has never been contained by institutions — teachers, neighbors, Jesus — arrives at a moment of violent reckoning, positioning himself as both victim of a false savior and instigator of a revolution against whoever currently holds power.","opus":"A rebellious rejection of authority, teachers, and religion, building toward a violent revolution that dethrones a king and kills the false savior."},"in-flames~sounds-of-a-playground-fading":{"src":"haiku","haiku":"Humanity is fading and losing identity, trapped as ghosts in a dying world. The song grieves lost childhood innocence and questions what purpose remains as time runs out.","sonnet":"The song mourns a sense of fading identity and belonging — the narrator describes himself and others as ghosts of a dying breed running out of time, unable to recognise what brought them here, and afraid of being left behind as an era ends.","opus":"A meditation on mortality and being a fading remnant of a dying breed, seeking answers in silence while sensing time running out and an end beginning."},"nevermore~poison-godmachine":{"src":"haiku","haiku":"Media and television are weapons designed to pacify and control through false information and fear. The song frames mass media as an addictive poison that replaces authentic spirituality with manufactured desires.","sonnet":"The narrator indicts television and media as a delivery system for psychological poison — pacifying and controlling the population through useless information and fear, with the narrator positioning himself as the antidote or final nail in that system's coffin.","opus":"An attack on mass media as a poisonous, god-like machine that feeds lies, pacifies, and manipulates, casting the broadcast screen as a false savior people willingly consume."},"megadeth~trust":{"src":"haiku","haiku":"A relationship crumbles under the weight of mutual betrayal and lies, leaving both parties unable to trust. The narrator aches from past wrongs and fears their patterns will repeat.","sonnet":"A relationship has destroyed any capacity for trust on both sides — both parties lied so thoroughly that nothing is left, and the narrator can neither let go of the person nor believe anything said between them, including his own words.","opus":"A doomed relationship poisoned by lust and constant lies, where the couple can no longer trust each other yet cannot fully let go, leaving the speaker begging for help."},"annihilator~wicked-mystic":{"src":"haiku","haiku":"An ancient evil entity feeds on fear and corrupts human hearts, exploiting weakness and breaking moral codes. The song warns that darkness and hatred dwell inside all people and can be awakened.","sonnet":"The song argues that hatred lurks in all people — even the devout — and that weakened or curious minds are vulnerable to a dark internal force that awakens the evil within, breaking moral codes and corrupting from the inside out.","opus":"An account of an ancient malevolent force that feeds on pain and fear and awakens the hatred lurking in everyone, even the holy, as proof of evil in the soul."},"megadeth~sleepwalker":{"src":"haiku","haiku":"A sleepwalking killer imagines violent murders each night, acting out elaborate killing fantasies. The narrator finds dark pleasure in these nocturnal crimes, free from consequences in dreams.","sonnet":"The narrator describes elaborate and graphic fantasies of murdering someone — drowning, garroting, dumping bodies — all contained within dreams, so that each time he wakes up everything is unchanged; the song is a dark comic tour through violent dream-logic.","opus":"From the perspective of a dreaming killer who nightly murders and disposes of victims through elaborate, mob-style methods, then wakes to find it was only a dream."},"soundgarden~the-day-i-tried-to-live":{"src":"haiku","haiku":"A person attempts to seize the day but discovers they are fundamentally dishonest and failures. Each attempt—wealth redistribution, risk-taking, and self-improvement—proves futile and hypocritical.","sonnet":"The narrator describes a failed attempt to genuinely engage with the world and other people — his efforts collapsing into wallowing and self-deception — ultimately concluding that he is a liar and that trying to live is something he has to keep attempting without ever quite succeeding.","opus":"A struggle to truly live and connect that keeps collapsing into futility and self-deception, with the speaker recognizing he was a liar and getting nowhere but dead."},"dz-deathrays~gina-works-at-hearts":{"src":"haiku","haiku":"A woman trapped in nightlife and sex work craves attention despite her emptiness and pain. The song portrays her desire for recognition as both her motivation and her downfall.","sonnet":"Gina works at a venue or club not out of passion or money but for the attention, and the narrator observes her dead-eyed exhaustion with detachment — she is numb, running on drugs and borrowed affection, and he can only transactionally acknowledge what she has become.","opus":"A bleak portrait of Gina, who works at a club, craves attention, and loses herself to drugs, with her dead eyes and wasted smile treated as things that can be bought."},"muse~starlight":{"src":"haiku","haiku":"A person pursues an unattainable dream, fleeing from those who care for them. They seek connection and meaning through an impossible goal, questioning if the struggle is worth continuing.","sonnet":"The narrator is on a journey that carries him away from people who care about him, and he fixates on one person he longs to hold — chasing a distant light that may not be worth the pursuit, but unable to stop or let that connection fade.","opus":"Aboard a ship carrying him away, the speaker chases a distant starlight and clings to a love he refuses to let go of, pleading that it never fade away."},"pro8l3m~teb-200-1":{"src":"haiku","haiku":"Polish narrative of a night spiraling through parties, cocaine use, and hedonism as a group of friends loses track of their stash. The song captures the chaos and moral decay of urban drug culture.","sonnet":"A night of heavy drinking and cocaine use is reconstructed in comedic detail — a group of young men drift through a gym session, bars, a failed attempt at a brothel, and a house party, until the narrator wakes up confused about where his stash went, only to remember he hid it in his other trousers before going out.","opus":"A darkly comic tale of a man who discovers his stash of cash and cocaine missing from a drawer, then retraces a chaotic, drunken night of drinking, drugs, women, and clubbing to piece together where it went, finally recalling he hid it himself."},"rammstein~deutschland":{"src":"haiku","haiku":"Germany embodies a paradox of love and curse, young yet ancient, beautiful yet destructive. The song expresses complicated attachment to a nation defined by contradictions and historical trauma.","sonnet":"The song addresses Germany itself as a lover that the narrator cannot fully love or give himself to — the relationship defined by fire and cold, by pride and shame, by centuries of history that make Germany simultaneously a curse and a blessing, something to damn and to adore.","opus":"An intensely ambivalent address to Germany itself, the speaker torn between loving and damning his homeland, evoking its cold history, division, arrogance, and the idea that what rises high falls deep."},"korn~twisted-transistor":{"src":"haiku","haiku":"A lonely person finds salvation and meaning through music, which reaches inside them and provides solace. The song urges persistence through suffering, affirming that music transcends isolation.","sonnet":"The song is addressed to an outcast who feels lonely and misunderstood, telling her that music is the one thing that truly reaches inside and sustains you when the world is indifferent — hold on to it, because it does understand.","opus":"Music itself is the refuge for a lonely, misunderstood person, personified as a twisted transistor that reaches inside, preaches defiance, and helps them hang on in an unfair world."},"placebo~for-what-it-s-worth":{"src":"haiku","haiku":"A person reflects on love's costs and failures—breaking families, slow decay, and deep emptiness. They end isolated and unloved, questioning whether any sacrifice was worthwhile.","sonnet":"The narrator reflects on personal damage — a slow disease that has drained him, a broken family, near-death — and offers himself to someone with an emptiness inside, positioning the relationship as the only thing left in a life that has otherwise left him alone and scraping by.","opus":"Bidding goodbye at life's end, the speaker recounts a wasting disease, a broken family, and desperate desire, while observing that no one cares for the destitute and friendless."},"pendulum~witchcraft":{"src":"haiku","haiku":"A woman is in danger from a killer approaching through her home. The song builds dread as those around her fail to help, culminating in her disappearance and death.","sonnet":"The song builds a tense domestic horror scenario: a woman is in danger from someone — described as a killer in the hallway — and the urgency mounts as the narrator warns her she has no time left and must get out before he reaches her.","opus":"An urgent warning to a woman in danger, sensing a killer approaching through the hallway and repeatedly urging her to get out and flee far away."},"karnivool~we-are":{"src":"haiku","haiku":"Society has become diseased and stagnant, with people worn down and conforming mindlessly. The song calls for complete reset and renewal, rejecting current structures to face our true shape.","sonnet":"The song diagnoses a collective failure — society is diseased, trust is gone, people shuffle numbly in line, and the wisdom offered by those in charge comes without any real vision; the narrator wants a reset, urging people to face the shape they are in before it is too late for the next generation.","opus":"A collective reckoning with a broken, mistrustful society, fearful of what they have become yet longing to shed their catatonic conformity and reset everything for future generations."},"hilltop-hoods~cosby-sweater":{"src":"haiku","haiku":"A rapper boasts of superiority and dominance, celebrating confidence and swagger. The song is primarily braggadocio about skill, fashion, and unflinching self-assurance.","sonnet":"A confident hip-hop boast track in which the narrator asserts his creative dominance over rivals and compares himself to chess masters and legends, delivering punchlines and cultural references with deliberate playfulness and self-assurance.","opus":"A braggadocious display of rap confidence and dominance, packed with pop-culture and celebrity name-drops, the emcees casting themselves as champions always several moves ahead of rivals."},"ashes-divide~the-stone":{"src":"haiku","haiku":"Humans endure what they cannot change by pretending and letting go, metaphorically trapped like flowers unable to break through stone.","sonnet":"A song about emotional suppression and the futility of pretending pain away — the narrator pushes hardship aside and feigns acceptance, but remains trapped like flowers unable to break through stone.","opus":"About the exhausting work of pushing away pain and pretending everything is fine, and the sense of being stuck like flowers that never break through the stone; the speaker wants to stop denying and simply feel something real."},"celldweller~the-last-firstborn":{"src":"haiku","haiku":"The narrator grapples with death by suicide, questioning his own courage and imagining the darkness of his final moments while wishing things had ended differently.","sonnet":"A firstborn son grapples with a brother's apparent suicide, feeling drawn toward the same fate — he hears his brother's voice beckoning him, wonders whether he has the courage to cross that threshold, and wishes desperately it had ended differently.","opus":"A grieving sibling reckons with a brother's death and an act he can't believe, hearing his voice as an echo and imagining following him to death's door; the recurring vision of a body on the ground and a beckoning shadow ties the family's fate to violence and the wish that it hadn't ended this way."},"crossfaith~wipeout":{"src":"haiku","haiku":"A call to break free from the past, overthinking, and doubt to embrace fearless change and move toward a new future.","sonnet":"A declaration of breaking free from the past and charging toward an unknown future without fear, rejecting overthinking and external judgment in favor of forward momentum.","opus":"A charge toward the future with no turning back, urging fearless belief and flight into something new while refusing to be judged, confused, or held to a perfect plan."},"anthrax~i-am-the-law":{"src":"haiku","haiku":"Judge Dredd enforces brutal justice in a dystopian mega-city through absolute authority and unwavering law.","sonnet":"A tribute to Judge Dredd, the comic-book lawman of Mega-City One, tracing his uncompromising career — from the academy through wars against Soviet invaders — and his role as judge, jury, and executioner who tolerates no crime.","opus":"A tribute to the comic-book lawman Judge Dredd, recounting his brutal enforcement of justice in Mega-City as judge, jury and executioner who fights crime as the ultimate sin."},"machine-head~in-the-presence-of-my-enemies":{"src":"haiku","haiku":"A declaration of righteous anger toward those who harm innocents and destroy hope, vowing to stand merciless over their graves.","sonnet":"A self-described non-violent man declares that anyone who harms children or wages pointless war has forfeited his mercy, and he vows to stand over their grave without grief when they die.","opus":"A man who claims to be peaceful vows merciless violence and vengeance against those who harm children and wage pointless war, imagining standing on his enemy's grave; it frames retribution against destroyers of innocence."},"linkin-park~guilty-all-the-same-feat-rakim":{"src":"haiku","haiku":"Those in power and media manipulate society while escaping accountability, all guilty of the same corruption they exploit and profit from.","sonnet":"An accusation directed at authority figures who preach and point fingers while bearing equal guilt themselves — the rap verse extends the critique to corporate and record-industry greed that manipulates artists and consumers alike.","opus":"An angry rebuke of authorities and moralizers who lecture others while being corrupt themselves, extended in the verse to greedy corporations, media and record companies that manipulate and exploit; everyone pointing fingers is judged guilty all the same."},"machine-head~take-my-scars":{"src":"haiku","haiku":"Rejection of false beliefs and division to find a truer path, carrying the scars of hardship while demanding others open their eyes.","sonnet":"A rejection of a hypocritical belief system — presented as a false messiah that teaches division and numbs people to suffering — contrasted with the narrator's own harder, unsparing experience of life at street level.","opus":"A furious rejection of inherited religion and false messiahs, contrasting the privileged who never had to struggle with the speaker's real pain; he demands people open their eyes and finds his own way to break down the walls."},"heathen~bloodkult":{"src":"haiku","haiku":"Urban violence and gang culture form a brutal code where survival means kill or be killed in an endless, vicious cycle.","sonnet":"A grim portrait of urban gang violence as an inescapable cycle: packs prey on each other by a kill-or-be-killed code, corruption runs through every level of society, and prisons and graveyards fill without end.","opus":"A grim portrait of street violence and a kill-or-be-killed code, where guns, corruption and desensitization to death spread through rich and poor alike in an endless, unsavable cycle."},"artillery~when-death-comes":{"src":"haiku","haiku":"Rising from inner darkness and evil to face one's demons while questioning whether escape is possible before death arrives.","sonnet":"A figure haunted by inner evil and a branded, rootless past asks whether it is possible to shed that burden and live differently, knowing death is always closing in from behind.","opus":"A weary wanderer rising from evil and boredom, carrying blood on his soul down an endless road while asking whether he can cast off fear and live another life before death sneaks up on him."},"queens-of-the-stone-age~3-s-7-s":{"src":"haiku","haiku":"The comfort of lies over painful truth and the cost of ignoring reality, where ignorance becomes a false paradise.","sonnet":"A meditation on chosen ignorance and self-deception — the narrator prefers comfortable lies to painful truth, and reflects on how bluffing and making others forget has become his way of staying afloat.","opus":"A plea to be lied to for comfort, embracing ignorance as bliss because the truth hurts too much; the speaker also boasts of bluffing and getting away with deception, making everyone forget."},"nothing-more~ripping-me-apart":{"src":"haiku","haiku":"A passionate and destructive relationship tears the narrator apart, with the partner simultaneously elevating and devastating him.","sonnet":"A toxic relationship is described as something that simultaneously destroys and sustains — a force that elevates the narrator to godlike feeling but never lets him heal, tearing him apart even as it pulls him back.","opus":"A torturous, addictive relationship that both pulls the speaker together and tears him apart, described through violent imagery of a gun, a throat-grip and a dagger; the other person is his lie, his dream and everything to him even as they destroy him."},"nevermore~the-psalm-of-lydia":{"src":"haiku","haiku":"A dream of witnessing Lydia vanquishing demons and enemies, blending ancient heroism with mystical, surreal imagery.","sonnet":"In a feverish dream set across a thousand winters, the narrator witnesses Lydia — a figure of legacy and uprising — slay demons and confront those who insist it is not yet her time to leave.","opus":"A dreamlike vision in which the speaker relives a thousand past winters to tell the tale of Lydia, whose legacy rises against demons and doom; pain is born from memory of lost pleasures, and voices insist it is not yet her time to leave."},"type-o-negative~september-sun":{"src":"haiku","haiku":"The narrator obsesses over a woman named Elizabeth and her stealing of his soul, unable to escape the memory across years.","sonnet":"A man named Peter is still haunted years later by a woman named Elizabeth — her autumn presence stole something vital from him, and the song circles obsessively around warnings to leave her alone and the unanswered question of why it had to be him.","opus":"A haunted, grief-stricken man screams the name Elizabeth into autumn's decay, insisting she was never there while mourning a lost love that stole his soul over ten years; he begs to be left alone with his tormented memory."},"raubtier~en-hj-ltes-v-g":{"src":"haiku","haiku":"A hero walks the path of battle and sacrifice, facing danger unflinching and choosing honorable death over survival in Valhalla.","sonnet":"A Swedish hymn to the heroic warrior path — a Sigurd-like figure tenderly bids farewell to his woman, grasps his sword, and rides toward battle and death, knowing that blood-written deeds earn eternal memory and a place in Valhalla.","opus":"A Norse-flavored ode to the hero's path, depicting a warrior with divine blood who marches into battle without fear, tender to his woman but iron-handed with his sword, ready to fall and die like a man; his deeds earn eternal glory as he charges toward Valhalla."},"romes~fever":{"src":"haiku","haiku":"After a breakup, the narrator rediscovers his independence and self-worth, celebrating freedom while remaining emotionally guarded.","sonnet":"After a one-sided relationship ends, the narrator celebrates his freedom — buying himself the diamond ring he had saved for his partner, refusing her calls, and insisting she only now realizes what she had lost.","opus":"After a draining relationship, the singer walks away and spends his money on himself, feeling free and 'on fire'; beneath the bravado he admits he was ready to commit and only ever wanted to be hers before she pushed him to the edge."},"nine-inch-nails~down-in-it":{"src":"haiku","haiku":"Once elevated and free, the narrator descends into despair and darkness, becoming what he despises and losing his former self.","sonnet":"A fall from confident self-possession into emptiness — the narrator recalls floating above it all until a tiny pull dragged him down, and now he mourns a former sense of identity and strength that has completely dissolved.","opus":"A fall from a high, invincible feeling into rock bottom, as the speaker who once felt like somebody is now hollowed out and dragged down, the joke on him; imagery of a needle and the world's weight underscores the collapse."},"the-prodigy~voodoo-people-pendulum-remix":{"src":"haiku","haiku":"A celebration of those who fearlessly do what others dare not—the outlaws, the transgressors, the boundary-breakers.","sonnet":"The lyrics are essentially a repeated chant celebrating \"voodoo people\" who do what others dare not — there is no narrative beyond this incantatory invocation of transgressive, magic-tinged defiance.","opus":"Built almost entirely from a chanted refrain about 'magic people' and 'voodoo people' who do what others don't dare do, evoking a mood of daring, mystique and transgression rather than a narrative."},"rammstein~moskau":{"src":"haiku","haiku":"Moscow is portrayed as an aging prostitute, beautiful yet decaying, that captivates and seduces through money and lust.","sonnet":"Moscow is personified as an aging, gold-toothed prostitute — beautiful, alluring, and only available for money — while the Russian chorus ironically hails pioneer children singing Lenin's praises, undercutting Soviet nostalgia with a cynical portrait of the city.","opus":"Introduced as a song about the world's most beautiful city, it personifies Moscow as an aging, gold-toothed prostitute the speaker desires and pays for, mixing lust and disgust; a chirpy Russian chorus about Young Pioneers singing songs to Lenin plays against the sordid imagery."},"nothing-s-carved-in-stone~out-of-control":{"src":"haiku","haiku":"Inner conflict and self-doubt drive obsession, making communication impossible while the narrator struggles to show his true self.","sonnet":"Someone tries to process a pattern of self-imposed isolation and rigid thinking, wondering whether rewinding and starting over would change anything, and tentatively opening up to another person as the only thread connecting inner voices to the outside world.","opus":"A restless, self-doubting speaker who copied others to build himself feels tension and the urge to crash, yet longs to open up and show everything to someone; he senses hidden answers out there and that his feelings will recur no matter how he tries to start over."},"death-grips~hacker":{"src":"haiku","haiku":"A chaotic, surreal boast of technological infiltration and transgression, speaking in absurdist wordplay and provocative imagery.","sonnet":"A chaotic, omnipresent intruder — equal parts hacker, provocateur, and outlaw tourist — boasts of penetrating systems and personal spaces, rendering everything around him unstable or erased while positioning himself outside any cultural or moral grid.","opus":"A frenetic, boastful stream of surreal images casting the narrator as an intrusive 'hacker' who has infiltrated your area and knows your numbers; through absurd, aggressive wordplay it flaunts menace, notoriety and being both most loved and most hated."},"introvert~mending-breaking":{"src":"haiku","haiku":"The narrator endlessly cycles through self-doubt and breaking down, unable to escape the pattern of struggling and failing.","sonnet":"A cycle of barely recovering only to fall apart again — plagued by self-doubt and exhaustion, the narrator keeps having to drag themselves back up alone, with no clear end to the pattern in sight.","opus":"About depression and self-doubt, with empty bottles and constant struggle; the speaker keeps breaking every part of himself and having to pull himself out, caught in an exhausting cycle of mending and breaking."},"limp-bizkit~killer-in-you":{"src":"haiku","haiku":"A homicidal maniac stalks and terrorizes, challenging listeners to confront the violent potential within themselves.","sonnet":"A relentless fictional killer is described in escalating terms of violence, and the listener is challenged to confront the capacity for brutality within themselves rather than wait passively to be victimized.","opus":"A lurid warning about a merciless killer on the loose who slaughters without conscience, urging listeners to fight back and find the 'killer in you' to survive when the moment of truth arrives."},"slayer~seasons-in-the-abyss":{"src":"haiku","haiku":"A sadistic killer finds thrilling stimulation in torture and murder, viewed as an inescapable descent into madness.","sonnet":"A descent into violence and mental dissolution — the song moves through images of self-incision, sadistic ritual, and bodily desecration, framed as a kind of trance in which the self is erased and insanity takes over.","opus":"A descent into a killer's psyche, blending the anticipation and stimulation of murder with instructions to close your eyes and let your mind drain as you die; graphic images of dismemberment and ritual execution render insanity in the abyss."},"bloodhound-gang~the-ballad-of-chasey-lain":{"src":"haiku","haiku":"An obsessive fan's crude sexual fantasy directed at an adult film actress through mock fan letters.","sonnet":"A series of increasingly frustrated fan letters addressed to a porn actress, pleading for a specific sexual act and escalating from polite request to aggrieved demand when no reply comes.","opus":"A comic series of increasingly desperate fan letters to porn actress Chasey Lain, crudely begging for a sexual favor and complaining she never writes back; the humor rides on the vulgar, obsessive fixation."},"celldweller~electric-eye":{"src":"haiku","haiku":"An omniscient satellite watches and monitors humanity, keeping people safe and controlled from above.","sonnet":"Sung from the perspective of a surveillance satellite, the song describes an all-seeing, ever-vigilant system that monitors souls from orbit, promising safety and control to those beneath its gaze.","opus":"Sung from the perspective of an all-seeing surveillance satellite that watches, scans and monitors from the sky, promising to keep you safe while it keeps you under its control."},"make-them-suffer~the-first-movement":{"src":"haiku","haiku":"A boy hears a mysterious voice in the wind and meets a woman who drives him through the city, exploring connection and romance.","sonnet":"A boy who hears a mysterious female voice finally works up the courage to trust her when she pulls up and offers him a ride, and the song traces the tentative, hopeful beginning of a bond that may matter only to him.","opus":"A boy is drawn by a beautiful, haunting voice and dreams of a girl who finally arrives to pick him up for a ride, urging him to be brave and trust himself; unease grows as she begins driving in circles and the future turns uncertain."},"acid-drinkers~consument":{"src":"haiku","haiku":"Consumers mindlessly absorb information and media propaganda, manipulated to act like instruments while surrendering independent thought.","sonnet":"A Polish critique of the passive consumer: a person who eats, drinks, absorbs political noise from radio and TV, and parrots opinions without ever thinking independently — the song asks whether the listener is that consumer.","opus":"A Polish satire of the passive consumer who eats just to eat and parrots political babble from radio and newspapers, bombarded with garbage and information; it challenges the listener to ask whether they too are just a manipulated instrument."},"nine-inch-nails~the-great-destroyer":{"src":"haiku","haiku":"The narrator harbors destructive potential and murder lurking within, hoping surveillance cannot detect this hidden darkness.","sonnet":"Under surveillance by an unseen authority, the narrator conceals an inner urge toward total destruction, fearing that the system watching him will detect the violent potential he harbors and that he himself barely suppresses.","opus":"Set in a surveilled, controlled world where everything is written down and thoughts are pumped into your head; the speaker hides a limitless potential to murder everything, declaring himself the great destroyer while hoping they can't see it."},"zedd~addicted-to-a-memory-feat-bahari":{"src":"haiku","haiku":"Two former lovers cling to the memory of their relationship despite becoming enemies and emotional slaves to the past.","sonnet":"Two people remain in a relationship that has run out of genuine feeling, unable to leave because they are hooked on what it used to be rather than what it is now.","opus":"About clinging to a burned-out, volatile relationship, holding on to who the couple used to be as sentimental slaves running on empty; they're addicted to the memory rather than the reality."},"slayer~angel-of-death":{"src":"haiku","haiku":"The Holocaust horrors are depicted through the perspective of Josef Mengele conducting cruel medical experiments on prisoners.","sonnet":"A graphic account of the atrocities committed by Nazi doctor Josef Mengele at Auschwitz — mass murder, medical torture, and forced experimentation — described without commentary as a catalogue of the Holocaust's systematic horrors.","opus":"A graphic account of the Nazi death camps and the human experiments carried out at Auschwitz, cataloguing torture, mutilation and mass death under the 'angel of death' who sadistically kills in the name of the Aryan race."},"arch-enemy~my-apocalypse":{"src":"haiku","haiku":"The narrator senses personal apocalypse approaching, consumed by morbid despair as hope fades and darkness closes in.","sonnet":"A sense of personal disintegration — suppressed emotions, fading hope, and whispering delusions — builds toward a feeling that one's own end is imminent and already felt approaching.","opus":"An inward collapse of long-buried emotions and fading hope, with distorted voices and dying dreams; the speaker feels a personal apocalypse and the end drawing near."},"sodom~fuck-the-police":{"src":"haiku","haiku":"Police represent oppressive authority using violence and lies to control populations while escaping accountability for their injustice.","sonnet":"An anti-authoritarian screed casting law enforcement and political power as tools of oppression, control, and lies that breed injustice, anger, and eventual rebellion.","opus":"A rebellious protest against corrupt, oppressive authority and the injustice of law, condemning people for being remote-controlled slaves; its chanted refrain rejects the police and calls for standing up to power hungry to kill."},"exodus~deathamphetamine":{"src":"haiku","haiku":"Addiction to methamphetamine destroys life through sleep deprivation, physical decay, and the impossibility of escape.","sonnet":"A detailed portrait of methamphetamine addiction's arc — the pipe, the five-day runs, the sleep deprivation, the paranoia, the physical decay — ending with the user having lost everything and heading toward death.","opus":"A harrowing depiction of methamphetamine addiction, following the pipe, the sleepless multi-day binges and the physical and mental ruin as the user wastes away toward death, losing everything and everyone."},"hadouken~the-vortex":{"src":"haiku","haiku":"A chaotic storm of hedonism and violence forms a swirling vortex of weekends spent pursuing destruction and excess.","sonnet":"Weekend crowds are drawn into a swirling vortex of collective energy — the song compares the scene to colliding particles and incited violence, celebrating the chaotic release of spending every weekend as if the world is ending.","opus":"Frames the wild energy of weekend partying as a gathering storm or vortex that sweeps everyone up, celebrating spending each weekend as if the world's ending amid riotous chaos."},"artillery~10-000-devils":{"src":"haiku","haiku":"Tormented by inner voices and possession, the narrator feels pulled into darkness with the world collapsing around them.","sonnet":"Someone trapped in a cycle of internal guilt, possessed voices, and psychological collapse feels 10,000 devils pulling them under — the mind becomes a torture chamber and life a wreck from which there is no visible escape.","opus":"An inner torment of guilt and sin, where the mind becomes a torture chamber and life feels like a train wreck; ten thousand devils drag the person under, chaining them to the living dead as their world ends."},"daylight-dies~sunset":{"src":"haiku","haiku":"Watching the sky and sun fade, the narrator observes the day's end and the loss of self under the same unchanging skies.","sonnet":"Watching the daylight die — amber fading to gray — becomes a mirror for a self already lost beneath these same skies, and the song sits with that grief without resolution.","opus":"A melancholy meditation on watching the day and sun die, consigning the fading light to the grave; under these same skies of bleeding yellow and cold gray, the speaker lost himself."},"strapping-young-lad~zen":{"src":"haiku","haiku":"An assertion of god-like power and superiority over demons, with aggressive declarations of dominance and defiance.","sonnet":"A volatile, near-incoherent confrontation — shouted declarations that \"we\" are gods, not demons, and a demand to know why the other person keeps staring — frames a fractured sense of being misread or provoked past a point of no return.","opus":"A ranting, grandiose voice insisting it wasn't kidding and struggling to keep both feet on the ground as life spins; it swings between claiming godhood and demons, confronting a watcher and chasing a manic sense of 'zen.'"},"filter~the-only-way-is-the-wrong-way":{"src":"haiku","haiku":"Resistance against forced conformity and manipulation, where every attempt to change the narrator only strengthens his defiance.","sonnet":"A refusal to be remade by someone who keeps pushing and making hollow promises — the narrator insists that every attempt to change them only adds more chains, and that no good path is left when the relationship is this adversarial.","opus":"A defiant refusal to disappear or be changed, addressing someone whose broken promises and pressure only wear the speaker down with chains; he feels forced into a with-me-or-against-me bind where the only way left is the wrong way."},"we-came-as-romans~black-hole":{"src":"haiku","haiku":"The narrator falls into a psychological black hole, fighting gravity that pulls out the worst parts of himself.","sonnet":"A recurring mental collapse — just when the narrator feels stable, a black hole in his own head pulls him back down, drawing out his worst self while words left unsaid sink him further.","opus":"About a mental black hole that pulls the worst part out of the speaker just as he thinks he's safe; he fights its gravity, reaching into the darkness and sinking in words left unsaid."},"deftones~poltergeist":{"src":"haiku","haiku":"A toxic relationship where one partner plays games to provoke the other, creating obsessive tension and control.","sonnet":"The narrator is worn down by a partner who plays games and feigns ignorance, yet despite the frustration and exhaustion he admits he loves this person obsessively — the push and pull of it keeps him hanging on.","opus":"About a toxic relationship game the speaker is sick of yet can't escape, watching the other play dumb to drive him wild; he admits he loves them to death as much as they love the game, and something in it keeps him hanging on."},"avoid~flashbang":{"src":"haiku","haiku":"Losing one's sense of self amid chaos and neurotic manipulation, struggling to remember identity while reality crumbles.","sonnet":"A state of disorientation and rage — the narrator has lost their sense of self, can't see straight, feels manipulated and looked down on, and wants to watch those responsible fall while struggling to remember who they are.","opus":"A disoriented, drug-fueled voice that has lost its head and can't see its path, with only seconds to think and struggling to remember what it's like to be itself; as the world crumbles it turns defiant, wanting to watch its tormentors fall."},"grimes~4-m":{"src":"haiku","haiku":"Late-night encounters at 4 AM with concerns about sickness and falling, invoking Aphrodite and addressing celestial themes.","sonnet":"A late-night wander at 4 AM accompanied by a distant male voice and a creeping sense of illness or unraveling — the hour itself becomes a state of mind, something the narrator keeps falling into.","opus":"A restless late-night scene at 4 AM invoking Aphrodite and constellations, where a man's casual small talk mixes with a warning that 'you're gonna get sick'; the mood is one of falling down and unraveling in the small hours."},"pezet~supergirl":{"src":"haiku","haiku":"An intimate portrait of a partner who is authentic, natural, and unconventional, balancing wild youth culture with genuine connection.","sonnet":"A Polish love song cataloguing the small, specific pleasures of being with a woman who is relaxed, authentic, and at home in his world — smoking together, watching films, drinking wine, driving without a destination — and calling her his supergirl.","opus":"A tender Polish love song cataloguing all the small, everyday things the speaker adores about his girlfriend: smoking, listening to music, watching films, her tattoos and scars, her uninhibited nature and their nights together; he calls her his supergirl and feels they're made for each other."},"yonaka~ordinary":{"src":"haiku","haiku":"A partner pursues the comfort of ordinary routine while losing the spark within, choosing stagnation over genuine passion.","sonnet":"A confrontation with someone who keeps returning to a loveless comfort rather than accepting genuine care — the narrator sees the fire gone from their eyes and challenges them to admit they are settling, not living.","opus":"Addressed to someone stuck in a lifeless, comfortable rut, running back to a partner they never loved; the speaker, who can't be enough for them, presses whether settling for the 'ordinary' is really what they want when the fire inside has gone out."},"queens-of-the-stone-age~i-m-designer":{"src":"haiku","haiku":"A critique of consumerism and manufactured identity where generations sell themselves for wealth and fame rather than authenticity.","sonnet":"A corrosive self-portrait of a generation that has replaced idealism with marketability — the narrator admits to counterfeiting himself for sale while mocking those who claim they cannot be bought, since refusing a low offer is still just negotiating a price.","opus":"A cynical take on a generation for sale, where fame and fortune are the only real things and everything is prostitution and counterfeiting the self; the speaker mocks the idea of selling out while insisting that what truly matters can't be bought or owned."},"limp-bizkit~stuck":{"src":"haiku","haiku":"Greed and materialism trap people in cycles of desperation, with the narrator frustrated by those chasing money at any cost.","sonnet":"A tirade against people trying to take the narrator's money and status — a greedy woman and opportunistic rivals are called out, and the narrator insists he will survive their schemes by staying hostile to anyone motivated by greed.","opus":"A hostile rap aimed at a greedy woman blowing up his phone and chasing his cash, with the speaker boasting of surviving on his music and threatening anyone digging for his money; the hook mocks her as bad luck and 'stuck' on his green."},"limp-bizkit~nobody-loves-me":{"src":"haiku","haiku":"Social alienation and rejection drive the narrator to despair, feeling worthless while watching others succeed and judge him.","sonnet":"A rant about feeling alienated, attacked, and misunderstood — the narrator lashes back at critics and a hostile world while also turning inward with self-loathing, declaring nobody cares and mocking his own victimhood in the same breath.","opus":"A bitter, self-loathing rant about feeling hated, misunderstood and fed up with the world and its deadlines; the refrain 'nobody loves me, nobody cares' swings between defiance and despair, even calling himself a piece of shit."},"serj-tankian~harakiri":{"src":"haiku","haiku":"Mass animal deaths and human destruction suggest societal collapse where love or death are the only choices remaining.","sonnet":"Mass animal die-offs — beached drum fish and blackbirds falling from the sky — are read as signs of a civilization that has built monuments to itself while ignoring the ways of the wise, and the song asks whether humanity can love one another or will simply die together.","opus":"A meditation on mankind born to die and hurting each other with lies, illustrated by mass self-destruction of beached fish and blackbirds falling from the sky; amid warnings that we must love each other or die, the speaker asks when it's time to rise and believes the fallen are finally free."},"serj-tankian~sky-is-over":{"src":"haiku","haiku":"Catastrophic loss and regret pervade as the sky closes in, though yearning for connection amid civilizational decline persists.","sonnet":"A relationship fraying under some larger, unaffordable collapse — the sky being \"over\" signals both personal loss and a broader civilizational exhaustion, and the narrator does not want to let go but cannot hold on.","opus":"A sense that the sky, and the world, is over, tangled with a strained relationship of disappointment and craziness; it turns outward to accuse a destructive force at war with the planet whose persuasion wrecks economies, empires and countries."},"dream-theater~constant-motion":{"src":"haiku","haiku":"Obsessive compulsion drives the narrator in endless motion toward self-destruction, unable to stop or escape the spiral.","sonnet":"An obsessive, racing mind that cannot slow down or let go — tunnel-vision impulses, compulsive yearning, and escalating inner chaos keep the narrator in perpetual motion, unable to find serenity or an exit.","opus":"A portrait of a racing, obsessive, out-of-control mind, driven by dark impulse and unable to let go or stop the burning; tunnel vision, panic and insanity keep the speaker's 'wheels in constant motion' with no way out."},"in-extremo~horizont":{"src":"haiku","haiku":"A man haunted by repeated betrayals and broken promises in a relationship reaches a breaking point when he loses his partner. At the horizon where sea meets sky, he waits for them, consumed by regret over the harm he caused and the futility of redemption.","sonnet":"A man confesses to a long pattern of lying, hurting, and suppressing his feelings toward someone he loved, and only in the moment of losing that person does he fully grasp the damage he caused. He imagines waiting at the horizon where sea meets sky, hoping to be found, but recognises the regret has come too late.","opus":"A remorseful speaker tallies a thousand betrayals, lies, and broken promises, realizing only after losing his love what he has done and reaping the storm he sowed. He longs to wait for her where the horizon meets the sea, hoping she will find him there."},"arch-enemy~i-am-legend-out-for-blood":{"src":"haiku","haiku":"A predator stalks and hunts its victim with single-minded intent, using sensory domination and brute force. The song is framed as a relentless pursuit ending in destruction.","sonnet":"A relentless pursuer stalks a target with single-minded lethal intent, describing itself as harder than steel and driven by a lifelong will to kill. The song is a first-person declaration of predatory aggression with no stated motivation beyond the hunt itself.","opus":"A relentless predator stalks its prey from behind, vowing to hunt it down, tear it apart, and crush its soul. The refrain fixates on a single hunger: being out for the victim's blood."},"arch-enemy~ravenous":{"src":"haiku","haiku":"A figure consumed by hunger for power, flesh, and spiritual conquest performs ritual slaughter to absorb the essence of victims. They invoke a blasphemous godhood through cannibalistic imagery.","sonnet":"A voice claims the power to seize and consume another person's soul and blood, casting itself as a carnivorous, god-like entity feeding on flesh through quasi-religious ritual. The imagery frames violent consumption as a path to divinity.","opus":"A ravenous entity hunts a living person's soul, tearing the flesh and draining the blood to feed on it and become a god. It frames the ritual slaughter as a blasphemous, carnivorous act of taking another's life force."},"machine-head~crashing-around-you":{"src":"haiku","haiku":"Internal trauma and self-doubt are personified as an attacking force that undermines the victim's confidence and relationships. The song reveals that this destructive entity is the victim's own consciousness.","sonnet":"The song is narrated by a person's own inner voice of self-doubt and self-destruction, describing itself as the source of nightmares, shame, paranoia, and the feeling that nothing is ever good enough. The twist at the end reveals the tormenting presence is the self: \"I am you.\"","opus":"The song voices the inner tormentor of self-doubt and self-hatred, the shadow that whispers you're never good enough and makes your world crash down. Its final turn reveals the accuser is the listener's own self."},"soundgarden~black-hole-sun":{"src":"haiku","haiku":"A surreal meditation on alienation and despair using fragmented, dreamlike imagery—a black hole masquerading as healing, a world of decay hidden beneath surface beauty. The song explores shame, disconnection, and the wish for oblivion.","sonnet":"The speaker describes a decaying, oppressive world — stifling heat, dead skies, dishonest times — and pleads with a surreal celestial force, a black hole sun, to come and wash it all away. The refrain carries a desperate, almost ecstatic longing for obliteration of the suffocating present.","opus":"Through surreal, disquieting imagery of disguises, snakes, and a dead-looking sky, the song sits in disgrace and dread and pleads for a black hole sun to come wash it all away. It is a bleak longing for something to erase the surrounding rot."},"rammstein~liebe-ist-f-r-alle-da":{"src":"haiku","haiku":"Sexual desire is framed as predatory and violent, with the narrator using manipulation and imprisonment in fantasy to claim unwilling partners. The song conflates love with conquest and violation.","sonnet":"A man approaches attractive strangers with false charm while privately admitting that love is not available to him; he retreats into fantasies in which the women cannot resist him. The lyrics shift from excluded longing to something darker when the fantasy turns coercive — he holds her and no one sees her weep.","opus":"A predatory speaker eyes beautiful bodies in the sun and admits that getting sex means acting friendly, then retreats into a fantasy where he confines a woman who does not resist. He bitterly repeats that love is for everyone but not for him."},"alice-in-chains~rooster":{"src":"haiku","haiku":"A Vietnam veteran survives combat and its aftermath—physical wounds, psychological scars, and separation from family. Despite death closing in, he refuses to break under the pressure of war.","sonnet":"A soldier in Vietnam navigates constant mortal danger, alienation at home, and the desperate hope of survival, drawing strength from the belief that he simply will not die. The character, nicknamed Rooster, receives a photo of his son from his wife while enduring bullets and disease in the field.","opus":"Told from the perspective of a soldier who feels his own homeland spits on him, the song follows him through combat, mosquito pills, and a dying buddy as he clings to survival. The nicknamed 'Rooster' refuses to die."},"nevermore~emptiness-unobstructed":{"src":"haiku","haiku":"A seeker travels toward spiritual transcendence and answers, confronting emptiness and confusion. Though truth remains elusive, a pained angel offers shelter amid cosmic confusion.","sonnet":"The song expresses a spiritual restlessness — a search for meaning, transcendence, and answers that the confusing, spinning world cannot provide. The speaker yearns to reach a higher plane beyond the valley of deception, finding some comfort in the idea of a \"pained angel\" offering shelter through the darkest hours.","opus":"A seeker asks to be taken to a higher plane and southern shore in search of something more, confronting a confusing world no one understands and a cold, brutal truth. Amid the emptiness he finds a pained angel who shelters and sings through the darkest hours."},"celldweller~i-believe-you":{"src":"haiku","haiku":"Someone who is repeatedly manipulated and exploited by another's lies continues to trust and comply despite awareness of the deception. They rationalize the abuse and their own weakness.","sonnet":"The singer reflects on having been manipulated and exploited — fed lies, made to fight someone else's battles, worn down into passivity — and bitterly acknowledges that he accepted it all. The repeated \"that's all right\" is sardonic, marking how completely the deception took hold.","opus":"A beaten-down speaker describes being manipulated by someone whose lie he was sold and can't escape, fighting their fights until he's left bleeding and spineless. He keeps insisting it's all right because he still believes and submits to them, even as he calls himself a sucker."},"lock-the-basement~come-back-to-life":{"src":"haiku","haiku":"Digital resurrection and eternal imprisonment in a virtual machine replace physical death. The song depicts souls trapped in software, forced into endless cycles of reanimation.","sonnet":"The song presents the idea of digital resurrection: a consciousness is copied and trapped inside a machine against its will, forced into endless, disembodied existence even though it can no longer breathe or see. The narrator is indifferent to the subject's suffering, insisting it keep returning to life inside the system.","opus":"The song imagines copying a soul into a machine to force eternal, infinite life, indifferent to whether the subject can breathe or see. It frames this digital resurrection as cold and coercive, like software prompting to continue."},"kyuss~gardenia":{"src":"haiku","haiku":"A high-powered vehicle becomes a metaphor for sexual prowess and dominance, with the narrator reveling in speed, power, and conquest. The song celebrates unbridled aggression and physical power.","sonnet":"The lyrics celebrate a powerful, road-worn vehicle — a transport queen — through imagery of engine noise, burning fuel, speed, and physical exhilaration, treating the car and the drive as a form of ecstatic communion. The experience is described in hyperbolic, almost sexual terms.","opus":"A revved-up ode to a powerful car, cast in the language of speed, fuel, and sex as the singer merges with the roaring, fuel-burning machine. It's a blur of drags, chrome, and 'making love' to the vehicle."},"slipknot~i-am-hated":{"src":"haiku","haiku":"The narrator declares universal hatred and rejection, positioning themselves as anti-cancer while living in permanent alienation. They reject society while harboring contempt for everyone, including themselves.","sonnet":"The singer projects universal mutual hatred — directed outward at a conformist, mediocre world and inward at a life described as always having been shit — framing himself and the band as a necessary \"anti-cancer\" that has no use for the social games around them. The song swings between defiance and exhausted self-loathing.","opus":"A defiant outcast declares the whole world his enemy, spitting contempt at mediocrity, fakes, and bosses while embracing being fat, ugly, and hated. The song turns alienation into a proud, aggressive creed of self-worth and hostility."},"nine-inch-nails~the-collector":{"src":"haiku","haiku":"A compulsive gatherer of emotional debris, pain, and suffering carries them like living things that multiply and suffocate. Unable to release what they've collected, they become a vessel for others' hurt.","sonnet":"The narrator is compelled to absorb and carry other people's pain, describing himself as dragging a net that collects feelings he cannot release — they grow inside him, multiply, and eventually suffocate him. The act of swallowing it all becomes both compulsion and self-destruction.","opus":"The speaker is a compulsive collector of others' hurt and feelings, dragging a net that gathers pain which then grows and festers inside him. He tries to swallow it all like a dutiful 'good boy,' choking on the overwhelming accumulation."},"machine-head~five":{"src":"haiku","haiku":"A survivor recounts childhood sexual abuse at age five, processing the trauma of violation, threats, and stolen innocence. The song confronts the psychological damage inflicted by a perpetrator.","sonnet":"The song is a direct account of childhood sexual abuse: the speaker recalls being molested at age five, the threats used to silence him, and the lasting psychological devastation that followed. The title refers to his age, and the lyrics make clear the trauma has never left.","opus":"A survivor recounts being molested as a five-year-old, the smell and threats of his abuser, and the lasting suffering and lost innocence. He directs raw rage at the abuser and prays for the memory to go away."},"system-of-a-down~deer-dance":{"src":"haiku","haiku":"Police brutality and riot suppression target peaceful protesters advocating for justice and change. The song critiques militarized force used against the vulnerable and disempowered.","sonnet":"The song condemns police violence against peaceful protesters, depicting riot police with rubber bullets and batons suppressing crowds of young people near the Staples Center in Los Angeles. It frames the state's force as bullying of the weak and calls for resistance against neutrality in the face of injustice.","opus":"The song depicts a protest met by riot police with batons and rubber bullets outside the Staples Center, contrasting peaceful youth with armored, militarized force. It condemns authorities who 'push the weak around.'"},"meshuggah~combustion":{"src":"haiku","haiku":"Human hatred and moral corruption are laid bare in absolute clarity, burning away all illusion. The song frames humanity's capacity for evil as vividly illuminated truth.","sonnet":"The song presents a moment of brutal, unwanted clarity in which all illusions about humanity are stripped away, revealing the full picture of human hatred, greed, and self-deception. The speaker commands the listener to stare directly at this reflection — a portrait painted with lies on a canvas of suffering.","opus":"The song describes a moment of merciless, absolute clarity in which every illusion about what humanity is falls away. What is revealed is the burning hatred and voracity within all people, the human dream incinerated and deceived."},"emigrate~i-m-still-alive":{"src":"haiku","haiku":"A survivor of catastrophe and loss emerges battered but defiant, riding lightning and claiming resurrection. Despite hardship, they persist with renewed electrical force.","sonnet":"A voice on the edge of collapse insists it is still alive despite having given up everything and been drained of energy; it reaches toward light and calls out not to be left behind. The song is built around the tension between exhaustion and a stubborn will to continue.","opus":"A speaker who has given up everything and burned out defiantly insists he is still alive and will come back, powered by an inner light and the fuse of his own attack. It's a charged declaration of survival and resurgence."},"karnivool~l1fel1ke":{"src":"haiku","haiku":"Fragile emotional intimacy is fractured by mistrust and manipulation, with one partner using and abusing the other's vulnerability. The song captures betrayal disguised as lifelike tenderness.","sonnet":"The song depicts a relationship corroded by dependency and substance use, where one person watches another slip away while denying responsibility. The speaker oscillates between fragility and the offer of an escape — a place of ecstasy — that looks more like enabling than salvation.","opus":"The song traces a strained, codependent relationship tangled with drug use, as the speaker feels a 'remedy' kicking in, denies fault, and describes coming down and feeling fragile. He offers to take the other away to a place he calls ecstasy while watching them slip away."},"puddle-of-mudd~nobody-told-me":{"src":"haiku","haiku":"A lost and confused wanderer lacks guidance and direction in life, burdened by childhood pain they carry forward. They struggle to find their way home amid uncertainty and fear.","sonnet":"The speaker describes a life with no clear direction, haunted by a difficult past that weighs him down and a persistent sense of being lost and afraid. Roads and horizons serve as recurring images for the aimlessness and the daily grind of getting through another identical day.","opus":"A directionless speaker looks back on a mediocre childhood he carries like a bag of bricks, lost on a bleak road with nobody to tell him where to go. He can't find his way home and is stuck grinding through the same days in doubt and fear."},"polaris~creatures-of-habit":{"src":"haiku","haiku":"A relationship deteriorates as both partners spiral into blame, resentment, and mutual destruction. What once bound them now traps them in endless cycles of harm and regret.","sonnet":"Two people in a deteriorating relationship accuse each other of cruelty and control, while the speaker insists he cannot be remade into whatever the other person demands. The house is described as hostile, full of old grievances like ghosts in the walls, and both parties are running out of time before the damage becomes irreversible.","opus":"The song dissects a broken relationship where the bond that once held two people together now only holds them back, trapped in an endless eye-for-an-eye. The speaker pleads he can't be what the other imagines and invites them to break him, exhausted by the cycle."},"type-o-negative~white-slavery":{"src":"haiku","haiku":"Drug addiction and its cycle of craving, loss of self, and nightmarish repetition trap the user. The song depicts addiction as a nightmare of erosion and dependency.","sonnet":"The song is about cocaine addiction: a craving that infects its user, consumes money, destroys the self, and ultimately drives a wish for death. The bridge repurposes Pepsi and Coca-Cola advertising slogans to mock the way addiction is sold and normalised.","opus":"The song describes cocaine addiction as a nightmare of restless craving and self-loss, the 'summer snow' that leaves the user rotting and praying for death. It bitterly frames drug use as slowly killing yourself while your money flows away."},"a-perfect-circle~gimme-gimme-gimme":{"src":"haiku","haiku":"Insatiable greed and want drive the narrator to dangerous excess, willing to destroy themselves and others. They demand more without purpose or justification.","sonnet":"A figure describes himself as a loaded gun going off — idle, aggressive, and driven by insatiable, unexamined craving. He acknowledges the world has bigger problems but dismisses that, and admits his relentless need for more will eventually kill him.","opus":"A restless, insatiable voice demands more and more without any reason why, sitting like a loaded gun with nothing to do but shoot off. It knows this craving is self-destructive and could end up killing him."},"testament~more-than-meets-the-eye":{"src":"haiku","haiku":"A prisoner of the mind faces persecution and paranoia until confronting and defeating the demons that haunt them. The song charts recovery from mental torment.","sonnet":"The song moves through two phases: first, a man haunted by paranoia, insomnia, and voices that tell him he is always being judged; then, a turning point where he confronts and defeats those demons, reclaiming control of his fate. The title phrase suggests the internal struggle is not visible from outside.","opus":"The song moves from a person imprisoned and tormented by haunting voices, feeling his life turned upside down and slipping into insanity, to a turn where he conquers his fears and takes control of his fate. It charts a shift from being haunted to mastering his own destiny."},"rammstein~wollt-ihr-das-bett-in-flammen-sehen":{"src":"haiku","haiku":"Sex and love are equated with warfare, violence, and bloodshed, depicting intimate contact as mutual stabbing and death. The song frames desire as destructive conflict.","sonnet":"The song addresses an audience directly with a string of provocative questions about desire for violent, transgressive sex, and then reduces everything to the blunt declaration: sex is a battle, love is war. The rhetoric implicates the listeners in their own appetite for destruction.","opus":"The song taunts the listener with violent, erotic imagery, asking if they want the bed in flames and to lick blood from a blade, equating sex with battle and love with war. It links desire, violence, and death, asking where all the dead come from."},"geddy-lee~my-favorite-headache":{"src":"haiku","haiku":"A nihilistic observer retreats into paranoia and detachment, watching the world collapse while anchoring themselves through numbness. They oscillate between denial and despair.","sonnet":"A man in a state of quiet breakdown describes habitual withdrawal — hiding, watching the sea or the TV, running until he collapses — while admitting he has little to say and is caught between nihilism and an awareness that reality demands more than he can offer. The image of watching the sea and then seeing it on TV captures the blurring of the real and the mediated.","opus":"The song portrays a man on the edge of a quiet breakdown, anchoring himself by watching the sea and TV, caught in cycles of hiding, watching, running, and falling that he can't stop. He apologizes for being so nihilistic and realistic, with little left to say."},"kreator~amok-run":{"src":"haiku","haiku":"A victim of prolonged abuse and soul-theft turns violent avenger, going on a massacre as final act of control and divine punishment. The song is framed as martyrdom through bloodshed.","sonnet":"The song is told from the perspective of someone who has been pushed past endurance by others' cruelty and decides to carry out a mass killing on what he calls his glorious final day, dying himself in the process. The narrative depicts the internal logic of a spree killing without endorsing it.","opus":"Pushed past his breaking point by abuse that scarred his soul, the speaker resolves to unleash a vengeful killing spree so his name will be remembered forever. He casts his rampage as martyrdom, bringing torment and death before dying with his victims."},"austrian-death-machine~get-to-the-choppa":{"src":"haiku","haiku":"A desperate escape from overwhelming threat drives the group toward the only exit—a helicopter. The song emphasizes urgency and the raw will to survive.","sonnet":"The song is built entirely around the premise of an urgent military escape: a group under fire must reach a helicopter immediately or die, while armed enemies try to stop them. The lyrics are a direct, repeated command to evacuate with no deeper subtext.","opus":"Built around the urgent command to reach the helicopter as the only way out, the song stages a frantic combat escape under fire. It cheers pushing forward, shooting attackers, and getting away dead or alive."},"in-flames~darker-times":{"src":"haiku","haiku":"Autumn's return triggers deep insecurity and a sense that troubling times are ahead. The song expresses longing for truth while accepting the burden of living a lie.","sonnet":"A person retreats into invented isolation to manage insecurity and fear, waiting for someone to offer a better plan while walking a thin line between honest unhappiness and the lie of performed happiness. The mood is one of suppressed anxiety and the uneasy truce of getting by.","opus":"The song sits in a season of insecurity and fear, questioning who is really in charge as darker times set in and someone hides in invented isolation. It settles into knowingly living a lie, letting in fleeting happiness while walking a thin line."},"artillery~uniform":{"src":"haiku","haiku":"Authoritarian control and coercive conformity suppress individuality and free thought, with state power hiding corruption. The song warns against silent surrender to oppression.","sonnet":"The song describes living under an authoritarian surveillance state where fear is constant, informers could be neighbors, and the only safe choice is silence. The uniform of the title represents the faceless enforcers who keep order through threat and control.","opus":"The song evokes a paranoid surveillance state where you can't trust friends or neighbors and must shut your mouth to survive, with informers hiding everywhere. It targets the uniformed 'public servant number one' as a menacing figure playing with power like a child with a gun."},"arch-enemy~carry-the-cross":{"src":"haiku","haiku":"The burden of perpetual suffering, judgment, and cyclical pain becomes an inescapable cross. The song depicts reincarnated torment and strength drawn from endless hardship.","sonnet":"The song uses the image of carrying a cross as a metaphor for a lifetime of burden, suffering, and cycles of pain that repeat without end. Each time the speaker is beaten down, the cross holds them in place while others walk away laughing.","opus":"The song casts life as an endless burden carried like a cross through the ages, watched and mocked by others waiting for the bearer to fall. It frames the suffering as damnation and confession, with pain itself becoming a source of strength to keep going."},"system-of-a-down~attack":{"src":"haiku","haiku":"Collective resistance rises against oppressive systems, propaganda, and violence inflicted on civilians. The song calls for unified assault against servitude and environmental destruction.","sonnet":"The song calls for collective uprising against propaganda, colonial violence, and the destruction of homes, schools, and hospitals by state power. It frames the coming attack as a necessary response to years of manufactured compliance and the human cost of military aggression.","opus":"The song rails against war, propaganda, and cold 'steel machines' that consume human euphoria, calling for an attack on servitude and years of manipulation. It catalogs the bombing of homes, schools, hospitals, and villages as the horror being resisted."},"serj-tankian~weave-on":{"src":"haiku","haiku":"Sisters as weavers stitch together the suffering of war, poverty, and injustice into a fabric of human pain. The song mourns the blood-soaked threads of conflict and corruption.","sonnet":"The song addresses women — \"sisters\" — who must weave the full record of human suffering: war, poverty, crime, displacement, unmarked graves. The act of weaving with blood-soaked thread becomes a metaphor for bearing witness to atrocity and continuing to endure despite it.","opus":"Addressing the fates as 'sisters' weaving on a loom of pain, the song asks them to stitch together the world's poverty, crime, war, and unmarked graves with blood-red thread. It condemns love of money and race and hate of neighbors, ending with a vow to endure whatever must come."},"dream-theater~pull-me-under":{"src":"haiku","haiku":"Life as an inescapable current pulls the narrator deeper, moving toward mortality with ambiguous acceptance. The song explores surrender to fate, honor, and the pull toward death.","sonnet":"A figure confronts mortality and the accelerating passage of time, resolved to face what is coming without fear while driven by honor and a need to right wrongs. The closing fragment from Hamlet — \"Oh that this too, too solid flesh would melt\" — anchors the song's meditation on the desire to dissolve into something larger.","opus":"The song reflects on mortality and a world spinning without the speaker as every breath brings him closer to his last, yet he declares he is not afraid. Echoing Hamlet's imagery, he feels only honor and spite and gives himself over to being pulled under."},"alex-klingle~colors-back":{"src":"haiku","haiku":"A fading connection between lovers slips away as intimacy fades and fragility sets in. The song captures the desperate wish to restore lost color and feeling in a dying bond.","sonnet":"Two people in a fragile, fading connection experience a moment of unexpected renewed feeling — \"colors back\" — that briefly restores the sense of closeness between them. The lyrics are fragmentary and impressionistic, evoking physical touch and the fear of drifting apart.","opus":"The song captures two people fading fast in a relationship, scared of the hurt if they crash, yet finding a spark of renewal in 'colors back' as they feel each other's touch. It lingers on breathing as one and the fragile pull between fear and connection."},"onslaught~godhead":{"src":"haiku","haiku":"Organized religion is condemned as corrupt manipulation that weaponizes faith to control populations. The song attacks religious authority as predatory and evil.","sonnet":"The song attacks organised Christianity as a con built on lies, abuse, and violence, depicting the church as a predatory cult that produces evil while preaching innocence. The repeated phrase \"children of god\" is turned into an accusation.","opus":"The song is a furious attack on organized Christianity, portraying it as a corrupt cult of lies, war-mongering evangelism, and abusive priests. It brands the 'children of god' as pure evil and vows to see them all in hell."},"carcass~316l-grade-surgical-steel":{"src":"haiku","haiku":"Love is depicted as cold, heartless, and militaristic—a metallic hardness that cuts and betrays. The song equates romance with surgical precision and emotional destruction.","sonnet":"The song declares a cold rejection of love and romantic vulnerability, arguing that love is nothing more than varying degrees of lust and that opening your heart only leads to pain. The surgical steel of the title is the hardened, emotion-proof state the speaker has chosen.","opus":"Using cold surgical and cardiac imagery, the song denies the existence of true love and reduces it to varying degrees of lust, mistrust, and mutual harm. The heart is recast as a cast-metal object, and the speaker warns against fooling yourself with claims of love or care."},"bloodhound-gang~pennsylvania":{"src":"haiku","haiku":"A parade of 1990s cultural detritus and low-class kitsch defines an unremarkable life registered in Pennsylvania. The song celebrates mediocrity and regional anti-identity.","sonnet":"The song builds an extended catalogue of things that are culturally déclassé, embarrassing, or past their time — all labelled \"we\" — and then places a sentimental, anonymous love against this backdrop of mediocrity: the other person is a briefly felt impulse on a postcard, while the speaker is a nameless airbrushed heart on a Subaru registered in Pennsylvania.","opus":"The song piles up absurd, trashy pop-culture references and crude images to sketch a low-rent identity, tying it all to a nameless heart airbrushed on a Subaru's license plate registered in Pennsylvania. It's a self-mocking portrait of tacky Americana rooted in that state."},"deftones~romantic-dreams":{"src":"haiku","haiku":"A hypnotized admirer watches a partner's fleeting, cyclical moods while yearning for the night to never end. The song captures obsessive desire and magical thinking in attraction.","sonnet":"The speaker is transfixed by someone whose changing nature he watches closely, promising devotion and wishing the night they share would never end. The mood is hypnotic and intimate, built around the desire to remain suspended in a single moment of closeness.","opus":"The song fixates on an alluring figure whose changing phases the speaker watches, hypnotized by their name and wishing the night would never end. He urges them to seize their dream now while the stage is theirs."},"system-of-a-down~aerials":{"src":"haiku","haiku":"Life flows inevitably forward like a waterfall, with humans swept along in cycles of wanting without commitment. The song invites mental transcendence through surrender and freedom.","sonnet":"The song describes life as a continuous flow — a waterfall and a river — through which people move, lose themselves, and find something larger than the individual self. The \"aerials\" in the sky represent the freedom gained when the small, ego-driven mind is released.","opus":"Using the image of life as a waterfall where we lose ourselves in the river and find it all again, the song urges letting go of the 'small mind' to free your life. It contrasts those who want to play and choose against never wanting to stay or lose, pointing toward an eternal prize."},"tv-on-the-radio~happy-idiot":{"src":"haiku","haiku":"Post-breakup numbness and self-harm mask the pain of abandonment. The narrator embraces deliberate stupidity and self-destruction to avoid confronting grief.","sonnet":"After being left by someone, the speaker shuts down his mind deliberately to avoid the pain of the loss, embracing a state of deliberate blankness — waving at cars, banging his head against the wall — because ignorance is the only way he can keep functioning. The \"happy idiot\" persona is a coping mechanism, not a genuine state.","opus":"After a breakup that sent the speaker on a long way down, he tries to numb the pain by playing a 'happy idiot,' waving at cars and banging his head against the wall until he feels nothing. Shutting it all off is his way to keep his mind off the person who left."},"zheani~whore-of-babylon":{"src":"haiku","haiku":"A biblical whore figure reclaims transgressive power through explicit sexuality and blasphemy, challenging moral authority. The song invokes drunken ecstasy in forbidden pleasure and rebellion.","sonnet":"The song adopts the voice of the Whore of Babylon from Revelation — arrayed in scarlet, drunk on the blood of saints — as a figure of transgressive, unapologetic power. The speaker challenges critics who try to diminish her, embracing the role of the outcast flame that burns brighter than those who condemn her.","opus":"Drawing on the biblical Whore of Babylon drunk on the blood of the saints, the speaker identifies with that fiery, defiant figure who would rather be hated than hold back the truth. She hurls scorn at a jaded rival while bursting into flame and drowning in the identity she's claimed."},"gorillaz~el-ma-ana":{"src":"haiku","haiku":"Summer's passing marks loss of youth and the fading of a precious connection. The narrator reaches toward a future reconciliation while acknowledging separation and time's grip.","sonnet":"The speaker reflects on feeling abandoned and estranged — summer has turned cold, a relationship is slipping away — but holds onto a quiet, recurring hope that the other person will one day want to be with him. The tone is melancholy and patient, not angry.","opus":"The song mourns a fading connection with imagery of summer no longer knowing the speaker and love slipping into dying, as he insists he's fine while losing his mind. He clings to the hope that maybe in time the other will want to be his."},"korn~insane":{"src":"haiku","haiku":"Internal cancer and psychological torment consume the narrator's life, with no escape or relief from the weight of persecution. The song describes hopelessness and isolation.","sonnet":"The speaker describes an internal torment — a persistent, growing force he calls a cancer — that eats away at him, dominates his thoughts, and exposes everything he tries to hide, leaving him horrified and isolated. He acknowledges being beaten down and blames himself for what he cannot contain.","opus":"The song depicts life eaten away from the inside by a spreading, cancer-like affliction that grows in the head and leaves the speaker horrified and beaten down. He blames himself, feels unable to be understood, and repeatedly calls the state insane."},"porcupine-tree~anesthetize":{"src":"haiku","haiku":"Pharmaceutical numbness and media distraction anesthetize modern life, creating a zombie-like detachment from reality. The song contrasts this apathy with fleeting moments of genuine human connection.","sonnet":"The song traces a state of medicated, media-saturated numbness — pills, TV, shopping malls, zombie-like drifting — and beneath it a suppressed memory of a particular warm day by the water when someone was \"stolen\" from the speaker in the moment the sky went dark. The personal loss is buried under layers of apathy.","opus":"The song portrays a numbed, medicated existence of apathy, TV, malls, and shuffling like a zombie, where nothing feels real and even a gun in hand seems tempting. It critiques a hollow consumer culture that anesthetizes people, closing on a wistful memory of watching waves at the shore."},"health~stonefist":{"src":"haiku","haiku":"Two people acknowledge that love has died between them, yet they persist forward unable to return or change. The song expresses resignation to losing the spark of intimacy.","sonnet":"Two people acknowledge they have moved past the point of love — it is no longer in their hearts — yet remain possessed by what they have lost rather than moving freely forward. The song circles around the paradox of knowing something is over while being unable to let go of it.","opus":"The song dwells on a relationship where both people know love is no longer in their hearts, staying possessed by what they lost and unable to go backwards or grow young again. It repeats the bleak acknowledgment that there is no coming back."},"limp-bizkit~the-story":{"src":"haiku","haiku":"Celebrity, fame, and cultural icons inevitably rise and fall in cycles of glory and disposability. The song reflects on how every hero becomes replaceable and forgotten.","sonnet":"The song reflects on the rise-and-fall arc of fame and identity, arguing that heroes are disposable, glory is temporary, and everyone eventually loses whatever made them relevant. It addresses people who have faded — fighters, actors, rappers, scene figures — and the hypocrisy of those who live off their past image.","opus":"The song reflects on fleeting moments of glory and how heroes and fame are disposable, with everyone eventually coming down from their highs. It mocks fighters, rappers, actors, and hipsters who can't do their thing anymore, urging people to live and let die."},"bring-me-the-horizon~fuck":{"src":"haiku","haiku":"A brief, intense affair plays out knowing its imminent end, with bodies as the only language two people share before final separation. The song frames fleeting intimacy as both transcendent and doomed.","sonnet":"Two people spend a single, intense night together knowing it will not last, framing sex and closeness as the only goodbye they know how to make. The song repeatedly returns to the impossibility of parting from someone you have barely begun to know.","opus":"The song is a reckless plea to spend a fleeting night having sex until the sun or their hearts give out, a night to remember and a day to forget. Beneath the urgency runs the ache of young love and the fear of saying goodbye before hello was even said."},"the-prodigy~fuel-my-fire":{"src":"haiku","haiku":"Betrayal and distrust fuel the narrator's rage and motivation, transforming grief into a grudge that burns indefinitely. The song frames anger as a renewable fuel for survival.","sonnet":"The speaker directs sustained anger at someone who betrayed and lied to them, declaring that the wound and the grudge are permanent and that the treachery only intensifies his drive. The betrayal becomes the fuel for ongoing rage rather than something to be forgiven.","opus":"The speaker sarcastically thanks a liar who betrayed his trust, channeling that betrayal into rage and a grudge he'll hold for life. People like the one who stabbed him in the back only fuel his fire."},"type-o-negative~nettie":{"src":"haiku","haiku":"A mother's unconditional compassion and sufferance become the narrator's salvation, despite their own failures. The song is a tribute to maternal sacrifice and forgiveness.","sonnet":"The song is a tribute to the singer's mother — an empathetic, deeply religious woman from Brooklyn who weeps nightly for others' pain and responds to her son's failings not with anger but with prayer. He acknowledges her compassion has been its own form of suffering and calls her the most beautiful person he has known.","opus":"The song is a tender tribute to Nettie, a compassionate woman whose empathy for others' pain becomes her own suffering, who loves the flawed speaker despite the grief he caused. He comforts her, promising to catch and be there for her as she has been for him."},"rob-zombie~feel-so-numb":{"src":"haiku","haiku":"Disconnection from moral responsibility and the world produces a strange euphoria, where darkening the sun feels good. The song captures amoral numbness and detachment.","sonnet":"The song layers surreal, frenetic imagery — midnight drives, radio chatter, brain trash, porn flash — over a refrain of feeling simultaneously good and numb, good and bad, asking \"what have I done\" against a blacked-out sun. The overall effect is of dissociated, overstimulated modern life producing a state of feeling everything and nothing at once.","opus":"Over restless, surreal imagery of midnight drives, radio talk shows, and a blackened sun, the speaker oscillates between feeling good, bad, and numb while asking what he has done. It's a disoriented, drug-hazed rush urging the listener to feel it and make it all right."},"exodus~raze":{"src":"haiku","haiku":"A call to indiscriminate destruction and chaos—starting fires, burning everything down without consequence or hesitation, reveling in demolition for its own sake.","sonnet":"A thrash-metal call to total destruction: the narrator invites a companion to burn and level everything in sight, explicitly dismissing consequences and reveling in pure demolition for its own sake.","opus":"A gleeful call to total destruction, urging listeners to burn and demolish everything without caring about consequences or taking any blame."},"annihilator~the-trend":{"src":"haiku","haiku":"Criticism of those who plagiarize, fake authenticity, and mindlessly follow trends instead of creating something original. The song accuses trend-followers of being parasites who steal from previous generations.","sonnet":"An attack on opportunists who imitate and exploit a music culture they never genuinely belonged to, condemning them as corporate parasites who sell counterfeit identity to a naive young audience.","opus":"A scornful attack on a poser who fakes authenticity and chases whatever is fashionable, dismissed as a parasite selling counterfeit trends to a gullible young generation."},"nevermore~your-poison-throne":{"src":"haiku","haiku":"An address to someone sitting on a metaphorical throne of poison—obscuring lessons and causing spiritual or emotional harm. The speaker challenges the listener to rise above their corrupted position.","sonnet":"The song challenges someone who clings to a position of corrupted power, arguing that their \"poison throne\" blinds them to necessary truths and that all their plans will ultimately collapse.","opus":"An address to someone enthroned on their own poison, questioning what they want from the world and warning that their arrogance blinds them to a coming reckoning before it all falls apart."},"megadeth~rust-in-peace-polaris":{"src":"haiku","haiku":"A bleak meditation on nuclear warfare personified as the Polaris missile system—depicting it as a god of annihilation that judges humanity and spreads disease through radioactive fallout, implying the inevitability of nuclear winter and global destruction.","sonnet":"Told from the perspective of a nuclear-armed submarine missile, the song depicts the horror of nuclear war — the weapon boasts of its indiscriminate destructive power, while the lyrics describe a world destroyed by a third world war and left in nuclear winter.","opus":"Voiced from the perspective of a nuclear missile that boasts of ruling land, sea, and air and passing judgment on humanity, the song depicts nuclear holocaust, a poisoned dying planet, and warheads left to rust after annihilation."},"megadeth~devils-island":{"src":"haiku","haiku":"A prisoner on Devil's Island awaits execution, haunted by the memory of a woman associated with evil. The song moves between present damnation and past betrayal, ending with themes of judgment and redemption through burning.","sonnet":"A prisoner awaiting execution on a remote, inescapable island reflects on the chain of events that led him there, involving a woman whose evil he could not escape, culminating in his final walk to the stake.","opus":"A condemned prisoner awaits execution on an inescapable island surrounded by sharks, haunted by an evil woman and the memory of the night that damned him, resigned to remain there even beyond death."},"nightwish~wish-i-had-an-angel":{"src":"haiku","haiku":"A confession of lust and moral compromise—the speaker desires angelic salvation or connection but recognizes their own capacity for cruelty and betrayal. Beauty is entangled with darkness and hypocrisy.","sonnet":"The narrator is consumed by lust and self-destructive desire, longing for an angel while acknowledging that old loves and lies are hard to shed, and that beauty is inseparable from dark impulses.","opus":"A confession of lust and self-destruction, longing to possess another person's 'angel' for a single moment while admitting the cruelty, betrayal, and dark thoughts wrapped up in that desire."},"kyuss~hurricane":{"src":"haiku","haiku":"An expression of emotional numbness, resignation, and suffocation. The speaker feels nothing, cannot breathe, and has lost the capacity to move forward—their life has destroyed them.","sonnet":"A portrait of emotional numbness and physical suffocation — the narrator feels nothing and cannot breathe, overwhelmed by a life that has worn them down completely.","opus":"A numb, suffocating state of mind, insisting on feeling nothing while begging to be lifted up out of suffering that has overwhelmed the speaker's life."},"the-prodigy~invaders-must-die":{"src":"haiku","haiku":"A defiant battle cry built on the repeated slogan 'Invaders must die'—a call to resist and destroy those who would invade or destroy.","sonnet":"A stark, defiant declaration of identity: the band asserts its presence and issues the uncompromising command that invaders must die, with no elaboration beyond the repeated slogan.","opus":"Built almost entirely on the chanted declaration that invaders must die, an aggressive slogan of defiance against intruders."},"nine-inch-nails~shit-mirror":{"src":"haiku","haiku":"A transformation into something monstrous through the consumption of others' hatred and fear. The speaker becomes increasingly unrecognizable, feeding on loathing while mutating into an alien creature.","sonnet":"The narrator undergoes a disturbing personal transformation — acquiring new power and appetite while feeding on others' hatred — and observes with unease that he is becoming something unrecognizable, culminating in a violent act he admits he knew was wrong all along.","opus":"A person feels themselves mutating into something new and unrecognizable, embracing the change even as they hint at having crossed a line and left someone dead on the bathroom floor."},"number-girl~eight-beater":{"src":"haiku","haiku":"A Japanese-language track about restlessness and repetition in urban life. The speaker wanders through a city of feedback and transience, cycling through sexual desire and loss of communication, feeling trapped in patterns.","sonnet":"The song captures a restless, anxious state of urban drifting — the narrator describes living in a city of feedback and anxiety, unable to communicate, caught between fleeting sexual impulse and Buddhist impermanence, wandering without direction in a Japanese style.","opus":"A restless, intoxicated narrator drifts through a feverish Japanese city of alienation and friction between minds, describing surging sexual impulses, the Buddhist sense of impermanence, and an inability to truly communicate amid endless feedback."},"pezet~slang-2":{"src":"haiku","haiku":"A Polish-language song documenting street slang and vernacular from the speaker's neighborhood. It catalogs colloquial terms for drugs, money, relationships, and lifestyle while acknowledging that everyone, regardless of education, speaks this slang.","sonnet":"A Polish hip-hop glossary of street slang: the narrator systematically explains the meaning of neighbourhood expressions — from drug and drinking terms to everyday insults and greetings — presenting slang as an ingrained part of his community's identity rather than a sign of criminality.","opus":"A playful catalogue of Polish street slang, translating the coded words the narrator's neighborhood uses for drugs, money, deals, greetings, and people, celebrating slang as a shared habit that has stayed with them for years."},"thornhill~arkangel":{"src":"haiku","haiku":"A twisted love song where the speaker claims someone as their angel while also confessing to being a killer who has lost his way. The desire is possessive and violent—hearts belong to the speaker, and violence is reframed as passion.","sonnet":"An obsessive, possessive pursuit of a woman the narrator calls his angel — he is convinced her heart belongs to him, sees through her denials, and confesses to a violent, self-destructive compulsion that has left him lost.","opus":"An obsessive, possessive fixation frames a lover as an 'angel' the speaker demands, veering into imagery of himself as a killer who has lost his way and wants her to break and to hurt him."},"cherryfilter~cherry-filter":{"src":"haiku","haiku":"A love song in Korean dialect expressing deep affection and gratitude. The speaker dedicates their strength and songs to the beloved, asking to be allowed into their heart despite feeling foolish or unworthy.","sonnet":"A Korean-language declaration of love and gratitude: the narrator acknowledges past fears and failures but finds the strength to carry on because of the person they love, promising to deliver their heart and all their hopes through music.","opus":"A heartfelt love song in which the singer, calling themselves silly, offers their whole story, heart, and hopes through music to the person they love, wanting to be uplifted by that feeling."},"bring-me-the-horizon~throne":{"src":"haiku","haiku":"The band reflects on 'Throw me to the wolves'—a song about how adversity and those who want to see you fail actually become the force that shapes who you are and drives your success.","sonnet":"This is a spoken commentary track rather than a song with lyrics: the vocalist recounts how \"Throne\" was written as a defiant comeback, inspired by the idea that the people who tried to break him ultimately made him who he is.","opus":"Spoken commentary in which the singer explains that the song 'Throne' came from the idea that the people who break and hurt you, and who want to see you fail, are the ones who made you who you are."},"poppy~chic-chick":{"src":"haiku","haiku":"A defiant assertion of independence and self-assured power. The speaker is assertive, self-protective, and demands respect while making her own decisions without apology.","sonnet":"A self-assured declaration of female dominance and independence — the narrator presents herself as aggressive, classy, and unapologetically in control, demanding others bow to her authority and dismissing anyone who objects.","opus":"A brash declaration of female self-sufficiency and defiance, with the narrator crowning herself her own bodyguard and matriarch and daring anyone who dislikes her attitude to deal with it."},"system-of-a-down~soil":{"src":"haiku","haiku":"A requiem for a friend who died by suicide, exploring themes of confidence, weakness, and the inability to prevent someone's predetermined fate. The song grapples with the paradox that evil exists within all of us.","sonnet":"A raw elegy for a friend who died by suicide — the narrator recalls the shock and grief of the loss, wrestling with helplessness and rage, and acknowledging that the man's inner demons drove him to an act no one around him could prevent.","opus":"A raw response to a friend's suicide by gunshot, mixing grief, disbelief, and anger while wrestling with the idea that evil lives within human skin and demanding to know why he was taken away."},"frost~pocket-sun":{"src":"haiku","haiku":"A contemplation of love as a source of escape through time and alternate possibilities. The speaker has experienced profound journeys through history and fantasy, yet the beloved remains their only constant anchor.","sonnet":"The narrator describes a personal talisman — a \"pocket sun,\" a window-like source of light — that anchors him across disorienting journeys through time and imagination, expressing a longing to rewind and hold onto someone who feels like a lifeline.","opus":"Through surreal images of watching Rome burn and traveling through time until he becomes his own ancestor, the narrator clings to a beloved 'pocket sun' as the one thing he wants amid everything coming undone."},"skyharbor~ethos":{"src":"haiku","haiku":"A song about shedding shame, transformation, and self-realization. The speaker has changed and is not who others perceive; they are seeking a second chance and learning to manifest the life they want to see.","sonnet":"A song about personal reinvention after being misunderstood and dismissed — the narrator sheds a false identity, clears away internal ghosts, and insists that change is possible, reaching toward a life lived with genuine purpose rather than shame.","opus":"A weary plea for a second chance and self-renewal, insisting that everyone can change as the narrator sheds his old self, clears the ghosts from his mind, and rises past helplessness to survive."},"health~tears":{"src":"haiku","haiku":"A fragmented meditation on letting go, loss, and the dissolution of connection. Memories are distorted, souls are surrendered, and the speaker and listener are abandoned to die alone.","sonnet":"A fragmented meditation on love, surrender, and dissolution — a voice urges letting go and giving up, while the imagery of never waking and dying alone suggests that the relationship or the self it sustained is beyond saving.","opus":"A bleak farewell between two people, asking love to save them once while urging the other to let go and give up, arriving at the conclusion that we die alone."},"limp-bizkit~intro":{"src":"haiku","haiku":"An energetic call-and-response announcement that Limp Bizkit is here and the moment is real—a brash introduction that sets the tone with repeated 'Who's in the house?' and 'Bring it on' attitude.","sonnet":"A short hype-up intro track in which the band announces its own arrival and invites the crowd to respond, functioning as a live-concert-style call-and-response opener with no narrative content.","opus":"A hype introduction announcing the band's arrival, repeatedly asking who's in the house and answering that Limp Bizkit is."},"polaris~pray-for-rain":{"src":"haiku","haiku":"A meditation on emotional exhaustion and the hollowness of hope. The speaker has sacrificed everything to no avail, watches hope fade, and contemplates their own corruption and solitude as they await redemption that may never come.","sonnet":"The narrator describes a slow emotional exhaustion — draining optimism until hollow — and a cynical, faithless view of himself that contrasts with who he once was; he clings to the faint hope that some renewing force will come, like rain extinguishing the fire in him.","opus":"A meditation on emotional depletion and self-doubt, where the narrator drains himself dry, faces his worst enemy in the mirror, and clings to a last ember of hope while confronting mortality, guilt, and the fear of dying alone."},"rammstein~hilf-mir":{"src":"haiku","haiku":"A German-language song told from a child's perspective discovering fire—playing with matches when alone, becoming fascinated and burned. The refrain 'the fire loves me' becomes ambiguous: does fire love or destroy? Ends with resurrection from ashes.","sonnet":"Retelling the cautionary tale of a child left alone who lights matches out of loneliness and fascination with fire, the song follows the girl as the flames engulf her entirely, ending with her burned to ash — a dark fairy-tale about childhood danger and obsession with fire.","opus":"Retelling a Struwwelpeter tale, a child left home alone plays with matches and is consumed by fire, crying for help as the flames both love and kill her before she rises from the ashes toward the sun."},"nine-inch-nails~satellite":{"src":"haiku","haiku":"Surveillance and loss of privacy. A satellite watches and monitors every word and thought, is always present, and represents an inescapable system of control embedded in consciousness.","sonnet":"The song is told from the perspective of a pervasive surveillance entity — a satellite that monitors every word, claims to be inside the listener's head, and asserts it is always one step ahead, evoking a world of total information control.","opus":"A depiction of pervasive surveillance, personified as a satellite that watches, listens to every word, and gets inside your head, one step ahead of anyone trying to escape it."},"gorillaz~stylo":{"src":"haiku","haiku":"A meditation on electric love and connection that flows through the world at night. The song treats love as a powerful, transformative force that carries meaning and possibility despite hardship and depression.","sonnet":"The song frames love as an electric, overloading force that flows through people and sustains them through hard weeks, urging listeners to rise above depression and recession by letting that energy carry them forward.","opus":"Using imagery of electricity, overload, and power surging through circuitry, the song equates love with an electric current that flows through everyone and helps lift people out of depression and hard times."},"nine-inch-nails~running":{"src":"haiku","haiku":"A song about inescapable pursuit and surveillance. The speaker attempts to hide from watchers who are always aligned against them, but eventually realizes there is nowhere left to run—they have been caught.","sonnet":"A paranoid, claustrophobic song about being watched and hunted — the narrator follows someone for comfort while sensing that unseen forces are always closing in, and he is running out of places to hide.","opus":"A paranoid, isolated narrator trails after someone while feeling constantly watched by shadowy pursuers, admitting he is running out of places to hide and will never get away."},"system-of-a-down~chop-suey":{"src":"haiku","haiku":"A song about hiding pain and despair beneath a facade. The singer confronts someone about suicide and spiritual disconnection, asking why they hide their scars and questioning if angels should die. It invokes abandonment by a father figure.","sonnet":"The song moves between a bitter portrait of someone covering up self-destruction with appearances, and a cry of abandonment addressed to God — asking why he has been forsaken — framing suicide and death as a \"self-righteous\" act that the narrator both condemns and mourns.","opus":"Depicting someone masking their pain with makeup and hidden scars, the song moves through themes of self-righteous suicide and ends with Christ's words of being forsaken on the cross."},"grimes~flesh-without-blood":{"src":"haiku","haiku":"A heartbreak narrative where the speaker recognizes a partner's hollow transformation and loss of authenticity. What once was genuine light has been corrupted by greed and fame, leaving only an empty shell.","sonnet":"The narrator ends a relationship with someone whose beauty and voice she once admired but who proved destructive, conditional, and ultimately driven by money and fame; she withdraws her care and asks to be released.","opus":"The end of a soured relationship, in which the narrator no longer sees any light in a former partner who craved money and fame, and declares she no longer cares as she tells them to let her go."},"crossfaith~freedom-feat-rou-reynolds":{"src":"haiku","haiku":"A call to liberation from control and regulation. Pursued by overwhelming forces, the speaker and others break limitations and try to reclaim freedom while being hunted by machines and systems designed to contain them.","sonnet":"The song splits between an anthem of collective liberation — breaking limitations and finding home within — and a dystopian verse about people pursued by machines in a neglected cityscape, framing resistance against mechanical or systemic control as a march of the soul.","opus":"A rebellious anthem of breaking free from control and machines, urging a companion to stand together and find a home, following a figure who runs and is chased through a neglected, mechanized world."},"the-crystal-method~weapons-of-mass-distortion":{"src":"haiku","haiku":"A Russian-language reflection on the speaker's love for modern rock and roll as an embodiment of their generation. Despite the current state of the genre, the speaker identifies themselves as children of rock and roll, mourning lost companions.","sonnet":"A Russian-language nostalgic reflection on rock and roll: the narrator celebrates the genre as a personal identity and recalls the joyful, improvised performances of youth with close friends he has since lost touch with, lamenting that those days are gone.","opus":"A nostalgic tribute to rock 'n' roll, with the Russian narrator recalling the diamond days of playing carelessly with his best friends and declaring that rock 'n' roll is himself and his generation."},"circle-of-dust~neophyte":{"src":"haiku","haiku":"A narrative of arrival and initiation. An alien/divine visitor welcomes a newcomer as a satellite to a darker knowledge. The initiate must ascend through darkness to become their new self—a process framed as inevitable transformation.","sonnet":"Framed around sampled sci-fi dialogue about alien invaders, the song addresses a newcomer — a \"neophyte\" — welcoming them into awakening, urging them to look up from passive drifting and embrace a new beginning, with a protective vow to never let them go.","opus":"Framed with sci-fi film samples about invaders from space, the song welcomes a 'neophyte' into a darker world, promising ascension, new knowledge, and protection even as death's wind wipes out all life on the planet."},"black-light-burns~animal":{"src":"haiku","haiku":"An exploration of conflicting desire and self-loathing. The speaker is attracted to something primal and destructive even as they recognize its danger—they hate that they love this animalistic pull.","sonnet":"The narrator is caught in a hateful, compulsive love — he despises his attraction to someone who lies and manipulates, yet keeps being drawn back, recognising that he would surrender everything to let that dark \"animal\" inside him loose again.","opus":"A confession of a toxic, addictive attraction, where the narrator hates that he loves someone, craves their lies and cruelty, and would give everything to let the 'animal' of that desire in."},"serj-tankian~beethoven-s-c":{"src":"haiku","haiku":"A song about love, time, and civilization's moral collapse. The speaker condemns the commercialization of love and confronts the listener about their blindness and abandonment, all while walking through dead landscapes seeking connection.","sonnet":"A fractured meditation on love, betrayal, and civilisational collapse — the narrator insists love is not about profit or riches, while imagery of clocks failing and civilisation on trial suggests a world and a personal relationship both crumbling from dishonesty.","opus":"An abstract lament on love, time, and mortality, contrasting genuine affection against greed for profit and fame while civilization stands on trial and the narrator, left alone and going blind, feels the clock running out."},"sodom~gisela":{"src":"haiku","haiku":"A German-language song about the dissolution of a past romance. The speaker once knew a woman named Gisela who represented something transgressive and valuable, but she is now gone—discovered in a personal ad, no longer special.","sonnet":"A darkly comic song about a man who once valued a woman for her forbidden appeal, only to discover her advertising herself in a pornographic magazine, where her explicit personal ad promises to fulfil any desire — the song plays the absurdity of this revelation for crude, sardonic effect.","opus":"A crude, satirical piece about a lost love giving way to a pornographic magazine advertisement, in which a woman named Gisela promises to fulfill every desire and serve up any pleasure on a silver platter."},"annihilator~alison-hell":{"src":"haiku","haiku":"A nightmare narrative where a child discovers a mysterious box and becomes obsessed with fire, ultimately burning herself. Her imagined terror 'Alison Hell' becomes real—a manifestation created from her own fear and loneliness.","sonnet":"The song is narrated by a tormenting voice inside a woman's mind — an entity she herself created through fear and isolation — that drives her to madness, trapping her in a basement and sealing her in a private hell.","opus":"A tormented girl named Alison, taunted and haunted by a lurking presence born from her own untended fears, descends into madness and hell, trapped, naked, and alone with the monster she created."},"onslaught~born-for-war":{"src":"haiku","haiku":"A bleak portrait of a soldier programmed from birth for violence and death. The song depicts systematic dehumanization, psychological destruction, and the transformation of a person into a killing machine through indoctrination and warfare.","sonnet":"A portrait of a soldier conditioned from birth to kill, tracing the brutal cycle of violence, coercion, and death that defines his existence from cradle to grave, framing war as a system that manufactures human weapons and discards them.","opus":"A grim portrait of a soldier bred and conditioned to be a killing machine, tracing how violence, indoctrination, and the destruction of life turn a child into a weapon bound for death from cradle to grave."},"alice-in-chains~lesson-learned":{"src":"haiku","haiku":"A reflection on wisdom gained through pain and disconnection. The speaker has learned harsh lessons about trust and self-deception, discovering that their darkest hour brought unexpected illumination.","sonnet":"The song reflects on hard-won self-knowledge — the narrator has been disconnected and self-deceiving, but in his darkest moment something clicks, offering not a complete answer but a small, real insight that serves as another lesson in survival.","opus":"Reflecting on hard-won experience, the song frames pain and scars as lessons and suggests that in your darkest hour a clarifying thought can strike like gold, even if it isn't the final answer."},"nevermore~the-death-of-passion":{"src":"haiku","haiku":"A lament of emotional emptiness and the death of feeling. The speaker stands hollow and shadowed, their passions extinguished by time and deception, becoming void and emptiness itself.","sonnet":"The narrator addresses someone who has hollowed him out with deception, leaving him a shadow of himself — all passion is dead, self-destruction fills his mind, and he sees the other person as diseased and fundamentally empty.","opus":"A hollowed-out man addresses a deceiver whose lies have killed all his passions, leaving him a self-destructive shadow consumed by confusion, contempt, and emptiness."},"type-o-negative~world-coming-down":{"src":"haiku","haiku":"A self-aware confession of self-destruction and depression. The speaker recognizes they are collapsing their own world through self-hatred despite appearing fortunate, and cannot escape their role in the demolition.","sonnet":"The narrator acknowledges that he alone is responsible for the collapse of his own life — filled with self-hatred despite his fortune, unable to fake joy, he accepts that his world is coming down through his own actions and refuses to pretend otherwise.","opus":"A confession of self-hatred and guilt, in which the narrator recognizes that he alone has brought his world crashing down and refuses to feign the joy others expect of him, choosing to burn out rather than fade weakly."},"onslaught~code-black":{"src":"haiku","haiku":"A chilling depiction of fascistic rise and violent revolution. The song portrays a new supremacist movement built on hatred, propaganda, and systematic elimination, with violent forces deployed to destroy dissenters.","sonnet":"The song describes the rise of a neo-fascist order — using imagery of wolves, propaganda, purges, and a \"new world order\" — portraying ideological supremacism as it recruits, eliminates the weak, and systematically destroys those it deems impure.","opus":"A dystopian vision of a rising totalitarian 'new world order' built on hatred, supremacist propaganda, and the crushing of the weak, faith, and impurity in the name of a manufactured dream."},"alice-in-chains~sea-of-sorrow":{"src":"haiku","haiku":"An accusation of harm and a vow of survival. Someone has deeply hurt the speaker, and the speaker chooses to move forward while the other wallows in regret and sorrow.","sonnet":"The narrator has been wounded by someone and refuses to follow them into their ongoing self-destruction — he will survive and move forward while the other person wallows in sorrow, aiming his defiance back at them like a skull.","opus":"After being betrayed by someone who 'opened fire' on him, the narrator vows to move on and live for tomorrow while leaving the other person to wallow alone in a sea of sorrow."},"the-prodigy~narayan":{"src":"haiku","haiku":"A spiritual/apocalyptic narrative about transformation and awakening. As the western sun falls and the morning comes, a growing power and energy rises—the repeated invocation of Narayana (a Hindu deity) frames this as spiritual ascension.","sonnet":"A song about rising energy and collective awakening — the narrator feels a growing power within as a western age gives way to something new, weaving the Vedic mantra \"Om Namo Narayana\" into the sense that a transformative moment has arrived.","opus":"A mystical, uplifting call built around the chant Om Namo Narayana, sensing the western sun falling and telling the listener their time has come as a growing energy and power take hold."},"nine-inch-nails~various-methods-of-escape":{"src":"haiku","haiku":"An attempt to construct meaning and escape through art that no one hears. The speaker hallucinates plans and builds monuments to their own creation, then burns it all—unable to trust themselves or find genuine escape.","sonnet":"The narrator tries to find a way out — from a relationship or situation he cannot clearly distinguish from himself anymore — through destruction and ritual burning, but cannot fully break free or trust his own judgment.","opus":"A fractured mind describes hallucinations, self-harm, and a looping lyric no one hears, longing to let go and get away as the past repeats and the narrator can no longer trust himself or tell what's real."},"nine-inch-nails~not-anymore":{"src":"haiku","haiku":"A song about being frozen by fear and silenced, yet insisting on personal identity. The speaker resists transformation into someone else and clings to self-knowledge, even as they struggle to wake from a nightmare state.","sonnet":"The narrator describes being paralysed and unable to wake up — once certain of his identity and purpose, he now finds himself frozen, unable to shake the sense that everything he believed and worked toward has slipped away.","opus":"A person realizes they were turning into someone else and living on false hope, and now, frozen with fear and unable to wake up, they cling to their sense of who they are and vow it won't happen anymore."},"wargasm-uk~lapdance":{"src":"haiku","haiku":"A provocative track about defiance and contempt for authority. The speaker presents themselves as dangerous and transgressive while comparing government and politicians to strippers—all performing for an audience they disdain.","sonnet":"A defiant, confrontational song that compares politicians and authority figures to strippers — all performance and empty promises — while the narrator presents himself as an armed, lawless outlaw who will not be told what to do by a society that makes people want to kill.","opus":"A brash, provocative boast of an outlaw persona armed with guns, riding a motorcycle, disgusted by politicians who sound like strippers, and taunting a desirous listener with the offer of a free lap dance."},"nine-inch-nails~underneath-it-all":{"src":"haiku","haiku":"A song about haunting emotional attachment. Despite numbness and attempted severance, the speaker cannot escape feeling the other person; they remain crucified inside despite all attempts to kill the connection.","sonnet":"The narrator cannot rid himself of a person's presence — even after trying to kill the feeling, the other person still resonates underneath everything, leaving the narrator permanently stained by that connection.","opus":"An obsessive account of a presence that cannot be shaken, remaining inside and felt no matter how numb, damaged, or 'dead' the narrator becomes, leaving him stained by it."},"machine-head~days-turn-blue-to-gray":{"src":"haiku","haiku":"A tragic portrait of parental neglect and its generational damage. The speaker reflects on a father's absence, their own descent into addiction and self-destruction, and the guilt of perpetuating harm—now with no closure.","sonnet":"A confrontation with an absent, alcoholic and drug-addicted father who abandoned his children — the narrator traces the damage done across a childhood of crayons and clay that turned grey, ending with a plea for love and grief over a wound that never closed.","opus":"A bitter reckoning with a self-destructive, addicted parent whose drinking and neglect paralyzed and scarred their children, mixing rage, grief, and an unanswered plea for love and closure."},"nine-inch-nails~head-down":{"src":"haiku","haiku":"A dissociation narrative where the speaker rejects their present reality, denying their own face and life as real. Everything—including other people—feels like a dream they wish to escape.","sonnet":"The narrator feels completely alienated from his surroundings — nothing around him is recognisable as his own face, his own life, or reality at all — and addresses someone consumed by hate, warning that the consequences of who they have become have caught up with them.","opus":"A voice of oppression orders someone to keep their head down and know their place, while the person on the receiving end insists that none of this life is real and would give anything to escape it."},"ashen~outlier":{"src":"haiku","haiku":"A portrait of alienation and invisibility. The speaker is a social outcast tormented for being different, gradually becoming consumed by rage and darkness, ultimately threatening to make others understand their pain.","sonnet":"The song voices the pain of someone who feels perpetually misunderstood, medicated, and cast out — labelled a freak and a weird kid, dismissed and unseen — while expressing a burning rage and a desperate wish to finally be felt or remembered even in death.","opus":"An alienated outcast, dismissed as a freak and weirdo and failed by an uncaring listener, spirals through medication, rage, and self-loathing, seeing himself as an outlier trapped inside his own head."},"bring-me-the-horizon~go-to-hell-for-heaven-s-sake":{"src":"haiku","haiku":"A brutal severance song about burning bridges and rejecting a false or destructive person. The speaker bleeds out the listener's lies and condemns them to hell for their weakness and parasitism.","sonnet":"A scorched-earth rejection of someone the narrator despises — burning every bridge, denouncing them as a hollow, derivative person who breaks hearts — culminating in a final, unambiguous dismissal.","opus":"A furious kiss-off to a hollow, deceitful person, with the narrator burning down every bridge between them and telling this spineless follower to go to hell."},"celldweller~heart-on":{"src":"haiku","haiku":"A declarative love song where the speaker performs increasingly absurd acts of heroism and devotion to communicate their deep affection. The heart is pinned openly for the world to see—vulnerability is the point.","sonnet":"An exuberant, hyperbolic declaration of love: the narrator catalogues absurd feats of heroism performed for someone he loves, making clear through comic braggadocio that his devotion is total and unconditional.","opus":"An exuberant, over-the-top love song in which the narrator boasts of fighting monsters, sirens, and samurai to prove his devotion, wearing his heart on his sleeve just to say he loves the person completely."},"nine-inch-nails~the-wretched":{"src":"haiku","haiku":"A song about the moment of realization when life doesn't turn out as hoped, and joining a collective of the disappointed and broken. The lyrics explore disappointment, the inability to escape a cycle, and feeling trapped in spiritual or emotional emptiness.","sonnet":"A person confronts the total collapse of their hopes and expectations, realizing that life has not turned out as they wanted and that even the universe — imagined as God pushing them down — conspires to keep them stuck in misery. The song dwells on the loop of pretending and sinking, unable to break free.","opus":"A bitter reckoning with disillusionment, told to someone whose life didn't turn out the way they wanted; the speaker welcomes them into a shared misery and insists this crushing feeling is inescapable, even framing a vengeful god as pushing them down."},"machine-head~locust":{"src":"haiku","haiku":"A plague of locusts descends as a metaphor for consuming evil and societal decay, with faith and truth presented as the only redemption against the swarm. The song treats the locust invasion as a reckoning for corruption and deception.","sonnet":"A swarm of locusts descends as a biblical plague — a destructive force that chokes the sky, consumes the harvest, and bleeds the earth dry, yet the song ends with faith and truth ultimately tearing away the veil and exposing the charade.","opus":"Casts a devouring swarm of locusts as an apocalyptic plague that darkens the sky, consumes souls young and old, and reduces creation to a feast, framed with imagery of judgment where lies are torn away and a supposed purity ultimately prevails."},"muse~apocalypse-please":{"src":"haiku","haiku":"The song calls for emergency intervention and miraculous divine action to prevent the end of the world, framing salvation as urgent necessity. It presents apocalypse as imminent and demands transformative intervention.","sonnet":"A call for the world to declare an emergency and embrace an apocalyptic end, framing catastrophe as both inevitable and somehow redemptive — something miraculous and biblical that will finally pull humanity through.","opus":"Calls out for a miraculous, biblical rescue as the world ends, repeatedly declaring the apocalypse and pleading for something to pull humanity through."},"dream-theater~misunderstood":{"src":"haiku","haiku":"A meditation on feeling isolated and misperceived despite being surrounded by people, with the speaker describing themselves as superhuman or exceptional to explain their disconnection and loneliness. The theme is the gap between appearance and reality in social isolation.","sonnet":"A person grapples with deep social isolation — feeling abandoned despite being surrounded by people, knowing many yet truly knowing no one, and sensing that an outwardly superhuman or composed image has only made them more fundamentally misunderstood.","opus":"Explores an isolation felt even while surrounded by people, the sense of knowing many yet truly knowing no one, and the loneliness of being seen as superhuman while feeling abandoned and misunderstood."},"death-angel~god-vs-god":{"src":"haiku","haiku":"An internal conflict between self-love and self-destruction, portrayed as competing spiritual forces where attachment and dependency war with the desire to break free. The song centers on toxic emotional bondage and the plea for healing.","sonnet":"The narrator is trapped in a destructive relationship that feels both sacred and enslaving — drawn to someone who built walls and stole their future, they oscillate between needing to escape and being unable to leave, pleading for God to heal the part of them that remains in chains.","opus":"A tormented, addictive dependence on someone or something that feels like both a healer and a captor; the speaker can't break free, feels enslaved and destined to fail, and begs to be healed and set free."},"heathen~dying-season":{"src":"haiku","haiku":"A meditation on the costs of war—bloodshed, loss of life, and the suffering of soldiers—presented as the price of power and greed. The lyrics lament the cycle of violence and the inevitability of death in conflict.","sonnet":"An anti-war lament describing a season defined by bombs, fallen bodies, broken promises, and soldiers marching into dust, questioning whether the cost of war — the rivers of blood, the scarred sanity, the timeless wounds — is ever worth it.","opus":"A grim depiction of war as an endless season of death, with broken promises, marching soldiers, falling bombs, and shattered nations, questioning whether the suffering is ever worth the cost."},"kabanos~paliwoda":{"src":"haiku","haiku":"Paliwoda, a vengeful supernatural force, is unleashed to destroy evil and punish wrongdoing through violent retribution and destruction. The song treats vengeance as justice delivered by a relentless mythic entity against corruption and vice.","sonnet":"A Polish folk-metal ballad about a vengeful avenger called Paliwoda who breaks his chains, smashes walls, stabs the beast, and burns its corpse — a relentless force of righteous retribution who hunts down the wicked and is the last hope wherever despair and ruin reign.","opus":"A vengeful avenger figure who breaks his chains and hunts down a vile, wicked foe, promising to crush and destroy evil; the fates have turned against the villain, who cannot escape the coming reckoning and death."},"serj-tankian~butterfly":{"src":"haiku","haiku":"The song laments how societal inhibitions, submission, and repetition sacrifice individuals and destroy their spiritual potential, using the butterfly as a symbol of transformation from suppression to freedom. It calls for breaking free from collective conditioning.","sonnet":"The song protests collective self-destruction through fear and repetition — humanity trapped by its own inhibitions and suspicions — while the image of a moth becoming a butterfly stands for a beauty and transformation that shouldn't be falsified, paired with a call to abandon autocracy for more ecologically aware ways of being.","opus":"A dense, surreal protest against submission, self-imposed inhibition, and a world that sacrifices itself through suspicion and repetition, calling for love and eco-centric change over autocracy while refusing to be crucified or terrified."},"onslaught~killing-peace":{"src":"haiku","haiku":"Systematic violence, terrorism, and religious indoctrination are presented as forces that murder innocence and corrupt the pure-hearted, depicting war as an assault on goodness itself. The imagery portrays dehumanization through organized brutality.","sonnet":"An extreme-metal portrait of religiously framed mass violence — born into a world of religion and perpetual war, the narrator describes genocide, chemical killing, and demonic destruction as forces that tear apart innocence and shatter heaven's peace.","opus":"A violent, blasphemous vision of orchestrated genocide and religious war, depicting poison, sedation, and systematic killing that destroys the innocent and defiles the sacred, with humanity born into religion and a third world war."},"raubtier~dieseld-den":{"src":"haiku","haiku":"A suicide manifesto where the narrator plans mass destruction through poisoning water and oil before taking his own life, driven by vengeance against those he perceives as enemies. The song describes a final apocalyptic revenge fantasy.","sonnet":"A Swedish industrial-metal track narrating a revenge fantasy in which the speaker, driven by hatred, plans to poison the water supply and set fire to the oil — becoming the ultimate terrorist — before realizing his scheme will kill everyone including himself, and so he drinks his own deadly brew.","opus":"A vengeance-driven poisoner plots to contaminate water and set oil ablaze so his enemies die of thirst and fire, craving recognition as the terrorists' terrorist, then drinks his own deadly brew of turpentine and diesel to die alongside them."},"machine-head~ghosts-will-haunt-my-bones":{"src":"haiku","haiku":"Inner demons and haunting thoughts torment the speaker, creating a psychological war that manifests as physical torture and internal conflict. The ghosts are metaphorical intrusions of unresolved trauma and self-loathing.","sonnet":"The narrator is tormented by internal demons and dark thoughts that won't let them rest — the ghosts that haunt their bones are the anguished, conflicting voices inside their own head, the bile of self-hatred, and the crushing weight of sleepless nights.","opus":"A menacing inner torment where the speaker imagines inflicting pain on another while being haunted by relentless dark thoughts, demons, and self-loathing that won't leave him alone as night crashes down."},"blood-red-shoes~light-it-up":{"src":"haiku","haiku":"The song expresses frustration with worn-out promises and stale ideologies, calling for action and ignition to break through complacency and see real change. It centers on the exhaustion of false hope and the need for tangible activation.","sonnet":"A song about pushing past exhaustion and worn-out lies — acknowledging a fever of restless energy and the sense of growing out of an old life — and choosing to ignite something real rather than cling to false comfort or faded promises.","opus":"Restless energy against something old, worn out, and false; the speaker urges lighting it up for real, growing out of a life that no longer fits, and taking heart despite the lies."},"megadeth~never-walk-alone-a-call-to-arms":{"src":"haiku","haiku":"A complex narrative about redemption and protection where the speaker offers unconditional support despite past conflict, proclaiming intimate knowledge and the role of healer or savior. The song balances confession of love with a call to unified action.","sonnet":"A protective vow from someone who once shared the narrator's enmity but now pledges unconditional shelter — they will never let the other walk alone, having loved them even through hatred, and will carry the weight of past sins to stand as a guardian against whatever threatens.","opus":"A vow of unconditional protection from someone who was once the listener's enemy, promising to shelter, warm, and never let them walk alone, drinking away their pain and forgiving their trespasses."},"northlane~inamorata":{"src":"haiku","haiku":"A celebration of recovery and transformation through love, where the beloved has rescued the speaker from despair and now the speaker vows reciprocal devotion and loyalty. The song centers on mutual spiritual restoration.","sonnet":"A love song directed at a devoted partner who saved the narrator from drowning — literally and figuratively — restored their sight and sense of home, and whose boundless patience dissolved their panic; now the narrator declares it is their turn to burn with equal loyalty and devotion.","opus":"A devotional love song of being rescued and made whole by a beloved, vowing to now burn and bear the strain for them in return as a new dawn breaks and the speaker feels rebuilt and restored."},"tesseract~smile":{"src":"haiku","haiku":"A warning against manipulation and control, with the speaker resisting coercion and urging independence against a sinister entity attempting to dominate through psychological means. The smile masks menace and the need for free thought is central.","sonnet":"The narrator feels hunted and controlled by a menacing, mechanical presence that encourages killing and uses manipulation to dominate — a colossal, shadowing figure that smiles as it closes in, casting a shadow over everything and reducing the narrator to an object of its predatory design.","opus":"An unsettling scene of manipulation and control, where a mechanical, soothing voice urges a 'brave soldier' to keep killing and think for himself against a menacing figure whose ways control him."},"bring-me-the-horizon~can-you-feel-my-heart":{"src":"haiku","haiku":"The speaker struggles with emotional distance, internal demons, and the paradox of simultaneously craving and fearing closeness, expressing fear of vulnerability and the impossibility of escaping internal darkness. The song is about emotional isolation within relationships.","sonnet":"A plea from someone paralyzed by fear of closeness and self-destructive impulses — unable to drown their demons, hating both isolation and intimacy — who begs to be heard, fixed, and saved before the cycle of self-harm and numbness consumes them entirely.","opus":"A desperate plea for connection and salvation from someone drowning in numbness, fear of closeness, and inner demons, begging to be heard and fixed while apologizing to family."},"karnivool~themata":{"src":"haiku","haiku":"The song grapples with hypocrisy, materialistic greed, and the duality between seeing the world as alive versus a lie, with repeated emphasis on learning truth through experience and personal contradiction. It questions perception and deception in society.","sonnet":"A restless inner search for meaning and truth — the narrator navigates their own hypocrisy and greed, questioning what they see in a world that feels simultaneously alive and false, and struggling to know whether they are truly awake to it or still lost in the turning.","opus":"A searching, introspective reckoning with one's own greed and hypocrisy, oscillating between seeing the world as alive and seeing it as a lie, while surrendering to sensory experience and wondering what there is to see."},"shining~besvikelsens-dystra-monotoni":{"src":"haiku","haiku":"A suffocating landscape of anxiety closing in from all sides, where every bond and feeling inverts into its opposite—friends become enemies, love becomes hate, admiration turns to disgust. The song unfolds as a catalog of total emotional collapse.","sonnet":"A Swedish depiction of total emotional reversal in a bleak, tunnel-like landscape — friends become enemies, love turns to hate, admiration to disgust, joy to sorrow — an unrelenting descent into anxiety and loss on every side.","opus":"A bleak descent into endless tunnels and thousandfold anguish, charting how everything turns to its opposite: friends into enemies, love into hate, admiration into disgust, and joy into sorrow."},"ocean-grove~these-boys-light-fires":{"src":"haiku","haiku":"The song explores existential questioning and the search for meaning through friendship and connection, contrasting isolation with belonging and the desire to grow and find purpose. It questions identity and the role of companionship in self-discovery.","sonnet":"The narrator reflects on striving forward while questioning purpose and identity — finding their best self in the company of another, uncertain whether external validation or inner drive matters more, and circling the theme of bearing life's burdens both alone and together.","opus":"A young person's anxious striving for progress and meaning, questioning whether we're just matter and cells, and finding the best in himself alongside a companion while feeling he bears everything alone."},"nine-inch-nails~that-s-what-i-get":{"src":"haiku","haiku":"A breakup song about emotional betrayal and the pain of realization that a relationship was one-sided, with the speaker learning that their love and vulnerability were not reciprocated. The refrain captures bitter resignation to romantic loss.","sonnet":"The narrator reels from the betrayal of a romantic partner who has destroyed their confidence — naively devoted, they are now left crying and self-recriminating, accepting the heartbreak as what they deserved for trusting so completely.","opus":"The aftermath of a betrayal in love, where the speaker realizes he wasn't the only one, feels his confidence stripped away, and resigns himself that heartbreak is simply what he gets."},"james-and-the-cold-gun~plug-me-in":{"src":"haiku","haiku":"The song expresses emotional numbness and a desperate need to feel something, using metaphors of being plugged in or activated to convey hunger for vitality and sensation in a world of disconnection and desperation.","sonnet":"A person numbed by emotional disconnection and chaotic circumstances — failed relationships, aimlessness, violence around them — desperately craves stimulation and feeling, demanding to be switched on and made to feel something real.","opus":"A craving to feel anything at all amid numbness and aimlessness; the speaker, whose heart is trapped, repeatedly begs to be plugged in and turned on so he can escape feeling ignored."},"pezet~rock-n-roll":{"src":"haiku","haiku":"A celebration of hedonistic nightclub culture—drinking, dancing, and sexual abandon—as the speaker's personal rock and roll ethos, rejecting respectability in favor of raw excess and group solidarity in transgression. The song glorifies the party lifestyle.","sonnet":"A Polish rap track celebrating a night of hedonistic excess — drinks, clubs, crowds, and casual encounters — framed as the narrator's own version of rock and roll, equating rap performance energy with the reckless spirit of a live show even without guitars or vocalists.","opus":"A hedonistic night of clubbing, drinking, drugs, and women, framing a rap crew's raucous, chaotic partying as their own version of rock and roll where pop is the enemy and the crowd surges the stage."},"system-of-a-down~science":{"src":"haiku","haiku":"Science and rational analysis are critiqued for failing to account for faith, spirituality, and the intangible elements of human experience that transcend material explanation. The song argues faith is the force that animates existence beyond scientific understanding.","sonnet":"A rejection of science as the sole framework for understanding existence, arguing it fails to account for faith — the willingness to let go and trust the unfolding — and has failed the earth; the song ends with a call to let spirit, which moves through all things, guide humanity instead.","opus":"Argues that science has failed the world and Mother Earth by ignoring faith and spirit, insisting that surrendering to the unfolding and recognizing that spirit moves through all things matters more than prediction and programming."},"grimes~you-ll-miss-me-when-i-m-not-around":{"src":"haiku","haiku":"The song depicts suicidal ideation and self-harm with dark acceptance, presenting death or escape as inevitable while expressing the conviction that absence will be mourned. It centers on the finality and paradoxical legacy of self-destruction.","sonnet":"The narrator describes self-inflicted harm and death with a detached, almost defiant tone — assuring whoever is listening that they will be missed once gone, and cycling through images of drowning, shooting, and climbing to heaven, treating absence as a final form of significance.","opus":"Frames suicidal thoughts and self-harm in a detached, almost flippant tone, imagining being dead and underground while telling someone they'll miss the speaker once they're gone."},"pixies~where-is-my-mind":{"src":"haiku","haiku":"The song plays with surreal imagery and disorientation, describing a state of mental escape or dissociation where reality inverts and the speaker's consciousness drifts away. The recurring refrain captures existential bewilderment.","sonnet":"A disoriented narrator describes a dreamlike state of mental dissolution — upside-down, hollow-headed — framed around a Caribbean swim where even a small fish seemed to be communicating, capturing a feeling of the mind drifting somewhere unreachable.","opus":"A disorienting, dreamlike sense of losing one's mind, tied to surreal images of an upside-down world and swimming in the Caribbean where a little fish seems to try to talk to the speaker."},"karnivool~sky-machine":{"src":"haiku","haiku":"The song explores destiny, determinism, and the question of whether fate is fixed or open, with the speaker seeking answers from a mysterious figure who may hold knowledge of humanity's future. It centers on existential uncertainty and transcendence.","sonnet":"An address to an unknown, possibly extraterrestrial or transcendent presence — the narrator gazes at the sky waiting for something beyond human plans, asking it to show the way, and inviting it aboard a sky machine to reveal where it comes from and what humanity is ultimately seeking.","opus":"A longing to reach something beyond the sky and understand it, insisting there is no grand plan and choosing to cross the line with an open mind, while confronting the vicious things people hide and questioning whether one will run or stay."},"spiritbox~silk-in-the-strings":{"src":"haiku","haiku":"The speaker is emotionally manipulated and controlled by another, treated as a marionette or prey, unable to escape despite awareness of the entanglement. The silk metaphor captures the delicate yet inescapable bonds of toxic attachment.","sonnet":"The narrator is entangled in a toxic relationship with someone who handles them carelessly — like crushing a moth wing — and whose words have burrowed in like spider silk, impossible to shake off even after escape; the song dwells on the lingering psychological hold of a damaging bond.","opus":"Depicts a toxic, entangling attachment likened to being wrapped in silk and plucked to feed another; the speaker escapes yet still carries the harmful person with them, sickened by a relationship they can't fully shed."},"health~slaves-of-fear":{"src":"haiku","haiku":"From birth to death, humans are enslaved by fear—of rejection, difference, judgment, and mortality—wasting their years in service to anxiety rather than genuine struggle. The song laments the universal human condition of fear-driven existence.","sonnet":"A bleak meditation on the human condition as one of perpetual fear from birth to death — driven by desire for love or numbness, wasting years on pointless conflict, with no higher meaning or justice above us and no one to save or judge us.","opus":"Argues that people are ruled by fear from birth to death, wanting love or numbness and to be different without trying too hard, and questions why life is wasted in a world with no one above to judge, love, or give pain meaning."},"pro8l3m~outro":{"src":"haiku","haiku":"The narrator faces imminent death, reflecting on a life of crime, betrayal, and choosing vice over virtue with resignation and dark acceptance. The song is a final confession of someone at the end of a violent life.","sonnet":"A Polish hip-hop monologue delivered as a dying man's reckoning — the narrator, alone in a jungle of debts and enemies, accepts an imminent violent end while confessing that he always knew right from wrong but chose the other path anyway, from poverty toward the Hilton and Rolex, and now regrets it.","opus":"A dying man's final reckoning as he's hunted down and killed alone in a jungle; he regrets nothing yet acknowledges he knowingly chose the wrong path over doing good, pleading only for a quick end."},"trivium~brave-this-storm":{"src":"haiku","haiku":"Humanity faces apocalyptic judgment for complicity in violence and decay, with waves of destruction representing collective consequence for apathy and moral failure. The song grapples with how to endure inevitable reckoning.","sonnet":"Humanity is cast as the architect of its own apocalypse — violent, apathetic, and consumed by decay — and a rising storm of punishment is both deserved and unstoppable, with the narrator admitting they cannot endure or survive the reckoning they helped bring about.","opus":"An apocalyptic reckoning where humanity, cast as the guilty catalyst of its own destruction, is overwhelmed by crashing waves and decay; the speaker doubts he can ever brave the storm and wonders whether to accept that all is lost."},"serj-tankian~praise-the-lord-and-pass-the-ammunition":{"src":"haiku","haiku":"Religious faith, prophecy, and spiritual lineage are invoked alongside themes of warfare and weaponry, creating ironic tension between spiritual creation/love and physical violence and ammunition. The song juxtaposes sacred and martial imagery.","sonnet":"A cynical commentary on religion and violence — tracing a lineage from prophet to king to pauper and back to love — that asks believers to lay down their guns while sardonically invoking the phrase used to justify holy war, questioning whether devotion ever leads to peace or only more ammunition.","opus":"A satirical indictment of religion fused with violence, contrasting a call to lay down guns with the refrain of praising the Lord while passing the ammunition, mocking how faith and warfare intertwine while people await Armageddon."},"gorillaz~dirty-harry":{"src":"haiku","haiku":"The speaker describes survival amidst poverty, violence, and marginalization, needing weapons for protection while questioning whether the endless warfare is worth enduring. The song contrasts the desire for peace with the necessity of combat.","sonnet":"A soldier returned from war finds himself unable to dance, unable to rest, haunted by gunshots at night and the cheap cost of life — a rap verse weaves together combat guilt, surveillance, and the bitter contrast between political theatrics and the poverty and violence faced by those who serve.","opus":"A soldier in a desert war clings to a gun and just wants to dance, while a hardened rapper's verse conveys the constant hurt, paranoia, and cheapened value of life in combat, feeling like an expendable pawn after being told the war is over."},"rammstein~te-quiero-puta":{"src":"haiku","haiku":"A sexually charged love song that objectifies and desires a woman's body while explicitly disclaiming emotional attachment, celebrating physical pleasure and transgressive desire. The Spanish lyrics emphasize raw sensuality and carnal intent.","sonnet":"A Spanish-language song expressing raw, purely physical desire — the narrator wants a woman's body and pleasure, explicitly disclaiming any interest in her heart, repeating declarations of lust and demands for more.","opus":"A crude, lust-driven come-on in Spanish where the speaker repeatedly demands sex and a woman's body, explicitly wanting her 'fruit' rather than her heart."},"nevermore~we-disintegrate":{"src":"haiku","haiku":"The song explores ego death, the dissolution of self through awareness of inner chaos, and the question of human freedom versus technological enslavement. It centers on transcendence through disintegration and loss of individual identity.","sonnet":"The self dissolves as ego — an endless fusion of stillness and chaos — is confronted and undone, with the narrator yearning to freeze time and let rain and solitude wash the divides away, questioning whether humanity is ever truly free or permanently enslaved to technology.","opus":"A meditation on the ego as a void within self-awareness, framing its death as a path to rebirth amid stillness and chaos, and questioning whether we are ever truly free or slaves to technology as everything dissolves into gray."},"nevermore~timothy-leary":{"src":"haiku","haiku":"The song celebrates psychonaut Timothy Leary and the promise of LSD-expanded consciousness as a path to understanding inner harmony and genuine freedom, mourning his death and lamenting society's fear of transformation. It treats psychedelic experience as spiritual revelation.","sonnet":"A tribute to Timothy Leary framing him as a visionary who used psychedelics and Eastern philosophy to awaken inner harmony in people, while the establishment tried to silence him; the song mourns his death and suggests the world still needs his message of inner freedom as it continues to decline.","opus":"A tribute to Timothy Leary and psychedelic philosophy, portraying his quest for enlightenment through LSD and Eastern thought, lamenting how the establishment tried to silence him, and calling on his spirit as the world declines."},"onslaught~rest-in-pieces":{"src":"haiku","haiku":"Graphic descriptions of violent dismemberment, torture, and murder are presented as the work of a sadistic killer who views himself as a master of death and the complete obliteration of victims. The song is a showcase of extreme gore imagery.","sonnet":"A graphic depiction of a serial killer — methodical, sadistic, and relentless — who dismembers and destroys victims so completely that nothing remains and no one even knows their name, painting them as a self-styled messiah of death with a homicidal passion for the obscene.","opus":"A gruesome portrait of a sadistic killer who dissects, mutilates, and exterminates victims with clinical brutality, leaving anonymous corpses in pieces while reveling in obscene, homicidal cruelty."},"acid-drinkers~blind-leadin-the-blind":{"src":"haiku","haiku":"The song warns against following blind leaders or ignorant guides, expressing refusal to participate in directionless pursuit of unclear goals. It's a brief statement about distrust in uncritical following.","sonnet":"A brief, direct refusal to follow someone the narrator sees as ignorant and untrustworthy — rejecting their leadership and intentions outright, with the core image being a blind person leading others nowhere.","opus":"A refusal to follow an ignorant, untrustworthy leader, questioning where blindly following the blind can possibly lead."},"megadeth~liar":{"src":"haiku","haiku":"A scathing character assassination of a pathological liar whose entire existence is fraudulent, tracing his corruption from family dysfunction through criminal behavior and disease to inevitable spiritual ruin. The song catalogs dishonesty and depravity.","sonnet":"A venomous character assassination directed at a pathological liar — cataloguing their moral failures, diseased lifestyle, and every form of deception — concluding that lying is all they will ever be and delivering a vicious litany of physical and moral degradation.","opus":"A scathing takedown of a compulsive, degenerate liar, cataloguing his squalor, disease, dishonesty, and vile character while insisting lying is all he'll ever be."},"arch-enemy~revolution-begins":{"src":"haiku","haiku":"The song calls for individual liberation and self-determination against systems designed to control and predefine fate, asserting that revolution against manipulation begins within each person. It centers on breaking free from external control.","sonnet":"A call to resist the machinery of social control — rejecting the idea that fate is preordained or that one must play a part in the big machine — and insisting that revolution starts within each individual who chooses to stand their ground and break their mental chains.","opus":"A rallying call to break free from being a controlled cog in a machine, urging the listener to stand their ground and reject others dictating their fate because revolution begins within each person."},"nightwish~the-poet-and-the-pendulum":{"src":"haiku","haiku":"A dark narrative of a tortured poet and writer condemned by society, depicting suffering, sacrifice, and the duality of public performance versus private agony before a violent end. The song explores the cost of artistic creation and spiritual ruin.","sonnet":"A long, multi-part meditation on the death of a poet and artist — moving through despair, self-loathing, longing for an innocent past, and the terror of a life spent performing for a cold world — ending with his betrayal by friends and the bleak image of them spitting on his grave.","opus":"A tormented songwriter's symbolic death and inner anguish, portraying him as a suffering poet torn apart, longing for home and a merciful death, betrayed and mocked by his friends who spit on his grave as a dark passion play unfolds."},"filter~stuck-in-here":{"src":"haiku","haiku":"The speaker feels trapped in a confining situation with no escape, repeatedly acknowledging their imprisoned state and attempting psychological avoidance without success. The song is about inescapable confinement and stagnation.","sonnet":"A short, circular song about being trapped in a low, stagnant state — unable to advance, going through the motions without pay or purpose, advised simply to close the eyes and ignore it — with no clear resolution offered.","opus":"A sense of being trapped, stuck, and stalled in low gear and fear, urging oneself to shut the door, close one's eyes, and ignore it, while resenting a job that demands hours without fair pay."},"annihilator~coward":{"src":"haiku","haiku":"The speaker confronts a cowardly abuser who preys on weakness and betrays trust, vowing accountability and retribution for cruelty and deception. The song is an accusation and threat directed at an unrepentant wrongdoer.","sonnet":"A furious confrontation with someone who preyed on a woman's weakness, exploited her, and cheated repeatedly — the narrator vows to deliver pain when their worlds collide, demanding the target admit fault and face the consequences of their selfish deception.","opus":"A confrontation with a cheating, self-serving man who preyed on a woman's weakness; the speaker vows he can't hide, promises to deliver pain, and tells him his time is through as they stand up for her."},"muse~sober":{"src":"haiku","haiku":"Alcohol is personified as the only thing keeping the speaker emotionally alive and unfrozen, yet the substance itself threatens betrayal and destruction. The song explores dependence on a toxic substance for emotional survival.","sonnet":"A song addressing whisky and bourbon directly — Royal Canadian blend, Wild Turkey, Jameson, single malts — as the sole things that keep the narrator from freezing, even as they burn inside and are destined to turn on him.","opus":"Addresses alcohol as an intimate, personified companion of blended whiskeys and single malts that both comforts and turns on the speaker, the solid burn inside being the only thing keeping him unfrozen."},"crystal-castles~empathy":{"src":"haiku","haiku":"The song critiques conformist control where individuals must earn acceptance through symmetry and empathy, becoming conduits for systemic manipulation and passive consumption. It describes the erasure of individuality through manufactured consensus.","sonnet":"A cryptic portrait of conformity and social conditioning — the body is reshaped and hollowed out to meet external standards of symmetry, people are force-fed preferences and encouraged to forget individuality, all while cities fall and a chrysalis of self-controlled consciousness reaches its final, collapsing form.","opus":"A cryptic, unsettling take on conformity and manufactured feeling, suggesting people must work in symmetry to earn empathy, are conditioned to forget and be force-fed, and undergo a controlled transformation amid images of cities falling down."},"megadeth~reckoning-day":{"src":"haiku","haiku":"The speaker takes pleasure in inflicting psychological torment and pain on another person, celebrating their suffering and eventual collapse. The song is a portrait of sadistic enjoyment of another's breakdown.","sonnet":"The narrator takes a predatory pleasure in another person's distress and self-deception — watching them crumble, beg, and break — while insisting this is not revenge but simply a reckoning that is coming regardless, an inevitable settling of accounts.","opus":"A menacing address to a victim, relishing their pain, tears, and false hope while denying it's revenge, and insisting instead that a day of reckoning is coming for them."},"megadeth~poison-was-the-cure":{"src":"haiku","haiku":"The speaker reflects on a dangerous, toxic relationship that initially seemed protective but was actually venomous, with lingering effects that cannot be purged. The snake metaphor captures betrayal hidden within apparent love.","sonnet":"The narrator reflects on a toxic relationship — initially warm and secure, but with someone who was always a snake — whose venom has never left the bloodstream even after the relationship ended, leaving them sleepwalking toward ruin until they finally let go.","opus":"A destructive love likened to a venomous snake, whose poison lingers in the speaker's blood long after; he traces his ruin and near-death decline, cast as being crushed by someone he loved despite the warning signs."},"porcupine-tree~way-out-of-here":{"src":"haiku","haiku":"The speaker contemplates escape and fading away, unable to bear sympathy or scrutiny, fantasizing about erasure and forgetting in response to loss or crisis. The song centers on the desire to vanish rather than process grief.","sonnet":"An adolescent yearns to disappear — escaping the stares, the sympathy, and the intrusive questions about how they feel — and imagines erasing every trace of a person from their life, burning pictures and forgetting names, while at the train tracks dreaming of a way out.","opus":"A grieving person's desperate wish to escape and vanish from the staring, sympathy, and prying questions after a loss, resolving to erase all traces and memories of someone in order to forget them."},"tool~the-pot":{"src":"haiku","haiku":"The song criticizes hypocrisy and self-righteous judgment, calling out those who condemn others while being guilty of the same sins, accusing the hypocrite of being fundamentally dishonest. It's a direct attack on moral duplicity.","sonnet":"A savage accusation of hypocrisy directed at someone who moralizes and points fingers while being neck-deep in the same mud themselves — the kettle calling the pot black — with the narrator tearing apart their self-righteousness as the delusion of someone who must have been out of their mind.","opus":"A blistering accusation of hypocrisy, calling out someone who wags a finger in judgment while being just as guilty, corrupt, and intoxicated, echoing the pot calling the kettle black."},"outline-in-color~snakebit":{"src":"haiku","haiku":"The speaker escapes a toxic relationship characterized by betrayal and dismissal, expressing suicidal ideation and deep dissociation while asserting their determination to break free from a hell they stayed in too long. The song documents recovery and the cost of leaving.","sonnet":"The narrator severs ties with a person who left them hollow and trapped in a cycle of harm — acknowledging that staying would mean death, doubting the other's claimed changes, and clinging to the will to live even while feeling dissociated and cursed by fate.","opus":"Escaping a toxic, hellish relationship that left the speaker cold, dissociated, and clinging to life; he resolves he's done with someone who lied and gave up, even as he wrestles with suicidal despair and feeling that his fate is doom."},"pro8l3m~freon":{"src":"haiku","haiku":"A nocturnal love affair unfolds in fleeting moments away from conventional morality, with two people seeking escape from the mundane through passionate physical connection that feels both transcendent and ultimately doomed. The song romanticizes illicit transgression.","sonnet":"A Polish hip-hop song about two people who meet for a purely physical encounter in a cold room lit by a neon \"Night Club\" sign, say nothing meaningful, and part — then years later find each other again and repeat the same wordless ritual, both aware that naming the feeling would destroy it, and choosing to live it again anyway.","opus":"A pair of lovers meeting in a cold, neon-lit night and again years later, sharing wordless, intense intimacy and cigarettes while the world seems to hate them; a fleeting, defiant escape from everyday life haunted by longing and impending separation."}};
